def _clean_lfm_image(url: str | None) -> str | None:
    """Filtra URLs vacías o placeholders de Last.fm."""
    if not url:
        return None
    # Last.fm usa esta URL cuando no hay imagen
    if "2a96cbd8b46e442fc41c2b86b821562f" in url:
        return None
    return url

async def get_dominant_color(image_url: str, fallback: int = 0xd51007) -> int:
    """Descarga la imagen y devuelve un color vibrante y representativo usando Pillow."""
    if not image_url:
        return fallback
    try:
        import colorsys
        from PIL import Image as _PILImage
        from collections import Counter
        async with aiohttp.ClientSession() as session:
            async with session.get(image_url, timeout=aiohttp.ClientTimeout(total=8)) as resp:
                if resp.status != 200:
                    return fallback
                img_bytes = await resp.read()
        img = _PILImage.open(io.BytesIO(img_bytes)).convert("RGB").resize((150, 150))
        pixels = list(img.getdata())

        def to_hsv(r, g, b):
            return colorsys.rgb_to_hsv(r / 255, g / 255, b / 255)

        # Paso 1: colores con saturación decente y luminosidad media
        vibrant = [(r, g, b) for r, g, b in pixels if to_hsv(r, g, b)[1] > 0.25 and 0.15 < to_hsv(r, g, b)[2] < 0.95]
        # Paso 2: umbral más bajo si no hay suficientes
        if len(vibrant) < 50:
            vibrant = [(r, g, b) for r, g, b in pixels if to_hsv(r, g, b)[1] > 0.1 and 0.1 < to_hsv(r, g, b)[2] < 0.98]
        # Paso 3: portada B&W — usar todos
        if len(vibrant) < 50:
            vibrant = pixels

        # Buckets más finos (24 en vez de 32) y top 20
        buckets = Counter(((r >> 3) << 3, (g >> 3) << 3, (b >> 3) << 3) for r, g, b in vibrant)
        top = [color for color, _ in buckets.most_common(20)]

        # Score: saturación * penalización por extremos de luminosidad
        def score(c):
            h, s, v = colorsys.rgb_to_hsv(c[0] / 255, c[1] / 255, c[2] / 255)
            return s * (1 - abs(v - 0.55) * 0.6)

        best = max(top, key=score)
        r, g, b = best
        return (r << 16) | (g << 8) | b
    except Exception:
        return fallback


