def _parse_dt(s: str) -> datetime:
    """Parse ISO datetime string, always returning a timezone-aware datetime (UTC)."""
    dt = datetime.fromisoformat(s)
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=timezone.utc)
    return dt

