def get_level(player):
    drops = player.get("total_drops", 0)
    current = LEVELS[0]
    for lvl in LEVELS:
        if drops >= lvl["min_drops"]:
            current = lvl
        else:
            break
    return current

def get_next_level(player):
    drops = player.get("total_drops", 0)
    for i, lvl in enumerate(LEVELS):
        if drops < lvl["min_drops"]:
            return lvl
    return None

# ─── CONFIG POR SERVIDOR ────────────────────────────────────────────────────────
def load_config():
    os.makedirs(os.path.dirname(CONFIG_FILE), exist_ok=True)
    if os.path.exists(CONFIG_FILE):
        with open(CONFIG_FILE, "r") as f:
            return json.load(f)
    return {}

def save_config(config):
    os.makedirs(os.path.dirname(CONFIG_FILE), exist_ok=True)
    with open(CONFIG_FILE, "w") as f:
        json.dump(config, f, indent=2)

def is_bot_admin(interaction: discord.Interaction) -> bool:
    return interaction.user.id in BOT_ADMINS

def is_channel_blocked(interaction: discord.Interaction) -> bool:
    config = load_config()
    guild_id = str(interaction.guild_id)
    channel_id = str(interaction.channel_id)
    blocked = config.get(guild_id, {}).get("blocked_channels", [])
    return channel_id in blocked

# ─── TRANSFORMER: Member o User por ID ───────────────────────────────────────
# Resuelve usuarios que ya no están en el servidor (evita TransformerError)
class MemberOrUser(app_commands.Transformer):
    async def transform(self, interaction: discord.Interaction, value: str) -> discord.User:
        # Intentar como Member normal primero (mención o ID)
        value = value.strip().lstrip("<@!").rstrip(">")
        try:
            uid = int(value)
        except ValueError:
            raise app_commands.TransformerError(value, discord.AppCommandOptionType.string, self)
        # Intentar como Member del servidor
        member = interaction.guild.get_member(uid)
        if member:
            return member
        try:
            member = await interaction.guild.fetch_member(uid)
            return member
        except discord.NotFound:
            pass
        # Si no está en el servidor, devolver User global
        try:
            user = await interaction.client.fetch_user(uid)
            return user
        except discord.NotFound:
            raise app_commands.TransformerError(value, discord.AppCommandOptionType.string, self)

