MAX_VENTAS_DIARIAS = 10

def get_ventas_hoy(player):
    hoy = datetime.now(timezone.utc).strftime("%Y-%m-%d")
    ventas_data = player.get("ventas_diarias", {})
    if ventas_data.get("fecha") != hoy:
        return 0
    return ventas_data.get("cantidad", 0)

def registrar_venta(player):
    hoy = datetime.now(timezone.utc).strftime("%Y-%m-%d")
    if player.get("ventas_diarias", {}).get("fecha") != hoy:
        player["ventas_diarias"] = {"fecha": hoy, "cantidad": 0}
    player["ventas_diarias"]["cantidad"] += 1

