def devolver_apuesta(game: dict):
    """Devuelve monedas o carta al retador de una apuesta cancelada/expirada."""
    data = load_data()
    challenger = get_player(data, game["players"][0])
    if game["apuesta_tipo"] == "monedas":
        challenger["coins"] = challenger.get("coins", 0) + game["apuesta_valor"]
    else:
        carta_p1 = game.get("carta_p1")
        if carta_p1 and carta_p1 not in challenger["cards"]:
            challenger["cards"].append(carta_p1)
    save_data(data)

def get_player(data, user_id):
    uid = str(user_id)
    if uid not in data:
        data[uid] = {"cards": [], "last_drop": None, "total_drops": 0, "coins": 100}
    if "coins" not in data[uid]:
        data[uid]["coins"] = 100
    return data[uid]

def weighted_drop(include_secret=True):
    """Drop aleatorio. Los sobres nunca pueden dar cartas secretas."""
    global suertex3_active, suertex6_active, suertex10_active, admin_abuse_active
    # Cartas evento: solo las vigentes (< 7 días) y solo durante admin_abuse
    vigentes_ids = set(get_evento_cards_vigentes().keys()) if admin_abuse_active else set()
    pool = [c for c in CARDS if c["rarity"] != "evento" or c["id"] in vigentes_ids]
    if not include_secret:
        pool = [c for c in pool if c["rarity"] not in ("secret", "grail")]

    if suertex10_active:
        boost_map = {
            "common":    1,
            "uncommon":  3,
            "rare":      6,
            "epic":      100,
            "legendary": 40,
            "mythic":    12,
            "grail":     5,
            "secret":    2,
            "evento":    0,
        }
        weights = [boost_map.get(c["rarity"], RARITY_CONFIG[c["rarity"]]["drop_rate"]) for c in pool]
    elif admin_abuse_active:
        # suertex6 base + evento x6
        boost_map = {
            "common":    2,
            "uncommon":  4,
            "rare":      5,
            "epic":      60,
            "legendary": 24,
            "mythic":    6,
            "grail":     3,
            "secret":    1.2,
            "evento":    1.8,  # 0.30 base × 6
        }
        weights = [boost_map.get(c["rarity"], RARITY_CONFIG[c["rarity"]]["drop_rate"]) for c in pool]
    elif suertex6_active:
        # x6 para épica, legendaria, mítica — grail también sube considerablemente
        boost_map = {
            "common":    2,
            "uncommon":  4,
            "rare":      5,
            "epic":      60,
            "legendary": 24,
            "mythic":    6,
            "grail":     3,
            "secret":    1.2,
        }
        weights = [boost_map.get(c["rarity"], RARITY_CONFIG[c["rarity"]]["drop_rate"]) for c in pool]
    elif suertex3_active:
        # x3 para épica, legendaria, mítica, secreta — comunes/poco/raras reducidas
        boost_map = {
            "common":    5,
            "uncommon":  8,
            "rare":      8,
            "epic":      30,
            "legendary": 12,
            "mythic":    3,
            "grail":     1,
            "secret":    0.6,
        }
        weights = [boost_map.get(c["rarity"], RARITY_CONFIG[c["rarity"]]["drop_rate"]) for c in pool]
    else:
        weights = [RARITY_CONFIG[c["rarity"]]["drop_rate"] for c in pool]
    return random.choices(pool, weights=weights, k=1)[0]

def can_drop(player):
    global suertex3_active, suertex6_active, suertex10_active, admin_abuse_active
    if player["last_drop"] is None:
        return True, 0
    if admin_abuse_active:
        return True, 0
    last = _parse_dt(player["last_drop"])
    diff = datetime.now(timezone.utc) - last
    cooldown_mins = 2 if (suertex3_active or suertex6_active or suertex10_active) else COOLDOWN_MINUTES
    cooldown = timedelta(minutes=cooldown_mins)
    if diff >= cooldown:
        return True, 0
    remaining = int((cooldown - diff).total_seconds() // 60) + 1
    return False, remaining

def card_embed(card, owner_name=None):
    rarity = RARITY_CONFIG[card["rarity"]]
    is_secret = card["rarity"] == "secret"
    is_grail  = card["rarity"] == "grail"
    is_evento = card["rarity"] == "evento"
    is_star   = card["rarity"] == "star"
    color = 0x1a1a2e if is_secret else (0xffd700 if is_grail else (0x00cfff if is_evento else (0xfffacd if is_star else rarity["color"])))
    title = f"{'⬛ ' if is_secret else ''}{'🏆 ' if is_grail else ''}{'💎 ' if is_evento else ''}{'⭐ ' if is_star else ''}{card['emoji']} {card['artist']}{'  ⬛' if is_secret else ''}{'  🏆' if is_grail else ''}{'  💎' if is_evento else ''}{'  ⭐' if is_star else ''}"
    embed = discord.Embed(
        title=title,
        description=f"**🎵 {card['song']}** ({card['year']})",
        color=color
    )
    rareza_display = f"{rarity['emoji']} {'SECRET' if is_secret else ('G R A I L' if is_grail else ('E V E N T O' if is_evento else ('S  T  A  R' if is_star else card['rarity'].upper())))} {rarity['stars']}"
    embed.add_field(name="Rareza", value=rareza_display, inline=True)
    embed.add_field(name="Power", value=f"⚡ {card['power']}/100", inline=True)
    if is_grail:
        embed.add_field(name="🏆 Valor", value=f"🏆 Precio: **{get_buy_price(card['rarity']):,} 🪙** · Solo /drop · Tradeable entre usuarios · No se vende al bot", inline=False)
    elif is_secret:
        embed.add_field(name="💎 Valor", value=f"⬛ Precio: **{get_buy_price(card['rarity']):,} 🪙** · Solo /drop · Tradeable entre usuarios · No se vende al bot", inline=False)
    elif is_evento:
        embed.add_field(name="💎 Valor", value=f"💎 Precio: **{get_buy_price(card['rarity']):,} 🪙** · Solo durante **Admin Abuse** · Tradeable entre usuarios · No se vende al bot", inline=False)
    elif is_star:
        embed.add_field(name="⭐ Valor", value=f"⭐ Precio: **∞** · Solo para quienes conocen el secreto · No tiene precio", inline=False)
    else:
        embed.add_field(name="Precio", value=f"🪙 Compra: **{get_buy_price(card['rarity'])}** | Venta: **{get_sell_price(card['rarity'])}**", inline=False)
    embed.add_field(name="Descripción", value=card["description"], inline=False)
    if card.get("image"):
        embed.set_image(url=card["image"])
    embed.set_footer(text=f"ID: {card['id']}" + (f" | {owner_name}" if owner_name else ""))
    return embed

