# ─── Asegurar ffmpeg para spotDL ──────────────────────────────────────────────
def _ensure_spotdl_deps():
    import subprocess, shutil, pathlib
    # ffmpeg via yt-dlp (más confiable que spotdl)
    if not shutil.which("ffmpeg"):
        spotdl_ffmpeg = pathlib.Path.home() / ".spotdl" / "ffmpeg"
        ytdlp_ffmpeg  = pathlib.Path.home() / ".local" / "bin" / "ffmpeg"
        if not spotdl_ffmpeg.exists() and not ytdlp_ffmpeg.exists():
            print("[FFMPEG] no encontrado, descargando via yt-dlp...")
            try:
                import yt_dlp.utils
                subprocess.run(
                    ["python3", "-m", "yt_dlp", "--ffmpeg-location", str(pathlib.Path.home() / ".local" / "bin")],
                    capture_output=True
                )
                # Usar spotdl como fallback
                subprocess.run(["spotdl", "--download-ffmpeg"], capture_output=True)
                print("[FFMPEG] descargado ✅")
            except Exception as e:
                print(f"[FFMPEG] Error: {e}")
    # Verificar ruta final
    for p in [
        shutil.which("ffmpeg"),
        str(pathlib.Path.home() / ".spotdl" / "ffmpeg"),
        str(pathlib.Path.home() / ".local" / "bin" / "ffmpeg"),
        "/usr/bin/ffmpeg",
        "/usr/local/bin/ffmpeg",
    ]:
        if p and pathlib.Path(p).exists():
            os.environ["FFMPEG_PATH"] = p
            print(f"[FFMPEG] usando: {p}")
            break
    # deno
    if not shutil.which("deno"):
        spotdl_deno = pathlib.Path.home() / ".spotdl" / "deno"
        if not spotdl_deno.exists():
            print("[spotDL] deno no encontrado, descargando...")
            try:
                subprocess.run(["spotdl", "--download-deno"], capture_output=True)
                print("[spotDL] deno descargado ✅")
            except Exception as e:
                print(f"[spotDL] Error descargando deno: {e}")

_ensure_spotdl_deps()

