async def lastfm_callback_handler(request):
    """Recibe el callback de Last.fm OAuth después de que el usuario autoriza."""
    state = request.rel_url.query.get("state")
    lfm_token = request.rel_url.query.get("token")  # token que manda Last.fm

    if not state or not _oauth_has(state):
        return web.Response(text="❌ Sesión inválida o expirada. Vuelve a Discord y usa .fmset", status=400)
    if not lfm_token:
        return web.Response(text="❌ Last.fm no mandó el token. Intenta de nuevo con .fmset", status=400)

    discord_id = _oauth_pop(state)
    result = await _lastfm_get_session(lfm_token)
    if not result:
        return web.Response(text="❌ No se pudo obtener la sesión de Last.fm. Intenta de nuevo con .fmset", status=400)
    username, session_key = result
    set_lastfm_user(discord_id, username, session_key)

    # Notificar al usuario en Discord
    try:
        user = await bot.fetch_user(discord_id)
        embed = discord.Embed(
            title="✅ ¡Conectado a Last.fm!",
            description=f"Tu cuenta **{username}** quedó vinculada.\nYa puedes usar `.np`, `.topartists`, `.toptracks` y más 🎵",
            color=0xd51007
        )
        embed.set_footer(text=f"last.fm/{username}")
        await user.send(embed=embed)
    except Exception:
        pass

    return web.Response(
        content_type="text/html",
        text=f"""
        <html><head><meta charset="utf-8">
        <style>body{{font-family:sans-serif;background:#111;color:#fff;display:flex;align-items:center;justify-content:center;height:100vh;margin:0;flex-direction:column;gap:12px}}
        h1{{color:#d51007}}p{{color:#aaa}}</style></head>
        <body><h1>✅ ¡Listo, {username}!</h1>
        <p>Tu cuenta de Last.fm quedó vinculada al bot.</p>
        <p>Puedes cerrar esta pestaña y volver a Discord 🎵</p></body></html>
        """
    )

async def start_health_server():
    app = web.Application()
    app.router.add_get("/", health_handler)
    app.router.add_get("/lastfm/callback", lastfm_callback_handler)
    runner = web.AppRunner(app)
    await runner.setup()
    port = int(os.environ.get("PORT", 8080))
    site = web.TCPSite(runner, "0.0.0.0", port)
    await site.start()
    print(f"✅ Health server en puerto {port}")

@bot.event
async def on_ready():
    apply_card_overrides()
    print(f"✅ {bot.user} online")
    print(f"📀 {len(CARDS)} cartas cargadas")
    await start_health_server()
    # Backup automático cada hora
    async def hourly_backup_loop():
        await bot.wait_until_ready()
        while not bot.is_closed():
            make_hourly_backup()
            await asyncio.sleep(3600)
    asyncio.create_task(hourly_backup_loop())
    # Recuperar apuestas pendientes del archivo y devolver todo al retador
    apuestas_guardadas = load_pending_apuestas()
    if apuestas_guardadas:
        for apuesta_id, game in apuestas_guardadas.items():
            try:
                devolver_apuesta(game)
            except Exception as e:
                print(f"⚠️ Error devolviendo apuesta {apuesta_id}: {e}")
        save_pending_apuestas({})
        print(f"♻️ {len(apuestas_guardadas)} apuestas pendientes devueltas al reiniciar")
    # Bot disponible en todos los servidores
    # Registrar views persistentes para que funcionen tras reinicios
    bot.add_view(NBAControlView(0))
    bot.add_view(NBAApuestasView(0))
    try:
        synced = await bot.tree.sync()
        print(f"⚡ {len(synced)} comandos sincronizados")
    except Exception as e:
        print(f"Error sync: {e}")

