@bot.tree.command(name="drop", description="Obtén una carta random 🎴")
async def drop(interaction: discord.Interaction):

    if is_banned(interaction.user.id):
        await interaction.response.send_message("🚫 Estás baneado del bot y no puedes usar este comando.", ephemeral=True)
        return

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return
    data = load_data()
    player = get_player(data, interaction.user.id)

    # ── SUERTEX10: solo 1 drop por usuario ──────────────────────────────────
    if suertex10_active and interaction.user.id in suertex10_used_users:
        await interaction.response.send_message(
            "🔟 Ya usaste tu drop del **SUERTE X10**. Solo se permite **1 drop por usuario** durante este evento.",
            ephemeral=True
        )
        return

    ok, mins = can_drop(player)
    if not ok:
        h = mins // 60
        m = mins % 60
        t = f"{h}h {m}m" if h > 0 else f"{m}m"
        await interaction.response.send_message(f"⏳ Espera **{t}** más para tu drop.", ephemeral=True)
        return
    card = weighted_drop()
    player["cards"].append(card["id"])
    player["last_drop"] = datetime.now(timezone.utc).isoformat()
    player["total_drops"] += 1
    player["username"] = interaction.user.display_name

    # Registrar uso en suertex10
    if suertex10_active:
        suertex10_used_users.add(interaction.user.id)

    # Registrar copia de carta evento
    if card["rarity"] == "evento":
        copias_restantes = registrar_copia_evento(card["id"])

    save_data(data)
    msgs = {"common": "Una carta...","uncommon": "Ooh 👀","rare": "🔵 RARA!","epic": "🟣 ÉPICA!! WOW!","legendary": "🟡 **LEGENDARIA!!!**","mythic": "🔴 **🔥 MÍTICA 🔥** BRO!!!","grail": "🏆 **G R A I L** 🏆 JAMAL IT'S CALLING","secret": "⬛ **S E C R E T A** ⬛ BRO QUÉ???","evento": "💎 **E V E N T O** 💎 ADMIN ABUSE REAL!!!"}
    embed = card_embed(card, interaction.user.display_name)

    # Si es evento, agregar cuántas copias quedan
    if card["rarity"] == "evento":
        embed.add_field(
            name="💎 Copias restantes",
            value=f"**{copias_restantes}/{EVENTO_MAX_COPIAS}** copias disponibles en el bot" if copias_restantes > 0 else "⚠️ **¡ÚLTIMA COPIA!** Ya no saldrá más.",
            inline=False
        )

    ventas_hoy = get_ventas_hoy(player)
    view = DropSellView(interaction.user.id, card["id"], ventas_hoy)
    await interaction.response.send_message(content=f"{msgs[card['rarity']]}\n{interaction.user.mention} obtuvo:", embed=embed, view=view)

    # ── Log de drop legendaria o superior ──────────────────────────────────
    RAREZAS_LOG = {"legendary", "mythic", "grail", "secret", "evento"}
    if card["rarity"] in RAREZAS_LOG:
        servidor = interaction.guild.name if interaction.guild else "DM"
        canal_nombre = interaction.channel.name if interaction.channel else "desconocido"
        rarity_emojis = {"legendary": "🟡", "mythic": "🔴", "grail": "🏆", "secret": "⬛", "evento": "💎"}
        await send_log(
            titulo=f"{rarity_emojis.get(card['rarity'], '🎴')} Drop {card['rarity'].upper()}",
            descripcion=f"{interaction.user.mention} (`{interaction.user.name}` · ID: `{interaction.user.id}`) obtuvo una carta **{card['rarity']}**.",
            color=RARITY_LOG_COLORS.get(card["rarity"], 0xf1c40f),
            campos=[
                ("🎵 Carta", f"**{card['song']}** — {card['artist']}", True),
                ("⚡ Power", f"{card['power']}/100", True),
                ("📍 Servidor", f"{servidor} · #{canal_nombre}", True),
                ("📊 Total drops", str(player.get("total_drops", 0)), True),
            ],
            footer=f"Drop #{player.get('total_drops', 0)}",
            user_id=interaction.user.id,
            user_name=str(interaction.user),
            guild_id=interaction.guild.id if interaction.guild else None,
            guild_name=interaction.guild.name if interaction.guild else "DM",
        )

    # ── Notificación de carta especial ──────────────────────────────────────
    RAREZAS_NOTIFICAR = {"mythic", "grail", "secret", "evento"}
    if card["rarity"] in RAREZAS_NOTIFICAR:
        notif_channel = bot.get_channel(1510384266322772110)
        if notif_channel:
            rarity_cfg = RARITY_CONFIG[card["rarity"]]
            titulos = {
                "mythic":  "🔴 ¡CARTA MÍTICA OBTENIDA!",
                "grail":   "🏆 ¡G R A I L OBTENIDO!",
                "secret":  "⬛ ¡CARTA SECRETA OBTENIDA!",
                "evento":  "💎 ¡CARTA EVENTO OBTENIDA!",
            }
            notif_embed = discord.Embed(
                title=titulos[card["rarity"]],
                description=f"{interaction.user.mention} acaba de obtener una carta **{card['rarity'].upper()}**:",
                color=rarity_cfg["color"]
            )
            notif_embed.add_field(name="🎵 Canción", value=f"**{card['song']}**", inline=True)
            notif_embed.add_field(name="🎤 Artista", value=card["artist"], inline=True)
            notif_embed.add_field(name="⚡ Power", value=f"{card['power']}/100", inline=True)
            if card.get("image"):
                notif_embed.set_thumbnail(url=card["image"])
            notif_embed.set_footer(text=f"Drop en #{interaction.channel.name if interaction.channel else 'desconocido'}")
            await notif_channel.send(embed=notif_embed)

class OfferModal(discord.ui.Modal, title="💰 Hacer Oferta"):
    cantidad = discord.ui.TextInput(
        label="¿Cuántas monedas ofreces?",
        placeholder="Ej: 5000",
        min_length=1,
        max_length=10
    )

    def __init__(self, owner_id: int, card_id: str):
        super().__init__()
        self.owner_id = owner_id
        self.card_id = card_id

    async def on_submit(self, interaction: discord.Interaction):
        try:
            oferta = int(self.cantidad.value.replace(",", "").replace(".", ""))
        except ValueError:
            await interaction.response.send_message("❌ Ingresa un número válido.", ephemeral=True)
            return
        if oferta <= 0:
            await interaction.response.send_message("❌ La oferta debe ser mayor a 0.", ephemeral=True)
            return

        data = load_data()
        comprador = get_player(data, interaction.user.id)
        if comprador.get("coins", 0) < oferta:
            await interaction.response.send_message(f"❌ No tienes suficientes monedas. Tienes **{comprador.get('coins', 0):,} 🪙**", ephemeral=True)
            return

        card = next((c for c in CARDS if c["id"] == self.card_id), None)
        card_name = f"{card['artist']} — {card['song']}" if card else self.card_id

        owner = await interaction.client.fetch_user(self.owner_id)
        rarity = RARITY_CONFIG[card["rarity"]] if card else {}

        # Embed que le llega al dueño de la carta
        embed = discord.Embed(
            title="💰 ¡Tienes una oferta!",
            description=f"{interaction.user.mention} quiere comprarte:\n**{card_name}**\n\nOferta: **{oferta:,} 🪙**",
            color=0xf39c12
        )
        if card and card.get("image"):
            embed.set_thumbnail(url=card["image"])
        embed.set_footer(text=f"Tienes 2 minutos para aceptar o rechazar")

        # Vista de aceptar/rechazar para el dueño
        accept_view = OfferAcceptView(
            owner_id=self.owner_id,
            buyer_id=interaction.user.id,
            card_id=self.card_id,
            oferta=oferta
        )

        # Enviar la oferta directamente en el canal con mención al dueño
        await interaction.response.send_message(
            content=f"{owner.mention} 💰 **{interaction.user.display_name}** te ofrece **{oferta:,} 🪙** por tu carta **{card_name}**",
            embed=embed,
            view=accept_view
        )

class OfferAcceptView(discord.ui.View):
    def __init__(self, owner_id: int, buyer_id: int, card_id: str, oferta: int):
        super().__init__(timeout=120)
        self.owner_id = owner_id
        self.buyer_id = buyer_id
        self.card_id = card_id
        self.oferta = oferta
        self.usado = False

    @discord.ui.button(label="✅ Aceptar", style=discord.ButtonStyle.success, emoji="✅")
    async def aceptar(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.owner_id:
            await interaction.response.send_message("❌ Solo el dueño puede responder esta oferta.", ephemeral=True)
            return
        if self.usado:
            await interaction.response.send_message("❌ Esta oferta ya fue procesada.", ephemeral=True)
            return
        self.usado = True

        data = load_data()
        owner_p  = get_player(data, self.owner_id)
        buyer_p  = get_player(data, self.buyer_id)

        # Verificaciones
        if self.card_id not in owner_p["cards"]:
            await interaction.response.send_message("❌ Ya no tienes esa carta.", ephemeral=True)
            return
        if buyer_p.get("coins", 0) < self.oferta:
            await interaction.response.send_message("❌ El comprador ya no tiene suficientes monedas.", ephemeral=True)
            return

        # Transferencia
        owner_p["cards"].remove(self.card_id)
        buyer_p["cards"].append(self.card_id)
        buyer_p["coins"]  = buyer_p.get("coins", 0) - self.oferta
        owner_p["coins"]  = owner_p.get("coins", 0) + self.oferta
        save_data(data)

        card = next((c for c in CARDS if c["id"] == self.card_id), None)
        card_name = f"{card['artist']} — {card['song']}" if card else self.card_id

        for item in self.children:
            item.disabled = True

        await interaction.response.edit_message(
            content=f"✅ ¡Trato cerrado! Vendiste **{card_name}** por **{self.oferta:,} 🪙**",
            embed=None, view=self
        )

    @discord.ui.button(label="❌ Rechazar", style=discord.ButtonStyle.danger, emoji="❌")
    async def rechazar(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.owner_id:
            await interaction.response.send_message("❌ Solo el dueño puede responder esta oferta.", ephemeral=True)
            return
        if self.usado:
            await interaction.response.send_message("❌ Esta oferta ya fue procesada.", ephemeral=True)
            return
        self.usado = True

        for item in self.children:
            item.disabled = True

        await interaction.response.edit_message(
            content="❌ Oferta rechazada.",
            embed=None, view=self
        )

    async def on_timeout(self):
        for item in self.children:
            item.disabled = True

class DropSellView(discord.ui.View):
    def __init__(self, user_id: int, card_id: str, ventas_hoy: int):
        super().__init__(timeout=60)
        self.user_id = user_id
        self.card_id = card_id
        self.usado = False
        card = next((c for c in CARDS if c["id"] == card_id), None)
        price = get_sell_price(card["rarity"]) if card else 0
        restantes = MAX_VENTAS_DIARIAS - ventas_hoy
        if card and card["rarity"] == "grail":
            btn = discord.ui.Button(
                label="🏆 Carta GRAIL — No se puede vender",
                style=discord.ButtonStyle.secondary,
                emoji="🏆",
                disabled=True
            )
        elif card and card["rarity"] == "secret":
            btn = discord.ui.Button(
                label="⬛ Carta Secreta — No se puede vender",
                style=discord.ButtonStyle.secondary,
                emoji="🤫",
                disabled=True
            )
        elif card and card["rarity"] == "evento":
            btn = discord.ui.Button(
                label="💎 Carta EVENTO — No se puede vender",
                style=discord.ButtonStyle.secondary,
                emoji="💎",
                disabled=True
            )
        elif ventas_hoy >= MAX_VENTAS_DIARIAS:
            btn = discord.ui.Button(
                label=f"Límite diario alcanzado (0/{MAX_VENTAS_DIARIAS})",
                style=discord.ButtonStyle.secondary,
                emoji="🚫",
                disabled=True
            )
        else:
            btn = discord.ui.Button(
                label=f"Vender por {price} 🪙 ({restantes} ventas restantes)",
                style=discord.ButtonStyle.danger,
                emoji="💰"
            )
            btn.callback = self.vender_callback
        self.add_item(btn)
        # Botón de oferta (visible para todos)
        offer_btn = discord.ui.Button(
            label="💰 Hacer Oferta",
            style=discord.ButtonStyle.primary,
            emoji="💰",
            row=1
        )
        offer_btn.callback = self.oferta_callback
        self.add_item(offer_btn)

    async def oferta_callback(self, interaction: discord.Interaction):
        if interaction.user.id == self.user_id:
            await interaction.response.send_message("❌ No puedes hacerte una oferta a ti mismo.", ephemeral=True)
            return
        modal = OfferModal(self.user_id, self.card_id)
        await interaction.response.send_modal(modal)

    async def vender_callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Esta carta no es tuya.", ephemeral=True)
            return
        if self.usado:
            await interaction.response.send_message("❌ Ya usaste esta acción.", ephemeral=True)
            return
        self.usado = True
        data = load_data()
        player = get_player(data, interaction.user.id)

        ventas_hoy = get_ventas_hoy(player)
        if ventas_hoy >= MAX_VENTAS_DIARIAS:
            await interaction.response.send_message(f"❌ Ya vendiste **{MAX_VENTAS_DIARIAS} cartas** hoy.", ephemeral=True)
            return
        if self.card_id not in player["cards"]:
            await interaction.response.send_message("❌ Ya no tienes esa carta.", ephemeral=True)
            return

        card = next((c for c in CARDS if c["id"] == self.card_id), None)
        price = get_sell_price(card["rarity"])
        player["cards"].remove(self.card_id)
        player["coins"] = player.get("coins", 100) + price
        registrar_venta(player)
        save_data(data)

        for item in self.children:
            item.disabled = True
        ventas_restantes = MAX_VENTAS_DIARIAS - get_ventas_hoy(player)
        rarity = RARITY_CONFIG[card["rarity"]]
        await interaction.response.edit_message(
            content=f"💰 Vendiste **{card['artist']} — {card['song']}** por **{price} 🪙** | Balance: **{player['coins']:,} 🪙** | Ventas restantes hoy: **{ventas_restantes}/{MAX_VENTAS_DIARIAS}**",
            view=self
        )

    async def on_timeout(self):
        for item in self.children:
            item.disabled = True

@bot.tree.command(name="coleccion", description="Tu colección de cartas 📚")
async def coleccion(interaction: discord.Interaction):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return
    data = load_data()
    player = get_player(data, interaction.user.id)
    if not player["cards"]:
        await interaction.response.send_message("Sin cartas aún. Usa `/drop`! 🎴", ephemeral=True)
        return
    owned_cards = [c for c in CARDS if c["id"] in player["cards"]]
    rarity_count = {}
    for c in owned_cards:
        rarity_count[c["rarity"]] = rarity_count.get(c["rarity"], 0) + 1
    artists = set(c["artist"] for c in owned_cards)
    lvl = get_level(player)
    embed = discord.Embed(title=f"📀 {interaction.user.display_name}", color=0x1a1a2e)
    embed.add_field(name="📊 Stats", value=f"Cartas: **{len(player['cards'])}**\nÚnicas: **{len(set(player['cards']))}**\nArtistas: **{len(artists)}**\nDrops: **{player['total_drops']}**", inline=True)
    embed.add_field(name=f"{lvl['emoji']} Nivel", value=f"**Nv.{lvl['level']}** {lvl['name']}", inline=True)
    rl = [f"{RARITY_CONFIG[r]['emoji']} {r.upper()}: **{n}**" for r, n in sorted(rarity_count.items(), key=lambda x: ["secret","grail","evento","mythic","legendary","epic","rare","uncommon","common"].index(x[0]) if x[0] in ["secret","grail","evento","mythic","legendary","epic","rare","uncommon","common"] else 99)]
    if rl:
        embed.add_field(name="🎴 Rareza", value="\n".join(rl), inline=False)
    unique = list({c["id"]: c for c in owned_cards}.values())
    top5 = sorted(unique, key=lambda x: x["power"], reverse=True)[:5]
    embed.add_field(name="⚡ Top 5", value="\n".join([f"`{i+1}.` {c['emoji']} **{c['artist']}** {c['song']} ⚡{c['power']}" for i, c in enumerate(top5)]), inline=False)
    embed.set_thumbnail(url=interaction.user.display_avatar.url)
    await interaction.response.send_message(embed=embed)

