class RepetidасView(discord.ui.View):
    def __init__(self, repetidas_cards, target, user_id, total_extra):
        super().__init__(timeout=120)
        self.repetidas_cards = repetidas_cards
        self.target = target
        self.user_id = user_id
        self.total_extra = total_extra
        self.page = 0
        self.per_page = 15
        import math
        self.total_pages = max(1, math.ceil(len(repetidas_cards) / self.per_page))
        self._update_buttons()

    def _update_buttons(self):
        self.prev_btn.disabled = self.page == 0
        self.next_btn.disabled = self.page >= self.total_pages - 1
        self.page_lbl.label = f"{self.page + 1}/{self.total_pages}"

    def build_embed(self):
        start = self.page * self.per_page
        end = start + self.per_page
        page_cards = self.repetidas_cards[start:end]

        titulo = f"🔁 Cartas repetidas de {self.target.display_name}"
        embed = discord.Embed(
            title=titulo,
            description=f"**{len(self.repetidas_cards)}** cartas repetidas · **{self.total_extra}** copias extra\n\u200b",
            color=0xe67e22
        )
        lines = []
        for card, count in page_cards:
            rarity_cfg = RARITY_CONFIG[card["rarity"]]
            price = get_buy_price(card["rarity"])
            lines.append(f"{rarity_cfg['emoji']} **{card['artist']}** — {card['song']} ×{count} · `{card['id']}` · 🪙{price:,}")
        embed.add_field(name="\u200b", value="\n".join(lines), inline=False)
        embed.set_footer(text=f"Página {self.page + 1}/{self.total_pages} • Usa /transferir o el mercado para intercambiarlas")
        embed.set_thumbnail(url=self.target.display_avatar.url)
        return embed

    @discord.ui.button(label="◀", style=discord.ButtonStyle.primary, row=0)
    async def prev_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ No es tu comando.", ephemeral=True)
            return
        self.page -= 1
        self._update_buttons()
        await interaction.response.edit_message(embed=self.build_embed(), view=self)

    @discord.ui.button(label="1/1", style=discord.ButtonStyle.secondary, disabled=True, row=0)
    async def page_lbl(self, interaction: discord.Interaction, button: discord.ui.Button):
        pass

    @discord.ui.button(label="▶", style=discord.ButtonStyle.primary, row=0)
    async def next_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ No es tu comando.", ephemeral=True)
            return
        self.page += 1
        self._update_buttons()
        await interaction.response.edit_message(embed=self.build_embed(), view=self)

@bot.tree.command(name="repetidas", description="Ver tus cartas repetidas 🔁")
@app_commands.describe(usuario="Usuario a consultar (opcional, por defecto tú)")
async def repetidas(interaction: discord.Interaction, usuario: discord.Member = None):
    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return

    target = usuario or interaction.user
    data = load_data()
    player = get_player(data, target.id)
    cards_list = player.get("cards", [])

    from collections import Counter
    conteo = Counter(cards_list)
    repetidas_ids = {cid: count for cid, count in conteo.items() if count > 1}

    if not repetidas_ids:
        msg = "No tienes cartas repetidas. ✅" if target == interaction.user else f"{target.display_name} no tiene cartas repetidas. ✅"
        await interaction.response.send_message(msg, ephemeral=True)
        return

    RARITY_ORDER = ["secret", "grail", "evento", "mythic", "legendary", "epic", "rare", "uncommon", "common"]
    repetidas_cards = []
    for cid, count in repetidas_ids.items():
        card = next((c for c in CARDS if c["id"] == cid), None)
        if card:
            repetidas_cards.append((card, count))
    repetidas_cards.sort(key=lambda x: (RARITY_ORDER.index(x[0]["rarity"]) if x[0]["rarity"] in RARITY_ORDER else 99, -x[1]))

    total_extra = sum(c - 1 for _, c in repetidas_ids.items())
    view = RepetidасView(repetidas_cards, target, interaction.user.id, total_extra)
    await interaction.response.send_message(embed=view.build_embed(), view=view, ephemeral=True)

@bot.tree.command(name="perfil", description="Ver tus estadísticas completas 📊")
@app_commands.describe(usuario="Usuario a ver (opcional, por defecto tú)")
async def perfil(interaction: discord.Interaction, usuario: discord.Member = None):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return
    target = usuario or interaction.user
    data = load_data()
    player = get_player(data, target.id)

    owned_cards = [c for c in CARDS if c["id"] in player["cards"]]
    rarity_count = {"common": 0, "uncommon": 0, "rare": 0, "epic": 0, "legendary": 0, "mythic": 0}
    for c in owned_cards:
        rarity_count[c["rarity"]] = rarity_count.get(c["rarity"], 0) + 1

    lvl = get_level(player)
    next_lvl = get_next_level(player)
    drops = player.get("total_drops", 0)
    coins = player.get("coins", 100)

    # Calcular poder total (excluir carta star — no afecta ranking ni stats)
    total_power = sum(c["power"] for c in owned_cards if c["rarity"] != "star")
    artists = set(c["artist"] for c in owned_cards)

    # Barra de progreso al siguiente nivel
    if next_lvl:
        prev_drops = lvl["min_drops"]
        needed = next_lvl["min_drops"] - prev_drops
        current_progress = drops - prev_drops
        progress_pct = min(current_progress / needed, 1.0) if needed > 0 else 1.0
        filled = int(progress_pct * 10)
        bar = "█" * filled + "░" * (10 - filled)
        progress_text = f"`{bar}` {current_progress}/{needed}\nPróximo: **Nv.{next_lvl['level']}** {next_lvl['name']}"
    else:
        progress_text = "✅ **Nivel máximo alcanzado**"

    # Color según rareza más alta
    rareza_orden = ["secret", "grail", "evento", "mythic", "legendary", "epic", "rare", "uncommon", "common"]
    best_rarity = next((r for r in rareza_orden if rarity_count.get(r, 0) > 0), "common")
    embed_color = RARITY_CONFIG[best_rarity]["color"]

    embed = discord.Embed(
        title=f"{'👤' if target == interaction.user else '🔍'} Perfil de {target.display_name}",
        color=embed_color
    )
    embed.set_thumbnail(url=target.display_avatar.url)

    # Nivel
    embed.add_field(
        name=f"{lvl['emoji']} Nivel {lvl['level']} — {lvl['name']}",
        value=progress_text,
        inline=False
    )

    # Economía
    embed.add_field(
        name="💰 Economía",
        value=f"🪙 Monedas: **{coins:,}**\n📀 Total drops: **{drops}**",
        inline=True
    )

    # Colección
    embed.add_field(
        name="🎴 Colección",
        value=f"Total cartas: **{len(player['cards'])}**\nÚnicas: **{len(set(player['cards']))}**\nArtistas: **{len(artists)}**\n⚡ Poder total: **{total_power}**",
        inline=True
    )

    # Raridades
    rareza_lines = []
    for r in rareza_orden:
        count = rarity_count.get(r, 0)
        if count > 0:
            rareza_lines.append(f"{RARITY_CONFIG[r]['emoji']} {r.upper()}: **{count}**")
    if rareza_lines:
        embed.add_field(
            name="✨ Raridades",
            value="\n".join(rareza_lines),
            inline=False
        )

    # Top 3 cartas más poderosas
    unique_cards = list({c["id"]: c for c in owned_cards}.values())
    top3 = sorted(unique_cards, key=lambda x: x["power"], reverse=True)[:3]
    if top3:
        top_text = "\n".join([f"`{i+1}.` {c['emoji']} **{c['artist']}** — {c['song']} ⚡{c['power']}" for i, c in enumerate(top3)])
        embed.add_field(name="🏆 Top 3 cartas", value=top_text, inline=False)

    embed.set_footer(text=f"Underground Hip Hop Cards | {len(CARDS)} cartas en el juego")
    await interaction.response.send_message(embed=embed)

class CartaNavView(discord.ui.View):
    def __init__(self, user_id: int, cards: list, index: int):
        super().__init__(timeout=120)
        self.user_id = user_id
        self.cards = cards      # lista de cartas del artista
        self.index = index      # índice actual

    def build_embed(self, player_cards: list) -> discord.Embed:
        card = self.cards[self.index]
        embed = card_embed(card)
        count = player_cards.count(card["id"])
        embed.add_field(name="Tu colección", value=f"✅ Tienes **{count}x**" if count else "❌ No la tienes", inline=False)
        embed.set_footer(text=f"Carta {self.index + 1} de {len(self.cards)} · {card['artist']} | ID: {card['id']}")
        return embed

    def update_buttons(self):
        self.prev_btn.disabled = self.index == 0
        self.next_btn.disabled = self.index == len(self.cards) - 1

    @discord.ui.button(emoji="◀️", style=discord.ButtonStyle.secondary, custom_id="carta_prev")
    async def prev_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Este menú no es tuyo.", ephemeral=True)
            return
        self.index -= 1
        self.update_buttons()
        data = load_data()
        player = get_player(data, interaction.user.id)
        await interaction.response.edit_message(embed=self.build_embed(player["cards"]), view=self)

    @discord.ui.button(emoji="▶️", style=discord.ButtonStyle.secondary, custom_id="carta_next")
    async def next_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Este menú no es tuyo.", ephemeral=True)
            return
        self.index += 1
        self.update_buttons()
        data = load_data()
        player = get_player(data, interaction.user.id)
        await interaction.response.edit_message(embed=self.build_embed(player["cards"]), view=self)

@bot.tree.command(name="carta", description="Inspecciona una carta 🔍")
@app_commands.describe(artista="Filtrar por artista", cancion="Buscar canción específica")
async def carta(interaction: discord.Interaction, artista: str = None, cancion: str = None):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return
    data = load_data()
    player = get_player(data, interaction.user.id)

    # Si cancion es un ID directo (del autocomplete), mostrar esa carta con navegación
    card = next((c for c in CARDS if c["id"] == cancion), None)
    if not card and cancion:
        card = next((c for c in CARDS if cancion.lower() in f"{c['artist']} {c['song']}".lower()), None)
    if card:
        # Armar lista del artista para poder navegar
        artist_cards = [c for c in CARDS if c["artist"] == card["artist"]]
        idx = next((i for i, c in enumerate(artist_cards) if c["id"] == card["id"]), 0)
        view = CartaNavView(interaction.user.id, artist_cards, idx)
        view.update_buttons()
        embed = view.build_embed(player["cards"])
        await interaction.response.send_message(embed=embed, view=view)
        return

    # Si solo artista, mostrar la primera carta con botones de navegación
    if artista:
        matches = [c for c in CARDS if artista.lower() in c["artist"].lower()]
        if not matches:
            await interaction.response.send_message(f"❌ No se encontró el artista `{artista}`.", ephemeral=True)
            return
        view = CartaNavView(interaction.user.id, matches, 0)
        view.update_buttons()
        embed = view.build_embed(player["cards"])
        await interaction.response.send_message(embed=embed, view=view)
        return

    await interaction.response.send_message("🔍 Usa el autocompletado para buscar por artista o canción.", ephemeral=True)

@carta.autocomplete("artista")
async def carta_artista_autocomplete(interaction: discord.Interaction, current: str):
    artists = sorted(set(c["artist"] for c in CARDS))
    return [app_commands.Choice(name=a, value=a) for a in artists if current.lower() in a.lower()][:25]

@carta.autocomplete("cancion")
async def carta_cancion_autocomplete(interaction: discord.Interaction, current: str):
    try:
        artista_filter = interaction.namespace.artista
    except Exception:
        artista_filter = None
    pool = CARDS
    if artista_filter:
        pool = [c for c in CARDS if artista_filter.lower() in c["artist"].lower()]
    results = []
    for c in pool:
        label = f"{RARITY_CONFIG[c['rarity']]['emoji']} {c['artist']} — {c['song']}"
        if current.lower() in label.lower():
            results.append(app_commands.Choice(name=label[:100], value=c["id"]))
        if len(results) >= 25:
            break
    return results

CARDS_PER_PAGE = 15

def build_lista_embed(cards_to_show, owned, page, total_pages, artista=None):
    start = page * CARDS_PER_PAGE
    end = start + CARDS_PER_PAGE
    page_cards = cards_to_show[start:end]
    titulo = f"📋 Cartas — {artista}" if artista else "📋 Underground Hip Hop Cards"
    embed = discord.Embed(title=titulo, color=0x6c5ce7)
    lines = []
    for c in page_cards:
        tienes = "✅" if c["id"] in owned else "❌"
        rarity_emoji = RARITY_CONFIG[c["rarity"]]["emoji"]
        lines.append(f"{tienes} {rarity_emoji} `{c['id']}` **{c['artist']}** — {c['song']} ⚡{c['power']}")
    embed.description = "\n".join(lines)
    embed.set_footer(text=f"Página {page + 1}/{total_pages} • {len(cards_to_show)} cartas totales | {len(CARDS)} en el juego")
    return embed

class ListaView(discord.ui.View):
    def __init__(self, cards_to_show, owned, artista, total_pages, user_id):
        super().__init__(timeout=120)
        self.cards = cards_to_show
        self.owned = owned
        self.artista = artista
        self.total_pages = total_pages
        self.page = 0
        self.user_id = user_id
        self._update_buttons()

    def _update_buttons(self):
        self.first_btn.disabled = self.page == 0
        self.prev_btn.disabled = self.page == 0
        self.next_btn.disabled = self.page >= self.total_pages - 1
        self.last_btn.disabled = self.page >= self.total_pages - 1
        self.page_label.label = f"{self.page + 1} / {self.total_pages}"

    @discord.ui.button(label="⏮", style=discord.ButtonStyle.secondary, custom_id="first")
    async def first_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Solo quien usó el comando puede cambiar de página.", ephemeral=True)
            return
        self.page = 0
        self._update_buttons()
        await interaction.response.edit_message(embed=build_lista_embed(self.cards, self.owned, self.page, self.total_pages, self.artista), view=self)

    @discord.ui.button(label="◀", style=discord.ButtonStyle.primary, custom_id="prev")
    async def prev_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Solo quien usó el comando puede cambiar de página.", ephemeral=True)
            return
        self.page = max(0, self.page - 1)
        self._update_buttons()
        await interaction.response.edit_message(embed=build_lista_embed(self.cards, self.owned, self.page, self.total_pages, self.artista), view=self)

    @discord.ui.button(label="1 / 1", style=discord.ButtonStyle.secondary, custom_id="page_label", disabled=True)
    async def page_label(self, interaction: discord.Interaction, button: discord.ui.Button):
        pass

    @discord.ui.button(label="▶", style=discord.ButtonStyle.primary, custom_id="next")
    async def next_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Solo quien usó el comando puede cambiar de página.", ephemeral=True)
            return
        self.page = min(self.total_pages - 1, self.page + 1)
        self._update_buttons()
        await interaction.response.edit_message(embed=build_lista_embed(self.cards, self.owned, self.page, self.total_pages, self.artista), view=self)

    @discord.ui.button(label="⏭", style=discord.ButtonStyle.secondary, custom_id="last")
    async def last_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Solo quien usó el comando puede cambiar de página.", ephemeral=True)
            return
        self.page = self.total_pages - 1
        self._update_buttons()
        await interaction.response.edit_message(embed=build_lista_embed(self.cards, self.owned, self.page, self.total_pages, self.artista), view=self)

    async def on_timeout(self):
        for item in self.children:
            item.disabled = True

# ─── ARTISTA: PROGRESO POR ARTISTA ───────────────────────────────────────────

RARITY_ORDER = ["secret", "grail", "evento", "mythic", "legendary", "epic", "rare", "uncommon", "common"]
ARTISTA_PER_PAGE = 12

def build_artista_embed(artist_cards, owned, page, total_pages, artist_name, filter_mode, display_name=None):
    start = page * ARTISTA_PER_PAGE
    end = start + ARTISTA_PER_PAGE
    page_cards = artist_cards[start:end]

    total = len(artist_cards)
    tienes_total = sum(1 for c in artist_cards if c["id"] in owned)
    faltan_total = total - tienes_total
    pct = int((tienes_total / total) * 100) if total > 0 else 0

    # Barra de progreso
    filled = pct // 10
    bar = "█" * filled + "░" * (10 - filled)

    color_map = {"mythic": 0xff0000, "legendary": 0xf1c40f, "epic": 0x9b59b6,
                 "rare": 0x3498db, "uncommon": 0x2ecc71, "common": 0x95a5a6}
    # Color según rareza más alta que tienes
    embed_color = 0x6c5ce7
    for r in RARITY_ORDER:
        if any(c["rarity"] == r and c["id"] in owned for c in artist_cards):
            embed_color = color_map.get(r, 0x6c5ce7)
            break

    titulo = f"🎤 {artist_name}"
    if display_name:
        titulo += f" — 👤 {display_name}"
    if filter_mode == "tienes":
        titulo += " — ✅ Tienes"
    elif filter_mode == "faltan":
        titulo += " — ❌ Faltan"

    embed = discord.Embed(title=titulo, color=embed_color)
    embed.description = f"`{bar}` **{pct}%** — {tienes_total}✅ de {total} | ❌ Faltan {faltan_total}"

    lines = []
    for c in page_cards:
        tienes = "✅" if c["id"] in owned else "❌"
        rarity_emoji = RARITY_CONFIG[c["rarity"]]["emoji"]
        lines.append(f"{tienes} {rarity_emoji} **{c['song']}** ⚡{c['power']} `{c['id']}`")

    embed.add_field(name="Cartas", value="\n".join(lines) if lines else "—", inline=False)
    embed.set_footer(text=f"Página {page + 1}/{total_pages} • {len(artist_cards)} cartas")
    return embed

class ArtistaView(discord.ui.View):
    def __init__(self, artist_cards, owned, artist_name, user_id, filter_mode="todas", display_name=None):
        super().__init__(timeout=180)
        self.all_cards = artist_cards
        self.owned = owned
        self.artist_name = artist_name
        self.user_id = user_id
        self.filter_mode = filter_mode
        self.display_name = display_name
        self._apply_filter()
        self._update_buttons()

    def _apply_filter(self):
        if self.filter_mode == "tienes":
            self.cards = [c for c in self.all_cards if c["id"] in self.owned]
        elif self.filter_mode == "faltan":
            self.cards = [c for c in self.all_cards if c["id"] not in self.owned]
        else:
            self.cards = self.all_cards
        import math
        self.total_pages = max(1, math.ceil(len(self.cards) / ARTISTA_PER_PAGE))
        self.page = 0

    def _update_buttons(self):
        self.prev_btn.disabled = self.page == 0
        self.next_btn.disabled = self.page >= self.total_pages - 1
        self.page_label.label = f"{self.page + 1} / {self.total_pages}"
        self.btn_todas.style = discord.ButtonStyle.primary if self.filter_mode == "todas" else discord.ButtonStyle.secondary
        self.btn_tienes.style = discord.ButtonStyle.success if self.filter_mode == "tienes" else discord.ButtonStyle.secondary
        self.btn_faltan.style = discord.ButtonStyle.danger if self.filter_mode == "faltan" else discord.ButtonStyle.secondary

    def current_embed(self):
        return build_artista_embed(self.cards, self.owned, self.page, self.total_pages, self.artist_name, self.filter_mode, self.display_name)

    @discord.ui.button(label="📋 Todas", style=discord.ButtonStyle.primary, row=0)
    async def btn_todas(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Solo quien usó el comando puede interactuar.", ephemeral=True)
            return
        self.filter_mode = "todas"
        self._apply_filter()
        self._update_buttons()
        await interaction.response.edit_message(embed=self.current_embed(), view=self)

    @discord.ui.button(label="✅ Tienes", style=discord.ButtonStyle.secondary, row=0)
    async def btn_tienes(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Solo quien usó el comando puede interactuar.", ephemeral=True)
            return
        self.filter_mode = "tienes"
        self._apply_filter()
        self._update_buttons()
        await interaction.response.edit_message(embed=self.current_embed(), view=self)

    @discord.ui.button(label="❌ Faltan", style=discord.ButtonStyle.secondary, row=0)
    async def btn_faltan(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Solo quien usó el comando puede interactuar.", ephemeral=True)
            return
        self.filter_mode = "faltan"
        self._apply_filter()
        self._update_buttons()
        await interaction.response.edit_message(embed=self.current_embed(), view=self)

    @discord.ui.button(label="◀", style=discord.ButtonStyle.primary, row=1)
    async def prev_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Solo quien usó el comando puede interactuar.", ephemeral=True)
            return
        self.page = max(0, self.page - 1)
        self._update_buttons()
        await interaction.response.edit_message(embed=self.current_embed(), view=self)

    @discord.ui.button(label="1 / 1", style=discord.ButtonStyle.secondary, custom_id="artista_page_label", disabled=True, row=1)
    async def page_label(self, interaction: discord.Interaction, button: discord.ui.Button):
        pass

    @discord.ui.button(label="▶", style=discord.ButtonStyle.primary, row=1)
    async def next_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Solo quien usó el comando puede interactuar.", ephemeral=True)
            return
        self.page = min(self.total_pages - 1, self.page + 1)
        self._update_buttons()
        await interaction.response.edit_message(embed=self.current_embed(), view=self)

    async def on_timeout(self):
        for item in self.children:
            item.disabled = True

@bot.tree.command(name="artista", description="Ve el progreso de cartas de un artista 🎤")
@app_commands.describe(
    artista="Nombre del artista",
    usuario="Ver el progreso de otro usuario (opcional)",
    visible="¿Mostrar el resultado a todos en el canal?"
)
@app_commands.choices(visible=[
    app_commands.Choice(name="🔒 Solo para mí", value="no"),
    app_commands.Choice(name="📢 Visible para todos", value="si"),
])
async def artista_cmd(interaction: discord.Interaction, artista: str, usuario: app_commands.Transform[discord.User, MemberOrUser] = None, visible: str = "no"):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return

    artist_cards = [c for c in CARDS if artista.lower() in c["artist"].lower()]
    if not artist_cards:
        await interaction.response.send_message(f"❌ No hay cartas del artista `{artista}`.", ephemeral=True)
        return

    artist_cards.sort(key=lambda c: (RARITY_ORDER.index(c["rarity"]) if c["rarity"] in RARITY_ORDER else 99, -c["power"]))

    data = load_data()
    target = usuario if usuario else interaction.user
    player = get_player(data, target.id)
    owned = set(player["cards"])
    artist_name = artist_cards[0]["artist"]

    # Si es otro usuario, mostrar su nombre en el título
    display_name = target.display_name if target.id != interaction.user.id else None

    ephemeral = visible != "si"
    view = ArtistaView(artist_cards, owned, artist_name, interaction.user.id, display_name=display_name)
    await interaction.response.send_message(embed=view.current_embed(), view=view, ephemeral=ephemeral)

@artista_cmd.autocomplete("artista")
async def artista_cmd_autocomplete(interaction: discord.Interaction, current: str):
    artists = sorted(set(c["artist"] for c in CARDS))
    return [app_commands.Choice(name=a, value=a) for a in artists if current.lower() in a.lower()][:25]

@bot.tree.command(name="lista", description="Todas las cartas disponibles 📋")
@app_commands.describe(artista="Filtrar por artista (opcional)")
async def lista(interaction: discord.Interaction, artista: str = None):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return
    data = load_data()
    player = get_player(data, interaction.user.id)
    owned = set(player["cards"])
    cards_to_show = [c for c in CARDS if not artista or artista.lower() in c["artist"].lower()]
    if not cards_to_show:
        await interaction.response.send_message(f"❌ No hay cartas de '{artista}'.", ephemeral=True)
        return
    import math
    total_pages = math.ceil(len(cards_to_show) / CARDS_PER_PAGE)
    view = ListaView(cards_to_show, owned, artista, total_pages, interaction.user.id)
    embed = build_lista_embed(cards_to_show, owned, 0, total_pages, artista)
    await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

# ─── BATTLE CON ACEPTAR/RECHAZAR ────────────────────────────────────────────

@bot.tree.command(name="battle", description="Retar a otro usuario a una batalla ⚔️")
@app_commands.describe(oponente="A quién quieres retar")
async def battle(interaction: discord.Interaction, oponente: discord.Member):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return
    if oponente.id == interaction.user.id or oponente.bot:
        await interaction.response.send_message("❌ No puedes retarte a ti mismo ni a un bot.", ephemeral=True)
        return
    data = load_data()
    p1 = get_player(data, interaction.user.id)
    p2 = get_player(data, oponente.id)
    if not p1["cards"]:
        await interaction.response.send_message("❌ Necesitas cartas para batallar. Usa `/drop`!", ephemeral=True)
        return
    if not p2["cards"]:
        await interaction.response.send_message(f"❌ {oponente.display_name} no tiene cartas todavía.", ephemeral=True)
        return

    battle_id = f"{interaction.user.id}_{oponente.id}"
    pending_battles[battle_id] = {
        "challenger_id": interaction.user.id,
        "opponent_id": oponente.id,
    }

    embed = discord.Embed(
        title="⚔️ ¡RETO DE BATALLA!",
        description=f"{interaction.user.mention} te reta a una batalla, {oponente.mention}!\n\nUsa `/aceptar_batalla @{interaction.user.display_name}` o `/rechazar_batalla @{interaction.user.display_name}` para responder.",
        color=0xe74c3c
    )
    embed.set_footer(text="El reto expira en 60 segundos")
    await interaction.response.send_message(
        content=f"{oponente.mention} tienes un reto de batalla!",
        embed=embed
    )
    await send_log(
        titulo="⚔️ Reto de batalla enviado",
        descripcion=f"{interaction.user.mention} retó a {oponente.mention}.",
        color=0xe74c3c,
        user_id=interaction.user.id, user_name=str(interaction.user),
        guild_id=interaction.guild.id if interaction.guild else None, guild_name=interaction.guild.name if interaction.guild else 'DM',
    )

    await asyncio.sleep(60)
    if battle_id in pending_battles:
        del pending_battles[battle_id]

@bot.tree.command(name="aceptar_batalla", description="Aceptar un reto de batalla ✅")
@app_commands.describe(retador="Usuario que te retó")
async def aceptar_batalla(interaction: discord.Interaction, retador: discord.Member):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return
    battle_id = f"{retador.id}_{interaction.user.id}"
    battle = pending_battles.get(battle_id)
    if not battle:
        await interaction.response.send_message("❌ No tienes ningún reto pendiente de ese usuario.", ephemeral=True)
        return

    del pending_battles[battle_id]

    data = load_data()
    p1 = get_player(data, retador.id)
    p2 = get_player(data, interaction.user.id)

    if not p1["cards"] or not p2["cards"]:
        await interaction.response.send_message("❌ Ambos necesitan cartas para batallar.", ephemeral=True)
        return

    p1_best = max([c for c in CARDS if c["id"] in p1["cards"] and c["rarity"] != "star"], key=lambda x: x["power"])
    p2_best = max([c for c in CARDS if c["id"] in p2["cards"] and c["rarity"] != "star"], key=lambda x: x["power"])
    s1 = p1_best["power"] + random.randint(-10, 10)
    s2 = p2_best["power"] + random.randint(-10, 10)
    winner = retador if s1 >= s2 else interaction.user
    loser = interaction.user if s1 >= s2 else retador
    r1, r2 = RARITY_CONFIG[p1_best["rarity"]], RARITY_CONFIG[p2_best["rarity"]]

    prize = 150
    winner_data = get_player(data, winner.id)
    winner_data["coins"] = winner_data.get("coins", 100) + prize
    save_data(data)

    embed = discord.Embed(title="⚔️ ¡BATALLA COMPLETADA!", color=0xe74c3c)
    embed.add_field(
        name=f"🥊 {retador.display_name}",
        value=f"{p1_best['emoji']} **{p1_best['artist']}** — {p1_best['song']}\n{r1['emoji']} ⚡{p1_best['power']} → **{s1} pts**",
        inline=True
    )
    embed.add_field(
        name=f"🥊 {interaction.user.display_name}",
        value=f"{p2_best['emoji']} **{p2_best['artist']}** — {p2_best['song']}\n{r2['emoji']} ⚡{p2_best['power']} → **{s2} pts**",
        inline=True
    )
    embed.add_field(name="🏆 GANADOR", value=f"**{winner.mention}** gana **{prize} monedas** 🪙!", inline=False)
    await interaction.response.send_message(embed=embed)
    await send_log(
        titulo="⚔️ Batalla completada",
        descripcion=f"**{winner.mention}** ganó la batalla contra **{loser.mention}** y obtuvo **{prize} 🪙**.",
        color=0xe74c3c,
        campos=[
            ("🥊 Ganador", f"{winner.mention}", True),
            ("💀 Perdedor", f"{loser.mention}", True),
            ("💰 Premio", f"**{prize} 🪙**", True),
        ],
        user_id=winner.id, user_name=str(winner),
        guild_id=interaction.guild.id if interaction.guild else None, guild_name=interaction.guild.name if interaction.guild else 'DM',
    )

@bot.tree.command(name="rechazar_batalla", description="Rechazar un reto de batalla ❌")
@app_commands.describe(retador="Usuario que te retó")
async def rechazar_batalla(interaction: discord.Interaction, retador: discord.Member):

    battle_id = f"{retador.id}_{interaction.user.id}"
    if battle_id not in pending_battles:
        await interaction.response.send_message("❌ No tienes ningún reto pendiente de ese usuario.", ephemeral=True)
        return
    del pending_battles[battle_id]
    await interaction.response.send_message(
        f"❌ {interaction.user.mention} rechazó el reto de batalla de {retador.mention}."
    )
    await send_log(
        titulo="❌ Reto de batalla rechazado",
        descripcion=f"{interaction.user.mention} rechazó el reto de {retador.mention}.",
        color=0x95a5a6,
        user_id=interaction.user.id, user_name=str(interaction.user),
        guild_id=interaction.guild.id if interaction.guild else None, guild_name=interaction.guild.name if interaction.guild else 'DM',
    )

# ─── CASINO: RULETA ──────────────────────────────────────────────────────────

@bot.tree.command(name="ruleta", description="Apuesta en la ruleta del casino 🎰")
@app_commands.describe(color="Elige: rojo, negro o verde", apuesta="Cantidad de monedas a apostar")
@app_commands.choices(color=[
    app_commands.Choice(name="🔴 Rojo (x2)", value="rojo"),
    app_commands.Choice(name="⚫ Negro (x2)", value="negro"),
    app_commands.Choice(name="🟢 Verde (x14)", value="verde"),
])
async def ruleta(interaction: discord.Interaction, color: str, apuesta: int):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return
    if apuesta <= 0:
        await interaction.response.send_message("❌ La apuesta debe ser mayor a 0.", ephemeral=True)
        return
    if apuesta > 10000:
        await interaction.response.send_message("❌ La apuesta máxima es 10,000 monedas.", ephemeral=True)
        return

    data = load_data()
    player = get_player(data, interaction.user.id)
    coins = player.get("coins", 100)

    # Bloquear ruleta si tiene préstamo activo
    loan = player.get("loan")
    if loan and not loan.get("paid_off", False) and loan.get("amount", 0) > 0:
        await interaction.response.send_message(
            f"🏦 No puedes apostar en la ruleta mientras tengas un **préstamo activo**.\n"
            f"Deuda actual: **{loan['amount']:,} 🪙** — Usa `/pagar_prestamo` primero.",
            ephemeral=True
        )
        return

    if apuesta > coins:
        await interaction.response.send_message(f"❌ No tienes suficientes monedas. Tienes **{coins}** 🪙", ephemeral=True)
        return

    opciones = ["rojo", "negro", "verde"]
    weights = [18, 18, 2]
    resultado = random.choices(opciones, weights=weights, k=1)[0]
    emojis = {"rojo": "🔴", "negro": "⚫", "verde": "🟢"}
    multiplicadores = {"rojo": 2, "negro": 2, "verde": 14}

    await interaction.response.defer()
    msg_embed = discord.Embed(title="🎰 RULETA GIRANDO...", color=0x2c3e50)
    msg_embed.description = "🔴 ⚫ 🟢 🔴 ⚫ 🟢 ..."
    await interaction.followup.send(embed=msg_embed)
    await asyncio.sleep(2)

    # Recargar datos DESPUÉS del sleep para evitar race conditions con otros comandos
    data = load_data()
    player = get_player(data, interaction.user.id)
    coins = player.get("coins", 100)
    if apuesta > coins:
        embed_err = discord.Embed(title="🎰 RULETA — Error", description=f"❌ Ya no tienes suficientes monedas.\nBalance actual: **{coins:,}** 🪙", color=0xe74c3c)
        await interaction.edit_original_response(embed=embed_err)
        return

    if resultado == color:
        mult = multiplicadores[color]
        ganancia = apuesta * mult - apuesta
        player["coins"] = coins + ganancia
        embed = discord.Embed(
            title=f"🎰 RULETA — {emojis[resultado]} {resultado.upper()}",
            description=f"**¡GANASTE!** 🎉\nApostaste **{apuesta}** 🪙 en {emojis[color]} **{color}**",
            color=0x27ae60
        )
        embed.add_field(name="Multiplicador", value=f"x{mult}", inline=True)
        embed.add_field(name="Ganancia", value=f"+**{ganancia}** 🪙", inline=True)
        embed.add_field(name="Balance", value=f"**{player['coins']:,}** 🪙", inline=True)
    else:
        player["coins"] = coins - apuesta
        embed = discord.Embed(
            title=f"🎰 RULETA — {emojis[resultado]} {resultado.upper()}",
            description=f"**Perdiste** 😔\nApostaste **{apuesta}** 🪙 en {emojis[color]} **{color}**",
            color=0xe74c3c
        )
        embed.add_field(name="Resultado", value=f"Cayó {emojis[resultado]} **{resultado}**", inline=True)
        embed.add_field(name="Perdiste", value=f"-**{apuesta}** 🪙", inline=True)
        embed.add_field(name="Balance", value=f"**{player['coins']:,}** 🪙", inline=True)

    save_data(data)
    resultado_txt = f"Apostó **{apuesta:,} 🪙** en {emojis[color]} {color} — salió {emojis[resultado]} {resultado}. {'¡Ganó!' if resultado == color else 'Perdió.'}"
    await send_log(
        titulo="🎰 Ruleta",
        descripcion=f"{interaction.user.mention} jugó ruleta. {resultado_txt}",
        color=0x27ae60 if resultado == color else 0xe74c3c,
        campos=[("💰 Apuesta", f"**{apuesta:,} 🪙**", True), ("🎯 Color elegido", f"{emojis[color]} {color}", True), ("🎲 Resultado", f"{emojis[resultado]} {resultado}", True)],
        user_id=interaction.user.id,
        guild_id=interaction.guild_id,
        guild_name=interaction.guild.name if interaction.guild else "DM",
    )

    embed.set_footer(text="🎲 /ruleta | 🔴47.4% ⚫47.4% 🟢5.2%")
    await interaction.edit_original_response(embed=embed)

# ─── RULETA GRAIL ───────────────────────────────────────────────────────────

class GrailRouletteView(discord.ui.View):
    """Vista de confirmación para la Ruleta Grail."""

    def __init__(self, user_id: int, grail_apostado: dict, grail_deseado: dict):
        super().__init__(timeout=60)
        self.user_id = user_id
        self.grail_apostado = grail_apostado
        self.grail_deseado = grail_deseado

    @discord.ui.button(label="🎰 GIRAR LA RULETA", style=discord.ButtonStyle.danger)
    async def confirmar(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Esta ruleta no es tuya.", ephemeral=True)
            return

        await interaction.response.defer()
        self.stop()
        for item in self.children:
            item.disabled = True

        data = load_data()
        uid = str(interaction.user.id)
        player = data.get(uid, {})
        cards = player.get("cards", [])

        # Verificar que aún tiene el grail apostado
        if self.grail_apostado["id"] not in cards:
            await interaction.followup.send("❌ Ya no tienes la carta GRAIL que ibas a apostar.", ephemeral=True)
            return

        # Verificar que tiene 35,000 monedas
        coins = player.get("coins", 0)
        if coins < 35000:
            await interaction.followup.send(f"❌ Ya no tienes suficientes monedas. Tienes **{coins:,} 🪙**.", ephemeral=True)
            return

        # Verificar que el grail deseado no lo tiene ya
        if self.grail_deseado["id"] in cards:
            await interaction.followup.send("❌ Ya tienes ese GRAIL. Elige uno diferente.", ephemeral=True)
            return

        import random

        # Cobrar las 35,000 monedas y quitar el grail apostado
        player["coins"] = coins - 35000
        cards.remove(self.grail_apostado["id"])

        # Tirar: 30% ganas el grail deseado, 70% te dan una common aleatoria
        roll = random.random()

        if roll < 0.30:
            # ¡GANÓ el grail deseado!
            cards.append(self.grail_deseado["id"])
            data[uid]["cards"] = cards
            save_data(data)

            embed = discord.Embed(
                title="🏆 ¡¡GRAIL OBTENIDO!! 🎰",
                description=(
                    f"✨ **¡Lo lograste!** La ruleta te sonrió.\n\n"
                    f"**Apostaste:** {self.grail_apostado['emoji']} `{self.grail_apostado['artist']} — {self.grail_apostado['song']}` (GRAIL)\n"
                    f"**Obtuviste:** {self.grail_deseado['emoji']} `{self.grail_deseado['artist']} — {self.grail_deseado['song']}` (GRAIL)\n\n"
                    f"💸 Se han descontado **35,000 🪙** | Balance: **{player['coins']:,} 🪙**"
                ),
                color=0xf1c40f
            )
            if self.grail_deseado.get("image"):
                embed.set_image(url=self.grail_deseado["image"])
            embed.set_footer(text="🎰 Ruleta Grail | 30% GRAIL · 70% Common")

            await send_log(
                titulo="🏆 Ruleta Grail — GRAIL GANADO",
                descripcion=f"{interaction.user.mention} apostó `{self.grail_apostado['song']}` y GANÓ `{self.grail_deseado['song']}`.",
                color=0xf1c40f,
                campos=[
                    ("Apostado", self.grail_apostado['song'], True),
                    ("Ganado", self.grail_deseado['song'], True),
                    ("Costo", "35,000 🪙", True),
                ],
                user_id=interaction.user.id,
                guild_id=interaction.guild_id,
                guild_name=interaction.guild.name if interaction.guild else "DM",
            )

        else:
            # Perdió — recibe una carta common aleatoria que no tenga
            comunes_disponibles = [
                c for c in CARDS
                if c["rarity"] == "common" and c["id"] not in cards
            ]
            if not comunes_disponibles:
                # Fallback: cualquier common
                comunes_disponibles = [c for c in CARDS if c["rarity"] == "common"]

            carta_consolacion = random.choice(comunes_disponibles) if comunes_disponibles else None
            if carta_consolacion:
                cards.append(carta_consolacion["id"])

            data[uid]["cards"] = cards
            save_data(data)

            desc_consolacion = (
                f"{carta_consolacion['emoji']} `{carta_consolacion['artist']} — {carta_consolacion['song']}` (Common)"
                if carta_consolacion else "*(No había comunes disponibles, no se dio carta)*"
            )

            embed = discord.Embed(
                title="😔 La ruleta no te quiso hoy... 🎰",
                description=(
                    f"**Apostaste:** {self.grail_apostado['emoji']} `{self.grail_apostado['artist']} — {self.grail_apostado['song']}` (GRAIL)\n"
                    f"**Querías:** {self.grail_deseado['emoji']} `{self.grail_deseado['artist']} — {self.grail_deseado['song']}` (GRAIL)\n\n"
                    f"❌ No salió el GRAIL. Recibiste una carta de consolación:\n"
                    f"➜ {desc_consolacion}\n\n"
                    f"💸 Se han descontado **35,000 🪙** | Balance: **{player['coins']:,} 🪙**"
                ),
                color=0xe74c3c
            )
            embed.set_footer(text="🎰 Ruleta Grail | 30% GRAIL · 70% Common")

            await send_log(
                titulo="🎰 Ruleta Grail — perdió",
                descripcion=f"{interaction.user.mention} apostó `{self.grail_apostado['song']}`, quería `{self.grail_deseado['song']}` y PERDIÓ.",
                color=0xe74c3c,
                campos=[
                    ("Apostado", self.grail_apostado['song'], True),
                    ("Deseado", self.grail_deseado['song'], True),
                    ("Costo", "35,000 🪙", True),
                ],
                user_id=interaction.user.id,
                guild_id=interaction.guild_id,
                guild_name=interaction.guild.name if interaction.guild else "DM",
            )

        await interaction.edit_original_response(embed=embed, view=None)

    @discord.ui.button(label="Cancelar", style=discord.ButtonStyle.secondary)
    async def cancelar(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Esta ruleta no es tuya.", ephemeral=True)
            return
        self.stop()
        await interaction.response.edit_message(
            embed=discord.Embed(title="❌ Ruleta Grail cancelada", color=0x95a5a6),
            view=None
        )


@bot.tree.command(name="ruleta_grail", description="Apuesta un GRAIL por otro GRAIL 🏆🎰 (cuesta 35,000 🪙 · 30% de éxito)")
@app_commands.describe(
    grail_apostado="ID de tu carta GRAIL que pones en juego",
    grail_deseado="ID del GRAIL que quieres ganar",
)

async def ruleta_grail(interaction: discord.Interaction, grail_apostado: str, grail_deseado: str):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return

    uid = str(interaction.user.id)
    data = load_data()
    if uid not in data:
        data[uid] = {"cards": [], "last_drop": None, "total_drops": 0, "coins": 100}
    player = data[uid]
    cards = player.get("cards", [])

    # ── Validar carta apostada ──────────────────────────────────────────────
    carta_apostada = next((c for c in CARDS if c["id"] == grail_apostado), None)
    if not carta_apostada:
        await interaction.response.send_message("❌ No encontré ninguna carta con ese ID.", ephemeral=True)
        return
    if carta_apostada["rarity"] != "grail":
        await interaction.response.send_message("❌ Solo puedes apostar cartas de rareza **GRAIL**.", ephemeral=True)
        return
    if grail_apostado not in cards:
        await interaction.response.send_message("❌ No tienes esa carta GRAIL en tu colección.", ephemeral=True)
        return

    # ── Validar carta deseada ───────────────────────────────────────────────
    carta_deseada = next((c for c in CARDS if c["id"] == grail_deseado), None)
    if not carta_deseada:
        await interaction.response.send_message("❌ No encontré ninguna carta GRAIL con ese ID como premio.", ephemeral=True)
        return
    if carta_deseada["rarity"] != "grail":
        await interaction.response.send_message("❌ La carta que quieres ganar también debe ser de rareza **GRAIL**.", ephemeral=True)
        return
    if grail_apostado == grail_deseado:
        await interaction.response.send_message("❌ No puedes apostar y pedir la misma carta.", ephemeral=True)
        return
    if grail_deseado in cards:
        await interaction.response.send_message("❌ Ya tienes ese GRAIL. Elige uno que no tengas.", ephemeral=True)
        return

    # ── Validar monedas ─────────────────────────────────────────────────────
    coins = player.get("coins", 0)
    if coins < 35000:
        await interaction.response.send_message(
            f"❌ Necesitas **35,000 🪙** para jugar la Ruleta Grail.\nTienes: **{coins:,} 🪙**.",
            ephemeral=True
        )
        return

    # ── Mostrar confirmación ────────────────────────────────────────────────
    embed = discord.Embed(
        title="🎰 RULETA GRAIL — Confirmación",
        description=(
            f"⚠️ **¿Estás seguro?** Esta apuesta es irreversible.\n\n"
            f"**Apuestas:** {carta_apostada['emoji']} `{carta_apostada['artist']} — {carta_apostada['song']}` (GRAIL)\n"
            f"**Quieres ganar:** {carta_deseada['emoji']} `{carta_deseada['artist']} — {carta_deseada['song']}` (GRAIL)\n"
            f"**Costo fijo:** 35,000 🪙 (tienes {coins:,} 🪙)\n\n"
            f"🟢 **30%** — Ganas el GRAIL que elegiste\n"
            f"🔴 **70%** — Pierdes tu GRAIL y recibes una carta **Common** aleatoria\n\n"
            f"*Tu GRAIL apostado se pierde en cualquier caso.*"
        ),
        color=0xe67e22
    )
    embed.set_footer(text="Tienes 60 segundos para confirmar.")

    view = GrailRouletteView(interaction.user.id, carta_apostada, carta_deseada)
    await interaction.response.send_message(embed=embed, view=view)


