@bot.tree.command(name="ranking", description="Top coleccionistas 🏆")
async def ranking(interaction: discord.Interaction):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return
    data = load_data()
    scores = []
    for uid, player in data.items():
        cards = player.get("cards") or []
        if cards:
            owned = [c for c in CARDS if c["id"] in cards and c["rarity"] != "star"]
            score = sum(c["power"] for c in owned) + sum(200 if c["rarity"] == "mythic" else 50 if c["rarity"] == "legendary" else 0 for c in owned)
            mythics = sum(1 for c in owned if c["rarity"] == "mythic")
            lvl = get_level(player)
            scores.append((uid, score, len(cards), mythics, lvl))
    scores.sort(key=lambda x: x[1], reverse=True)
    embed = discord.Embed(title="🏆 Ranking", color=0xf39c12)
    medals = ["🥇","🥈","🥉","4️⃣","5️⃣","6️⃣","7️⃣","8️⃣","9️⃣","🔟"]
    lines = []
    for i, (uid, score, cards, mythics, lvl) in enumerate(scores[:10]):
        try:
            user = bot.get_user(int(uid)) or await bot.fetch_user(int(uid))
            name = user.display_name
        except:
            name = f"User#{uid[:4]}"
        lines.append(f"{medals[i]} **{name}** {lvl['emoji']}Nv.{lvl['level']} — {score} pts {'🔴×'+str(mythics) if mythics else ''} ({cards} cartas)")
    embed.description = "\n".join(lines) if lines else "Nadie tiene cartas aún."
    await interaction.response.send_message(embed=embed)

