@bot.tree.command(name="ver_cartas", description="Ver las cartas de un usuario 👀")
@app_commands.describe(usuario="Usuario del que quieres ver las cartas")
async def ver_cartas(interaction: discord.Interaction, usuario: discord.Member):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return
    data = load_data()
    player = get_player(data, usuario.id)
    if not player["cards"]:
        await interaction.response.send_message(f"❌ {usuario.display_name} no tiene cartas aún.", ephemeral=True)
        return
    owned_cards = [c for c in CARDS if c["id"] in player["cards"]]
    unique = list({c["id"]: c for c in owned_cards}.values())
    unique_sorted = sorted(unique, key=lambda x: ["secret","grail","evento","mythic","legendary","epic","rare","uncommon","common"].index(x["rarity"]) if x["rarity"] in ["secret","grail","evento","mythic","legendary","epic","rare","uncommon","common"] else 99)
    total_pages = max(1, (len(unique_sorted) + CARDS_PER_PAGE - 1) // CARDS_PER_PAGE)
    owned_ids = set(player["cards"])
    embed = build_lista_embed(unique_sorted, owned_ids, 0, total_pages, artista=f"Cartas de {usuario.display_name}")
    view = ListaView(unique_sorted, owned_ids, f"Cartas de {usuario.display_name}", total_pages, interaction.user.id)
    await interaction.response.send_message(embed=embed, view=view)

@bot.tree.command(name="transferir", description="Transfiere monedas a otro usuario 💸 (máx. 100,000 por transferencia)")
@app_commands.describe(
    usuario="Usuario al que quieres enviar monedas",
    cantidad="Cantidad de monedas a transferir (máx. 100,000)"
)
async def transferir(interaction: discord.Interaction, usuario: discord.Member, cantidad: int):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return

    sender_id = interaction.user.id

    if usuario.id == sender_id:
        await interaction.response.send_message("❌ No puedes transferirte monedas a ti mismo.", ephemeral=True)
        return

    if usuario.bot:
        await interaction.response.send_message("❌ No puedes transferir monedas a un bot.", ephemeral=True)
        return

    if cantidad <= 0:
        await interaction.response.send_message("❌ La cantidad debe ser mayor a **0**.", ephemeral=True)
        return

    if cantidad > 100000:
        await interaction.response.send_message("❌ El límite por transferencia es de **100,000** 🪙.", ephemeral=True)
        return

    data = load_data()
    sender = get_player(data, sender_id)
    receiver = get_player(data, usuario.id)

    sender_coins = sender.get("coins", 100)
    if sender_coins < cantidad:
        await interaction.response.send_message(
            f"❌ No tienes suficientes monedas.\nTienes **{sender_coins:,}** 🪙 y quieres enviar **{cantidad:,}** 🪙.",
            ephemeral=True
        )
        return

    sender["coins"] = sender_coins - cantidad
    receiver["coins"] = receiver.get("coins", 100) + cantidad
    save_data(data)
    await send_log(
        titulo="💸 Transferencia de monedas",
        descripcion=f"{interaction.user.mention} transfirió **{cantidad:,} 🪙** a {usuario.mention}.",
        color=0x2ecc71,
        campos=[
            ("💸 Cantidad", f"**{cantidad:,} 🪙**", True),
            ("📤 De", f"{interaction.user.mention}", True),
            ("📥 A", f"{usuario.mention}", True),
        ],
        user_id=interaction.user.id, user_name=str(interaction.user),
        guild_id=interaction.guild.id if interaction.guild else None, guild_name=interaction.guild.name if interaction.guild else 'DM',
    )

    embed = discord.Embed(
        title="💸 Transferencia Exitosa",
        description=f"{interaction.user.mention} le envió **{cantidad:,}** 🪙 a {usuario.mention}",
        color=0x2ecc71
    )
    embed.add_field(name=f"💰 Balance de {interaction.user.display_name}", value=f"**{sender['coins']:,}** 🪙", inline=True)
    embed.add_field(name=f"💰 Balance de {usuario.display_name}", value=f"**{receiver['coins']:,}** 🪙", inline=True)
    await interaction.response.send_message(embed=embed)

@bot.tree.command(name="vender", description="Vende una carta por monedas 💰 (máx. 10 por día)")
@app_commands.describe(artista="Filtrar por artista (opcional)", carta_id="Selecciona la carta a vender")
async def vender(interaction: discord.Interaction, carta_id: str, artista: str = None):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return
    data = load_data()
    player = get_player(data, interaction.user.id)

    ventas_hoy = get_ventas_hoy(player)
    if ventas_hoy >= MAX_VENTAS_DIARIAS:
        await interaction.response.send_message(
            f"❌ Ya vendiste **{MAX_VENTAS_DIARIAS} cartas** hoy. Vuelve mañana para vender más.",
            ephemeral=True
        )
        return

    card = next((c for c in CARDS if c["id"] == carta_id), None)
    if not card:
        await interaction.response.send_message(f"❌ Carta `{carta_id}` no existe.", ephemeral=True)
        return
    if card["rarity"] == "secret":
        await interaction.response.send_message("⬛ Las cartas **SECRETAS** no se pueden vender. Son únicas e inamovibles del /drop.", ephemeral=True)
        return
    if card["rarity"] == "star":
        await interaction.response.send_message("⭐ La carta **✦ TUENI ✦** no se puede vender. Es tuya y solo tuya.", ephemeral=True)
        return
    if card["rarity"] == "evento":
        await interaction.response.send_message("💎 Las cartas de **EVENTO** no se pueden vender al bot. Son exclusivas del Admin Abuse.", ephemeral=True)
        return
    if card["rarity"] == "grail":
        await interaction.response.send_message("🏆 Las cartas **GRAIL** no se pueden vender. Son demasiado raras para desprenderte de ellas.", ephemeral=True)
        return
    if card["rarity"] == "easter":
        if carta_id not in player["cards"]:
            await interaction.response.send_message("❌ No tienes esa carta.", ephemeral=True)
            return
        # Vender la carta easter: troll — dice 99M pero da 99k
        player["cards"].remove(carta_id)
        player["coins"] = player.get("coins", 100) + 99000
        registrar_venta(player)
        save_data(data)
        embed = discord.Embed(
            title="💰 Carta vendida",
            description=(
                "🎵 **Rick Astley — Never Gonna Give You Up**\n\n"
                "La carta fue vendida por 🪙 **$99,000,000**"
            ),
            color=0x2ecc71
        )
        embed.set_image(url="https://media.tenor.com/x8v1oNUOmg4AAAAM/rickroll-roll.gif")
        embed.add_field(name="Balance", value=f"**{player['coins']:,}** 🪙", inline=True)
        await interaction.response.send_message(embed=embed)
        return
    if carta_id not in player["cards"]:
        await interaction.response.send_message(f"❌ No tienes esa carta.", ephemeral=True)
        return

    price = get_sell_price(card["rarity"])
    player["cards"].remove(carta_id)
    player["coins"] = player.get("coins", 100) + price
    registrar_venta(player)
    save_data(data)
    await send_log(
        titulo="💰 Carta vendida",
        descripcion=f"{interaction.user.mention} vendió **{card['artist']}** — {card['song']}.",
        color=0xf39c12,
        campos=[
            ("🎵 Carta", f"{card['artist']} — {card['song']}", True),
            ("⚡ Rareza", card["rarity"].upper(), True),
            ("💰 Precio", f"**{price:,} 🪙**", True),
        ],
        user_id=interaction.user.id, user_name=str(interaction.user),
        guild_id=interaction.guild.id if interaction.guild else None, guild_name=interaction.guild.name if interaction.guild else 'DM',
    )

    ventas_restantes = MAX_VENTAS_DIARIAS - get_ventas_hoy(player)
    rarity = RARITY_CONFIG[card["rarity"]]
    embed = discord.Embed(
        title="💰 Carta vendida",
        description=f"{rarity['emoji']} **{card['artist']}** — {card['song']}\nVendida por **{price} monedas** 🪙",
        color=0xf39c12
    )
    embed.add_field(name="Balance", value=f"**{player['coins']:,}** 🪙", inline=True)
    embed.add_field(name="Ventas restantes hoy", value=f"**{ventas_restantes}/{MAX_VENTAS_DIARIAS}**", inline=True)
    await interaction.response.send_message(embed=embed)

