@vender.autocomplete("carta_id")
async def vender_carta_autocomplete(interaction: discord.Interaction, current: str):
    data = load_data()
    player = get_player(data, interaction.user.id)
    owned_ids = set(player["cards"])
    try:
        artista_filter = interaction.namespace.artista
    except Exception:
        artista_filter = None
    pool = [c for c in CARDS if c["id"] in owned_ids and c["rarity"] != "secret"]
    if artista_filter:
        pool = [c for c in pool if artista_filter.lower() in c["artist"].lower()]
    results = []
    seen = set()
    for c in pool:
        if c["id"] in seen:
            continue
        seen.add(c["id"])
        label = f"{RARITY_CONFIG[c['rarity']]['emoji']} {c['artist']} — {c['song']} ({get_sell_price(c['rarity'])} 🪙)"
        if current.lower() in label.lower():
            results.append(app_commands.Choice(name=label[:100], value=c["id"]))
        if len(results) >= 25:
            break
    return results

# ─── TIENDA DE SOBRES ─────────────────────────────────────────────────────────

# ── helpers de inventario de sobres ───────────────────────────────────────────
def get_sobres(player):
    """Devuelve el inventario de sobres: {"common": 3, "rare": 1, ...}"""
    return player.setdefault("sobres", {})

def agregar_sobres(player, rareza: str, cantidad: int):
    sobres = get_sobres(player)
    sobres[rareza] = sobres.get(rareza, 0) + cantidad

def quitar_sobres(player, rareza: str, cantidad: int) -> bool:
    sobres = get_sobres(player)
    if sobres.get(rareza, 0) < cantidad:
        return False
    sobres[rareza] -= cantidad
    if sobres[rareza] == 0:
        del sobres[rareza]
    return True

# ── View para ABRIR sobres del inventario ─────────────────────────────────────
class AbrirSobreView(discord.ui.View):
    def __init__(self, user_id: int, rareza: str, cantidad: int):
        super().__init__(timeout=90)
        self.user_id = user_id
        self.rareza = rareza
        self.cantidad = cantidad
        self.usado = False

    @discord.ui.button(label="🎴 Abrir", style=discord.ButtonStyle.success)
    async def abrir(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Este sobre no es tuyo.", ephemeral=True)
            return
        if self.usado:
            await interaction.response.send_message("❌ Ya usaste esta acción.", ephemeral=True)
            return
        self.usado = True

        data = load_data()
        player = get_player(data, self.user_id)

        # Quitar los sobres del inventario
        if not quitar_sobres(player, self.rareza, self.cantidad):
            await interaction.response.send_message("❌ Ya no tienes esos sobres.", ephemeral=True)
            return

        # Sacar cartas aleatorias de esa rareza (nunca secretas desde sobres)
        cartas_de_rareza = [c for c in CARDS if c["rarity"] == self.rareza and c["rarity"] != "secret"]
        cards_obtenidas = [random.choice(cartas_de_rareza) for _ in range(self.cantidad)]

        # Agregar cartas al inventario
        for c in cards_obtenidas:
            player["cards"].append(c["id"])
        save_data(data)

        for item in self.children:
            item.disabled = True

        rarity_cfg = RARITY_CONFIG[self.rareza]
        pack_cfg = PACK_CONFIG[self.rareza]

        if self.cantidad == 1:
            c = cards_obtenidas[0]
            embed = discord.Embed(
                title=f"🎴 ¡Sobre abierto! {rarity_cfg['emoji']}",
                description=f"**{pack_cfg['name']}** abierto",
                color=rarity_cfg["color"]
            )
            embed.add_field(
                name=f"{c['emoji']} {c['artist']}",
                value=f"**{c['song']}** ({c['year']})\n{rarity_cfg['emoji']} {c['rarity'].upper()} ⚡{c['power']}\n_{c['description']}_",
                inline=False
            )
            if c.get("image"):
                embed.set_image(url=c["image"])
        else:
            embed = discord.Embed(
                title=f"🎴 ¡{self.cantidad} Sobres abiertos! {rarity_cfg['emoji']}",
                description=f"Obtuviste **{self.cantidad} cartas {rarity_cfg['emoji']} {self.rareza.upper()}**:",
                color=rarity_cfg["color"]
            )
            for c in cards_obtenidas[:25]:
                embed.add_field(
                    name=f"{c['emoji']} {c['artist']}",
                    value=f"{c['song']} ⚡{c['power']}",
                    inline=True
                )

        sobres_restantes = get_sobres(player).get(self.rareza, 0)
        embed.set_footer(text=f"Cartas agregadas a tu colección ✅ | Sobres {rarity_cfg['emoji']} restantes: {sobres_restantes}")
        await interaction.response.edit_message(embed=embed, view=self)

    @discord.ui.button(label="❌ Cancelar", style=discord.ButtonStyle.secondary)
    async def cancelar(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Este sobre no es tuyo.", ephemeral=True)
            return
        if self.usado:
            await interaction.response.send_message("❌ Ya usaste esta acción.", ephemeral=True)
            return
        self.usado = True
        for item in self.children:
            item.disabled = True
        await interaction.response.edit_message(
            content="Apertura cancelada. Los sobres siguen en tu inventario 📦",
            view=self
        )

