@bot.tree.command(name="sobre_comprar", description="Compra sobres y guárdalos en tu inventario 📦")
@app_commands.describe(rareza="Rareza del sobre", cantidad="Cantidad de sobres (1-10)")
@app_commands.choices(rareza=[
    app_commands.Choice(name="⚪ Común — 80 monedas",         value="common"),
    app_commands.Choice(name="🟢 Infrecuente — 250 monedas",  value="uncommon"),
    app_commands.Choice(name="🔵 Raro — 700 monedas",         value="rare"),
    app_commands.Choice(name="🟣 Épico — 1,800 monedas",      value="epic"),
    app_commands.Choice(name="🟡 Legendario — 5,500 monedas", value="legendary"),
    app_commands.Choice(name="🔴 Mítico — 18,000 monedas",    value="mythic"),
])
async def comprar_sobre(interaction: discord.Interaction, rareza: str, cantidad: int = 1):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return
    if cantidad < 1 or cantidad > 10:
        await interaction.response.send_message("❌ Puedes comprar entre **1 y 10** sobres a la vez.", ephemeral=True)
        return

    pack = PACK_CONFIG[rareza]
    rarity_cfg = RARITY_CONFIG[rareza]
    precio_total = pack["price"] * cantidad

    data = load_data()
    player = get_player(data, interaction.user.id)
    coins = player.get("coins", 100)

    if coins < precio_total:
        falta = precio_total - coins
        await interaction.response.send_message(
            f"❌ No tienes suficientes monedas.\n"
            f"Necesitas **{precio_total:,}** 🪙 ({cantidad}× {pack['name']})\n"
            f"Tienes **{coins:,}** 🪙 — Te faltan **{falta:,}** 🪙",
            ephemeral=True
        )
        return

    player["coins"] = coins - precio_total
    agregar_sobres(player, rareza, cantidad)
    save_data(data)
    await send_log(
        titulo="📦 Sobres comprados",
        descripcion=f"{interaction.user.mention} compró **{cantidad}x** sobre(s) {rareza.upper()}.",
        color=pack["color"],
        campos=[
            ("📦 Rareza", f"{pack['emoji']} {rareza.upper()}", True),
            ("🔢 Cantidad", str(cantidad), True),
            ("💸 Gastado", f"**{precio_total:,} 🪙**", True),
        ],
        user_id=interaction.user.id, user_name=str(interaction.user),
        guild_id=interaction.guild.id if interaction.guild else None, guild_name=interaction.guild.name if interaction.guild else 'DM',
    )

    total_de_esa = get_sobres(player).get(rareza, 0)
    embed = discord.Embed(
        title=f"{pack['emoji']} {'Sobre comprado' if cantidad == 1 else f'{cantidad} Sobres comprados'}!",
        description=(
            f"Guardados en tu inventario 📦\n"
            f"Úsalos cuando quieras con `/sobre_abrir {rareza}`"
        ),
        color=pack["color"]
    )
    embed.add_field(name="Comprado", value=f"**{cantidad}×** {pack['emoji']} {pack['name']}", inline=True)
    embed.add_field(name="Costo", value=f"**{precio_total:,}** 🪙", inline=True)
    embed.add_field(name="Saldo", value=f"**{player['coins']:,}** 🪙", inline=True)
    embed.add_field(name="📦 En inventario", value=f"**{total_de_esa}×** {rarity_cfg['emoji']} {rareza.upper()}", inline=False)
    embed.set_footer(text="/sobres para ver todo tu inventario de sobres")
    await interaction.response.send_message(embed=embed)

