# ─── AUTOCOMPLETE HELPERS ─────────────────────────────────────────────────────

# Lista de todos los artistas únicos del catálogo
ALL_ARTISTS = list(dict.fromkeys(c["artist"] for c in CARDS))

async def artista_autocomplete(interaction: discord.Interaction, current: str):
    """Autocomplete para el campo artista: muestra todos los artistas disponibles."""
    data = load_data()
    buyer_id = str(interaction.user.id)
    # Artistas que tienen cartas disponibles (de otros usuarios)
    available_ids = set()
    for uid, pdata in data.items():
        if uid != buyer_id:
            for cid in pdata.get("cards", []):
                available_ids.add(cid)
    available_artists = list(dict.fromkeys(
        c["artist"] for c in CARDS
        if c["id"] in available_ids and (not current or current.lower() in c["artist"].lower())
    ))
    # Si no hay nada en el mercado aún, mostrar todos los artistas como referencia
    if not available_artists:
        available_artists = [a for a in ALL_ARTISTS if not current or current.lower() in a.lower()]
    return [app_commands.Choice(name=a, value=a) for a in available_artists[:25]]

async def cancion_autocomplete(interaction: discord.Interaction, current: str):
    """Autocomplete para canciones — filtra por el artista ya ingresado si hay uno."""
    artista_val = interaction.namespace.artista or ""
    data = load_data()
    buyer_id = str(interaction.user.id)
    available_ids = set()
    for uid, pdata in data.items():
        if uid != buyer_id:
            for cid in pdata.get("cards", []):
                available_ids.add(cid)

    canciones = []
    seen_songs = set()
    for c in CARDS:
        if c["id"] not in available_ids:
            continue
        if artista_val and artista_val.lower() not in c["artist"].lower():
            continue
        if current and current.lower() not in c["song"].lower():
            continue
        if c["song"] not in seen_songs:
            seen_songs.add(c["song"])
            canciones.append(c)

    return [
        app_commands.Choice(
            name=f"{c['artist']} — {c['song']}"[:100],
            value=c["id"]  # Devolvemos el ID de carta directo para compra inmediata
        )
        for c in canciones[:25]
    ]

@bot.tree.command(name="comprar", description="Busca y compra cartas del mercado entre usuarios 🛒")
@app_commands.describe(
    artista="Filtrar por artista (autocomplete)",
    cancion="Buscar canción — selecciona del menú para comprar directo",
    rareza="Filtrar por rareza",
    precio_oferta="Precio personalizado que ofreces 🪙 (opcional)"
)
@app_commands.autocomplete(artista=artista_autocomplete, cancion=cancion_autocomplete)
@app_commands.describe(precio_oferta="Precio que quieres ofrecer (opcional, deja en blanco para precio estándar)")
@app_commands.choices(rareza=[
    app_commands.Choice(name="⚪ Común",      value="common"),
    app_commands.Choice(name="🟢 Infrecuente", value="uncommon"),
    app_commands.Choice(name="🔵 Rara",        value="rare"),
    app_commands.Choice(name="🟣 Épica",       value="epic"),
    app_commands.Choice(name="🟡 Legendaria",  value="legendary"),
    app_commands.Choice(name="🔴 Mítica",      value="mythic"),
])
async def comprar(interaction: discord.Interaction, artista: str = None, cancion: str = None, rareza: str = None, precio_oferta: int = None):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return

    data = load_data()
    buyer_id = str(interaction.user.id)

    # Recolectar todas las cartas disponibles (de otros usuarios)
    # seller_map: card_id -> [seller_id1, seller_id2, ...] (todos los dueños)
    available_card_ids = set()
    seller_map = {}
    for uid, pdata in data.items():
        if uid != buyer_id:
            for cid in pdata.get("cards", []):
                # Excluir cartas star del mercado — son intransferibles
                card_check = next((c for c in CARDS if c["id"] == cid), None)
                if card_check and card_check["rarity"] == "star":
                    continue
                available_card_ids.add(cid)
                if cid not in seller_map:
                    seller_map[cid] = []
                if uid not in seller_map[cid]:
                    seller_map[cid].append(uid)

    if not available_card_ids:
        await interaction.response.send_message(
            "❌ No hay cartas disponibles en el mercado todavía.\n"
            "Los usuarios necesitan obtener cartas con `/drop` para que aparezcan aquí.",
            ephemeral=True
        )
        return

    # Si cancion es un ID de carta directo (viene del autocomplete de canción), compra directa
    direct_card = next((c for c in CARDS if c["id"] == cancion), None)
    if direct_card and cancion in available_card_ids:
        sellers = seller_map.get(cancion, [])
        if isinstance(sellers, str):
            sellers = [sellers]
        # Filtrar vendedores válidos
        sellers_validos = [s for s in sellers if cancion in data.get(s, {}).get("cards", [])]
        if not sellers_validos:
            await interaction.response.send_message("❌ Esta carta ya no está disponible.", ephemeral=True)
            return
        if len(sellers_validos) == 1:
            await _iniciar_oferta_compra(interaction, direct_card, sellers_validos[0], data, precio_oferta)
        else:
            # Múltiples dueños — mostrar picker
            rarity_cfg = RARITY_CONFIG[direct_card["rarity"]]
            opciones = []
            for sid in sellers_validos[:25]:
                seller_info = data.get(sid, {})
                nombre = seller_info.get("username", "") or f"Usuario {sid[:6]}"
                opciones.append(discord.SelectOption(label=nombre, description=f"Comprar a {nombre}", value=sid, emoji="👤"))
            embed = discord.Embed(
                title="👥 ¿A quién quieres comprarle?",
                description=f"{rarity_cfg['emoji']} **{direct_card['artist']}** — {direct_card['song']}\n\n**{len(sellers_validos)} usuarios** tienen esta carta. Elige a quién hacerle la oferta:",
                color=rarity_cfg["color"]
            )
            if direct_card.get("image"):
                embed.set_thumbnail(url=direct_card["image"])
            view = SellerPickerView(direct_card, sellers_validos, data, interaction.user.id, opciones, precio_oferta)
            await interaction.response.send_message(embed=embed, view=view, ephemeral=True)
        return

    # Filtrar catálogo
    market_cards = []
    for card in CARDS:
        if card["id"] not in available_card_ids:
            continue

        if artista and artista.lower() not in card["artist"].lower():
            continue
        if cancion and cancion.lower() not in card["song"].lower():
            continue
        if rareza and card["rarity"] != rareza:
            continue
        market_cards.append(card)

    # Deduplicar por ID
    seen = set()
    unique_market = []
    for c in market_cards:
        if c["id"] not in seen:
            seen.add(c["id"])
            unique_market.append(c)

    if not unique_market:
        filtros_txt = []
        if artista: filtros_txt.append(f"artista: **{artista}**")
        if cancion: filtros_txt.append(f"canción: **{cancion}**")
        if rareza: filtros_txt.append(f"rareza: **{rareza}**")
        filtros_str = " | ".join(filtros_txt) if filtros_txt else "ningún filtro"
        await interaction.response.send_message(
            f"❌ No hay cartas disponibles con {filtros_str}.\nPrueba con otros filtros.",
            ephemeral=True
        )
        return

    buyer = get_player(data, interaction.user.id)
    view = MercadoView(unique_market, buyer, interaction.user.id, seller_map)
    embed = build_mercado_embed(unique_market, buyer, 0, artista, cancion, rareza, seller_map=seller_map, data=data)
    await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

class SellerPickerView(discord.ui.View):
    """Muestra un Select para elegir a qué vendedor comprarle cuando hay varios."""
    def __init__(self, card, sellers, data, user_id, opciones, precio_oferta=None):
        super().__init__(timeout=60)
        self.card = card
        self.sellers = sellers
        self.data = data
        self.user_id = user_id
        self.precio_oferta = precio_oferta

        select = discord.ui.Select(placeholder="Elige al vendedor...", options=opciones)
        select.callback = self.seller_callback
        self.add_item(select)

    async def seller_callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Solo quien usó el comando puede comprar.", ephemeral=True)
            return
        seller_id = interaction.data["values"][0]
        data = load_data()
        await _iniciar_oferta_compra(interaction, self.card, seller_id, data, self.precio_oferta)

async def _iniciar_oferta_compra(interaction: discord.Interaction, card, seller_id: str, data: dict, precio_custom: int = None):
    """Envía oferta al vendedor con botones de aceptar/rechazar en el mismo canal."""
    buyer = get_player(data, interaction.user.id)
    price = precio_custom if precio_custom and precio_custom > 0 else get_buy_price(card["rarity"])
    coins = buyer.get("coins", 100)

    if coins < price:
        await interaction.response.send_message(
            f"❌ No tienes suficientes monedas.\nNecesitas **{price:,}** 🪙, tienes **{coins:,}** 🪙.",
            ephemeral=True
        )
        return

    # Verificar que la carta sigue disponible
    seller_data = data.get(seller_id, {})
    if card["id"] not in seller_data.get("cards", []):
        await interaction.response.send_message("❌ Esta carta ya no está disponible.", ephemeral=True)
        return

    offer_key = f"{interaction.user.id}_{seller_id}_{card['id']}"
    if offer_key in pending_market_offers:
        await interaction.response.send_message("⏳ Ya tienes una oferta pendiente para esta carta.", ephemeral=True)
        return

    pending_market_offers[offer_key] = {
        "buyer_id": interaction.user.id,
        "seller_id": seller_id,
        "card_id": card["id"],
        "price": price,
    }

    rarity = RARITY_CONFIG[card["rarity"]]
    seller_mention = f"<@{seller_id}>"

    # Notificación pública en el canal con botones para el vendedor
    embed_seller = discord.Embed(
        title="💰 ¡Oferta de compra!",
        description=(
            f"{interaction.user.mention} quiere comprarte esta carta, {seller_mention}:\n\n"
            f"{rarity['emoji']} **{card['artist']}** — {card['song']}\n"
            f"⚡ Power: {card['power']}/100\n\n"
            f"Precio: **{price:,}** 🪙 → El vendedor recibiría: **{price:,}** 🪙"
        ),
        color=rarity["color"]
    )
    embed_seller.set_image(url=card.get("image", ""))
    embed_seller.set_footer(text=f"⏳ El vendedor tiene 2 minutos para responder")

    view_seller = VentaOfertaView(offer_key, interaction.user.id, int(seller_id), card["id"], price)
    await interaction.response.send_message(
        content=f"{seller_mention} tienes una oferta de compra! 👆",
        embed=embed_seller,
        view=view_seller
    )

    # Auto-expirar la oferta en 2 minutos
    await asyncio.sleep(120)
    if offer_key in pending_market_offers:
        del pending_market_offers[offer_key]

class VentaOfertaView(discord.ui.View):
    """Botones que le aparecen al VENDEDOR para aceptar o rechazar la oferta en el canal."""
    def __init__(self, offer_key: str, buyer_id: int, seller_id: int, card_id: str, price: int):
        super().__init__(timeout=120)
        self.offer_key = offer_key
        self.buyer_id = buyer_id
        self.seller_id = seller_id
        self.card_id = card_id
        self.price = price
        self.usado = False

    @discord.ui.button(label="✅ Aceptar venta", style=discord.ButtonStyle.success)
    async def aceptar(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.seller_id:
            await interaction.response.send_message("❌ Solo el vendedor puede responder esta oferta.", ephemeral=True)
            return
        if self.usado:
            await interaction.response.send_message("❌ Ya respondiste esta oferta.", ephemeral=True)
            return
        if self.offer_key not in pending_market_offers:
            await interaction.response.send_message("❌ Esta oferta ya expiró o fue cancelada.", ephemeral=True)
            return
        self.usado = True
        del pending_market_offers[self.offer_key]

        data = load_data()
        buyer = get_player(data, self.buyer_id)
        seller = get_player(data, self.seller_id)

        if self.card_id not in seller.get("cards", []):
            for item in self.children: item.disabled = True
            await interaction.response.edit_message(content="❌ Ya no tienes esa carta.", embed=None, view=self)
            return
        if buyer.get("coins", 100) < self.price:
            for item in self.children: item.disabled = True
            await interaction.response.edit_message(content="❌ El comprador ya no tiene suficientes monedas.", embed=None, view=self)
            return

        # Ejecutar transacción
        buyer["coins"] -= self.price
        seller["cards"].remove(self.card_id)
        seller["coins"] = seller.get("coins", 100) + int(self.price)
        buyer["cards"].append(self.card_id)
        save_data(data)

        card = next((c for c in CARDS if c["id"] == self.card_id), None)
        rarity = RARITY_CONFIG[card["rarity"]]

        for item in self.children: item.disabled = True

        embed_ok = discord.Embed(
            title="✅ ¡Venta completada!",
            description=(
                f"<@{self.buyer_id}> compró de <@{self.seller_id}>:\n\n"
                f"{rarity['emoji']} **{card['artist']}** — {card['song']}\n\n"
                f"💸 <@{self.buyer_id}> pagó: **{self.price:,}** 🪙\n"
                f"💰 <@{self.seller_id}> recibió: **{int(self.price):,}** 🪙"
            ),
            color=0x27ae60
        )
        embed_ok.set_image(url=card.get("image", ""))
        await interaction.response.edit_message(content=None, embed=embed_ok, view=self)

    @discord.ui.button(label="❌ Rechazar", style=discord.ButtonStyle.danger)
    async def rechazar(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.seller_id:
            await interaction.response.send_message("❌ Solo el vendedor puede responder esta oferta.", ephemeral=True)
            return
        if self.usado:
            await interaction.response.send_message("❌ Ya respondiste esta oferta.", ephemeral=True)
            return
        self.usado = True
        if self.offer_key in pending_market_offers:
            del pending_market_offers[self.offer_key]

        card = next((c for c in CARDS if c["id"] == self.card_id), None)
        rarity = RARITY_CONFIG[card["rarity"]] if card else {}

        for item in self.children: item.disabled = True

        embed_rechazado = discord.Embed(
            title="❌ Oferta rechazada",
            description=(
                f"<@{self.seller_id}> rechazó la oferta de <@{self.buyer_id}>.\n\n"
                f"{rarity.get('emoji','🎴')} **{card['artist']}** — {card['song']} sigue en su colección."
            ) if card else "❌ Oferta rechazada.",
            color=0xe74c3c
        )
        await interaction.response.edit_message(content=None, embed=embed_rechazado, view=self)

    async def on_timeout(self):
        for item in self.children: item.disabled = True
        if self.offer_key in pending_market_offers:
            del pending_market_offers[self.offer_key]

def build_mercado_embed(cards, buyer, page, artista=None, cancion=None, rareza=None, seller_map=None, data=None):
    import math
    MARKET_PER_PAGE = 10
    total_pages = max(1, math.ceil(len(cards) / MARKET_PER_PAGE))
    start = page * MARKET_PER_PAGE
    end = start + MARKET_PER_PAGE
    page_cards = cards[start:end]

    filtros = []
    if artista: filtros.append(f"🎤 {artista}")
    if cancion: filtros.append(f"🎵 {cancion}")
    if rareza: filtros.append(f"{RARITY_CONFIG[rareza]['emoji']} {rareza.upper()}")
    titulo = "🛒 Mercado de Cartas"
    if filtros:
        titulo += " — " + " | ".join(filtros)

    embed = discord.Embed(title=titulo, color=0x2ecc71,
        description=f"💰 Tus monedas: **{buyer.get('coins', 100):,}** 🪙\nSelecciona una carta para hacer una oferta.\n")

    lines = []
    for i, c in enumerate(page_cards):
        rarity_cfg = RARITY_CONFIG[c["rarity"]]
        price = get_buy_price(c["rarity"])
        can_buy = "✅" if buyer.get("coins", 100) >= price else "❌"
        # Obtener nombre(s) del/los vendedor(es)
        seller_name = ""
        if seller_map and data:
            sids = seller_map.get(c["id"], [])
            if isinstance(sids, str):
                sids = [sids]  # compatibilidad legacy
            nombres = []
            for sid in sids[:3]:  # max 3 nombres visibles
                seller_info = data.get(sid, {})
                n = seller_info.get("username", "") or f"ID:{sid[:6]}"
                nombres.append(n)
            if nombres:
                seller_name = f" · 👤 {', '.join(nombres)}"
                if len(sids) > 3:
                    seller_name += f" +{len(sids)-3}"
        lines.append(f"`{start+i+1}.` {rarity_cfg['emoji']} **{c['artist']}** — {c['song']} | 🪙 **{price:,}** {can_buy}{seller_name}")
    embed.description += "\n".join(lines)
    embed.set_footer(text=f"Página {page+1}/{total_pages} • {len(cards)} cartas disponibles")
    return embed

class MercadoView(discord.ui.View):
    MARKET_PER_PAGE = 10

    def __init__(self, cards, buyer, user_id, seller_map):
        super().__init__(timeout=120)
        self.cards = cards
        self.buyer = buyer
        self.user_id = user_id
        self.seller_map = seller_map
        self.page = 0
        import math
        self.total_pages = max(1, math.ceil(len(cards) / self.MARKET_PER_PAGE))
        self._rebuild_select()
        self._update_nav()

    def _rebuild_select(self):
        to_remove = [i for i in self.children if isinstance(i, discord.ui.Select)]
        for item in to_remove:
            self.remove_item(item)

        start = self.page * self.MARKET_PER_PAGE
        end = start + self.MARKET_PER_PAGE
        page_cards = self.cards[start:end]

        options = []
        for c in page_cards:
            rarity_cfg = RARITY_CONFIG[c["rarity"]]
            price = get_buy_price(c["rarity"])
            options.append(discord.SelectOption(
                label=f"{c['artist']} — {c['song'][:40]}",
                description=f"{rarity_cfg['emoji']} {c['rarity'].upper()} | {price:,} monedas",
                value=c["id"],
                emoji=rarity_cfg["emoji"]
            ))

        select = discord.ui.Select(placeholder="Selecciona una carta para hacer una oferta...", options=options)
        select.callback = self.select_callback
        self.add_item(select)

    def _update_nav(self):
        self.prev_btn.disabled = self.page == 0
        self.next_btn.disabled = self.page >= self.total_pages - 1
        self.page_lbl.label = f"{self.page+1}/{self.total_pages}"

    async def select_callback(self, interaction: discord.Interaction):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ Solo quien usó el comando puede comprar.", ephemeral=True)
            return
        card_id = interaction.data["values"][0]
        card = next((c for c in CARDS if c["id"] == card_id), None)
        if not card:
            await interaction.response.send_message("❌ Carta no encontrada.", ephemeral=True)
            return

        sellers = self.seller_map.get(card_id, [])
        if isinstance(sellers, str):
            sellers = [sellers]

        if not sellers:
            await interaction.response.send_message("❌ Esta carta ya no está disponible.", ephemeral=True)
            return

        data = load_data()

        # Filtrar vendedores que aún tienen la carta
        sellers_validos = [s for s in sellers if card_id in data.get(s, {}).get("cards", [])]
        if not sellers_validos:
            await interaction.response.send_message("❌ Esta carta ya no está disponible en el mercado.", ephemeral=True)
            return

        # Si solo hay un vendedor, ir directo
        if len(sellers_validos) == 1:
            await _iniciar_oferta_compra(interaction, card, sellers_validos[0], data)
            return

        # Hay múltiples vendedores — mostrar picker para elegir a quién comprarle
        rarity_cfg = RARITY_CONFIG[card["rarity"]]
        opciones = []
        for sid in sellers_validos[:25]:
            seller_info = data.get(sid, {})
            nombre = seller_info.get("username", "") or f"Usuario {sid[:6]}"
            opciones.append(discord.SelectOption(
                label=nombre,
                description=f"Comprar a {nombre}",
                value=sid,
                emoji="👤"
            ))

        embed = discord.Embed(
            title=f"👥 ¿A quién quieres comprarle?",
            description=f"{rarity_cfg['emoji']} **{card['artist']}** — {card['song']}\n\n**{len(sellers_validos)} usuarios** tienen esta carta. Elige a quién hacerle la oferta:",
            color=rarity_cfg["color"]
        )
        if card.get("image"):
            embed.set_thumbnail(url=card["image"])

        view = SellerPickerView(card, sellers_validos, data, self.user_id, opciones)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

    @discord.ui.button(label="◀", style=discord.ButtonStyle.primary, row=1)
    async def prev_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ No es tu comando.", ephemeral=True)
            return
        self.page = max(0, self.page - 1)
        self._update_nav()
        self._rebuild_select()
        data = load_data()
        buyer = get_player(data, self.user_id)
        await interaction.response.edit_message(embed=build_mercado_embed(self.cards, buyer, self.page, seller_map=self.seller_map, data=data), view=self)

    @discord.ui.button(label="1/1", style=discord.ButtonStyle.secondary, disabled=True, row=1)
    async def page_lbl(self, interaction: discord.Interaction, button: discord.ui.Button):
        pass

    @discord.ui.button(label="▶", style=discord.ButtonStyle.primary, row=1)
    async def next_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ No es tu comando.", ephemeral=True)
            return
        self.page = min(self.total_pages - 1, self.page + 1)
        self._update_nav()
        self._rebuild_select()
        data = load_data()
        buyer = get_player(data, self.user_id)
        await interaction.response.edit_message(embed=build_mercado_embed(self.cards, buyer, self.page, seller_map=self.seller_map, data=data), view=self)

    async def on_timeout(self):
        for item in self.children:
            item.disabled = True

# ─── APOSTAR (GATO) ──────────────────────────────────────────────────────────

pending_apuestas = {}

def _board_str(board):
    s = {0: "⬜", 1: "🔵", 2: "🔴"}
    rows = []
    for r in range(3):
        rows.append(" ".join(s[board[r*3+c]] for c in range(3)))
    return "\n".join(rows)

def _check_winner(board):
    wins = [(0,1,2),(3,4,5),(6,7,8),(0,3,6),(1,4,7),(2,5,8),(0,4,8),(2,4,6)]
    for a, b, c in wins:
        if board[a] == board[b] == board[c] != 0:
            return board[a]
    if 0 not in board:
        return -1
    return 0

def _gato_embed(game, status):
    p1_id, p2_id = game["players"]
    tipo = game["apuesta_tipo"]
    if tipo == "monedas":
        apuesta_str = f"🪙 **{game['apuesta_valor']:,} monedas** cada uno"
    else:
        c1 = next((c for c in CARDS if c["id"] == game.get("carta_p1")), None)
        c2 = next((c for c in CARDS if c["id"] == game.get("carta_p2")), None)
        apuesta_str = f"🎴 **{c1['song'] if c1 else '?'}** vs **{c2['song'] if c2 else '?'}**"
    embed = discord.Embed(
        title="🎮 GATO — Apuesta",
        description=f"{_board_str(game['board'])}\n\n{status}",
        color=0x6c5ce7
    )
    embed.add_field(name="🔵 Jugador 1", value=f"<@{p1_id}>", inline=True)
    embed.add_field(name="🔴 Jugador 2", value=f"<@{p2_id}>", inline=True)
    embed.add_field(name="Apuesta", value=apuesta_str, inline=False)
    return embed

class GatoView(discord.ui.View):
    def __init__(self, apuesta_id):
        super().__init__(timeout=300)
        self.apuesta_id = apuesta_id
        self._rebuild()

    def _rebuild(self):
        self.clear_items()
        game = pending_apuestas.get(self.apuesta_id)
        if not game:
            return
        board = game["board"]
        ended = _check_winner(board) != 0
        s = {0: "⬜", 1: "🔵", 2: "🔴"}
        for idx in range(9):
            r = idx // 3
            cell = board[idx]
            btn = discord.ui.Button(
                label=s[cell],
                style=discord.ButtonStyle.secondary if cell == 0 else discord.ButtonStyle.primary,
                disabled=(cell != 0 or ended),
                row=r,
                custom_id=f"gato_{self.apuesta_id}_{idx}"
            )
            btn.callback = self._make_cb(idx)
            self.add_item(btn)

    def _make_cb(self, idx):
        async def cb(interaction: discord.Interaction):
            game = pending_apuestas.get(self.apuesta_id)
            if not game:
                await interaction.response.send_message("❌ La partida ya no existe.", ephemeral=True)
                return
            current = game["players"][game["turn"] - 1]
            if interaction.user.id != current:
                await interaction.response.send_message("❌ No es tu turno.", ephemeral=True)
                return
            if game["board"][idx] != 0:
                await interaction.response.send_message("❌ Casilla ocupada.", ephemeral=True)
                return

            game["board"][idx] = game["turn"]
            winner = _check_winner(game["board"])

            if winner == 0:
                game["turn"] = 2 if game["turn"] == 1 else 1
                next_id = game["players"][game["turn"] - 1]
                sym = "🔵" if game["turn"] == 1 else "🔴"
                self._rebuild()
                await interaction.response.edit_message(
                    embed=_gato_embed(game, f"Turno de <@{next_id}> {sym}"),
                    view=self
                )
                return

            # Fin del juego
            del pending_apuestas[self.apuesta_id]
            # Borrar del archivo persistente
            guardadas = load_pending_apuestas()
            guardadas.pop(self.apuesta_id, None)
            save_pending_apuestas(guardadas)
            self._rebuild()
            data = load_data()
            p1 = get_player(data, game["players"][0])
            p2 = get_player(data, game["players"][1])

            if winner == -1:
                if game["apuesta_tipo"] == "monedas":
                    p1["coins"] = p1.get("coins", 0) + game["apuesta_valor"]
                    p2["coins"] = p2.get("coins", 0) + game["apuesta_valor"]
                else:
                    if game["carta_p1"] not in p1["cards"]:
                        p1["cards"].append(game["carta_p1"])
                    if game["carta_p2"] not in p2["cards"]:
                        p2["cards"].append(game["carta_p2"])
                save_data(data)
                emb = _gato_embed(game, "🤝 ¡Empate! Se devuelven las apuestas.")
                emb.color = 0x95a5a6
                await interaction.response.edit_message(embed=emb, view=self)
                apuesta_desc = f"**{game['apuesta_valor']:,} 🪙**" if game["apuesta_tipo"] == "monedas" else "carta"
                await send_log(
                    titulo="🎮 Gato — Empate",
                    descripcion=f"Empate entre <@{game['players'][0]}> y <@{game['players'][1]}> — apuesta devuelta: {apuesta_desc}",
                    color=0x95a5a6,
                    campos=[("👤 J1", f"<@{game['players'][0]}>", True), ("👤 J2", f"<@{game['players'][1]}>", True), ("💰 Apuesta", apuesta_desc, True)],
                    guild_id=interaction.guild_id,
                    guild_name=interaction.guild.name if interaction.guild else "DM",
                )
                return

            win_idx = winner - 1
            lose_idx = 1 - win_idx
            win_p = [p1, p2][win_idx]
            win_id = game["players"][win_idx]
            lose_p = [p1, p2][lose_idx]

            extra = ""
            if game["apuesta_tipo"] == "monedas":
                win_p["coins"] = win_p.get("coins", 0) + game["apuesta_valor"] * 2
                extra = f"\n🪙 Ganó **{game['apuesta_valor']:,} monedas** netas (bote: **{game['apuesta_valor']*2:,}** 🪙)"
            else:
                carta_ganador = game[f"carta_p{win_idx+1}"]
                carta_perdedor = game[f"carta_p{lose_idx+1}"]
                if carta_ganador not in win_p["cards"]:
                    win_p["cards"].append(carta_ganador)
                win_p["cards"].append(carta_perdedor)
                c_win = next((c for c in CARDS if c["id"] == carta_ganador), None)
                c_los = next((c for c in CARDS if c["id"] == carta_perdedor), None)
                extra = f"\n🎴 Ganó **{c_los['song'] if c_los else '?'}**"

            save_data(data)
            emb = _gato_embed(game, f"🏆 ¡Ganó <@{win_id}>!{extra}")
            emb.color = 0xf39c12
            await interaction.response.edit_message(embed=emb, view=self)
            apuesta_desc = f"**{game['apuesta_valor']:,} 🪙**" if game["apuesta_tipo"] == "monedas" else "carta"
            await send_log(
                titulo="🎮 Gato — Partida terminada",
                descripcion=f"<@{win_id}> ganó contra <@{game['players'][lose_idx]}> — apuesta: {apuesta_desc}",
                color=0xf39c12,
                campos=[("🏆 Ganador", f"<@{win_id}>", True), ("😞 Perdedor", f"<@{game['players'][lose_idx]}>", True), ("💰 Apuesta", apuesta_desc, True)],
                user_id=win_id,
                guild_id=interaction.guild_id,
                guild_name=interaction.guild.name if interaction.guild else "DM",
            )
        return cb

class ApuestaAceptarView(discord.ui.View):
    def __init__(self, apuesta_id, challenger_id, rival_id):
        super().__init__(timeout=60)
        self.apuesta_id = apuesta_id
        self.challenger_id = challenger_id
        self.rival_id = rival_id

    @discord.ui.button(label="Aceptar reto 🎮", style=discord.ButtonStyle.success)
    async def aceptar(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.rival_id:
            await interaction.response.send_message("❌ Este reto no es para ti.", ephemeral=True)
            return
        game = pending_apuestas.get(self.apuesta_id)
        if not game or game.get("estado") != "esperando":
            await interaction.response.send_message("❌ Ya no disponible.", ephemeral=True)
            return
        data = load_data()
        rival = get_player(data, self.rival_id)
        if game["apuesta_tipo"] == "monedas":
            if rival.get("coins", 0) < game["apuesta_valor"]:
                await interaction.response.send_message(
                    f"❌ No tienes suficientes monedas. Necesitas **{game['apuesta_valor']:,}** 🪙", ephemeral=True)
                return
            rival["coins"] -= game["apuesta_valor"]
        else:
            if game["carta_p2"] not in rival["cards"]:
                await interaction.response.send_message("❌ Ya no tienes esa carta.", ephemeral=True)
                return
            rival["cards"].remove(game["carta_p2"])
        game["estado"] = "jugando"
        save_data(data)
        for item in self.children:
            item.disabled = True
        await interaction.message.edit(view=self)
        view = GatoView(self.apuesta_id)
        first_id = game["players"][0]
        await interaction.response.send_message(
            embed=_gato_embed(game, f"¡Empezamos! Turno de <@{first_id}> 🔵"),
            view=view
        )

    @discord.ui.button(label="Rechazar ❌", style=discord.ButtonStyle.danger)
    async def rechazar(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.rival_id:
            await interaction.response.send_message("❌ Este reto no es para ti.", ephemeral=True)
            return
        game = pending_apuestas.pop(self.apuesta_id, None)
        if not game:
            await interaction.response.send_message("❌ Ya no disponible.", ephemeral=True)
            return
        data = load_data()
        challenger = get_player(data, self.challenger_id)
        if game["apuesta_tipo"] == "monedas":
            challenger["coins"] = challenger.get("coins", 0) + game["apuesta_valor"]
        else:
            if game["carta_p1"] not in challenger["cards"]:
                challenger["cards"].append(game["carta_p1"])
        save_data(data)
        # Borrar del archivo persistente
        guardadas = load_pending_apuestas()
        guardadas.pop(self.apuesta_id, None)
        save_pending_apuestas(guardadas)
        for item in self.children:
            item.disabled = True
        await interaction.message.edit(content="❌ Reto rechazado.", view=self)
        await interaction.response.send_message("Rechazado.", ephemeral=True)

    async def on_timeout(self):
        game = pending_apuestas.pop(self.apuesta_id, None)
        if not game:
            return
        data = load_data()
        challenger = get_player(data, self.challenger_id)
        if game["apuesta_tipo"] == "monedas":
            challenger["coins"] = challenger.get("coins", 0) + game["apuesta_valor"]
        else:
            if game["carta_p1"] not in challenger["cards"]:
                challenger["cards"].append(game["carta_p1"])
        save_data(data)
        # Borrar del archivo persistente
        guardadas = load_pending_apuestas()
        guardadas.pop(self.apuesta_id, None)
        save_pending_apuestas(guardadas)
        for item in self.children:
            item.disabled = True

async def apostar_tu_carta_autocomplete(interaction: discord.Interaction, current: str):
    data = load_data()
    player = get_player(data, interaction.user.id)
    owned = set(player["cards"])
    results = []
    seen = set()
    for c in CARDS:
        if c["id"] not in owned:
            continue
        label = f"{RARITY_CONFIG[c['rarity']]['emoji']} {c['artist']} — {c['song']}"
        if current and current.lower() not in label.lower():
            continue
        if c["id"] not in seen:
            seen.add(c["id"])
            results.append(app_commands.Choice(name=label[:100], value=c["id"]))
        if len(results) >= 25:
            break
    return results

async def apostar_carta_rival_autocomplete(interaction: discord.Interaction, current: str):
    rival_obj = getattr(interaction.namespace, "rival", None)
    tu_carta_val = getattr(interaction.namespace, "tu_carta", None) or ""
    data = load_data()
    rival_cards = set()
    if rival_obj:
        try:
            # rival_obj puede ser un Member/User o un int/str
            if hasattr(rival_obj, "id"):
                rival_id = rival_obj.id
            else:
                rival_id = int(rival_obj)
            rp = get_player(data, rival_id)
            rival_cards = set(rp["cards"])
        except Exception:
            pass
    if not rival_cards:
        return []
    # Obtener rareza de tu_carta — buscar por ID exacto
    my_rarity = None
    if tu_carta_val:
        my_card = next((c for c in CARDS if c["id"] == tu_carta_val), None)
        if my_card:
            my_rarity = my_card["rarity"]
    results = []
    seen = set()
    for c in CARDS:
        if c["id"] not in rival_cards:
            continue
        if my_rarity and c["rarity"] != my_rarity:
            continue
        label = f"{RARITY_CONFIG[c['rarity']]['emoji']} {c['artist']} — {c['song']}"
        if current and current.lower() not in label.lower():
            continue
        if c["id"] not in seen:
            seen.add(c["id"])
            results.append(app_commands.Choice(name=label[:100], value=c["id"]))
        if len(results) >= 25:
            break
    return results

async def subasta_carta_autocomplete(interaction: discord.Interaction, current: str):
    data = load_data()
    player = get_player(data, interaction.user.id)
    owned = set(player["cards"])
    artista_val = getattr(interaction.namespace, "artista_carta", None) or ""
    results = []
    seen = set()
    for c in CARDS:
        if c["id"] not in owned:
            continue
        if artista_val and artista_val.lower() not in c["artist"].lower():
            continue
        label = f"{RARITY_CONFIG[c['rarity']]['emoji']} {c['artist']} — {c['song']}"
        if current and current.lower() not in label.lower():
            continue
        if c["id"] not in seen:
            seen.add(c["id"])
            results.append(app_commands.Choice(name=label[:100], value=c["id"]))
        if len(results) >= 25:
            break
    return results

@bot.tree.command(name="apostar", description="Reta a otro usuario a un gato — apuesta cartas o monedas 🎮")
@app_commands.describe(
    rival="Usuario contra quien apostar",
    tipo="Tipo de apuesta",
    cantidad="Monedas a apostar (solo si tipo=monedas)",
    tu_carta="Tu carta a apostar (solo si tipo=carta)",
    carta_rival="Carta del rival que quieres ganar (solo si tipo=carta)"
)
@app_commands.choices(tipo=[
    app_commands.Choice(name="🪙 Monedas", value="monedas"),
    app_commands.Choice(name="🎴 Cartas",  value="carta"),
])
@app_commands.autocomplete(tu_carta=apostar_tu_carta_autocomplete, carta_rival=apostar_carta_rival_autocomplete)
async def apostar(interaction: discord.Interaction, rival: discord.Member, tipo: str,
                  cantidad: int = None, tu_carta: str = None, carta_rival: str = None):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 Canal bloqueado.", ephemeral=True)
        return
    if rival.id == interaction.user.id:
        await interaction.response.send_message("❌ No puedes apostar contra ti mismo.", ephemeral=True)
        return
    if rival.bot:
        await interaction.response.send_message("❌ No puedes apostar contra un bot.", ephemeral=True)
        return

    data = load_data()
    challenger = get_player(data, interaction.user.id)
    import time
    apuesta_id = f"gato_{interaction.user.id}_{rival.id}_{int(time.time())}"

    game = {
        "estado": "esperando",
        "players": [interaction.user.id, rival.id],
        "board": [0] * 9,
        "turn": 1,
        "apuesta_tipo": tipo,
        "apuesta_valor": 0,
        "carta_p1": None,
        "carta_p2": None,
    }

    if tipo == "monedas":
        if not cantidad or cantidad <= 0:
            await interaction.response.send_message("❌ Indica una cantidad mayor a 0.", ephemeral=True)
            return
        if challenger.get("coins", 0) < cantidad:
            await interaction.response.send_message(
                f"❌ No tienes suficientes monedas. Tienes **{challenger.get('coins',0):,}** 🪙", ephemeral=True)
            return
        challenger["coins"] -= cantidad
        game["apuesta_valor"] = cantidad
        apuesta_str = f"🪙 **{cantidad:,} monedas** cada uno"

    else:
        if not tu_carta or not carta_rival:
            await interaction.response.send_message(
                "❌ Debes indicar `tu_carta` y `carta_rival` con los IDs.", ephemeral=True)
            return
        card_p1 = next((c for c in CARDS if c["id"] == tu_carta), None)
        card_p2 = next((c for c in CARDS if c["id"] == carta_rival), None)
        if not card_p1:
            await interaction.response.send_message(f"❌ Carta `{tu_carta}` no existe.", ephemeral=True)
            return
        if not card_p2:
            await interaction.response.send_message(f"❌ Carta `{carta_rival}` no existe.", ephemeral=True)
            return
        if tu_carta not in challenger["cards"]:
            await interaction.response.send_message("❌ No tienes esa carta.", ephemeral=True)
            return
        rival_data = get_player(data, rival.id)
        if carta_rival not in rival_data["cards"]:
            await interaction.response.send_message(
                f"❌ {rival.display_name} no tiene esa carta.", ephemeral=True)
            return
        if card_p1["rarity"] != card_p2["rarity"]:
            r1e = RARITY_CONFIG[card_p1["rarity"]]["emoji"]
            r2e = RARITY_CONFIG[card_p2["rarity"]]["emoji"]
            await interaction.response.send_message(
                f"❌ Las cartas deben ser de la **misma rareza**.\n"
                f"Tu carta: {r1e} **{card_p1['rarity']}** | Carta rival: {r2e} **{card_p2['rarity']}**",
                ephemeral=True)
            return
        challenger["cards"].remove(tu_carta)
        game["carta_p1"] = tu_carta
        game["carta_p2"] = carta_rival
        r1e = RARITY_CONFIG[card_p1["rarity"]]["emoji"]
        r2e = RARITY_CONFIG[card_p2["rarity"]]["emoji"]
        apuesta_str = f"🎴 {r1e} **{card_p1['song']}** vs {r2e} **{card_p2['song']}**"

    save_data(data)
    pending_apuestas[apuesta_id] = game
    # Guardar en archivo para sobrevivir reinicios
    guardadas = load_pending_apuestas()
    guardadas[apuesta_id] = game
    save_pending_apuestas(guardadas)

    embed = discord.Embed(
        title="🎮 ¡Reto de Gato!",
        description=f"{interaction.user.mention} te reta a un gato, {rival.mention}!\n\n{apuesta_str}",
        color=0x6c5ce7
    )
    embed.add_field(name="🔵 Retador", value=interaction.user.mention, inline=True)
    embed.add_field(name="🔴 Retado",  value=rival.mention, inline=True)
    embed.set_footer(text="⏳ 60 segundos para aceptar o rechazar")
    view = ApuestaAceptarView(apuesta_id, interaction.user.id, rival.id)
    await interaction.response.send_message(content=rival.mention, embed=embed, view=view)

# ─── SUBASTA ─────────────────────────────────────────────────────────────────

active_auctions = {}

SUBASTA_MAX_TIME    = 180   # 3 minutos límite absoluto
SUBASTA_NO_BID_TIME = 120   # 2 minutos sin ninguna puja → termina
SUBASTA_IDLE_TIME   = 20    # 20 segundos sin nueva puja (después de al menos 1) → termina

def _subasta_embed(auction, card):
    rarity = RARITY_CONFIG[card["rarity"]]
    if auction["top_bidder_id"]:
        top = f"<@{auction['top_bidder_id']}> — **{auction['current_bid']:,}** 🪙"
    else:
        top = "Nadie aún"
    next_bid = auction["current_bid"] + auction["increment"]
    import time as _time
    start = auction.get("start_time", _time.time())
    elapsed = _time.time() - start
    remaining = max(0, int(SUBASTA_MAX_TIME - elapsed))
    mins, secs = divmod(remaining, 60)
    time_str = f"{mins}m {secs}s" if mins else f"{secs}s"
    embed = discord.Embed(
        title=f"🔨 SUBASTA — {rarity['emoji']} {card['song']}",
        description=(
            f"**{card['artist']}** · {card['year']}\n"
            f"⚡ Power: {card['power']}/100\n\n"
            f"💰 Puja actual: **{auction['current_bid']:,}** 🪙\n"
            f"📈 Siguiente puja: **{next_bid:,}** 🪙  (+{auction['increment']:,})\n"
            f"🥇 Va ganando: {top}"
        ),
        color=rarity["color"]
    )
    if card.get("image"):
        embed.set_image(url=card["image"])
    embed.set_footer(text=f"⏳ Tiempo restante: {time_str} · Subasta por <@{auction['owner_id']}>")
    return embed

async def _finalizar_subasta(auction_id: str, message=None):
    """Finaliza la subasta, reparte recompensas y edita el mensaje."""
    auction = active_auctions.pop(auction_id, None)
    if not auction:
        return
    data = load_data()
    card = next((c for c in CARDS if c["id"] == auction["card_id"]), None)

    if not auction["top_bidder_id"]:
        # Sin pujas → devolver carta
        owner = get_player(data, auction["owner_id"])
        if auction["card_id"] not in owner["cards"]:
            owner["cards"].append(auction["card_id"])
        save_data(data)
        try:
            ch = auction.get("channel")
            if ch:
                await ch.send(
                    f"🔔 La subasta de **{card['song'] if card else '?'}** terminó sin pujas. "
                    f"Carta devuelta a <@{auction['owner_id']}>."
                )
        except Exception:
            pass
    else:
        # Hay ganador
        winner = get_player(data, auction["top_bidder_id"])
        winner["cards"].append(auction["card_id"])
        owner = get_player(data, auction["owner_id"])
        owner["coins"] = owner.get("coins", 0) + auction["current_bid"]
        save_data(data)
        try:
            ch = auction.get("channel")
            if ch and card:
                rarity = RARITY_CONFIG[card["rarity"]]
                emb = discord.Embed(
                    title="🔨 ¡Subasta terminada!",
                    description=(
                        f"🏆 Ganador: <@{auction['top_bidder_id']}>\n"
                        f"{rarity['emoji']} **{card['artist']}** — {card['song']}\n"
                        f"Precio final: **{auction['current_bid']:,}** 🪙"
                    ),
                    color=0xf39c12
                )
                if card.get("image"):
                    emb.set_thumbnail(url=card["image"])
                await ch.send(embed=emb)
        except Exception:
            pass

    # Deshabilitar botones del mensaje original
    if message:
        try:
            disabled_view = discord.ui.View()
            btn = discord.ui.Button(label="Subasta finalizada", style=discord.ButtonStyle.secondary, disabled=True)
            disabled_view.add_item(btn)
            await message.edit(view=disabled_view)
        except Exception:
            pass

class SubastaView(discord.ui.View):
    def __init__(self, auction_id):
        super().__init__(timeout=None)   # Manejamos timeouts manualmente
        self.auction_id = auction_id
        self.message = None
        self._task = None

    def start_timer(self):
        self._task = asyncio.ensure_future(self._run_timer())

    async def _run_timer(self):
        import time as _time
        auction = active_auctions.get(self.auction_id)
        if not auction:
            return

        start_time = auction["start_time"]
        last_bid_count = 0

        while True:
            await asyncio.sleep(1)
            auction = active_auctions.get(self.auction_id)
            if not auction:
                return   # Ya fue finalizada por otro camino

            elapsed = _time.time() - start_time
            bid_count = auction.get("bid_count", 0)

            # Caso 1: Tiempo máximo absoluto (3 min)
            if elapsed >= SUBASTA_MAX_TIME:
                await _finalizar_subasta(self.auction_id, self.message)
                return

            # Caso 2: Sin ninguna puja y llevamos 2 minutos
            if bid_count == 0 and elapsed >= SUBASTA_NO_BID_TIME:
                await _finalizar_subasta(self.auction_id, self.message)
                return

            # Caso 3: Hubo al least 1 puja y no ha habido nueva en 5 segundos
            if bid_count > 0:
                last_bid_time = auction.get("last_bid_time", start_time)
                idle = _time.time() - last_bid_time
                if idle >= SUBASTA_IDLE_TIME:
                    await _finalizar_subasta(self.auction_id, self.message)
                    return

    @discord.ui.button(label="Pujar ⬆️", style=discord.ButtonStyle.success, emoji="💰")
    async def pujar(self, interaction: discord.Interaction, button: discord.ui.Button):
        import time as _time
        auction = active_auctions.get(self.auction_id)
        if not auction:
            await interaction.response.send_message("❌ Esta subasta ya terminó.", ephemeral=True)
            return
        if interaction.user.id == auction["owner_id"]:
            await interaction.response.send_message("❌ No puedes pujar en tu propia subasta.", ephemeral=True)
            return
        if interaction.user.id == auction["top_bidder_id"]:
            await interaction.response.send_message("❌ Ya eres el mayor postor.", ephemeral=True)
            return
        new_bid = auction["current_bid"] + auction["increment"]
        data = load_data()
        bidder = get_player(data, interaction.user.id)
        if bidder.get("coins", 0) < new_bid:
            await interaction.response.send_message(
                f"❌ No tienes suficientes monedas.\nNecesitas **{new_bid:,}** 🪙, tienes **{bidder.get('coins',0):,}** 🪙.",
                ephemeral=True)
            return
        # Devolver monedas al pujador anterior
        if auction["top_bidder_id"]:
            prev = get_player(data, auction["top_bidder_id"])
            prev["coins"] = prev.get("coins", 0) + auction["current_bid"]
        # Cobrar al nuevo pujador
        bidder["coins"] = bidder.get("coins", 0) - new_bid
        auction["current_bid"] = new_bid
        auction["top_bidder_id"] = interaction.user.id
        auction["bid_count"] = auction.get("bid_count", 0) + 1
        auction["last_bid_time"] = _time.time()
        save_data(data)
        card = next((c for c in CARDS if c["id"] == auction["card_id"]), None)
        await interaction.response.edit_message(embed=_subasta_embed(auction, card), view=self)

