# ─── TRADES ──────────────────────────────────────────────────────────────────

def _buscar_carta_propia(card_id: str, player: dict) -> dict | None:
    """Busca carta por ID exacto entre las cartas del jugador."""
    if card_id and card_id in player.get("cards", []):
        return next((c for c in CARDS if c["id"] == card_id), None)
    return None

def _format_card_line(card: dict) -> str:
    r = RARITY_CONFIG[card["rarity"]]
    return f"{r['emoji']} **{card['artist']}** — {card['song']} ⚡{card['power']}"


class TradeView(discord.ui.View):
    def __init__(self, trade_id: str, receiver_id: int, sender_id: int, sender_name: str):
        super().__init__(timeout=120)
        self.trade_id = trade_id
        self.receiver_id = receiver_id
        self.sender_id = sender_id
        self.sender_name = sender_name

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.receiver_id:
            await interaction.response.send_message("❌ Solo la persona que recibió el trade puede responder.", ephemeral=True)
            return False
        return True

    @discord.ui.button(label="✅ Aceptar", style=discord.ButtonStyle.success)
    async def aceptar(self, interaction: discord.Interaction, button: discord.ui.Button):
        trade = pending_trades.get(self.trade_id)
        if not trade:
            await interaction.response.send_message("❌ Este trade ya no está disponible.", ephemeral=True)
            return
        data = load_data()
        sender = get_player(data, trade["sender_id"])
        receiver = get_player(data, trade["receiver_id"])

        # Validar que sender aún tiene todas sus cartas
        for cid in trade["cards_offer"]:
            if cid not in sender["cards"]:
                del pending_trades[self.trade_id]
                for item in self.children: item.disabled = True
                await interaction.response.edit_message(view=self)
                await interaction.followup.send(f"❌ La otra persona ya no tiene todas las cartas ofrecidas (`{cid}`). Trade cancelado.", ephemeral=True)
                return

        # Validar que receiver aún tiene todas sus cartas
        for cid in trade["cards_want"]:
            if cid not in receiver["cards"]:
                del pending_trades[self.trade_id]
                for item in self.children: item.disabled = True
                await interaction.response.edit_message(view=self)
                await interaction.followup.send(f"❌ Ya no tienes la carta `{cid}`. Trade cancelado.", ephemeral=True)
                return

        # Validar monedas al aceptar
        coins_offer = trade.get("coins_offer", 0)
        coins_want  = trade.get("coins_want",  0)
        if coins_offer > 0 and sender.get("coins", 0) < coins_offer:
            del pending_trades[self.trade_id]
            for item in self.children: item.disabled = True
            await interaction.response.edit_message(view=self)
            await interaction.followup.send("❌ La otra persona ya no tiene suficientes monedas. Trade cancelado.", ephemeral=True)
            return
        if coins_want > 0 and receiver.get("coins", 0) < coins_want:
            del pending_trades[self.trade_id]
            for item in self.children: item.disabled = True
            await interaction.response.edit_message(view=self)
            await interaction.followup.send(f"❌ No tienes suficientes monedas (necesitas {coins_want:,}). Trade cancelado.", ephemeral=True)
            return

        # Ejecutar intercambio de cartas
        for cid in trade["cards_offer"]:
            sender["cards"].remove(cid)
            receiver["cards"].append(cid)
        for cid in trade["cards_want"]:
            receiver["cards"].remove(cid)
            sender["cards"].append(cid)

        # Ejecutar intercambio de monedas
        if coins_offer > 0:
            sender["coins"]   = sender.get("coins", 0) - coins_offer
            receiver["coins"] = receiver.get("coins", 0) + coins_offer
        if coins_want > 0:
            receiver["coins"] = receiver.get("coins", 0) - coins_want
            sender["coins"]   = sender.get("coins", 0) + coins_want

        save_data(data)
        del pending_trades[self.trade_id]

        cards_offer_info = [next((c for c in CARDS if c["id"] == cid), None) for cid in trade["cards_offer"]]
        cards_want_info  = [next((c for c in CARDS if c["id"] == cid), None) for cid in trade["cards_want"]]
        cards_offer_info = [c for c in cards_offer_info if c]
        cards_want_info  = [c for c in cards_want_info  if c]

        _sender_got   = [_format_card_line(c) for c in cards_want_info]
        _receiver_got = [_format_card_line(c) for c in cards_offer_info]
        if coins_want  > 0: _sender_got.append(f"🪙 {coins_want:,} monedas")
        if coins_offer > 0: _receiver_got.append(f"🪙 {coins_offer:,} monedas")

        embed = discord.Embed(title="✅ Trade completado!", color=0x27ae60)
        embed.add_field(name=f"{self.sender_name} recibió:", value="\n".join(_sender_got) or "—", inline=False)
        embed.add_field(name=f"{interaction.user.display_name} recibió:", value="\n".join(_receiver_got) or "—", inline=False)
        for item in self.children: item.disabled = True
        await interaction.response.edit_message(embed=embed, view=self, content=None)

        log_offer = ", ".join(f"{c['artist']} — {c['song']} (`{c['rarity']}`)" for c in cards_offer_info)
        log_want  = ", ".join(f"{c['artist']} — {c['song']} (`{c['rarity']}`)" for c in cards_want_info)
        await send_log(
            titulo="🔄 Trade completado",
            descripcion=f"**<@{trade['sender_id']}>** y **{interaction.user.mention}** completaron un intercambio.",
            color=0x27ae60,
            campos=[
                (f"{self.sender_name} dio ({len(cards_offer_info)})", log_offer, False),
                (f"{interaction.user.display_name} dio ({len(cards_want_info)})", log_want, False),
            ],
            guild_id=interaction.guild.id if interaction.guild else None,
            guild_name=interaction.guild.name if interaction.guild else "DM",
        )

    @discord.ui.button(label="❌ Rechazar", style=discord.ButtonStyle.danger)
    async def rechazar(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.trade_id in pending_trades:
            del pending_trades[self.trade_id]
        embed = discord.Embed(title="❌ Trade rechazado", description=f"{interaction.user.display_name} rechazó el trade.", color=0xe74c3c)
        for item in self.children: item.disabled = True
        await interaction.response.edit_message(embed=embed, view=self, content=None)


