    quiero_2="Carta #2 que quieres (opcional)",
    quiero_3="Carta #3 que quieres (opcional)",
    quiero_4="Carta #4 que quieres (opcional)",
    quiero_5="Carta #5 que quieres (opcional)",
    monedas_oferta="Monedas que tú pones en el trade",
    monedas_quiero="Monedas que quieres recibir",
