async def trade(
    interaction: discord.Interaction,
    usuario: discord.Member,
    oferta_1: str = None,
    quiero_1: str = None,
    oferta_2: str = None,
    oferta_3: str = None,
    oferta_4: str = None,
    oferta_5: str = None,
    quiero_2: str = None,
    quiero_3: str = None,
    quiero_4: str = None,
    quiero_5: str = None,
    monedas_oferta: int = 0,
    monedas_quiero: int = 0,
):
    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return
    if usuario.id == interaction.user.id or usuario.bot:
        await interaction.response.send_message("❌ No válido.", ephemeral=True)
        return

    monedas_oferta = max(0, monedas_oferta or 0)
    monedas_quiero = max(0, monedas_quiero or 0)

    data = load_data()
    sender   = get_player(data, interaction.user.id)
    receiver = get_player(data, usuario.id)

    if monedas_oferta > 0 and sender.get("coins", 0) < monedas_oferta:
        await interaction.response.send_message(f"❌ No tienes suficientes monedas. Tienes {sender.get('coins',0):,} y quieres ofrecer {monedas_oferta:,}.", ephemeral=True)
        return

    # Reunir IDs no nulos
    oferta_ids = [x for x in [oferta_1, oferta_2, oferta_3, oferta_4, oferta_5] if x]
    quiero_ids = [x for x in [quiero_1, quiero_2, quiero_3, quiero_4, quiero_5] if x]

    if not oferta_ids and not quiero_ids and monedas_oferta == 0 and monedas_quiero == 0:
        await interaction.response.send_message("❌ El trade está vacío.", ephemeral=True)
        return

    # Validar cartas ofrecidas (deben estar en las cartas del sender)
    cards_offer = []
    seen_offer = []
    for cid in oferta_ids:
        card = _buscar_carta_propia(cid, sender)
        if not card:
            await interaction.response.send_message(f"❌ No tienes la carta `{cid}` o no existe.", ephemeral=True)
            return
        if card["rarity"] == "star":
            await interaction.response.send_message("⭐ La carta **✦ TUENI ✦** no se puede tradear. Es intransferible.", ephemeral=True)
            return
        if cid in seen_offer:
            await interaction.response.send_message(f"❌ Pusiste la misma carta dos veces en tu oferta (`{cid}`).", ephemeral=True)
            return
        seen_offer.append(cid)
        cards_offer.append(card)

    # Validar cartas pedidas (deben estar en las cartas del receiver)
    cards_want = []
    seen_want = []
    for cid in quiero_ids:
        card = _buscar_carta_propia(cid, receiver)
        if not card:
            await interaction.response.send_message(f"❌ {usuario.display_name} no tiene la carta `{cid}` o no existe.", ephemeral=True)
            return
        if card["rarity"] == "star":
            await interaction.response.send_message("⭐ La carta **✦ TUENI ✦** no se puede tradear. Es intransferible.", ephemeral=True)
            return
        if cid in seen_want:
            await interaction.response.send_message(f"❌ Pediste la misma carta dos veces (`{cid}`).", ephemeral=True)
            return
        seen_want.append(cid)
        cards_want.append(card)

    trade_id = f"{interaction.user.id}_{usuario.id}"
    pending_trades[trade_id] = {
        "sender_id":   interaction.user.id,
        "receiver_id": usuario.id,
        "cards_offer": seen_offer,
        "cards_want":  seen_want,
        "coins_offer": monedas_oferta,
        "coins_want":  monedas_quiero,
    }

    _offer_lines = [_format_card_line(c) for c in cards_offer]
    _want_lines  = [_format_card_line(c) for c in cards_want]
    if monedas_oferta > 0: _offer_lines.append(f"🪙 **{monedas_oferta:,} monedas**")
    if monedas_quiero > 0: _want_lines.append(f"🪙 **{monedas_quiero:,} monedas**")

    embed = discord.Embed(title="🔄 Propuesta de Trade", color=0x3498db)
    embed.add_field(
        name=f"{interaction.user.display_name} ofrece:",
        value="\n".join(_offer_lines) or "—",
        inline=False
    )
    embed.add_field(
        name=f"{interaction.user.display_name} quiere:",
        value="\n".join(_want_lines) or "—",
        inline=False
    )
    embed.set_footer(text="⏱️ Esta propuesta expira en 2 minutos")
    view = TradeView(trade_id=trade_id, receiver_id=usuario.id, sender_id=interaction.user.id, sender_name=interaction.user.display_name)
    await interaction.response.send_message(
        content=f"{usuario.mention}, tienes una propuesta de trade de **{interaction.user.display_name}**!",
        embed=embed, view=view
    )


def _autocomplete_cartas_propias(owned_ids: list, current: str) -> list:
    seen = set()
    results = []
    for c in CARDS:
        if c["id"] not in owned_ids: continue
        if c["id"] in seen: continue
        seen.add(c["id"])
        label = f"{RARITY_CONFIG[c['rarity']]['emoji']} {c['artist']} — {c['song']}"
        if current.lower() in label.lower():
            results.append(app_commands.Choice(name=label[:100], value=c["id"]))
        if len(results) >= 25: break
    return results

def _autocomplete_cartas_ajenas(owned_ids: list, current: str) -> list:
    return _autocomplete_cartas_propias(owned_ids, current)

@trade.autocomplete("oferta_1")
@trade.autocomplete("oferta_2")
@trade.autocomplete("oferta_3")
@trade.autocomplete("oferta_4")
@trade.autocomplete("oferta_5")
async def autocomplete_oferta(interaction: discord.Interaction, current: str):
    data = load_data()
    sender = get_player(data, interaction.user.id)
    return _autocomplete_cartas_propias(sender.get("cards", []), current)

@trade.autocomplete("quiero_1")
@trade.autocomplete("quiero_2")
@trade.autocomplete("quiero_3")
@trade.autocomplete("quiero_4")
@trade.autocomplete("quiero_5")
async def autocomplete_quiero(interaction: discord.Interaction, current: str):
    try:
        usuario_id = interaction.namespace.usuario.id
    except Exception:
        return []
    data = load_data()
    receiver = get_player(data, usuario_id)
    return _autocomplete_cartas_ajenas(receiver.get("cards", []), current)

