# ─── CARTA DIVINA ────────────────────────────────────────────────────────────

carta_divina_last_use = {}   # guild_id -> datetime
carta_divina_claimed = {}    # guild_id -> bool (si ya fue reclamada)

class CartaDivinaView(discord.ui.View):
    def __init__(self, card: dict, guild_id: int):
        super().__init__(timeout=120)
        self.card = card
        self.guild_id = guild_id
        self.claimed = False

    @discord.ui.button(label="¡RECLAMAR CARTA!", style=discord.ButtonStyle.danger, emoji="🎴")
    async def reclamar(self, interaction: discord.Interaction, button: discord.ui.Button):
        if self.claimed or carta_divina_claimed.get(self.guild_id, False):
            await interaction.response.send_message("❌ Esta carta ya fue reclamada por alguien.", ephemeral=True)
            return

        self.claimed = True
        carta_divina_claimed[self.guild_id] = True

        # Desactivar botón
        button.disabled = True
        button.label = f"Reclamada por {interaction.user.display_name}"
        button.style = discord.ButtonStyle.secondary

        # Dar carta al usuario
        data = load_data()
        player = get_player(data, interaction.user.id)
        player["cards"].append(self.card["id"])
        player["username"] = interaction.user.display_name
        save_data(data)
        await send_log(
            titulo="🎴 Carta Divina reclamada",
            descripcion=f"{interaction.user.mention} reclamó **{self.card['artist']}** — {self.card['song']}.",
            color=0xffd700,
            campos=[("⚡ Rareza", self.card["rarity"].upper(), True)],
            user_id=interaction.user.id, user_name=str(interaction.user),
            guild_id=interaction.guild.id if interaction.guild else None, guild_name=interaction.guild.name if interaction.guild else 'DM',
        )

        embed = card_embed(self.card, interaction.user.display_name)
        rarity_cfg = RARITY_CONFIG[self.card["rarity"]]
        msg = "🔴 **🔥 MÍTICA 🔥**" if self.card["rarity"] == "mythic" else "🟡 **LEGENDARIA**"

        await interaction.response.edit_message(
            content=f"🎉 {interaction.user.mention} reclamó la carta divina!\n{msg}",
            embed=embed,
            view=self
        )

    async def on_timeout(self):
        self.claimed = True
        carta_divina_claimed[self.guild_id] = True
        for item in self.children:
            item.disabled = True
            item.label = "Tiempo agotado — nadie reclamó"
            item.style = discord.ButtonStyle.secondary

@bot.tree.command(name="carta_divina", description="Lanza una carta Legendaria o Mítica que el primero en clickear puede reclamar 🎴 (solo admins)")
async def carta_divina(interaction: discord.Interaction):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return

    if not is_bot_admin(interaction):
        await interaction.response.send_message("❌ No tienes permiso para usar este comando.", ephemeral=True)
        return

    # Cooldown 4 horas por servidor
    guild_id = interaction.guild_id
    last_use = carta_divina_last_use.get(guild_id)
    if last_use:
        diff = datetime.now(timezone.utc) - last_use
        if diff < timedelta(hours=4):
            remaining = timedelta(hours=4) - diff
            total_secs = int(remaining.total_seconds())
            h = total_secs // 3600
            m = (total_secs % 3600) // 60
            await interaction.response.send_message(
                f"⏳ La **Carta Divina** estará disponible en **{h}h {m}m**.",
                ephemeral=True
            )
            return

    # Registrar uso y resetear claimed
    carta_divina_last_use[guild_id] = datetime.now(timezone.utc)
    carta_divina_claimed[guild_id] = False

    # 50/50 legendaria o mítica
    rareza = random.choice(["legendary", "mythic"])
    pool = [c for c in CARDS if c["rarity"] == rareza]
    if not pool:
        await interaction.response.send_message("❌ No hay cartas disponibles de esa rareza.", ephemeral=True)
        return

    card = random.choice(pool)
    rarity_cfg = RARITY_CONFIG[rareza]
    embed = card_embed(card)

    titulo = "🔴 ¡CARTA MÍTICA DISPONIBLE!" if rareza == "mythic" else "🟡 ¡CARTA LEGENDARIA DISPONIBLE!"
    color = 0xff0000 if rareza == "mythic" else 0xffd700

    anuncio = discord.Embed(
        title=f"🎴 {titulo}",
        description="¡El primero en presionar el botón se lleva la carta!\n⚠️ Solo hay **una oportunidad** — actúa rápido.",
        color=color
    )
    anuncio.set_footer(text=f"Lanzada por {interaction.user.display_name} • Expira en 2 minutos")

    view = CartaDivinaView(card, guild_id)
    await interaction.response.send_message(embed=anuncio, view=view)
    await interaction.followup.send(embed=embed, view=None)

