TRABAJAR_COOLDOWN = 120  # 2 minutos

@bot.tree.command(name="trabajar", description="Trabaja para ganar entre 50 y 200 monedas 💼")
async def trabajar(interaction: discord.Interaction):

    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return
    data = load_data()
    player = get_player(data, interaction.user.id)

    ahora = datetime.now(timezone.utc)
    ultimo = player.get("last_trabajo")
    if ultimo:
        diff = (ahora - _parse_dt(ultimo)).total_seconds()
        if diff < TRABAJAR_COOLDOWN:
            restante = int(TRABAJAR_COOLDOWN - diff)
            mins = restante // 60
            segs = restante % 60
            t = f"{mins}m {segs}s" if mins > 0 else f"{segs}s"
            await interaction.response.send_message(f"⏳ Debes esperar **{t}** antes de trabajar de nuevo.", ephemeral=True)
            return

    trabajos = [
        "repartiste pizzas 🍕", "lavaste carros 🚗", "hiciste stream 🎮",
        "vendiste merch 👕", "diste clases de música 🎵", "fuiste DJ en una fiesta 🎧",
        "trabajaste en el estudio 🎙️", "hiciste delivery 📦", "vendiste beats 🥁",
    ]
    trabajo = random.choice(trabajos)
    ganancia = random.randint(50, 200)
    player["coins"] = player.get("coins", 0) + ganancia
    player["last_trabajo"] = ahora.isoformat()
    save_data(data)
    await send_log(
        titulo="💼 Trabajo",
        descripcion=f"{interaction.user.mention} trabajó y ganó **{ganancia} 🪙**.",
        color=0x27ae60,
        campos=[("💰 Ganancia", f"**{ganancia} 🪙**", True)],
        user_id=interaction.user.id, user_name=str(interaction.user),
        guild_id=interaction.guild.id if interaction.guild else None, guild_name=interaction.guild.name if interaction.guild else 'DM',
    )

    embed = discord.Embed(
        title="💼 ¡Trabajo completado!",
        description=f"{interaction.user.display_name} {trabajo} y ganó **{ganancia} 🪙**",
        color=0x27ae60
    )
    embed.add_field(name="💳 Balance", value=f"**{player['coins']:,} 🪙**", inline=True)
    embed.add_field(name="⏱️ Próximo trabajo", value="En **2 minutos**", inline=True)
    await interaction.response.send_message(embed=embed)

