# ─── ADMIN: EDITAR / AGREGAR CARTA ───────────────────────────────────────────

@bot.tree.command(name="editar_carta", description="Agregar o modificar una carta (solo admins) 🛠️")
@app_commands.describe(
    carta_id="ID de la carta a editar (ej: uzi_001). Si no existe se crea nueva.",
    artista="Nombre del artista",
    cancion="Título de la canción",
    album="Álbum o descripción (ej: Pink Tape (2023))",
    rareza="Rareza de la carta",
    imagen_url="URL de la imagen de portada",
    power="Poder de la carta (1-100)",
    year="Año de la carta",
    emoji="Emoji representativo de la carta"
)
@app_commands.choices(rareza=[
    app_commands.Choice(name="⚪ Común",       value="common"),
    app_commands.Choice(name="🟢 Infrecuente", value="uncommon"),
    app_commands.Choice(name="🔵 Rara",        value="rare"),
    app_commands.Choice(name="🟣 Épica",       value="epic"),
    app_commands.Choice(name="🟡 Legendaria",  value="legendary"),
    app_commands.Choice(name="🔴 Mítica",      value="mythic"),
    app_commands.Choice(name="🏆 Grail",       value="grail"),
    app_commands.Choice(name="⬛ Secreta",     value="secret"),
    app_commands.Choice(name="💎 Evento",      value="evento"),
])
async def editar_carta(
    interaction: discord.Interaction,
    carta_id: str,
    artista: str = None,
    cancion: str = None,
    album: str = None,
    rareza: str = None,
    imagen_url: str = None,
    power: int = None,
    year: int = None,
    emoji: str = None
):

    if not is_bot_admin(interaction) and interaction.user.id not in CARD_EDITORS:
        await interaction.response.send_message("❌ No tienes permiso para usar este comando.", ephemeral=True)
        return

    carta_id = carta_id.strip().lower().replace(" ", "_")
    card = next((c for c in CARDS if c["id"] == carta_id), None)
    es_nueva = card is None

    if es_nueva:
        # Crear carta nueva — todos los campos son obligatorios
        campos_faltantes = []
        if not artista:   campos_faltantes.append("artista")
        if not cancion:   campos_faltantes.append("cancion")
        if not album:     campos_faltantes.append("album")
        if not rareza:    campos_faltantes.append("rareza")
        if not power:     campos_faltantes.append("power")
        if not year:      campos_faltantes.append("year")
        if campos_faltantes:
            await interaction.response.send_message(
                f"❌ Para crear una carta nueva necesitas todos los campos.\nFaltan: **{', '.join(campos_faltantes)}**",
                ephemeral=True
            )
            return

        card = {
            "id": carta_id,
            "artist": artista,
            "song": cancion,
            "year": year,
            "rarity": rareza,
            "description": album,
            "emoji": emoji or "🎵",
            "power": max(1, min(100, power)),
            "image": imagen_url or ""
        }
        CARDS.append(card)
        # Guardar carta nueva en JSON para persistir al reiniciar
        overrides = load_card_overrides()
        overrides[carta_id] = card
        save_card_overrides(overrides)
        accion = "✨ Carta **creada**"
        color = 0x27ae60
    else:
        # Modificar carta existente — solo actualiza los campos enviados
        cambios = []
        if artista:
            cambios.append(f"Artista: `{card['artist']}` → `{artista}`")
            card["artist"] = artista
        if cancion:
            cambios.append(f"Canción: `{card['song']}` → `{cancion}`")
            card["song"] = cancion
        if album:
            cambios.append(f"Álbum: `{card['description']}` → `{album}`")
            card["description"] = album
        if rareza:
            cambios.append(f"Rareza: `{card['rarity']}` → `{rareza}`")
            card["rarity"] = rareza
        if imagen_url:
            cambios.append(f"Imagen actualizada")
            card["image"] = imagen_url
        if power:
            cambios.append(f"Power: `{card['power']}` → `{power}`")
            card["power"] = max(1, min(100, power))
        if year:
            cambios.append(f"Año: `{card['year']}` → `{year}`")
            card["year"] = year
        if emoji:
            cambios.append(f"Emoji: `{card['emoji']}` → `{emoji}`")
            card["emoji"] = emoji
        if not cambios:
            await interaction.response.send_message("⚠️ No enviaste ningún campo para modificar.", ephemeral=True)
            return
        # Guardar cambios en JSON para persistir al reiniciar
        overrides = load_card_overrides()
        if carta_id not in overrides:
            overrides[carta_id] = {}
        overrides[carta_id].update({k: card[k] for k in ["artist","song","year","rarity","description","emoji","power","image"]})
        save_card_overrides(overrides)
        accion = "✏️ Carta **modificada**"
        color = 0x3498db

    rarity_cfg = RARITY_CONFIG[card["rarity"]]
    embed = discord.Embed(
        title=f"🛠️ {accion}",
        color=color
    )
    embed.add_field(name="ID",      value=f"`{card['id']}`",          inline=True)
    embed.add_field(name="Artista", value=card["artist"],              inline=True)
    embed.add_field(name="Canción", value=card["song"],                inline=True)
    embed.add_field(name="Álbum",   value=card["description"],         inline=True)
    embed.add_field(name="Rareza",  value=f"{rarity_cfg['emoji']} {card['rarity'].upper()}", inline=True)
    embed.add_field(name="Power",   value=f"⚡ {card['power']}/100",   inline=True)
    embed.add_field(name="Año",     value=str(card["year"]),           inline=True)
    embed.add_field(name="Emoji",   value=card["emoji"],               inline=True)
    if not es_nueva and cambios:
        embed.add_field(name="Cambios", value="\n".join(cambios), inline=False)
    if card.get("image"):
        embed.set_image(url=card["image"])
    embed.set_footer(text=f"Por: {interaction.user.display_name} • Total cartas: {len(CARDS)}")
    await send_log(
        titulo=f"🛠️ [ADMIN] Carta {'creada' if es_nueva else 'editada'}",
        descripcion=f"{interaction.user.mention} {'creó' if es_nueva else 'editó'} la carta `{carta_id}` — **{card['artist']}** — {card['song']}.",
        color=color,
        campos=[("🆔 ID", f"`{carta_id}`", True), ("⚡ Rareza", card["rarity"].upper(), True)],
        user_id=interaction.user.id, user_name=str(interaction.user),
        guild_id=interaction.guild.id if interaction.guild else None, guild_name=interaction.guild.name if interaction.guild else 'DM',
    )
    await interaction.response.send_message(embed=embed, ephemeral=True)

@editar_carta.autocomplete("carta_id")
async def editar_carta_autocomplete(interaction: discord.Interaction, current: str):
    resultados = []
    seen = set()
    for c in CARDS:
        if current.lower() in c["id"].lower() or current.lower() in c["song"].lower() or current.lower() in c["artist"].lower():
            if c["id"] not in seen:
                seen.add(c["id"])
                label = f"{RARITY_CONFIG[c['rarity']]['emoji']} {c['artist']} — {c['song']} [{c['id']}]"
                resultados.append(app_commands.Choice(name=label[:100], value=c["id"]))
        if len(resultados) >= 25:
            break
    return resultados

# ─── SISTEMA DE PRÉSTAMOS ─────────────────────────────────────────────────────
#
# Reglas:
# • Máximo 25,000 monedas por préstamo
# • Solo un préstamo activo a la vez
# • Pago mínimo: 100 si el préstamo fue < 5000 | 1000 si fue >= 5000
# • Si no paga el mínimo en 1 hora → se incrementa la deuda (100 o 1000 según caso)
# • Pagos automáticos: se descuentan directo de las monedas del usuario
# ─────────────────────────────────────────────────────────────────────────────

LOAN_MAX = 25_000
LOAN_SMALL_THRESHOLD = 5_000   # préstamos < 5000
LOAN_SMALL_MIN_PAYMENT = 100
LOAN_BIG_MIN_PAYMENT = 1_000
LOAN_SMALL_PENALTY = 100
LOAN_BIG_PENALTY = 1_000
LOAN_PAYMENT_WINDOW_SECONDS = 3600  # 1 hora

# Task en segundo plano que revisa penalizaciones cada minuto
async def _loan_penalty_loop():
    await bot.wait_until_ready()
    while not bot.is_closed():
        await asyncio.sleep(60)
        try:
            data = load_data()
            changed = False
            now = datetime.now(timezone.utc)
            for uid, player in data.items():
                loan = player.get("loan")
                if not loan or loan.get("paid_off"):
                    continue
                last_payment_str = loan.get("last_payment")
                if not last_payment_str:
                    continue
                last_payment = _parse_dt(last_payment_str)
                elapsed = (now - last_payment).total_seconds()
                if elapsed >= LOAN_PAYMENT_WINDOW_SECONDS:
                    # Determinar penalización según monto original del préstamo
                    original = loan.get("original_amount", loan["amount"])
                    penalty = LOAN_BIG_PENALTY if original >= LOAN_SMALL_THRESHOLD else LOAN_SMALL_PENALTY
                    loan["amount"] += penalty
                    loan["last_payment"] = now.isoformat()  # reinicia ventana
                    changed = True
                    # Intentar notificar al usuario (DM o log)
                    try:
                        user = await bot.fetch_user(int(uid))
                        await user.send(
                            f"⚠️ **Aviso del Banco** — No realizaste el pago mínimo a tiempo.\n"
                            f"Se han añadido **+{penalty:,} 🪙** a tu deuda.\n"
                            f"Deuda actual: **{loan['amount']:,} 🪙**\n"
                            f"Usa `/pagar_prestamo` para pagar."
                        )
                    except Exception:
                        pass
            if changed:
                save_data(data)
        except Exception as e:
            print(f"[loan_penalty_loop] Error: {e}")

@bot.event
async def on_ready_loan():
    pass  # El loop se inicia en on_ready si no se ha iniciado ya

# Registramos el loop de penalización al on_ready del bot
_loan_loop_started = False

_original_on_ready = bot.event.__self__ if hasattr(bot.event, '__self__') else None

@bot.listen("on_ready")
async def start_loan_loop():
    global _loan_loop_started
    if not _loan_loop_started:
        _loan_loop_started = True
        bot.loop.create_task(_loan_penalty_loop())
        bot.loop.create_task(_reset_ventas_loop())

# ─── RESET VENTAS DIARIAS (12am hora México, UTC-6) ──────────────────────────

async def _reset_ventas_loop():
    """Loop que resetea ventas diarias de todos los jugadores a las 12am hora México (UTC-6)."""
    await bot.wait_until_ready()
    while not bot.is_closed():
        try:
            # Hora actual en UTC
            now_utc = datetime.now(timezone.utc)
            # Hora México = UTC-6
            now_mx = now_utc - timedelta(hours=6)
            # Próxima medianoche México
            next_midnight_mx = (now_mx + timedelta(days=1)).replace(hour=0, minute=0, second=0, microsecond=0)
            # Convertir de vuelta a UTC para calcular el delay
            next_midnight_utc = next_midnight_mx + timedelta(hours=6)
            seconds_until = (next_midnight_utc - now_utc).total_seconds()
            print(f"[reset_ventas] Próximo reset en {int(seconds_until//3600)}h {int((seconds_until%3600)//60)}m")
            await asyncio.sleep(seconds_until)
            # Ejecutar reset
            data = load_data()
            count = 0
            for uid, player in data.items():
                if "ventas_diarias" in player:
                    player["ventas_diarias"] = {"fecha": "", "cantidad": 0}
                    count += 1
            save_data(data)
            print(f"[reset_ventas] ✅ Ventas diarias reseteadas para {count} jugadores (12am México)")
        except Exception as e:
            print(f"[reset_ventas] Error: {e}")
            await asyncio.sleep(60)

