@bot.tree.command(name="agregar_carta_evento", description="[Admin] Activa una carta EVENTO por 7 días (máx 3 activas) 💎")
@app_commands.describe(carta_id="ID de la carta con rareza 'evento' a activar")
async def agregar_carta_evento(interaction: discord.Interaction, carta_id: str):
    if not is_bot_admin(interaction):
        await interaction.response.send_message("❌ Solo los admins del bot pueden usar este comando.", ephemeral=True)
        return

    carta_id = carta_id.strip().lower()
    card = next((c for c in CARDS if c["id"] == carta_id), None)

    if not card:
        await interaction.response.send_message(f"❌ Carta `{carta_id}` no existe.", ephemeral=True)
        return
    if card["rarity"] != "evento":
        await interaction.response.send_message(f"❌ La carta `{carta_id}` no tiene rareza **evento**. Cámbiala con `/editar_carta` primero.", ephemeral=True)
        return

    purgar_eventos_expirados()
    vigentes = get_evento_cards_vigentes()

    if carta_id in vigentes:
        entry = vigentes[carta_id]
        inicio = _parse_dt(entry["inicio"])
        expira = inicio + timedelta(days=7)
        restante = expira - datetime.now(timezone.utc)
        dias = restante.days
        horas = restante.seconds // 3600
        copias_restantes = EVENTO_MAX_COPIAS - entry.get("copias", 0)
        await interaction.response.send_message(
            f"⚠️ La carta **{card['song']}** ya está activa.\nExpira en **{dias}d {horas}h** · **{copias_restantes}** copias restantes.",
            ephemeral=True
        )
        return

    if len(vigentes) >= 3:
        nombres = []
        for cid in vigentes:
            c = next((x for x in CARDS if x["id"] == cid), None)
            nombres.append(f"`{cid}` — {c['song'] if c else '?'}")
        await interaction.response.send_message(
            f"❌ Ya hay **3 cartas evento activas** (máximo permitido).\n"
            f"Espera a que expire alguna o usa `/cartas_evento` para ver el estado.\n\n"
            + "\n".join(nombres),
            ephemeral=True
        )
        return

    # Registrar la carta
    registro = load_evento_cards()
    registro[carta_id] = {"inicio": datetime.now(timezone.utc).isoformat(), "copias": 0}
    await send_log(
        titulo="💎 [ADMIN] Carta evento activada",
        descripcion=f"{interaction.user.mention} activó la carta evento **{card['artist']}** — {card['song']} por 7 días.",
        color=0x9b59b6,
        campos=[("🎵 Carta", f"{card['artist']} — {card['song']}", True)],
        user_id=interaction.user.id, user_name=str(interaction.user),
        guild_id=interaction.guild.id if interaction.guild else None, guild_name=interaction.guild.name if interaction.guild else 'DM',
    )
    save_evento_cards(registro)

    expira = datetime.now(timezone.utc) + timedelta(days=7)
    embed = discord.Embed(
        title="💎 Carta EVENTO Activada",
        description=f"**{card['artist']} — {card['song']}** estará disponible durante el **Admin Abuse** por los próximos **7 días**.",
        color=0x00cfff
    )
    embed.add_field(name="ID", value=f"`{carta_id}`", inline=True)
    embed.add_field(name="Slots usados", value=f"**{len(vigentes)+1}/3**", inline=True)
    embed.add_field(name="Copias disponibles", value=f"**{EVENTO_MAX_COPIAS}** copias en total", inline=True)
    embed.add_field(name="Expira", value=f"<t:{int(expira.timestamp())}:R>", inline=True)
    if card.get("image"):
        embed.set_image(url=card["image"])
    embed.set_footer(text=f"Activada por {interaction.user.display_name}")
    await interaction.response.send_message(embed=embed)

