@bot.tree.command(name="buscar_carta", description="Busca quién tiene una carta específica en el servidor 🔍")
@app_commands.describe(carta_id="ID o nombre de la carta a buscar")
async def buscar_carta(interaction: discord.Interaction, carta_id: str):
    if is_channel_blocked(interaction):
        await interaction.response.send_message("🚫 El bot está desactivado en este canal.", ephemeral=True)
        return

    await interaction.response.defer()

    # Buscar la carta por ID o por nombre parcial
    carta_id = carta_id.strip().lower()
    card = next((c for c in CARDS if c["id"] == carta_id), None)
    if not card:
        # Intentar búsqueda por nombre de canción
        coincidencias = [c for c in CARDS if carta_id in c["song"].lower() or carta_id in c["artist"].lower()]
        if len(coincidencias) == 1:
            card = coincidencias[0]
        elif len(coincidencias) > 1:
            lista = "\n".join(f"`{c['id']}` — {c['artist']} · {c['song']}" for c in coincidencias[:10])
            await interaction.followup.send(
                f"🔍 Encontré **{len(coincidencias)}** cartas que coinciden. Usa el ID exacto:\n{lista}",
                ephemeral=True
            )
            return
        else:
            await interaction.followup.send(f"❌ No encontré ninguna carta con `{carta_id}`.", ephemeral=True)
            return

    data = load_data()
    rarity_cfg = RARITY_CONFIG[card["rarity"]]
    duenos = []

    for uid, player in data.items():
        if isinstance(player, dict) and card["id"] in player.get("cards", []):
            nombre = player.get("username") or f"<@{uid}>"
            cantidad = player["cards"].count(card["id"])
            duenos.append((uid, nombre, cantidad))

    embed = discord.Embed(
        title=f"🔍 {rarity_cfg['emoji']} {card['artist']} — {card['song']}",
        color=rarity_cfg["color"]
    )
    embed.add_field(name="Rareza", value=f"{rarity_cfg['emoji']} {card['rarity'].upper()}", inline=True)
    embed.add_field(name="ID", value=f"`{card['id']}`", inline=True)
    embed.add_field(name="Power", value=f"⚡ {card['power']}/100", inline=True)

    if not duenos:
        embed.description = "❌ **Nadie tiene esta carta** en el servidor todavía."
    else:
        embed.description = f"**{len(duenos)} usuario(s)** tienen esta carta:\n\u200b"
        for uid, nombre, cantidad in duenos[:20]:
            cant_txt = f" ×{cantidad}" if cantidad > 1 else ""
            embed.add_field(name=f"👤 {nombre}{cant_txt}", value=f"<@{uid}>", inline=True)
        if len(duenos) > 20:
            embed.set_footer(text=f"Mostrando 20 de {len(duenos)} usuarios")

    if card.get("image"):
        embed.set_thumbnail(url=card["image"])
    await interaction.followup.send(embed=embed)

@buscar_carta.autocomplete("carta_id")
async def buscar_carta_autocomplete(interaction: discord.Interaction, current: str):
    resultados = []
    seen = set()
    for c in CARDS:
        if current.lower() in c["id"].lower() or current.lower() in c["song"].lower() or current.lower() in c["artist"].lower():
            if c["id"] not in seen:
                seen.add(c["id"])
                label = f"{RARITY_CONFIG[c['rarity']]['emoji']} {c['artist']} — {c['song']} [{c['id']}]"
                resultados.append(app_commands.Choice(name=label[:100], value=c["id"]))
        if len(resultados) >= 25:
            break
    return resultados

# ─── COMANDO: /prestamo ───────────────────────────────────────────────────────

@bot.tree.command(name="prestamo", description="Pide un préstamo de monedas al banco 🏦")
@app_commands.describe(cantidad="Cantidad de monedas a pedir (máximo 25,000)")
async def prestamo(interaction: discord.Interaction, cantidad: int):
    if is_channel_blocked(interaction):
        await interaction.response.send_message("❌ Este comando está bloqueado en este canal.", ephemeral=True)
        return

    if cantidad <= 0:
        await interaction.response.send_message("❌ La cantidad debe ser mayor a 0.", ephemeral=True)
        return

    if cantidad > LOAN_MAX:
        await interaction.response.send_message(
            f"❌ El máximo de préstamo es **{LOAN_MAX:,} 🪙**.", ephemeral=True
        )
        return

    data = load_data()
    player = get_player(data, interaction.user.id)

    # Verificar nivel mínimo para préstamo
    nivel_actual = get_level(player)
    if nivel_actual["level"] < 6:
        siguiente = None
        for lvl in LEVELS:
            if lvl["level"] == 6:
                siguiente = lvl
                break
        drops_faltan = siguiente["min_drops"] - player.get("total_drops", 0)
        await interaction.response.send_message(
            f"❌ Necesitas ser al menos nivel **6 — Underground Fan 🌑** para pedir préstamos.\n"
            f"Actualmente eres **{nivel_actual['emoji']} {nivel_actual['name']}** (nivel {nivel_actual['level']}).\n"
            f"Te faltan **{drops_faltan}** drops para subir.",
            ephemeral=True
        )
        return

    # Verificar préstamo activo
    existing_loan = player.get("loan")
    if existing_loan and not existing_loan.get("paid_off", False):
        deuda = existing_loan["amount"]
        original = existing_loan.get("original_amount", deuda)
        min_pago = LOAN_BIG_MIN_PAYMENT if original >= LOAN_SMALL_THRESHOLD else LOAN_SMALL_MIN_PAYMENT
        await interaction.response.send_message(
            f"❌ Ya tienes un préstamo activo de **{deuda:,} 🪙**.\n"
            f"Pago mínimo: **{min_pago:,} 🪙** cada hora.\n"
            f"Usa `/pagar_prestamo` para abonar a tu deuda.",
            ephemeral=True
        )
        return

    # Otorgar el préstamo
    player["coins"] = player.get("coins", 100) + cantidad
    min_pago = LOAN_BIG_MIN_PAYMENT if cantidad >= LOAN_SMALL_THRESHOLD else LOAN_SMALL_MIN_PAYMENT
    penalty = LOAN_BIG_PENALTY if cantidad >= LOAN_SMALL_THRESHOLD else LOAN_SMALL_PENALTY

    player["loan"] = {
        "amount": cantidad,
        "original_amount": cantidad,
        "paid_off": False,
        "last_payment": datetime.now(timezone.utc).isoformat(),
    }
    save_data(data)

    embed = discord.Embed(
        title="🏦 Préstamo Aprobado",
        color=0x2ecc71
    )
    embed.add_field(name="💰 Préstamo",        value=f"**{cantidad:,} 🪙**",   inline=True)
    embed.add_field(name="🪙 Balance actual",  value=f"**{player['coins']:,} 🪙**", inline=True)
    embed.add_field(
        name="📋 Condiciones",
        value=(
            f"• Pago mínimo: **{min_pago:,} 🪙** cada hora\n"
            f"• Si no pagas a tiempo: +**{penalty:,} 🪙** de penalización\n"
            f"• Un solo préstamo a la vez\n"
            f"• Usa `/pagar_prestamo` para abonar"
        ),
        inline=False
    )
    embed.set_footer(text=f"Préstamo solicitado por {interaction.user.display_name}")
    await interaction.response.send_message(embed=embed)
    await send_log(
        titulo="🏦 Préstamo solicitado",
        descripcion=f"{interaction.user.mention} (`{interaction.user.name}` · ID: `{interaction.user.id}`) pidió un préstamo.",
        color=0x2ecc71,
        campos=[
            ("💰 Cantidad", f"**{cantidad:,} 🪙**", True),
            ("🪙 Saldo tras préstamo", f"**{player['coins']:,} 🪙**", True),
        ],
        guild_id=interaction.guild.id if interaction.guild else None,
        guild_name=interaction.guild.name if interaction.guild else "DM",
    )

# ─── COMANDO: /pagar_prestamo ────────────────────────────────────────────────

@bot.tree.command(name="pagar_prestamo", description="Paga parte o todo tu préstamo activo 💳")
@app_commands.describe(cantidad="Cantidad de monedas a pagar (deja en blanco para pagar todo)")
async def pagar_prestamo(interaction: discord.Interaction, cantidad: int = None):
    if is_channel_blocked(interaction):
        await interaction.response.send_message("❌ Este comando está bloqueado en este canal.", ephemeral=True)
        return

    data = load_data()
    player = get_player(data, interaction.user.id)

    loan = player.get("loan")
    if not loan or loan.get("paid_off", False):
        await interaction.response.send_message("✅ No tienes ningún préstamo activo.", ephemeral=True)
        return

    deuda_actual = loan["amount"]
    coins = player.get("coins", 100)
    original = loan.get("original_amount", deuda_actual)
    min_pago = LOAN_BIG_MIN_PAYMENT if original >= LOAN_SMALL_THRESHOLD else LOAN_SMALL_MIN_PAYMENT

    # Si no especifica cantidad, pagar todo lo que pueda (hasta la deuda)
    if cantidad is None:
        cantidad = min(deuda_actual, coins)

    if cantidad <= 0:
        await interaction.response.send_message("❌ La cantidad a pagar debe ser mayor a 0.", ephemeral=True)
        return

    if coins < cantidad:
        await interaction.response.send_message(
            f"❌ No tienes suficientes monedas.\n"
            f"Tienes: **{coins:,} 🪙** | Intentas pagar: **{cantidad:,} 🪙**",
            ephemeral=True
        )
        return

    if cantidad > deuda_actual:
        cantidad = deuda_actual  # No pagar de más

    # Aplicar pago
    player["coins"] = coins - cantidad
    loan["amount"] -= cantidad
    loan["last_payment"] = datetime.now(timezone.utc).isoformat()

    pagado_totalmente = loan["amount"] <= 0

    if pagado_totalmente:
        loan["amount"] = 0
        loan["paid_off"] = True
        save_data(data)
        embed = discord.Embed(
            title="✅ Préstamo Pagado Completamente",
            description=f"¡Felicitaciones! Has liquidado tu deuda.\nBalance actual: **{player['coins']:,} 🪙**",
            color=0x27ae60
        )
        await interaction.response.send_message(embed=embed)
        await send_log(
            titulo="✅ Préstamo liquidado",
            descripcion=f"{interaction.user.mention} (`{interaction.user.name}` · ID: `{interaction.user.id}`) pagó su préstamo **completamente**.",
            color=0x27ae60,
            campos=[
                ("💸 Pagado ahora", f"**{cantidad:,} 🪙**", True),
                ("💰 Original", f"**{original:,} 🪙**", True),
                ("🪙 Saldo restante", f"**{player['coins']:,} 🪙**", True),
            ],
            guild_id=interaction.guild.id if interaction.guild else None,
            guild_name=interaction.guild.name if interaction.guild else "DM",
        )
    else:
        save_data(data)
        embed = discord.Embed(
            title="💳 Pago Realizado",
            color=0x3498db
        )
        embed.add_field(name="💸 Pagado",          value=f"**{cantidad:,} 🪙**",          inline=True)
        embed.add_field(name="📉 Deuda restante",  value=f"**{loan['amount']:,} 🪙**",     inline=True)
        embed.add_field(name="🪙 Balance actual",  value=f"**{player['coins']:,} 🪙**",    inline=True)
        embed.add_field(
            name="⏰ Próximo pago mínimo",
            value=f"Tienes 1 hora para pagar al menos **{min_pago:,} 🪙** o se añadirá una penalización.",
            inline=False
        )
        embed.set_footer(text=f"Pago realizado por {interaction.user.display_name}")
        await interaction.response.send_message(embed=embed)
        await send_log(
            titulo="💳 Abono a préstamo",
            descripcion=f"{interaction.user.mention} (`{interaction.user.name}` · ID: `{interaction.user.id}`) hizo un abono.",
            color=0x3498db,
            campos=[
                ("💸 Pagado", f"**{cantidad:,} 🪙**", True),
                ("📉 Deuda restante", f"**{loan['amount']:,} 🪙**", True),
                ("🪙 Saldo", f"**{player['coins']:,} 🪙**", True),
            ],
            guild_id=interaction.guild.id if interaction.guild else None,
            guild_name=interaction.guild.name if interaction.guild else "DM",
        )

