@bot.tree.command(name="mi_prestamo", description="Consulta el estado de tu préstamo activo 📋")
async def mi_prestamo(interaction: discord.Interaction):
    if is_channel_blocked(interaction):
        await interaction.response.send_message("❌ Este comando está bloqueado en este canal.", ephemeral=True)
        return

    data = load_data()
    player = get_player(data, interaction.user.id)
    loan = player.get("loan")

    if not loan or loan.get("paid_off", False):
        await interaction.response.send_message("✅ No tienes ningún préstamo activo.", ephemeral=True)
        return

    deuda = loan["amount"]
    original = loan.get("original_amount", deuda)
    min_pago = LOAN_BIG_MIN_PAYMENT if original >= LOAN_SMALL_THRESHOLD else LOAN_SMALL_MIN_PAYMENT
    penalty = LOAN_BIG_PENALTY if original >= LOAN_SMALL_THRESHOLD else LOAN_SMALL_PENALTY
    last_payment = _parse_dt(loan["last_payment"])
    now = datetime.now(timezone.utc)
    elapsed = (now - last_payment).total_seconds()
    tiempo_restante = max(0, LOAN_PAYMENT_WINDOW_SECONDS - elapsed)
    minutos = int(tiempo_restante // 60)
    segundos = int(tiempo_restante % 60)
    coins = player.get("coins", 100)

    embed = discord.Embed(
        title="🏦 Estado de tu Préstamo",
        color=0xe74c3c if elapsed >= LOAN_PAYMENT_WINDOW_SECONDS * 0.8 else 0xf39c12
    )
    embed.add_field(name="💰 Préstamo original",  value=f"**{original:,} 🪙**",    inline=True)
    embed.add_field(name="📉 Deuda actual",        value=f"**{deuda:,} 🪙**",       inline=True)
    embed.add_field(name="🪙 Tu balance",          value=f"**{coins:,} 🪙**",       inline=True)
    embed.add_field(name="💳 Pago mínimo",         value=f"**{min_pago:,} 🪙**",    inline=True)
    embed.add_field(name="⚠️ Penalización",        value=f"**+{penalty:,} 🪙**",    inline=True)
    embed.add_field(
        name="⏰ Tiempo para pagar",
        value=f"**{minutos}m {segundos}s** restantes" if tiempo_restante > 0 else "⚠️ ¡Ya deberías haber pagado!",
        inline=True
    )
    embed.set_footer(text=f"Usa /pagar_prestamo para abonar a tu deuda")
    await interaction.response.send_message(embed=embed, ephemeral=True)

# ─── COMANDO: /reset_total ───────────────────────────────────────────────────

class ConfirmResetView(discord.ui.View):
    """Vista con botones de confirmación para el reset total."""

    def __init__(self, author_id: int):
        super().__init__(timeout=30)
        self.author_id = author_id

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author_id:
            await interaction.response.send_message(
                "❌ Solo quien ejecutó el comando puede confirmar esto.", ephemeral=True
            )
            return False
        return True

    @discord.ui.button(label="💀 SÍ, BORRAR TODO", style=discord.ButtonStyle.danger)
    async def confirmar(self, interaction: discord.Interaction, button: discord.ui.Button):
        # Borrar solo el progreso de jugadores y apuestas pendientes
        archivos_borrados = []
        for filepath in [DATA_FILE, PENDING_APUESTAS_FILE]:
            if os.path.exists(filepath):
                os.remove(filepath)
                archivos_borrados.append(os.path.basename(filepath))

        # Desactivar modos especiales activos
        global suertex3_active, suertex6_active, suertex10_active, admin_abuse_active
        suertex3_active = False
        suertex6_active = False
        suertex10_active = False
        admin_abuse_active = False

        self.clear_items()
        await interaction.response.edit_message(
            embed=discord.Embed(
                title="💀 RESET TOTAL EJECUTADO",
                description=(
                    "**Todos los datos han sido eliminados.**\n\n"
                    f"🗑️ Archivos borrados: `{'`, `'.join(archivos_borrados) if archivos_borrados else 'ninguno (ya estaban vacíos)'}`\n\n"
                    "Los jugadores ahora empiezan desde 0.\n"
                    "Modos especiales desactivados."
                ),
                color=0xe74c3c
            ),
            view=self
        )

    @discord.ui.button(label="Cancelar", style=discord.ButtonStyle.secondary)
    async def cancelar(self, interaction: discord.Interaction, button: discord.ui.Button):
        self.clear_items()
        await interaction.response.edit_message(
            embed=discord.Embed(
                title="✅ Reset cancelado",
                description="No se ha borrado nada.",
                color=0x2ecc71
            ),
            view=self
        )

    async def on_timeout(self):
        # Si expira el tiempo sin respuesta, deshabilitar los botones
        for item in self.children:
            item.disabled = True

