# ─── SISTEMA DE APUESTAS NBA2K ───────────────────────────────────────────────
#
# Flujo:
#  1. Admin: /sesion_nba [nombre]  →  embed de control con botones
#  2. Admin pulsa "➕ Nuevo partido" → modal para escribir los dos equipos
#  3. Embed se actualiza con botones de apuesta para todos los usuarios
#  4. Usuarios pulsan "💰 Apostar a X" → modal: monedas o carta
#  5. Admin pulsa "🔒 Cerrar apuestas" → nadie más puede apostar
#  6. Admin pulsa "🏆 Declarar ganador" → botones con los dos equipos
#  7. Se reparte el pozo proporcional; cartas se rifan weighted
#  8. Admin pulsa "➕ Nuevo partido" para el siguiente o "🔚 Cerrar sesión"
#
# Estado de una sesión (dict en memoria, clave = message.id del embed de control):
#   {
#     "nombre": str,
#     "admin_id": int,
#     "equipos": [str, str] | None,
#     "estado": "esperando" | "abierto" | "cerrado" | "terminado",
#     "apuestas": {
#         str(user_id): {
#             "equipo": str,
#             "monedas": int,
#             "cartas": [card_id, ...]
#         }
#     },
#     "historial": [ {partido, ganador, ganancias_totales}, ... ],
#     "channel_id": int,
#     "control_message_id": int,
#     "apuesta_message_id": int | None,
#   }

LOG_CHANNEL_ID = 1508977651912671312  # Canal de logs
NBA_SESSIONS: dict[int, dict] = {}  # message_id → sesión
NBA_TEAM_OWNERS: dict[str, int] = {}  # equipo → user_id (se carga/guarda en data)
NBA_TEAM_PRICE = 250_000
NBA_OWNER_WIN_REWARD = 15_000
NBA_BET_DURATION = 120  # segundos

def nba_embed_control(sesion: dict) -> discord.Embed:
    """Embed de control de la sesión (solo admins ven los botones de gestión)."""
    estado = sesion["estado"]
    equipos = sesion["equipos"]

    estado_txt = {
        "esperando": "⏳ Esperando partido...",
        "abierto":   "🟢 Apuestas abiertas",
        "cerrado":   "🔴 Apuestas cerradas",
        "terminado": "🏁 Sesión terminada",
    }.get(estado, estado)

    embed = discord.Embed(
        title=f"🏀 Sesión NBA2K — {sesion['nombre']}",
        color=0xe67e22
    )
    embed.add_field(name="Estado", value=estado_txt, inline=True)
    if equipos:
        embed.add_field(name="Partido actual", value=f"**{equipos[0]}** vs **{equipos[1]}**", inline=True)

    # Historial de partidos
    if sesion["historial"]:
        hist_txt = "\n".join(
            f"• {h['partido']} → 🏆 **{h['ganador']}**" for h in sesion["historial"]
        )
        embed.add_field(name="Historial", value=hist_txt, inline=False)

    embed.set_footer(text="Solo admins pueden usar los botones de control.")
    return embed

def nba_embed_apuestas(sesion: dict) -> discord.Embed:
    """Embed público donde los usuarios hacen sus apuestas."""
    equipos = sesion["equipos"]
    apuestas = sesion["apuestas"]
    estado = sesion["estado"]

    total_monedas = sum(a["monedas"] for a in apuestas.values())
    total_cartas = sum(len(a["cartas"]) for a in apuestas.values())

    # Contar por equipo
    def resumen_equipo(equipo):
        jugadores = [a for a in apuestas.values() if a["equipo"] == equipo]
        monedas = sum(a["monedas"] for a in jugadores)
        cartas = sum(len(a["cartas"]) for a in jugadores)
        txt = f"👥 {len(jugadores)} jugadores\n🪙 {monedas:,} monedas"
        if cartas:
            txt += f"\n🃏 {cartas} cartas"
        return txt

    embed = discord.Embed(
        title=f"🏀 {equipos[0]} vs {equipos[1]}",
        description="¡Haz tu apuesta! Pulsa el botón de tu equipo.",
        color=0x3498db if estado == "abierto" else 0x95a5a6
    )
    embed.add_field(name=f"🔵 {equipos[0]}", value=resumen_equipo(equipos[0]), inline=True)
    embed.add_field(name=f"🔴 {equipos[1]}", value=resumen_equipo(equipos[1]), inline=True)
    embed.add_field(
        name="💰 Pozo total",
        value=f"🪙 {total_monedas:,} monedas" + (f" + 🃏 {total_cartas} cartas" if total_cartas else ""),
        inline=False
    )

    if estado == "cerrado":
        embed.set_footer(text="🔒 Apuestas cerradas — esperando resultado...")
    elif estado == "abierto":
        embed.set_footer(text="✅ Apuestas abiertas")

    return embed

NBA_WIN_MULTIPLIER = 1.5  # Ganadores reciben su apuesta x1.5 (50% de ganancia)

async def resolver_partido(sesion: dict, ganador: str, interaction: discord.Interaction):
    """
    Nuevo sistema de cuota fija:
    - Ganadores: recuperan su apuesta + 50% extra (x1.5)
    - Perdedores: pierden todo lo apostado
    - Si nadie apostó al ganador: los perdedores pierden igual, el pozo desaparece
    - Cartas de perdedores: se rifan entre ganadores (weighted por monedas). Si no hay
      ganadores, se pierden.
    """
    data = load_data()
    apuestas = sesion["apuestas"]
    equipos = sesion["equipos"]
    perdedor = equipos[1] if ganador == equipos[0] else equipos[0]

    ganadores = {uid: a for uid, a in apuestas.items() if a["equipo"] == ganador}
    perdedores = {uid: a for uid, a in apuestas.items() if a["equipo"] == perdedor}

    # Cartas del pozo (de perdedores)
    cartas_pozo = []
    for a in perdedores.values():
        cartas_pozo.extend(a["cartas"])

    # Quitar cartas a perdedores
    for uid, a in perdedores.items():
        player = get_player(data, uid)
        for cid in a["cartas"]:
            if cid in player["cards"]:
                player["cards"].remove(cid)

    # Pagar a ganadores: apuesta * 1.5
    ganancias: dict[str, dict] = {}
    for uid, a in ganadores.items():
        pago = int(a["monedas"] * NBA_WIN_MULTIPLIER)
        player = get_player(data, uid)
        player["coins"] = player.get("coins", 0) + pago
        ganancias[uid] = {"apostado": a["monedas"], "cobrado": pago, "cartas": []}

    # Rifar cartas entre ganadores (weighted por monedas apostadas)
    if cartas_pozo and ganadores:
        pesos = [ganadores[uid]["monedas"] for uid in ganadores]
        uids_ganadores = list(ganadores.keys())
        for cid in cartas_pozo:
            ganador_carta = random.choices(uids_ganadores, weights=pesos, k=1)[0]
            player = get_player(data, ganador_carta)
            player["cards"].append(cid)
            ganancias[ganador_carta]["cartas"].append(cid)

    # Recompensa al dueño del equipo ganador
    owner_reward_info = None
    data2 = load_data()
    owner_id_str = data2.get("_nba_owners", {}).get(ganador)
    if owner_id_str:
        owner_p = get_player(data2, int(owner_id_str))
        owner_p["coins"] = owner_p.get("coins", 0) + NBA_OWNER_WIN_REWARD
        save_data(data2)
        owner_reward_info = (owner_id_str, NBA_OWNER_WIN_REWARD)
    else:
        save_data(data)

    # ── Embed de resultado ──────────────────────────────────────────────────────
    embed = discord.Embed(
        title=f"🏆 Resultado: **{ganador}** ganó",
        color=0x2ecc71
    )

    if not ganadores and not perdedores:
        embed.description = "Nadie apostó en este partido."
    elif not ganadores:
        # Hubo apostadores pero ninguno acertó
        total_perdido = sum(a["monedas"] for a in perdedores.values())
        embed.description = (
            f"Nadie apostó a **{ganador}**. "
            f"Los {len(perdedores)} apostador(es) al perdedor pierden sus monedas.\n"
            f"🪙 **{total_perdido:,}** monedas desaparecen del juego."
        )
        if cartas_pozo:
            embed.add_field(
                name="🃏 Cartas perdidas",
                value=f"{len(cartas_pozo)} carta(s) apostadas se pierden.",
                inline=False
            )
    else:
        lineas = []
        for uid, g in ganancias.items():
            try:
                user = await interaction.client.fetch_user(int(uid))
                nombre = user.display_name
            except Exception:
                nombre = f"<@{uid}>"
            ganancia_neta = g["cobrado"] - g["apostado"]
            txt = f"• **{nombre}** apostó 🪙 {g['apostado']:,} → cobró 🪙 **{g['cobrado']:,}** (+{ganancia_neta:,})"
            if g["cartas"]:
                txt += f" + 🃏 {len(g['cartas'])} carta(s)"
            lineas.append(txt)
        embed.add_field(name="💰 Ganadores (x1.5)", value="\n".join(lineas), inline=False)

        if perdedores:
            total_perdido = sum(a["monedas"] for a in perdedores.values())
            embed.add_field(
                name="💸 Perdedores",
                value=f"{len(perdedores)} usuario(s) perdieron 🪙 {total_perdido:,} en total.",
                inline=False
            )

    if owner_reward_info:
        oid, reward = owner_reward_info
        try:
            owner_user = await interaction.client.fetch_user(int(oid))
            owner_nombre = owner_user.display_name
        except Exception:
            owner_nombre = f"<@{oid}>"
        embed.add_field(
            name="👑 Dueño del equipo",
            value=f"**{owner_nombre}** recibe 🪙 +{reward:,} por la victoria de **{ganador}**",
            inline=False
        )

    channel = interaction.channel or bot.get_channel(sesion["channel_id"])
    if channel is None:
        channel = await bot.fetch_channel(sesion["channel_id"])
    await channel.send(embed=embed)

    # Guardar en historial
    sesion["historial"].append({
        "partido": f"{equipos[0]} vs {equipos[1]}",
        "ganador": ganador,
    })
    sesion["apuestas"] = {}
    sesion["equipos"] = None
    sesion["estado"] = "esperando"

