async def _auto_cerrar_apuestas(msg_id: int):
    """Cierra apuestas automáticamente tras NBA_BET_DURATION segundos."""
    await asyncio.sleep(NBA_BET_DURATION)
    sesion = NBA_SESSIONS.get(msg_id)
    if not sesion or sesion["estado"] != "abierto":
        return
    sesion["estado"] = "cerrado"
    channel = bot.get_channel(sesion["channel_id"])
    if channel is None:
        try:
            channel = await bot.fetch_channel(sesion["channel_id"])
        except Exception:
            return
    # Editar embed de control
    try:
        ctrl_msg = await channel.fetch_message(msg_id)
        await ctrl_msg.edit(embed=nba_embed_control(sesion), view=NBAControlView(msg_id))
    except Exception:
        pass
    # Editar embed de apuestas
    if sesion.get("apuesta_message_id"):
        try:
            ap_msg = await channel.fetch_message(sesion["apuesta_message_id"])
            await ap_msg.edit(embed=nba_embed_apuestas(sesion), view=None)
        except Exception:
            pass
    await channel.send(f"⏱️ **¡Tiempo!** Las apuestas del partido **{sesion['equipos'][0]}** vs **{sesion['equipos'][1]}** se cerraron automáticamente.")

async def _confirmar_partido(interaction: discord.Interaction, msg_id: int, equipo_a: str, equipo_b: str):
    """Lógica compartida para crear el partido tras elegir equipos."""
    sesion = NBA_SESSIONS.get(msg_id)
    if not sesion:
        await interaction.response.send_message("❌ Sesión no encontrada.", ephemeral=True)
        return

    sesion["equipos"] = [equipo_a, equipo_b]
    sesion["estado"] = "abierto"
    sesion["apuestas"] = {}
    await send_log(
        titulo="🏀 Nuevo partido NBA",
        descripcion=f"{interaction.user.mention} creó el partido **{equipo_a}** vs **{equipo_b}**.",
        color=0x1a73e8,
        campos=[("🏀 Partido", f"{equipo_a} vs {equipo_b}", False)],
        user_id=interaction.user.id, user_name=str(interaction.user),
        guild_id=interaction.guild.id if interaction.guild else None, guild_name=interaction.guild.name if interaction.guild else 'DM',
    )

    channel = interaction.channel or bot.get_channel(sesion["channel_id"])
    if channel is None:
        channel = await bot.fetch_channel(sesion["channel_id"])
    try:
        ctrl_msg = await channel.fetch_message(msg_id)
        await ctrl_msg.edit(embed=nba_embed_control(sesion), view=NBAControlView(msg_id))
    except Exception:
        pass

    view_apuestas = NBAApuestasView(msg_id)
    msg_apuestas = await channel.send(embed=nba_embed_apuestas(sesion), view=view_apuestas)
    sesion["apuesta_message_id"] = msg_apuestas.id

    # Lanzar cierre automático en 2 minutos
    asyncio.create_task(_auto_cerrar_apuestas(msg_id))

    await interaction.response.send_message(
        f"✅ Partido **{equipo_a}** vs **{equipo_b}** creado. ¡Apuestas abiertas por {NBA_BET_DURATION//60} minutos!",
        ephemeral=True
    )

class SelectEquipoB(discord.ui.Select):
    def __init__(self, msg_id: int, equipo_a: str, opciones: list[str], placeholder: str = "Elige el Equipo B..."):
        self.msg_id = msg_id
        self.equipo_a = equipo_a
        options = [discord.SelectOption(label=e) for e in opciones]
        super().__init__(placeholder=placeholder, options=options, min_values=1, max_values=1)

    async def callback(self, interaction: discord.Interaction):
        await _confirmar_partido(interaction, self.msg_id, self.equipo_a, self.values[0])

class ViewEquipoB(discord.ui.View):
    def __init__(self, msg_id: int, equipo_a: str, opciones: list[str]):
        super().__init__(timeout=60)
        filtrados = [e for e in opciones if e != equipo_a]
        mitad = len(filtrados) // 2
        self.add_item(SelectEquipoB(msg_id, equipo_a, filtrados[:mitad], "Equipo B — Equipos 1-14..."))
        self.add_item(SelectEquipoB(msg_id, equipo_a, filtrados[mitad:], "Equipo B — Equipos 15-29..."))

class SelectEquipoA(discord.ui.Select):
    def __init__(self, msg_id: int, opciones: list[str], placeholder: str):
        self.msg_id = msg_id
        self.opciones = opciones
