class ViewEquipoA(discord.ui.View):
    def __init__(self, msg_id: int, opciones: list[str]):
        super().__init__(timeout=60)
        mitad = len(opciones) // 2
        self.add_item(SelectEquipoA(msg_id, opciones[:mitad], "Equipo A — Equipos 1-15..."))
