class NBAControlView(discord.ui.View):
    """Botones de control de la sesión. Solo admins pueden usarlos."""

    def __init__(self, msg_id: int):
        super().__init__(timeout=None)
        self.msg_id = msg_id

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id not in BOT_ADMINS:
            await interaction.response.send_message("❌ Solo los admins pueden controlar la sesión.", ephemeral=True)
            return False
        return True

    @discord.ui.button(label="➕ Nuevo partido", style=discord.ButtonStyle.primary, row=0, custom_id="nba_ctrl_nuevo_partido")
    async def nuevo_partido(self, interaction: discord.Interaction, button: discord.ui.Button):
        sesion = NBA_SESSIONS.get(self.msg_id)
        if not sesion:
            await interaction.response.send_message("❌ Sesión no encontrada.", ephemeral=True)
            return
        if sesion["estado"] == "abierto":
            await interaction.response.send_message("❌ Cierra las apuestas antes de crear un nuevo partido.", ephemeral=True)
            return
        view_a = ViewEquipoA(self.msg_id, NBA_TEAMS)
        await interaction.response.send_message(
            "🏀 Elige el **Equipo A**:",
            view=view_a,
            ephemeral=True
        )

    @discord.ui.button(label="🔒 Cerrar apuestas", style=discord.ButtonStyle.danger, row=0, custom_id="nba_ctrl_cerrar_apuestas")
    async def cerrar_apuestas(self, interaction: discord.Interaction, button: discord.ui.Button):
        await interaction.response.defer(ephemeral=True)

        sesion = NBA_SESSIONS.get(self.msg_id)
        if not sesion or sesion["estado"] != "abierto":
            await interaction.followup.send("❌ No hay apuestas abiertas.", ephemeral=True)
            return
        sesion["estado"] = "cerrado"

        # Actualizar embeds
        await interaction.message.edit(embed=nba_embed_control(sesion), view=self)
        if sesion.get("apuesta_message_id"):
            try:
                msg = await interaction.channel.fetch_message(sesion["apuesta_message_id"])
                await msg.edit(embed=nba_embed_apuestas(sesion), view=NBAApuestasView(self.msg_id))
            except Exception:
                pass

        await interaction.followup.send("🔒 Apuestas cerradas.", ephemeral=True)

    @discord.ui.button(label="🏆 Declarar ganador", style=discord.ButtonStyle.success, row=1, custom_id="nba_ctrl_declarar_ganador")
    async def declarar_ganador(self, interaction: discord.Interaction, button: discord.ui.Button):
        sesion = NBA_SESSIONS.get(self.msg_id)
        if not sesion or sesion["estado"] != "cerrado":
            await interaction.response.send_message("❌ Primero cierra las apuestas.", ephemeral=True)
            return
        if not sesion["equipos"]:
            await interaction.response.send_message("❌ No hay partido activo.", ephemeral=True)
            return
        # Mostrar botones con los dos equipos
        await interaction.response.send_message(
            f"¿Quién ganó?",
            view=NBAGanadorView(self.msg_id, sesion["equipos"], interaction.message.id),
            ephemeral=True
        )

    @discord.ui.button(label="🔚 Cerrar sesión", style=discord.ButtonStyle.secondary, row=1, custom_id="nba_ctrl_cerrar_sesion")
    async def cerrar_sesion(self, interaction: discord.Interaction, button: discord.ui.Button):
        await interaction.response.defer(ephemeral=True)

        sesion = NBA_SESSIONS.get(self.msg_id)
        if not sesion:
            await interaction.followup.send("❌ Sesión no encontrada.", ephemeral=True)
            return

        sesion["estado"] = "terminado"

        # Ranking final
        data = load_data()
        embed = discord.Embed(
            title=f"🏁 Sesión **{sesion['nombre']}** terminada",
            color=0x9b59b6
        )
        partidos_txt = "\n".join(
            f"• {h['partido']} → 🏆 {h['ganador']}" for h in sesion["historial"]
        ) or "Ningún partido completado."
        embed.add_field(name="📋 Partidos", value=partidos_txt, inline=False)
        embed.set_footer(text=f"Total de partidos: {len(sesion['historial'])}")

        channel = interaction.channel or bot.get_channel(sesion["channel_id"])
        if channel is None:
            channel = await bot.fetch_channel(sesion["channel_id"])
        await channel.send(embed=embed)
        await interaction.message.edit(embed=nba_embed_control(sesion), view=None)
        NBA_SESSIONS.pop(self.msg_id, None)
        await interaction.followup.send("✅ Sesión cerrada.", ephemeral=True)

class NBAApuestasView(discord.ui.View):
    """Botones de apuesta para los usuarios."""

    def __init__(self, msg_id: int):
        super().__init__(timeout=None)
        self.msg_id = msg_id
        sesion = NBA_SESSIONS.get(msg_id)
        if sesion and sesion["equipos"]:
            self.add_item(NBABotonApostar(msg_id, sesion["equipos"][0], discord.ButtonStyle.primary))
            self.add_item(NBABotonApostar(msg_id, sesion["equipos"][1], discord.ButtonStyle.danger))

class NBABotonApostar(discord.ui.Button):
    def __init__(self, msg_id: int, equipo: str, style: discord.ButtonStyle):
        safe_id = equipo.replace(" ", "_").lower()[:50]
        super().__init__(label=f"💰 Apostar a {equipo}", style=style, custom_id=f"nba_apostar_{safe_id}")
        self.msg_id = msg_id
        self.equipo = equipo

    async def callback(self, interaction: discord.Interaction):
        sesion = NBA_SESSIONS.get(self.msg_id)
        if not sesion or sesion["estado"] != "abierto":
            await interaction.response.send_message("❌ Las apuestas están cerradas.", ephemeral=True)
            return
        # Bloquear al dueño de cualquiera de los dos equipos
        data = load_data()
        owners = data.get("_nba_owners", {})
        uid_str = str(interaction.user.id)
        equipos_en_partido = sesion.get("equipos", [])
        for eq in equipos_en_partido:
            if owners.get(eq) == uid_str:
                await interaction.response.send_message(
                    f"❌ Eres dueño de **{eq}** y no puedes apostar en este partido.",
                    ephemeral=True
                )
                return
        await interaction.response.send_modal(ModalApostar(self.msg_id, self.equipo))

class NBAGanadorView(discord.ui.View):
    """Botones para que el admin elija el equipo ganador."""

    def __init__(self, msg_id: int, equipos: list[str], ctrl_msg_id: int):
        super().__init__(timeout=60)
        self.msg_id = msg_id
        self.ctrl_msg_id = ctrl_msg_id
        for equipo in equipos:
            self.add_item(NBABotonGanador(msg_id, equipo, ctrl_msg_id))

class NBABotonGanador(discord.ui.Button):
    def __init__(self, msg_id: int, equipo: str, ctrl_msg_id: int):
        safe_id = equipo.replace(" ", "_").lower()[:50]
        super().__init__(label=f"🏆 {equipo}", style=discord.ButtonStyle.success, custom_id=f"nba_ganador_{safe_id}")
        self.msg_id = msg_id
        self.equipo = equipo
        self.ctrl_msg_id = ctrl_msg_id

    async def callback(self, interaction: discord.Interaction):
        if interaction.user.id not in BOT_ADMINS:
            await interaction.response.send_message("❌ Solo admins.", ephemeral=True)
            return

        sesion = NBA_SESSIONS.get(self.msg_id)
        if not sesion:
            await interaction.response.send_message("❌ Sesión no encontrada.", ephemeral=True)
            return

        await interaction.response.defer(ephemeral=True)
        await resolver_partido(sesion, self.equipo, interaction)

        # Actualizar embed de control
        try:
            ctrl_msg = await interaction.channel.fetch_message(self.msg_id)
            await ctrl_msg.edit(embed=nba_embed_control(sesion), view=NBAControlView(self.msg_id))
        except Exception:
            pass

        # Deshabilitar embed de apuestas
        if sesion.get("apuesta_message_id"):
            try:
                msg = await interaction.channel.fetch_message(sesion["apuesta_message_id"])
                await msg.edit(view=None)
            except Exception:
                pass

        await interaction.followup.send(f"✅ Ganador declarado: **{self.equipo}**", ephemeral=True)

# ─── COMANDO: /sesion_nba ────────────────────────────────────────────────────

@bot.tree.command(name="sesion_nba", description="[ADMIN] Abre una sesión de apuestas NBA2K 🏀")
@app_commands.describe(nombre="Nombre de la sesión (ej: 'Noche del viernes')")
async def sesion_nba(interaction: discord.Interaction, nombre: str):
    if not is_bot_admin(interaction):
        await interaction.response.send_message("❌ Solo los admins pueden abrir sesiones.", ephemeral=True)
        return
    if is_channel_blocked(interaction):
        await interaction.response.send_message("❌ Este comando está bloqueado en este canal.", ephemeral=True)
        return

    sesion = {
        "nombre": nombre,
        "admin_id": interaction.user.id,
        "equipos": None,
        "estado": "esperando",
        "apuestas": {},
        "historial": [],
        "channel_id": interaction.channel_id,
        "control_message_id": None,
        "apuesta_message_id": None,
    }

    # Enviar embed de control primero para obtener el message_id
    await interaction.response.send_message(
        embed=discord.Embed(title="🏀 Iniciando sesión...", color=0xe67e22)
    )
    msg = await interaction.original_response()
    sesion["control_message_id"] = msg.id

    NBA_SESSIONS[msg.id] = sesion

    await msg.edit(embed=nba_embed_control(sesion), view=NBAControlView(msg.id))
    await send_log(
        titulo="🏀 Sesión NBA abierta",
        descripcion=f"{interaction.user.mention} abrió la sesión **{nombre}**.",
        color=0xe67e22,
        user_id=interaction.user.id, user_name=str(interaction.user),
        guild_id=interaction.guild.id if interaction.guild else None, guild_name=interaction.guild.name if interaction.guild else 'DM',
    )

