async def autocomplete_equipo(
    interaction: discord.Interaction,
    current: str,
) -> List[app_commands.Choice[str]]:
    data = load_data()
    owners = data.get("_nba_owners", {})
    apodos = data.get("_nba_apodos", {})
    current_lower = current.lower()
    resultados = []
    for t in NBA_TEAMS:
        apodo = apodos.get(t, "")
        display = f"{t} ({apodo})" if apodo else t
        if current_lower in t.lower() or current_lower in apodo.lower():
            resultados.append(app_commands.Choice(name=display[:100], value=t))
    return resultados[:25]

@bot.tree.command(name="apodo_equipo", description="[ADMIN] Asigna o quita el apodo de un equipo NBA 🏷️")
@app_commands.describe(
    equipo="Equipo NBA al que cambiar el apodo",
    apodo="Apodo a asignar (déjalo vacío para quitarlo)"
)
@app_commands.autocomplete(equipo=autocomplete_equipo)
async def apodo_equipo(interaction: discord.Interaction, equipo: str, apodo: str = ""):
    if not is_bot_admin(interaction):
        await interaction.response.send_message("❌ Solo los admins pueden usar este comando.", ephemeral=True)
        return
    if equipo not in NBA_TEAMS:
        await interaction.response.send_message("❌ Equipo no válido.", ephemeral=True)
        return
    data = load_data()
    apodos = data.setdefault("_nba_apodos", {})
