@bot.tree.command(name="partido_nba", description="[ADMIN] Crea un nuevo partido en la sesión NBA2K activa 🏀")
@app_commands.describe(
    equipo_a="Primer equipo",
    equipo_b="Segundo equipo",
)
@app_commands.autocomplete(equipo_a=autocomplete_equipo, equipo_b=autocomplete_equipo)
async def partido_nba(interaction: discord.Interaction, equipo_a: str, equipo_b: str):
    if not is_bot_admin(interaction):
        await interaction.response.send_message("❌ Solo los admins pueden crear partidos.", ephemeral=True)
        return
    if is_channel_blocked(interaction):
        await interaction.response.send_message("❌ Este comando está bloqueado en este canal.", ephemeral=True)
        return

    # Buscar sesión activa en este canal
    sesion = None
    msg_id = None
    for mid, s in NBA_SESSIONS.items():
        if s["channel_id"] == interaction.channel_id and s["estado"] != "terminado":
            sesion = s
            msg_id = mid
            break

    if not sesion:
        await interaction.response.send_message(
            "❌ No hay ninguna sesión activa en este canal. Usa `/sesion_nba` primero.", ephemeral=True
        )
        return

    if sesion["estado"] == "abierto":
        await interaction.response.send_message(
            "❌ Cierra las apuestas del partido actual antes de crear uno nuevo.", ephemeral=True
        )
        return

    if equipo_a == equipo_b:
        await interaction.response.send_message("❌ Los dos equipos no pueden ser el mismo.", ephemeral=True)
        return

    sesion["equipos"] = [equipo_a, equipo_b]
    sesion["estado"] = "abierto"
    sesion["apuestas"] = {}
    await send_log(
        titulo="🏀 Nuevo partido NBA",
        descripcion=f"{interaction.user.mention} creó el partido **{equipo_a}** vs **{equipo_b}**.",
        color=0x1a73e8,
        campos=[("🏀 Partido", f"{equipo_a} vs {equipo_b}", False)],
        user_id=interaction.user.id, user_name=str(interaction.user),
        guild_id=interaction.guild.id if interaction.guild else None, guild_name=interaction.guild.name if interaction.guild else 'DM',
    )

    # Actualizar embed de control
    try:
        ctrl_msg = await interaction.channel.fetch_message(msg_id)
        await ctrl_msg.edit(embed=nba_embed_control(sesion), view=NBAControlView(msg_id))
    except Exception:
        pass

    # Publicar embed de apuestas
    channel = interaction.channel or bot.get_channel(sesion["channel_id"])
    if channel is None:
        channel = await bot.fetch_channel(sesion["channel_id"])
    view_apuestas = NBAApuestasView(msg_id)
    msg_apuestas = await channel.send(embed=nba_embed_apuestas(sesion), view=view_apuestas)
    sesion["apuesta_message_id"] = msg_apuestas.id

    await interaction.response.send_message(
        f"✅ Partido **{equipo_a}** vs **{equipo_b}** creado. ¡Apuestas abiertas!",
        ephemeral=True
    )

