COSTO_APODO = 5000

@bot.tree.command(name="mi_apodo", description="Cambia el apodo de tu equipo NBA 🏷️ (cuesta 5,000 🪙)")
@app_commands.describe(
    equipo="Tu equipo NBA",
    apodo="Apodo que quieres ponerle (ej: Pollo Asado)"
)
@app_commands.autocomplete(equipo=autocomplete_mi_equipo)
async def mi_apodo(interaction: discord.Interaction, equipo: str, apodo: str):
    data = load_data()
    owners = data.get("_nba_owners", {})
    if owners.get(equipo) != str(interaction.user.id):
        await interaction.response.send_message("❌ No eres dueño de ese equipo.", ephemeral=True)
        return
    apodo_final = apodo.strip()
    if not apodo_final:
        await interaction.response.send_message("❌ El apodo no puede estar vacío.", ephemeral=True)
        return
    player = get_player(data, interaction.user.id)
    if player.get("coins", 0) < COSTO_APODO:
        faltan = COSTO_APODO - player.get("coins", 0)
        await interaction.response.send_message(
            f"❌ No tienes suficientes monedas. Necesitas **{COSTO_APODO:,} 🪙** y te faltan **{faltan:,} 🪙**.",
            ephemeral=True
        )
        return
    player["coins"] -= COSTO_APODO
    data.setdefault("_nba_apodos", {})[equipo] = apodo_final
    save_data(data)
    saldo_restante = player['coins']
    await interaction.response.send_message(
        f"✅ Tu equipo **{equipo}** ahora se muestra como **{equipo} ({apodo_final})**.\n💸 Se descontaron **{COSTO_APODO:,} 🪙** | Saldo: **{saldo_restante:,} 🪙**",
        ephemeral=True
    )

@bot.tree.command(name="comprar_equipo", description=f"Compra un equipo NBA por {NBA_TEAM_PRICE:,} monedas 🏀")
@app_commands.describe(
    equipo="Equipo NBA que quieres comprar",
    apodo="Tu apodo que aparecerá junto al equipo (ej: Nova, Zapato...)"
)
@app_commands.autocomplete(equipo=autocomplete_equipo)
async def comprar_equipo(interaction: discord.Interaction, equipo: str, apodo: str = ""):
    if equipo not in NBA_TEAMS:
        await interaction.response.send_message("❌ Equipo no válido.", ephemeral=True)
        return
    data = load_data()
    owners = data.setdefault("_nba_owners", {})
    # Verificar si ya tiene dueño
    if equipo in owners:
        oid = owners[equipo]
        if oid == str(interaction.user.id):
            await interaction.response.send_message(f"❌ Ya eres dueño de **{equipo}**.", ephemeral=True)
        else:
            await interaction.response.send_message(f"❌ **{equipo}** ya tiene dueño (<@{oid}>).", ephemeral=True)
        return
    # Verificar monedas
    player = get_player(data, interaction.user.id)
    if player.get("coins", 0) < NBA_TEAM_PRICE:
        faltan = NBA_TEAM_PRICE - player.get("coins", 0)
        await interaction.response.send_message(
            f"❌ No tienes suficientes monedas. Te faltan **{faltan:,}** 🪙\nNecesitas: **{NBA_TEAM_PRICE:,}** | Tienes: **{player.get('coins', 0):,}**",
            ephemeral=True
        )
        return
    # Comprar
    player["coins"] -= NBA_TEAM_PRICE
    owners[equipo] = str(interaction.user.id)
    # Guardar apodo: si escribió uno se usa ese, si no se usa su nombre de Discord
    apodo_final = apodo.strip() if apodo.strip() else interaction.user.display_name
    data.setdefault("_nba_apodos", {})[equipo] = apodo_final
    nombre_mostrado = f"{equipo} ({apodo_final})"
    save_data(data)
    embed = discord.Embed(
        title="🏆 ¡Equipo comprado!",
        description=f"Ahora eres dueño de **{nombre_mostrado}** 🏀\nGanarás **{NBA_OWNER_WIN_REWARD:,}** 🪙 cada vez que tu equipo gane.",
        color=0x2ecc71
    )
    embed.set_footer(text=f"Saldo restante: {player['coins']:,} 🪙")
    await interaction.response.send_message(embed=embed)
    await send_log(
        titulo="🏀 Equipo NBA comprado",
        descripcion=f"{interaction.user.mention} (`{interaction.user.name}` · ID: `{interaction.user.id}`) compró un equipo.",
        color=0xf1c40f,
        campos=[
            ("🏀 Equipo", f"**{nombre_mostrado}**", True),
            ("💸 Precio pagado", f"**{NBA_TEAM_PRICE:,} 🪙**", True),
            ("🪙 Saldo restante", f"**{player['coins']:,} 🪙**", True),
        ],
        guild_id=interaction.guild.id if interaction.guild else None,
        guild_name=interaction.guild.name if interaction.guild else "DM",
    )

