@bot.tree.command(name="bans", description="📋 Ver lista de usuarios baneados del bot (solo admins)")
async def lista_bans(interaction: discord.Interaction):
    if not is_bot_admin(interaction):
        await interaction.response.send_message("❌ Solo admins del bot.", ephemeral=True)
        return

    bans = _load_bans()
    ahora = datetime.now(timezone.utc).isoformat()
    activos = {uid: b for uid, b in bans.items() if b.get("expires") is None or b["expires"] > ahora}
    if len(activos) != len(bans):
        _save_bans(activos)

    if not activos:
        await interaction.response.send_message("✅ No hay usuarios baneados actualmente.", ephemeral=True)
