@bot.tree.command(name="resultado_partido", description="[ADMIN] Registra el resultado de un partido de la liga y paga apuestas 📋")
@app_commands.describe(
    partido="Selecciona el partido",
    marcador="Marcador final (ej: 108-95)",
    ganador="Equipo ganador",
)
@app_commands.autocomplete(partido=autocomplete_partido_con_resultado, ganador=autocomplete_equipo)
async def resultado_partido(
    interaction: discord.Interaction,
    partido: str,
    marcador: str,
    ganador: str,
):
    if interaction.user.id not in LIGA_ADMINS:
        await interaction.response.send_message("❌ Solo admins.", ephemeral=True)
        return

    try:
        j_num, pid = partido.split("|")
        j_num, pid = int(j_num), int(pid)
    except Exception:
        await interaction.response.send_message("❌ Selecciona un partido válido del autocomplete.", ephemeral=True)
        return

    liga = load_liga()
    clave = str(j_num)
    if clave not in liga["jornadas"]:
        await interaction.response.send_message(f"❌ Jornada {j_num} no existe.", ephemeral=True)
        return

    p = next((x for x in liga["jornadas"][clave]["partidos"] if x["id"] == pid), None)
    if not p or p["resultado"] is not None:
        await interaction.response.send_message("❌ Partido no encontrado o ya tiene resultado.", ephemeral=True)
        return

    p["resultado"] = marcador
    p["ganador"] = ganador.strip()
    save_liga(liga)

    # Buscar si hay una sesión NBA activa para este partido y resolver apuestas
    sesion_activa = None
    for mid, s in NBA_SESSIONS.items():
        liga_info = s.get("liga", {})
        if liga_info.get("jornada") == j_num and liga_info.get("partido_id") == pid:
            sesion_activa = (mid, s)
            break

    await interaction.response.defer()

    if sesion_activa:
        mid, s = sesion_activa
        s["estado"] = "cerrado"
        await resolver_partido(s, ganador.strip(), interaction)
        NBA_SESSIONS.pop(mid, None)

    embed = discord.Embed(
        title=f"✅ Resultado — Jornada {j_num} · Partido {pid}",
        color=0x2ecc71
    )
    embed.add_field(name="Partido", value=f"**{p['local']}** vs **{p['visitante']}**", inline=False)
    embed.add_field(name="Marcador", value=f"🏀 {marcador}", inline=True)
    embed.add_field(name="Ganador", value=f"🏆 {ganador}", inline=True)
    await interaction.followup.send(embed=embed)
    await send_log(
        titulo="📋 Resultado de liga registrado",
        descripcion=f"{interaction.user.mention} (`{interaction.user.name}`) registró el resultado del Partido {pid} — Jornada {j_num}.",
        color=0x2ecc71,
        campos=[
            ("⚔️ Partido", f"{p['local']} vs {p['visitante']}", True),
            ("🏀 Marcador", marcador, True),
            ("🏆 Ganador", ganador, True),
        ],
        user_id=interaction.user.id,
        user_name=str(interaction.user),
    )

