async def autocomplete_partido_con_resultado_existente(interaction: discord.Interaction, current: str) -> List[app_commands.Choice[str]]:
    """Autocomplete que solo muestra partidos que YA tienen resultado."""
    liga = load_liga()
    data = load_data()
    apodos = data.get("_nba_apodos", {})
    opciones = []
    for j_num, jornada in sorted(liga["jornadas"].items(), key=lambda x: int(x[0])):
        for p in jornada["partidos"]:
            if p["resultado"] is None:
                continue
            local = apodos.get(p["local"], p["local"])
            visitante = apodos.get(p["visitante"], p["visitante"])
            label = f"J{j_num} P{p['id']}: {local} vs {visitante} [{p['resultado']}]"
            value = f"{j_num}|{p['id']}"
            if current.lower() in label.lower():
                opciones.append(app_commands.Choice(name=label[:100], value=value))
    return opciones[:25]

@bot.tree.command(name="editar_resultado", description="[ADMIN] Corrige el resultado de un partido ya registrado 📝")
@app_commands.describe(
    partido="Partido con resultado a corregir",
    marcador="Nuevo marcador (ej: 110-98)",
    ganador="Nuevo equipo ganador",
)
@app_commands.autocomplete(partido=autocomplete_partido_con_resultado_existente, ganador=autocomplete_equipo)
async def editar_resultado(
    interaction: discord.Interaction,
    partido: str,
    marcador: str,
    ganador: str,
):
    if interaction.user.id not in LIGA_ADMINS:
        await interaction.response.send_message("❌ Solo admins.", ephemeral=True)
        return

    try:
        j_num, pid = partido.split("|")
        j_num, pid = int(j_num), int(pid)
    except Exception:
        await interaction.response.send_message("❌ Selecciona un partido válido del autocomplete.", ephemeral=True)
        return

    liga = load_liga()
    clave = str(j_num)
    if clave not in liga["jornadas"]:
        await interaction.response.send_message(f"❌ Jornada {j_num} no existe.", ephemeral=True)
        return

    p = next((x for x in liga["jornadas"][clave]["partidos"] if x["id"] == pid), None)
    if not p:
        await interaction.response.send_message("❌ Partido no encontrado.", ephemeral=True)
        return
    if p["resultado"] is None:
        await interaction.response.send_message("❌ Ese partido aún no tiene resultado. Usa `/resultado_partido`.", ephemeral=True)
        return

    marcador_anterior = p["resultado"]
    ganador_anterior = p["ganador"]
    nuevo_ganador = ganador.strip()

    p["resultado"] = marcador.strip()
    p["ganador"] = nuevo_ganador
    save_liga(liga)

    data = load_data()
    owners = data.get("_nba_owners", {})
    lineas_coins = []

    # Solo tocar monedas si el ganador cambió
    if ganador_anterior != nuevo_ganador:
        # Quitar recompensa al dueño del ganador incorrecto
        owner_anterior_id = owners.get(ganador_anterior)
        if owner_anterior_id:
            owner_ant = get_player(data, int(owner_anterior_id))
            owner_ant["coins"] = max(0, owner_ant.get("coins", 0) - NBA_OWNER_WIN_REWARD)
            lineas_coins.append(f"🔴 <@{owner_anterior_id}> (dueño de **{ganador_anterior}**): -🪙 {NBA_OWNER_WIN_REWARD:,}")

        # Dar recompensa al dueño del nuevo ganador
        owner_nuevo_id = owners.get(nuevo_ganador)
        if owner_nuevo_id:
            owner_nvo = get_player(data, int(owner_nuevo_id))
            owner_nvo["coins"] = owner_nvo.get("coins", 0) + NBA_OWNER_WIN_REWARD
            lineas_coins.append(f"🟢 <@{owner_nuevo_id}> (dueño de **{nuevo_ganador}**): +🪙 {NBA_OWNER_WIN_REWARD:,}")

        save_data(data)

    embed = discord.Embed(
        title=f"✏️ Resultado editado — Jornada {j_num} · Partido {pid}",
        color=0x3498db
    )
    embed.add_field(name="Partido", value=f"**{p['local']}** vs **{p['visitante']}**", inline=False)
    embed.add_field(name="Antes", value=f"🏀 {marcador_anterior}  |  🏆 {ganador_anterior}", inline=False)
    embed.add_field(name="Ahora", value=f"🏀 {marcador.strip()}  |  🏆 {nuevo_ganador}", inline=False)

    if lineas_coins:
        embed.add_field(name="👑 Recompensa de dueños ajustada", value="\n".join(lineas_coins), inline=False)
    elif ganador_anterior == nuevo_ganador:
        embed.add_field(name="👑 Recompensa de dueños", value="El ganador no cambió, no se tocaron monedas.", inline=False)
    else:
        embed.add_field(name="👑 Recompensa de dueños", value="Ninguno de los dos equipos tiene dueño asignado.", inline=False)

    embed.set_footer(text="⚠️ Las apuestas ya pagadas no se pueden revertir.")
    await interaction.response.send_message(embed=embed)
    await send_log(
        titulo="✏️ Resultado de liga editado",
        descripcion=f"{interaction.user.mention} (`{interaction.user.name}`) editó el resultado del Partido {pid} — Jornada {j_num}.",
        color=0xe67e22,
        campos=[
            ("⚔️ Partido", f"{p['local']} vs {p['visitante']}", True),
            ("Antes", f"🏀 {marcador_anterior} | 🏆 {ganador_anterior}", True),
            ("Ahora", f"🏀 {marcador.strip()} | 🏆 {nuevo_ganador}", True),
        ] + ([("👑 Monedas ajustadas", "\n".join(lineas_coins), False)] if lineas_coins else []),
        user_id=interaction.user.id,
        user_name=str(interaction.user),
    )

