class ConfirmarReinicioLigaView(discord.ui.View):
    """Vista de confirmación antes de borrar todas las jornadas."""
    def __init__(self):
        super().__init__(timeout=30)

    @discord.ui.button(label="✅ Sí, reiniciar todo", style=discord.ButtonStyle.danger)
    async def confirmar(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id not in LIGA_ADMINS:
            await interaction.response.send_message("❌ Solo admins.", ephemeral=True)
            return
        liga = load_liga()
        total = len(liga.get("jornadas", {}))
        liga["jornadas"] = {}
        liga["jornada_actual"] = 0
        save_liga(liga)
        embed = discord.Embed(
            title="🗑️ Liga reiniciada",
            description=f"Se eliminaron **{total} jornada(s)**. La liga quedó en blanco.\nUsa `/crear_jornada` para empezar de nuevo.",
            color=0xe74c3c
        )
        self.stop()
        await interaction.response.edit_message(embed=embed, view=None)
        await send_log(
            titulo="🗑️ Liga reiniciada",
            descripcion=f"{interaction.user.mention} (`{interaction.user.name}`) reinició la liga completa. Se eliminaron **{total}** jornada(s).",
            color=0xe74c3c,
            user_id=interaction.user.id,
            user_name=str(interaction.user),
        )

    @discord.ui.button(label="❌ Cancelar", style=discord.ButtonStyle.secondary)
    async def cancelar(self, interaction: discord.Interaction, button: discord.ui.Button):
        embed = discord.Embed(
            title="Reinicio cancelado",
            description="No se modificó nada.",
            color=0x95a5a6
        )
        self.stop()
        await interaction.response.edit_message(embed=embed, view=None)

@bot.tree.command(name="reiniciar_liga", description="[ADMIN] Borra todas las jornadas y reinicia la liga desde cero 🗑️")
async def reiniciar_liga(interaction: discord.Interaction):
    if interaction.user.id not in LIGA_ADMINS:
        await interaction.response.send_message("❌ Solo admins.", ephemeral=True)
        return
    liga = load_liga()
    total = len(liga.get("jornadas", {}))
    if total == 0:
        await interaction.response.send_message("ℹ️ La liga ya está vacía, no hay jornadas que borrar.", ephemeral=True)
        return
    embed = discord.Embed(
        title="⚠️ ¿Reiniciar la liga completa?",
        description=f"Esto borrará **{total} jornada(s)** y todos sus partidos permanentemente.\n\n¿Estás seguro?",
        color=0xe67e22
    )
    view = ConfirmarReinicioLigaView()
    await interaction.response.send_message(embed=embed, view=view, ephemeral=True)

