@bot.tree.command(name="jornada", description="Muestra todos los partidos de una jornada de la liga 📅")
@app_commands.describe(numero="Número de jornada (deja vacío para ver la actual)")
async def ver_jornada(interaction: discord.Interaction, numero: int = 0):
    liga = load_liga()
    n = numero if numero > 0 else liga.get("jornada_actual", 0)
    if n == 0:
        await interaction.response.send_message("❌ No hay ninguna jornada creada aún.", ephemeral=True)
        return
    clave = str(n)
    if clave not in liga["jornadas"]:
        await interaction.response.send_message(f"❌ La jornada {n} no existe.", ephemeral=True)
        return

    partidos = liga["jornadas"][clave]["partidos"]
    jugados = [p for p in partidos if p["resultado"] is not None]
    pendientes = [p for p in partidos if p["resultado"] is None]

    embed = discord.Embed(
        title=f"📅 Jornada {n} — Liga Liveleak",
        color=0x3498db
    )
    if pendientes:
        lineas = [f"**{p['id']}.** 🏀 {p['local']} vs {p['visitante']}" for p in pendientes]
        embed.add_field(name="⏳ Pendientes", value="\n".join(lineas), inline=False)
    if jugados:
        lineas = [f"**{p['id']}.** {p['local']} vs {p['visitante']} — `{p['resultado']}` 🏆 {p['ganador']}" for p in jugados]
        embed.add_field(name="✅ Jugados", value="\n".join(lineas), inline=False)

    embed.set_footer(text=f"Jornada {n} de {TOTAL_JORNADAS} | {len(jugados)}/10 partidos jugados")
    await interaction.response.send_message(embed=embed)

# ─── /mi_equipo_liga ─────────────────────────────────────────────────────────

@bot.tree.command(name="mi_equipo_liga", description="Ve los partidos de tu equipo en la liga 🏀")
async def mi_equipo_liga(interaction: discord.Interaction):
    data = load_data()
    owners = data.get("_nba_owners", {})
    apodos = data.get("_nba_apodos", {})
    uid = str(interaction.user.id)

    mis_equipos = [eq for eq, oid in owners.items() if str(oid) == uid]
    if not mis_equipos:
        await interaction.response.send_message("❌ No tienes ningún equipo asignado.", ephemeral=True)
        return

    liga = load_liga()
    if not liga["jornadas"]:
        await interaction.response.send_message("❌ Aún no hay jornadas registradas en la liga.", ephemeral=True)
        return

    embed = discord.Embed(title="🏀 Tu equipo en la Liga Liveleak", color=0x9b59b6)

    for equipo in mis_equipos:
        apodo = apodos.get(equipo)
        nombre = f"{equipo} ({apodo})" if apodo else equipo
        jugados = []
        proximos = []

        for j_num, jornada in sorted(liga["jornadas"].items(), key=lambda x: int(x[0])):
            for p in jornada["partidos"]:
                es_local = equipo.lower() in p["local"].lower()
                es_visitante = equipo.lower() in p["visitante"].lower()
                if not (es_local or es_visitante):
                    continue
                rival = p["visitante"] if es_local else p["local"]
                if p["resultado"] is not None:
                    gano = p["ganador"] and equipo.lower() in p["ganador"].lower()
                    icon = "✅" if gano else "❌"
                    jugados.append(f"J{j_num} {icon} vs {rival} `{p['resultado']}`")
                else:
                    proximos.append(f"J{j_num} ⏳ vs {rival}")

        valor = ""
        if proximos:
            valor += "**Próximos:**\n" + "\n".join(proximos[:5]) + "\n"
        if jugados:
            valor += "**Jugados:**\n" + "\n".join(jugados[-5:])
        if not valor:
            valor = "Sin partidos registrados aún."

        embed.add_field(name=f"🏀 {nombre}", value=valor, inline=False)

    await interaction.response.send_message(embed=embed)



