# ═══════════════════════════════════════════════════════════════════════════════
# ─── LAST.FM ──────────────────────────────────────────────────────────────────
# ═══════════════════════════════════════════════════════════════════════════════

LASTFM_API_KEY = "3e59d610f09f24e275e3e7807e38b5c0"
LASTFM_BASE    = "https://ws.audioscrobbler.com/2.0/"
LASTFM_API_SECRET = os.environ.get("LASTFM_API_SECRET", "")
LASTFM_CALLBACK_BASE = os.environ.get("RAILWAY_PUBLIC_DOMAIN", "")  # ej: "mibot.up.railway.app"

# Tokens OAuth temporales pendientes: {token: discord_id}
_oauth_pending: dict[str, int] = {}

OAUTH_PENDING_FILE = "/data/oauth_pending.json"

def _load_oauth_pending() -> dict:
    try:
        if os.path.exists(OAUTH_PENDING_FILE):
            with open(OAUTH_PENDING_FILE, "r") as f:
                return json.load(f)
    except Exception:
        pass
    return {}

def _save_oauth_pending(pending: dict):
    try:
        os.makedirs(os.path.dirname(OAUTH_PENDING_FILE), exist_ok=True)
        with open(OAUTH_PENDING_FILE, "w") as f:
            json.dump(pending, f)
    except Exception:
        pass

def _oauth_add(token: str, discord_id: int):
    pending = _load_oauth_pending()
    pending[token] = discord_id
    _save_oauth_pending(pending)

def _oauth_pop(token: str) -> int | None:
    pending = _load_oauth_pending()
    discord_id = pending.pop(token, None)
    _save_oauth_pending(pending)
    return discord_id

def _oauth_has(token: str) -> bool:
    return token in _load_oauth_pending()

def _lastfm_oauth_url(discord_id: int) -> tuple[str, str]:
    """Genera la URL de autorización de Last.fm. Devuelve (url, state_token)."""
    import secrets
    state = secrets.token_urlsafe(16)
    _oauth_add(state, discord_id)
    callback = f"https://{LASTFM_CALLBACK_BASE}/lastfm/callback?state={state}"
    url = (
        f"https://www.last.fm/api/auth/"
        f"?api_key={LASTFM_API_KEY}"
        f"&cb={callback}"
    )
    return url, state

async def _lastfm_get_session(token: str) -> tuple | None:
    """Intercambia un token por (username, session_key) o None si falla."""
    import hashlib
    sig_str = f"api_key{LASTFM_API_KEY}methodauth.getSessiontoken{token}{LASTFM_API_SECRET}"
    api_sig = hashlib.md5(sig_str.encode()).hexdigest()
    params = {
        "method": "auth.getSession",
        "api_key": LASTFM_API_KEY,
        "token": token,
        "api_sig": api_sig,
        "format": "json",
    }
    async with aiohttp.ClientSession() as session:
        async with session.get(LASTFM_BASE, params=params) as resp:
            data = await resp.json(content_type=None)
    if "error" in data:
        return None
    sess = data.get("session", {})
    username = sess.get("name")
    session_key = sess.get("key")
    if not username or not session_key:
        return None
    return username, session_key
def get_lastfm_user(discord_id: int) -> str | None:
    data = load_data()
    return data.get("_lastfm", {}).get(str(discord_id))

def set_lastfm_user(discord_id: int, lastfm_username: str, session_key: str = None):
    data = load_data()
    if "_lastfm" not in data:
        data["_lastfm"] = {}
    data["_lastfm"][str(discord_id)] = lastfm_username
    if session_key:
        if "_lastfm_sessions" not in data:
            data["_lastfm_sessions"] = {}
        data["_lastfm_sessions"][str(discord_id)] = session_key
    save_data(data)

def get_lastfm_session_key(discord_id: int) -> str | None:
    data = load_data()
    return data.get("_lastfm_sessions", {}).get(str(discord_id))

# Guarda usuario de lastfm por discord id en data["_lastfm"]
async def lastfm_get(params: dict) -> dict | None:
    """Hace un GET a la API de Last.fm y devuelve el JSON o None si falla."""
    params["api_key"] = LASTFM_API_KEY
    params["format"]  = "json"
    async with aiohttp.ClientSession() as session:
        async with session.get(LASTFM_BASE, params=params) as resp:
            if resp.status != 200:
                return None
            return await resp.json()

def period_label(period: str) -> str:
    return {"7day": "última semana", "1month": "último mes", "3month": "últimos 3 meses",
            "6month": "últimos 6 meses", "12month": "último año", "overall": "todo el tiempo"}.get(period, period)

def lfm_footer(username: str) -> str:
    return f"🎵 last.fm/{username}"


# ── .fmset / .lset / .connect ─────────────────────────────────────────────────
def _make_lastfm_connect_embed_and_view(discord_id: int):
    """Genera el embed y botón de conexión OAuth de Last.fm."""
    url, state = _lastfm_oauth_url(discord_id)

    embed = discord.Embed(
        title="🎵 Conecta tu cuenta de Last.fm",
        description=(
            "Pulsa el botón de abajo para autorizar el bot en Last.fm.\n\n"
            "Te mandará a la página de Last.fm donde aceptas, y listo —\n"
            "no necesitas escribir tu nombre de usuario."
        ),
        color=0xd51007
    )
    embed.set_footer(text="El enlace expira en 10 minutos")

    view = discord.ui.View(timeout=600)
    btn = discord.ui.Button(label="Conectar con Last.fm", url=url, style=discord.ButtonStyle.link, emoji="🎵")
    view.add_item(btn)
    return embed, view, state

@bot.command(name="fmset", aliases=["lset", "fmconnect", "connectfm"])
async def fmset(ctx):
    """Conecta tu cuenta de Last.fm con OAuth. Uso: .fmset"""
    embed, view, state = _make_lastfm_connect_embed_and_view(ctx.author.id)
    try:
        await ctx.author.send(embed=embed, view=view)
        await ctx.reply("📬 Te mandé un mensaje privado con el enlace para conectarte a Last.fm.", mention_author=False)
    except discord.Forbidden:
        await ctx.reply(embed=embed, view=view, mention_author=False)

    async def _expire():
        await asyncio.sleep(600)
        _oauth_pop(state)
    asyncio.create_task(_expire())


# ── .np ───────────────────────────────────────────────────────────────────────
@bot.command(name="np", aliases=["fm", "nowplaying"])
async def np(ctx, member: discord.Member = None):
    """Lo que estás escuchando ahora. Uso: .np [@usuario]"""
    target = member or ctx.author
    username = get_lastfm_user(target.id)
    if not username:
        if target == ctx.author:
            embed, view, state = _make_lastfm_connect_embed_and_view(ctx.author.id)
            embed.title = "🎵 ¡Conecta tu Last.fm!"
            embed.description = (
                "No tienes ninguna cuenta de Last.fm vinculada.\n\n"
                "Pulsa el botón para conectarte — es rápido y no necesitas escribir nada."
            )
            await ctx.reply(embed=embed, view=view, mention_author=False)
            async def _expire():
                await asyncio.sleep(600)
                _oauth_pop(state)
            asyncio.create_task(_expire())
        else:
            await ctx.reply(f"❌ {target.display_name} no tiene cuenta de Last.fm vinculada.", mention_author=False)
        return
    recent_data = await lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 1, "extended": 1})
    if not recent_data or "error" in recent_data:
        await ctx.reply("❌ No pude conectar con Last.fm.", mention_author=False)
        return
    tracks = recent_data.get("recenttracks", {}).get("track", [])
    if not tracks:
        await ctx.reply("❌ No hay scrobbles recientes.", mention_author=False)
        return
    track = tracks[0] if isinstance(tracks, list) else tracks
    now_playing = track.get("@attr", {}).get("nowplaying") == "true"
    _a = track.get("artist", {})
    artist = ((_a.get("name") or _a.get("#text") or "?") if isinstance(_a, dict) else str(_a)).strip()
    song   = track.get("name", "?")
    album  = track.get("album", {}).get("#text", "")
    _raw_img = next((i["#text"] for i in track.get("image", []) if i.get("size") == "extralarge" and i.get("#text")), None)
    if _raw_img:
        _raw_img = re.sub(r'/i/u/\d+x\d+/', '/i/u/', _raw_img)
    image = _clean_lfm_image(_raw_img)
    loved  = track.get("loved") == "1"

    # Si no hay imagen en recenttracks, buscarla en album.getinfo
    if not image and album:
        _alb_data = await lastfm_get({"method": "album.getinfo", "artist": artist, "album": album, "autocorrect": 1})
        if _alb_data and "error" not in _alb_data:
            _alb_imgs = _alb_data.get("album", {}).get("image", [])
            _alb_raw = next((i["#text"] for i in reversed(_alb_imgs) if i.get("#text")), None)
            image = _clean_lfm_image(_alb_raw)

    # Check cover personalizado
    if album:
        _custom = get_custom_cover(artist, album)
        if _custom:
            image = _custom

    # Plays del artista actual para este usuario
    artist_data = await lastfm_get({"method": "artist.getinfo", "artist": artist, "username": username, "autocorrect": 1})
    artist_plays = int(artist_data.get("artist", {}).get("stats", {}).get("userplaycount", 0)) if artist_data and "error" not in artist_data else None

    track_url = f"https://www.last.fm/music/{artist.replace(' ', '+').replace('/', '%2F')}/_/{song.replace(' ', '+').replace('/', '%2F')}"

    description = f"**{artist}**" + (f" • *{album}*" if album else "")
    if loved:
        description += " ❤️"
    if artist_plays:
        description += f"\n\n{artist_plays:,} scrobbles de este artista"

    color = await get_dominant_color(image) if image else 0xd51007
    embed = discord.Embed(color=color, url=track_url)
    embed.set_author(name=f"{'🎵 Now Playing' if now_playing else '⏸️ Última canción'} — {target.display_name}", icon_url=target.display_avatar.url)
    embed.title = song
    embed.description = description
    if image:
        embed.set_thumbnail(url=image)
    embed.set_footer(text=lfm_footer(username))
    style = load_card_style(target.id)
    if style.card_mode == "embed":
        msg = await ctx.reply(embed=embed, mention_author=False)
    else:
        try:
            img_bytes = await generate_np_card(
                song=song, artist=artist, album=album,
                album_art_url=image or "", username=username,
                display_name=target.display_name,
                avatar_url=str(target.display_avatar.url),
                now_playing=now_playing, loved=loved,
                artist_plays=artist_plays, style=style,
            )
            ext = "gif" if img_bytes.read(6)[:6] in (b"GIF87a", b"GIF89a") else "png"
            img_bytes.seek(0)
            file = discord.File(fp=img_bytes, filename=f"nowplaying.{ext}")
            msg = await ctx.reply(file=file, mention_author=False)
        except Exception as _card_err:
            import traceback
            print(f"[np_card ERROR] {_card_err}\n{traceback.format_exc()}")
            msg = await ctx.reply(embed=embed, mention_author=False)
    await msg.add_reaction("🔥")
    await msg.add_reaction("🗑️")
    # Actualizar coronas en background
    if now_playing:
        bot.loop.create_task(update_crowns(ctx.guild, username, target.id))


# ── .setcard ─────────────────────────────────────────────────────────────────
@bot.command(name="setcard", aliases=["cardset", "npset"])
async def setcard_cmd(ctx, setting: str = "", *, value: str = ""):
    """
    Personaliza tu tarjeta NowPlaying.
    Uso:
      .setcard                    — ver tu estilo actual
      .setcard template <nombre>  — cambiar template (default/minimal/blur/retro/glass/cassette)
      .setcard bg <color hex>     — color de fondo (#1a1a2e)
      .setcard bg gradient #c1 #c2 — gradiente
      .setcard bgblur <0-60>      — intensidad de blur (funciona con fondo personalizado y blur_art)
      .setcard bgbrightness <0.0-1.0> — brillo del fondo (0.0=negro, 1.0=original)
      .setcard textcolor <hex>    — color del texto principal
      .setcard accent <hex>       — color de acento (o "auto" para extraer del art)
      .setcard art <left|right|hidden> — posición del album art
      .setcard artsize <px>       — tamaño del art (100-250)
      .setcard font <nombre>      — fuente (SpaceGrotesk/Unbounded/DM_Sans)
      .setcard vignette <on|off>  — vignette
      .setcard grain <on|off>     — grano de película
      .setcard reset              — restablecer todo
    """
    user_id = ctx.author.id
    style = load_card_style(user_id)
    setting = setting.lower().strip()

    if not setting:
        embed = discord.Embed(title="🎨 Tu estilo de tarjeta NowPlaying", color=0x2b2d31)
        embed.add_field(name="Template",  value=style.template, inline=True)
        embed.add_field(name="Fondo",     value=f"{style.bg_type} {style.bg_color}", inline=True)
        embed.add_field(name="Blur",      value=f"{style.bg_blur}", inline=True)
        embed.add_field(name="Brillo",    value=f"{int(style.bg_brightness * 100)}%", inline=True)
        embed.add_field(name="Acento",    value=style.text_accent, inline=True)
        embed.add_field(name="Art",       value=f"{style.art_position} ({style.art_size}px)", inline=True)
        embed.add_field(name="Fuente",    value=style.font_title, inline=True)
        embed.add_field(name="Efectos",   value=f"vignette={'✅' if style.vignette else '❌'}  grain={'✅' if style.grain else '❌'}", inline=True)
        embed.add_field(name="Modo",      value="🖼️ imagen" if style.card_mode == "imagen" else "📋 embed", inline=True)
        embed.add_field(name="Avatar",    value="🖼️ personalizado" if style.custom_avatar_url else "👤 Discord", inline=True)
        embed.set_footer(text="Usa .setcard <opción> <valor> para cambiar")
        return await ctx.reply(embed=embed, mention_author=False)

    if setting == "reset":
        save_card_style(user_id, CardStyle())
        return await ctx.reply("✅ Estilo restablecido al default.", mention_author=False)

    if setting == "template":
        templates = list(TEMPLATE_PRESETS.keys())
        if value not in templates:
            return await ctx.reply(f"❌ Templates disponibles: {', '.join(f'`{t}`' for t in templates)}", mention_author=False)
        style = apply_template(style, value)
        save_card_style(user_id, style)
        return await ctx.reply(f"✅ Template cambiado a `{value}`.", mention_author=False)

    if setting == "bg":
        parts = value.split()

        # ── Imagen adjunta o URL ───────────────────────────────────────────────
        img_url = None
        if ctx.message.attachments:
            img_url = ctx.message.attachments[0].url
        elif parts and parts[0].startswith("http"):
            img_url = parts[0]

        if img_url:
            # Validar que sea imagen o GIF
            ext = img_url.split("?")[0].lower()
            if not any(ext.endswith(e) for e in (".png", ".jpg", ".jpeg", ".webp", ".gif")):
                return await ctx.reply("❌ Formato no soportado. Usa PNG, JPG, WEBP o GIF.", mention_author=False)
            style.bg_type = "custom_image"
            style.bg_image_url = img_url
            save_card_style(user_id, style)
            return await ctx.reply("✅ Fondo personalizado guardado. Usa `.setcard bgblur <0-60>` para ajustar el blur.", mention_author=False)

        # ── Color sólido o gradiente ───────────────────────────────────────────
        if len(parts) == 3 and parts[0] == "gradient":
            style.bg_type = "gradient"
            style.bg_color  = parts[1] if parts[1].startswith("#") else f"#{parts[1]}"
            style.bg_color2 = parts[2] if parts[2].startswith("#") else f"#{parts[2]}"
        elif parts and parts[0].startswith("#"):
            style.bg_type = "solid"
            style.bg_color = parts[0]
        elif not parts or parts[0] == "imagen":
            return await ctx.reply(
                "❌ Adjunta una imagen al mensaje o pasa una URL.\n"
                "También puedes usar:\n"
                "• `.setcard bg #hex` — color sólido\n"
                "• `.setcard bg gradient #color1 #color2` — gradiente\n"
                "• `.setcard bg blur` — fondo del album art difuminado",
                mention_author=False
            )
        elif parts[0] == "blur":
            style.bg_type = "blur_art"
        else:
            return await ctx.reply("❌ Opción no reconocida para `bg`.", mention_author=False)

        save_card_style(user_id, style)
        return await ctx.reply("✅ Fondo actualizado.", mention_author=False)

    if setting == "bgreset":
        style.bg_type = "blur_art"
        style.bg_image_url = ""
        save_card_style(user_id, style)
        return await ctx.reply("✅ Fondo restablecido al blur del album art.", mention_author=False)

    if setting == "bgblur":
        try:
            v = max(0, min(60, int(value)))
            style.bg_blur = v
            # Solo cambia a blur_art si no tiene fondo personalizado
            if style.bg_type not in ("custom_image", "blur_art"):
                style.bg_type = "blur_art"
            elif style.bg_type != "custom_image":
                style.bg_type = "blur_art"
            save_card_style(user_id, style)
            tipo = "fondo personalizado" if style.bg_type == "custom_image" else "album art"
            return await ctx.reply(f"✅ Blur del {tipo}: `{v}`.", mention_author=False)
        except ValueError:
            return await ctx.reply("❌ Valor inválido. Usa un número entre 0 y 60.", mention_author=False)

    if setting == "bgbrightness":
        try:
            v = max(0.0, min(1.0, float(value)))
            style.bg_brightness = v
            save_card_style(user_id, style)
            pct = int(v * 100)
            return await ctx.reply(f"✅ Brillo del fondo: `{pct}%`.", mention_author=False)
        except ValueError:
            return await ctx.reply("❌ Valor inválido. Usa un número entre 0.0 y 1.0 (ej: `0.4` = 40%).", mention_author=False)

    if setting == "accent":
        if value.lower() == "auto":
            style.use_accent_from_art = True
            save_card_style(user_id, style)
            return await ctx.reply("✅ Acento automático activado (se extrae del album art).", mention_author=False)
        c = value.strip() if value.startswith("#") else f"#{value.strip()}"
        style.text_accent = c
        style.use_accent_from_art = False
        save_card_style(user_id, style)
        return await ctx.reply(f"✅ Color de acento: `{c}`.", mention_author=False)

    if setting == "textcolor":
        c = value.strip() if value.startswith("#") else f"#{value.strip()}"
        style.text_primary = c
        save_card_style(user_id, style)
        return await ctx.reply(f"✅ Color de texto: `{c}`.", mention_author=False)

    if setting == "art":
        opts = ["left", "right", "center", "hidden"]
        if value not in opts:
            return await ctx.reply(f"❌ Posiciones: {', '.join(f'`{o}`' for o in opts)}", mention_author=False)
        style.art_position = value
        save_card_style(user_id, style)
        return await ctx.reply(f"✅ Posición del art: `{value}`.", mention_author=False)

    if setting == "artsize":
        try:
            v = max(100, min(250, int(value)))
            style.art_size = v
            save_card_style(user_id, style)
            return await ctx.reply(f"✅ Tamaño del art: `{v}px`.", mention_author=False)
        except ValueError:
            return await ctx.reply("❌ Valor inválido. Usa un número entre 100 y 250.", mention_author=False)

    if setting == "font":
        style.font_title = value
        style.font_body = value
        save_card_style(user_id, style)
        return await ctx.reply(f"✅ Fuente cambiada a `{value}`. (Asegúrate de tener el .ttf en /data/fonts/)", mention_author=False)

    if setting == "vignette":
        style.vignette = value.lower() in ("on", "true", "1", "si", "sí")
        save_card_style(user_id, style)
        return await ctx.reply(f"✅ Vignette: {'activada' if style.vignette else 'desactivada'}.", mention_author=False)

    if setting == "grain":
        style.grain = value.lower() in ("on", "true", "1", "si", "sí")
        save_card_style(user_id, style)
        return await ctx.reply(f"✅ Grain: {'activado' if style.grain else 'desactivado'}.", mention_author=False)

    if setting == "avatar":
        img_url = None
        if ctx.message.attachments:
            img_url = ctx.message.attachments[0].url
        elif value.strip().startswith("http"):
            img_url = value.strip()

        if not img_url:
            return await ctx.reply(
                "❌ Adjunta una imagen al mensaje o pasa una URL.\n"
                "Para quitar tu avatar personalizado usa `.setcard avatareset`",
                mention_author=False
            )
        ext = img_url.split("?")[0].lower()
        if not any(ext.endswith(e) for e in (".png", ".jpg", ".jpeg", ".webp", ".gif")):
            return await ctx.reply("❌ Formato no soportado. Usa PNG, JPG, WEBP o GIF.", mention_author=False)
        style.custom_avatar_url = img_url
        save_card_style(user_id, style)
        return await ctx.reply("✅ Avatar personalizado guardado.", mention_author=False)

    if setting == "avatareset":
        style.custom_avatar_url = ""
        save_card_style(user_id, style)
        return await ctx.reply("✅ Avatar restablecido al de Discord.", mention_author=False)

    if setting == "modo":
        opts = ["imagen", "embed"]
        if value.lower() not in opts:
            return await ctx.reply("❌ Modos disponibles: `imagen` o `embed`", mention_author=False)
        style.card_mode = value.lower()
        save_card_style(user_id, style)
        label = "🖼️ Tarjeta imagen" if style.card_mode == "imagen" else "📋 Embed clásico"
        return await ctx.reply(f"✅ Modo cambiado a **{label}**.", mention_author=False)

    await ctx.reply("❌ Opción no reconocida. Usa `.setcard` para ver todas las opciones.", mention_author=False)


# ── .cardpreview ──────────────────────────────────────────────────────────────
@bot.command(name="cardpreview", aliases=["previewcard", "nppreview"])
async def cardpreview_cmd(ctx, template: str = ""):
    """Previsualiza un template sin guardar cambios."""
    style = load_card_style(ctx.author.id)
    if template:
        style = apply_template(style, template)

    username = get_lastfm_user(ctx.author.id)
    if not username:
        return await ctx.reply("❌ Conecta tu Last.fm primero con `.fmset`.", mention_author=False)

    recent = await lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 1, "extended": 1})
    if not recent or "error" in recent:
        return await ctx.reply("❌ No pude obtener tu canción actual.", mention_author=False)

    tracks = recent.get("recenttracks", {}).get("track", [])
    if not tracks:
        return await ctx.reply("❌ Sin scrobbles recientes.", mention_author=False)

    track = tracks[0] if isinstance(tracks, list) else tracks
    _a = track.get("artist", {})
    artist = ((_a.get("name") or _a.get("#text") or "?") if isinstance(_a, dict) else str(_a)).strip()
    song   = track.get("name", "?")
    album  = track.get("album", {}).get("#text", "")
    image_url = next((i["#text"] for i in track.get("image", []) if i.get("size") == "extralarge" and i.get("#text")), None)
    if image_url:
        image_url = re.sub(r'/i/u/\d+x\d+/', '/i/u/', image_url)
    image_url = _clean_lfm_image(image_url)

    img_bytes = await generate_np_card(
        song=song, artist=artist, album=album,
        album_art_url=image_url or "",
        username=username,
        display_name=ctx.author.display_name,
        avatar_url=str(ctx.author.display_avatar.url),
        now_playing=track.get("@attr", {}).get("nowplaying") == "true",
        loved=track.get("loved") == "1",
        style=style,
    )
    label = f"Preview — template `{template}`" if template else "Preview — tu estilo actual"
    file = discord.File(fp=img_bytes, filename="preview_card.png")
    await ctx.reply(f"🎨 {label}", file=file, mention_author=False)


# ── .link ────────────────────────────────────────────────────────────────────
@bot.command(name="link")
async def link_cmd(ctx, member: discord.Member = None):
    """
    Busca la canción actual en el tracker de Carti.
    Uso:
      .link              — respondiendo a un .np
      .link @usuario     — busca lo que escucha ese usuario
    """
    song_name = None

    # ── Caso 1: respuesta a un mensaje con embed de .np ──────────────────────
    if ctx.message.reference and not member:
        try:
            ref_msg = ctx.message.reference.resolved or await ctx.channel.fetch_message(ctx.message.reference.message_id)
            if ref_msg.embeds:
                emb = ref_msg.embeds[0]
                # El .np pone el nombre en title (como link azul)
                song_name = emb.title or ""
                # Si title viene vacío, intentar description
                if not song_name and emb.description:
                    song_name = emb.description.split("\n")[0].strip()
                import re as _re2
                song_name = _re2.sub(r"[*_`]", "", song_name).strip()
                print(f"[LINK] title={repr(emb.title)} desc={repr(str(emb.description)[:50])}")
        except Exception as e:
            print(f"[LINK] Error: {e}")

    # ── Caso 2: .link @usuario — consulta Last.fm ────────────────────────────
    if not song_name:
        target   = member or ctx.author
        username = get_lastfm_user(target.id)
        if not username:
            return await ctx.reply(
                f"❌ {'Tú no tienes' if target == ctx.author else f'{target.display_name} no tiene'} "
                "cuenta de Last.fm vinculada. Usa `.fmset` para conectarte.",
                mention_author=False,
            )
        recent_data = await lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 1})
        if not recent_data or "error" in recent_data:
            return await ctx.reply("❌ No pude conectar con Last.fm.", mention_author=False)
        tracks = recent_data.get("recenttracks", {}).get("track", [])
        if not tracks:
            return await ctx.reply("❌ No hay scrobbles recientes.", mention_author=False)
        track     = tracks[0] if isinstance(tracks, list) else tracks
        song_name = track.get("name", "")

    if not song_name:
        return await ctx.reply(
            "❌ No encontré ninguna canción. Responde a un `.np` o usa `.link @usuario`.",
            mention_author=False,
        )

    # ── Buscar en todos los trackers ─────────────────────────────────────────
    carti_results = _search(song_name)
    try:
        lone_results = _lone_search(song_name)
    except Exception:
        lone_results = []
    try:
        uzi_results = _uzi_search(song_name)
    except Exception:
        uzi_results = []
    try:
        che_results = _che_search(song_name)
    except Exception:
        che_results = []

    for s in carti_results: s["_tracker"] = "Playboi Carti"
    for s in lone_results:  s["_tracker"] = "Destroy Lonely"
    for s in uzi_results:   s["_tracker"] = "Lil Uzi Vert"
    for s in che_results:   s["_tracker"] = "Che"

    results = carti_results + lone_results + uzi_results + che_results

    if not results:
        return await ctx.reply(
            embed=discord.Embed(
                title="❌ No está en ningún tracker",
                description=f"**{song_name}** no aparece en ningún tracker.",
                color=0xe74c3c,
            ),
            mention_author=False,
        )

    embed_fns = {
        "Playboi Carti":  _embed_link,
        "Destroy Lonely": _lone_embed_link,
        "Lil Uzi Vert":   _uzi_embed_link,
        "Che":            _che_embed_link,
    }

    # Resultado único → embed de link directo con cover
    if len(results) == 1:
        s    = results[0]
        fn   = embed_fns.get(s.get("_tracker"), _embed_link)
        emb  = fn(s)
        cover = await _fetch_era_cover(s["era"])
        if cover:
            emb.set_thumbnail(url=cover)
        view = DownloadView(s, s.get("_tracker", ""))
        return await ctx.reply(embed=emb, view=view, mention_author=False)

    # Varios → lista paginada
    title = f'🔍  "{song_name}"'
    view  = CartiPageView(results, title, ctx.author.id)
    await ctx.reply(embed=_embed_list(results, title), view=view, mention_author=False)


# ── .cover ────────────────────────────────────────────────────────────────────
def _cover_key(artist: str, album: str) -> str:
    """Clave normalizada: artista|album en minúsculas sin espacios extra."""
    return f"{artist.strip().lower()}|{album.strip().lower()}"

def load_album_covers() -> dict:
    os.makedirs(os.path.dirname(ALBUM_COVERS_FILE), exist_ok=True)
    if os.path.exists(ALBUM_COVERS_FILE):
        with open(ALBUM_COVERS_FILE, "r") as f:
            return json.load(f)
    return {}

def save_album_covers(covers: dict):
    os.makedirs(os.path.dirname(ALBUM_COVERS_FILE), exist_ok=True)
    with open(ALBUM_COVERS_FILE, "w") as f:
        json.dump(covers, f, indent=2)

def get_custom_cover(artist: str, album: str) -> str | None:
    covers = load_album_covers()
    return covers.get(_cover_key(artist, album))

@bot.command(name="setcover", aliases=["sc"])
async def setcover(ctx, *, args: str = None):
    """[Admin] Pone un cover personalizado. Uso: .setcover artista | album | url"""
    if ctx.author.id not in BOT_ADMINS:
        await ctx.reply("❌ Solo los admins pueden usar este comando.", mention_author=False)
        return
    if not args or args.count("|") < 2:
        await ctx.reply("❌ Formato: `.setcover artista | album | url_de_la_imagen`", mention_author=False)
        return
    partes = [p.strip() for p in args.split("|", 2)]
    artist, album, url = partes
    if not artist or not album or not url:
        await ctx.reply("❌ Faltan datos. Formato: `.setcover artista | album | url`", mention_author=False)
        return
    if not url.startswith("http"):
        await ctx.reply("❌ La URL no parece válida.", mention_author=False)
        return
    covers = load_album_covers()
    covers[_cover_key(artist, album)] = url
    save_album_covers(covers)
    embed = discord.Embed(
        title="✅ Cover guardado",
        description=f"**{artist}** — {album}",
        color=0xd51007
    )
    embed.set_image(url=url)
    embed.set_footer(text=f"Clave: {_cover_key(artist, album)}")
    await ctx.reply(embed=embed, mention_author=False)

