@bot.command(name="removecover", aliases=["rc", "delcover"])
async def removecover(ctx, *, args: str = None):
    """[Admin] Elimina un cover personalizado. Uso: .removecover artista | album"""
    if ctx.author.id not in BOT_ADMINS:
        await ctx.reply("❌ Solo los admins pueden usar este comando.", mention_author=False)
        return
    if not args or "|" not in args:
        await ctx.reply("❌ Formato: `.removecover artista | album`", mention_author=False)
        return
    partes = [p.strip() for p in args.split("|", 1)]
    artist, album = partes
    covers = load_album_covers()
    key = _cover_key(artist, album)
    if key not in covers:
        await ctx.reply(f"❌ No hay cover personalizado para **{artist}** — {album}.", mention_author=False)
        return
    del covers[key]
    save_album_covers(covers)
    await ctx.reply(f"🗑️ Cover eliminado para **{artist}** — {album}.", mention_author=False)


@bot.command(name="cover", aliases=["co", "albumcover"])
async def cover(ctx, member: discord.Member = None):
    """Muestra el cover del álbum que estás escuchando. Uso: .cover [@usuario]"""
    target = member or ctx.author
    username = get_lastfm_user(target.id)
    if not username:
        if target == ctx.author:
            embed, view, state = _make_lastfm_connect_embed_and_view(ctx.author.id)
            embed.title = "🎵 ¡Conecta tu Last.fm!"
            embed.description = "No tienes ninguna cuenta de Last.fm vinculada.\n\nPulsa el botón para conectarte."
            await ctx.reply(embed=embed, view=view, mention_author=False)
            async def _expire():
                await asyncio.sleep(600)
                _oauth_pop(state)
            asyncio.create_task(_expire())
        else:
            await ctx.reply(f"❌ {target.display_name} no tiene cuenta de Last.fm vinculada.", mention_author=False)
        return

    data = await lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 1})
    if not data or "error" in data:
        await ctx.reply("❌ No pude conectar con Last.fm.", mention_author=False)
        return
    tracks = data.get("recenttracks", {}).get("track", [])
    if not tracks:
        await ctx.reply("❌ No hay scrobbles recientes.", mention_author=False)
        return

    track = tracks[0] if isinstance(tracks, list) else tracks
    _a = track.get("artist", {})
    artist = ((_a.get("name") or _a.get("#text") or "?") if isinstance(_a, dict) else str(_a)).strip()
    song   = track.get("name", "?")
    album  = track.get("album", {}).get("#text", "") or "Álbum desconocido"
    now_playing = track.get("@attr", {}).get("nowplaying") == "true"

    # Buscar cover: primero personalizado, luego el de Last.fm en máxima calidad
    custom = get_custom_cover(artist, album) if album != "Álbum desconocido" else None
    raw_image = next((i["#text"] for i in track.get("image", []) if i.get("size") == "extralarge" and i.get("#text")), None)
    if raw_image:
        raw_image = _clean_lfm_image(re.sub(r'/i/u/\d+x\d+/', '/i/u/', raw_image))
    image = custom or raw_image

    if not image:
        await ctx.reply(f"❌ No encontré cover para **{album}** — {artist}.", mention_author=False)
        return

    color = await get_dominant_color(image)
    embed = discord.Embed(color=color)
    embed.set_author(
        name=f"{'🎵 ' if now_playing else ''}{'Now Playing' if now_playing else 'Último álbum'} — {target.display_name}",
        icon_url=target.display_avatar.url
    )
    embed.title = album
    embed.description = f"**{artist}** — {song}"
    if custom:
        embed.description += "\n-# 🎨 Cover personalizado"
    embed.set_image(url=image)
    embed.set_footer(text=lfm_footer(username))
    await ctx.reply(embed=embed, mention_author=False)


