# ── .favs ─────────────────────────────────────────────────────────────────────

@bot.command(name="favs", aliases=["fav", "fa"])
async def favs(ctx, member: discord.Member = None):
    """Tus top canciones del artista que escuchas ahora. Uso: .favs [@usuario]"""
    target = member or ctx.author
    username = get_lastfm_user(target.id)
    if not username:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset tunombre`", mention_author=False)
        return

    # Detectar artista: reply a np o np actual
    artist_name = await extract_artist_from_reply_async(ctx.message)
    if not artist_name:
        # Obtener el artista del np actual
        np_data = await lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 1})
        if not np_data or "error" in np_data:
            await ctx.reply("❌ No pude conectar con Last.fm.", mention_author=False)
            return
        tracks = np_data.get("recenttracks", {}).get("track", [])
        if not tracks:
            await ctx.reply("❌ Sin scrobbles recientes.", mention_author=False)
            return
        track = tracks[0] if isinstance(tracks, list) else tracks
        artist_obj = track.get("artist", {})
        artist_name = ((artist_obj.get("name") or artist_obj.get("#text") or "") if isinstance(artist_obj, dict) else str(artist_obj)).strip()

    if not artist_name:
        await ctx.reply("❌ No pude detectar el artista.", mention_author=False)
        return

    # Buscar top tracks del artista para este usuario
    artist_data = await lastfm_get({
        "method": "artist.gettoptracks",
        "artist": artist_name,
        "username": username,
        "limit": 10,
        "autocorrect": 1,
    })
    if not artist_data or "error" in artist_data:
        await ctx.reply(f"❌ No encontré canciones de **{artist_name}**.", mention_author=False)
        return
    tracks = artist_data.get("toptracks", {}).get("track", [])
    if not tracks:
        await ctx.reply(f"❌ Sin datos de **{artist_name}** para `{username}`.", mention_author=False)
        return
    lineas = []
    for i, t in enumerate(tracks[:10], 1):
        plays = int(t.get("playcount", 0))
        lineas.append(f"`{i}.` **{t['name']}** — {plays:,} plays")
    embed = discord.Embed(
        title=f"🎵 Top canciones de {artist_name}",
        description="\n".join(lineas),
        color=0xd51007
    )
    embed.set_author(name=target.display_name, icon_url=target.display_avatar.url)
    embed.set_footer(text=lfm_footer(username))
    await ctx.reply(embed=embed, mention_author=False)


