# Sobreescribir los comandos para que acepten reply context de artista

@bot.command(name="artistinfo", aliases=["ai", "about"])
async def artistinfo(ctx, *, artist_name: str = None):
    """Info de un artista (o el que estás escuchando). Uso: .artistinfo [artista]"""
    username = get_lastfm_user(ctx.author.id)
    if not username:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset tunombre`", mention_author=False)
        return
    if not artist_name:
        artist_name = await extract_artist_from_reply_async(ctx.message)
    if not artist_name and username:
        np_data = await lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 1})
        if np_data and "error" not in np_data:
            tracks = np_data.get("recenttracks", {}).get("track", [])
            if tracks:
                t = tracks[0] if isinstance(tracks, list) else tracks
                a = t.get("artist", {})
                artist_name = (a.get("name") or a.get("#text") or "" if isinstance(a, dict) else str(a)).strip()
    if not artist_name:
        await ctx.reply("❌ Pon el nombre del artista o úsalo mientras escuchas algo.", mention_author=False)
        return
    data = await lastfm_get({"method": "artist.getinfo", "artist": artist_name, "username": username or "", "autocorrect": 1})
    if not data or "error" in data:
        await ctx.reply(f"❌ No encontré info de **{artist_name}**.", mention_author=False)
        return
    a = data.get("artist", {})
    name      = a.get("name", artist_name)
    listeners = int(a.get("stats", {}).get("listeners", 0))
    scrobbles = int(a.get("stats", {}).get("playcount", 0))
    user_plays = int(a.get("stats", {}).get("userplaycount", 0))
    tags = [t["name"] for t in a.get("tags", {}).get("tag", [])[:5]]
    embed = discord.Embed(title=name, url=a.get("url", ""), color=0xd51007)
    embed.add_field(name="Listeners", value=f"{listeners:,}", inline=True)
    embed.add_field(name="Scrobbles globales", value=f"{scrobbles:,}", inline=True)
    if user_plays and username:
        embed.add_field(name="Tus plays", value=f"{user_plays:,}", inline=True)
    if tags:
        embed.add_field(name="Tags", value=" · ".join(tags), inline=False)
    embed.set_footer(text=lfm_footer(username) if username else "last.fm")
    await ctx.reply(embed=embed, mention_author=False)


