@bot.command(name="whoknows", aliases=["wk", "w"])
async def whoknows(ctx, *, artist_name: str = None):
    """Quién más escucha un artista en el server. Uso: .whoknows [artista]"""
    username = get_lastfm_user(ctx.author.id)
    if not username:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset tunombre`", mention_author=False)
        return
    if not artist_name:
        artist_name = await extract_artist_from_reply_async(ctx.message)
    if not artist_name:
        np_data = await lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 1})
        if np_data and "error" not in np_data:
            tracks = np_data.get("recenttracks", {}).get("track", [])
            if tracks:
                t = tracks[0] if isinstance(tracks, list) else tracks
                a = t.get("artist", {})
                artist_name = (a.get("name") or a.get("#text") or "" if isinstance(a, dict) else str(a)).strip()
    if not artist_name:
        await ctx.reply("❌ No pude detectar el artista. Pon `.wk nombre del artista`", mention_author=False)
        return

    await ctx.message.add_reaction("⏳")
    data = load_data()
    lfm_map = data.get("_lastfm", {})
    results = []
    for discord_id_str, lfm_user in lfm_map.items():
        member = ctx.guild.get_member(int(discord_id_str))
        if not member:
            continue
        info = await lastfm_get({"method": "artist.getinfo", "artist": artist_name, "username": lfm_user, "autocorrect": 1})
        if not info or "error" in info:
            continue
        plays = int(info.get("artist", {}).get("stats", {}).get("userplaycount", 0))
        real_name = info.get("artist", {}).get("name", artist_name)
        if plays > 0:
            results.append((member, lfm_user, plays, real_name))

    await ctx.message.remove_reaction("⏳", ctx.guild.me)

    if not results:
        await ctx.reply(f"❌ Nadie en el server escucha **{artist_name}**.", mention_author=False)
        return

    results.sort(key=lambda x: x[2], reverse=True)
    real_name = results[0][3]

    # Actualizar corona
    crowns = get_crowns_data()
    guild_id = str(ctx.guild.id)
    if guild_id not in crowns:
        crowns[guild_id] = {}
    top_member, top_lfm, top_plays, _ = results[0]
    key = real_name.lower()
    old_crown = crowns[guild_id].get(key)
    crown_changed = old_crown and old_crown["discord_id"] != top_member.id
    crowns[guild_id][key] = {"discord_id": top_member.id, "username": top_lfm, "plays": top_plays, "artist": real_name}
    save_crowns_data(crowns)

    lineas = []
    for i, (member, lfm_user, plays, _) in enumerate(results[:15], 1):
        crown_icon = "👑 " if i == 1 else ""
        lfm_link = f"[{member.display_name}](https://www.last.fm/user/{lfm_user})"
        lineas.append(f"`{i}.` {crown_icon}{lfm_link} — {plays:,} plays")

    # Imagen del top álbum del artista buscado para color dinámico
    cover_img = None
    _top_alb = await lastfm_get({"method": "artist.gettopalbums", "artist": real_name, "limit": 1, "autocorrect": 1})
    if _top_alb and "error" not in _top_alb:
        _albs = _top_alb.get("topalbums", {}).get("album", [])
        if _albs:
            _alb_imgs = _albs[0].get("image", [])
            _alb_raw = next((i["#text"] for i in reversed(_alb_imgs) if i.get("#text")), None)
            cover_img = _clean_lfm_image(_alb_raw)
    color = await get_dominant_color(cover_img) if cover_img else 0xd51007

    embed = discord.Embed(title=f"🎵 Who knows {real_name}?", description="\n".join(lineas), color=color)
    if cover_img:
        embed.set_thumbnail(url=cover_img)
    embed.set_footer(text=f"{len(results)} oyente(s) en {ctx.guild.name}")
    if crown_changed:
        embed.add_field(name="👑 Corona nueva", value=f"**{top_member.display_name}** le quitó la corona a **{old_crown['username']}**!", inline=False)
    await ctx.reply(embed=embed, mention_author=False)


# ── .wkt (who knows track) ────────────────────────────────────────────────────

async def _get_np_track_and_artist(ctx, username: str):
    """Obtiene (artist, track) del np actual o de un reply a un embed del bot."""
    if ctx.message.reference:
        try:
            ref = ctx.message.reference.resolved
            if ref is None:
                ref = await ctx.channel.fetch_message(ctx.message.reference.message_id)
            if ref and ref.author.id == ctx.guild.me.id and ref.embeds:
                emb = ref.embeds[0]
                title = emb.title or ""
                desc = emb.description or ""
                # Embed de .np: title=canción, description="**artista** • *álbum*"
                # Embed de .ti / .wkt: title=canción, author=artista o "por **artista**"
                artist_name = ""
                track_name = ""
                # Intentar artista desde "por **artista**" en description (.wkt)
                m = re.match(r"por \*\*(.+?)\*\*", desc)
                if m:
                    artist_name = m.group(1).strip()
                # Intentar artista desde primer **bold** en description (.np)
                if not artist_name:
                    m = re.search(r"\*\*(.+?)\*\*", desc)
                    if m:
                        artist_name = m.group(1).strip()
                # Intentar artista desde embed.author (.ti, .albuminfo)
                if not artist_name and emb.author and emb.author.name:
                    artist_name = emb.author.name.strip()
                # Canción: el título del embed (ignorar títulos de wk/wka)
                if title and not re.match(r"[🎵💿]?\s*Who knows", title):
                    track_name = title.strip()
                if artist_name and track_name:
                    return artist_name, track_name
        except Exception:
            pass
    # Fallback: np actual
    data = await lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 1})
    if not data or "error" in data:
        return None, None
    tracks = data.get("recenttracks", {}).get("track", [])
    if not tracks:
        return None, None
    t = tracks[0] if isinstance(tracks, list) else tracks
    artist_obj = t.get("artist", {})
    artist_name = (artist_obj.get("name") or artist_obj.get("#text") or "" if isinstance(artist_obj, dict) else str(artist_obj)).strip()
    track_name = t.get("name", "").strip()
    if not artist_name or not track_name:
        return None, None
    return artist_name, track_name

async def _get_np_album_and_artist(ctx, username: str):
    """Obtiene (artist, album) del np actual o de un reply a un embed del bot."""
    if ctx.message.reference:
        try:
            ref = ctx.message.reference.resolved
            if ref is None:
                ref = await ctx.channel.fetch_message(ctx.message.reference.message_id)
            if ref and ref.author.id == ctx.guild.me.id and ref.embeds:
                emb = ref.embeds[0]
                title = emb.title or ""
                desc = emb.description or ""
                artist_name = ""
                album_name = ""
                # Embed de .wka: title="💿 Who knows Álbum?", author=artista
                m = re.match(r"💿\s*Who knows (.+?)\??$", title)
                if m:
                    album_name = m.group(1).strip()
                    if emb.author and emb.author.name:
                        artist_name = emb.author.name.strip()
                # Embed de .ali: title=álbum, author=artista
                if not album_name and title and not re.match(r"[🎵💿]?\s*Who knows", title):
                    album_name = title.strip()
                    if emb.author and emb.author.name:
                        artist_name = emb.author.name.strip()
                # Embed de .np: description="**artista** • *álbum*"
                if not artist_name or not album_name:
                    m = re.search(r"\*\*(.+?)\*\*", desc)
                    if m:
                        artist_name = m.group(1).strip()
                    m = re.search(r"• \*(.+?)\*", desc)
                    if m:
                        album_name = m.group(1).strip()
                if artist_name and album_name:
                    return artist_name, album_name
        except Exception:
            pass
    data = await lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 1})
    if not data or "error" in data:
        return None, None
    tracks = data.get("recenttracks", {}).get("track", [])
    if not tracks:
        return None, None
    t = tracks[0] if isinstance(tracks, list) else tracks
    artist_obj = t.get("artist", {})
    artist_name = (artist_obj.get("name") or artist_obj.get("#text") or "" if isinstance(artist_obj, dict) else str(artist_obj)).strip()
    album_name = t.get("album", {}).get("#text", "").strip()
    if not artist_name or not album_name:
        return None, None
    return artist_name, album_name

@bot.command(name="whoknowstrack", aliases=["wkt"])
async def whoknowstrack(ctx, *, query: str = None):
    """Quién más escucha una canción en el server. Uso: .wkt [artista | canción]"""
    username = get_lastfm_user(ctx.author.id)
    if not username:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset tunombre`", mention_author=False)
        return

    if query and "|" in query:
        parts = [p.strip() for p in query.split("|", 1)]
        artist_name, track_name = parts[0], parts[1]
    elif query:
        # Tratar todo como nombre de canción, artista desde np
        if not username:
            await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset tunombre`", mention_author=False)
            return
        np_data = await lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 1})
        if not np_data or "error" in np_data:
            await ctx.reply("❌ No pude conectar con Last.fm.", mention_author=False)
            return
        tracks = np_data.get("recenttracks", {}).get("track", [])
        t = (tracks[0] if isinstance(tracks, list) else tracks) if tracks else {}
        a = t.get("artist", {})
        artist_name = (a.get("name") or a.get("#text") or "" if isinstance(a, dict) else str(a)).strip()
        track_name = query
    else:
        if not username:
            await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset tunombre`", mention_author=False)
            return
        artist_name, track_name = await _get_np_track_and_artist(ctx, username)
        if not artist_name or not track_name:
            await ctx.reply("❌ No pude detectar la canción. Pon `.wkt artista | canción`", mention_author=False)
            return

    await ctx.message.add_reaction("⏳")
    data = load_data()
    lfm_map = data.get("_lastfm", {})
    results = []
    real_track = track_name
    real_artist = artist_name

    for discord_id_str, lfm_user in lfm_map.items():
        member = ctx.guild.get_member(int(discord_id_str))
        if not member:
            continue
        info = await lastfm_get({
            "method": "track.getinfo",
            "artist": artist_name,
            "track": track_name,
            "username": lfm_user,
            "autocorrect": 1,
        })
        if not info or "error" in info:
            continue
        t = info.get("track", {})
        plays = int(t.get("userplaycount", 0))
        real_track = t.get("name", track_name)
        real_artist = t.get("artist", {}).get("name", artist_name)
        if plays > 0:
            results.append((member, lfm_user, plays))

    await ctx.message.remove_reaction("⏳", ctx.guild.me)

    if not results:
        await ctx.reply(f"❌ Nadie en el server ha escuchado **{track_name}** de {artist_name}.", mention_author=False)
        return

    results.sort(key=lambda x: x[2], reverse=True)
    lineas = []
    for i, (member, lfm_user, plays) in enumerate(results[:15], 1):
        crown = "👑 " if i == 1 else ""
        lineas.append(f"`{i}.` {crown}**{member.display_name}** — {plays:,} plays")

    # Imagen de la canción para color dinámico
    track_info = await lastfm_get({"method": "track.getinfo", "artist": real_artist, "track": real_track, "autocorrect": 1})
    track_img = None
    if track_info and "error" not in track_info:
        imgs = track_info.get("track", {}).get("album", {}).get("image", [])
        track_img = next((i["#text"] for i in reversed(imgs) if i.get("#text")), None)
        if track_img:
            track_img = _clean_lfm_image(re.sub(r'/i/u/\d+x\d+/', '/i/u/', track_img))
    color = await get_dominant_color(track_img) if track_img else 0xd51007

    embed = discord.Embed(
        title=f"🎵 Who knows {real_track}?",
        description=f"por **{real_artist}**\n\n" + "\n".join(lineas),
        color=color
    )
    if track_img:
        embed.set_thumbnail(url=track_img)
    embed.set_footer(text=f"{len(results)} oyente(s) en {ctx.guild.name}")
    await ctx.reply(embed=embed, mention_author=False)


