@bot.command(name="taste", aliases=["tc"])
async def taste(ctx, member: discord.Member = None, period: str = "overall"):
    """Artistas en común con otro usuario. Uso: .taste @usuario [periodo]"""
    u1 = get_lastfm_user(ctx.author.id)
    if not u1:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset tunombre`", mention_author=False)
        return
    if not member:
        await ctx.reply("❌ Menciona a un usuario. Ej: `.taste @usuario`", mention_author=False)
        return
    u2 = get_lastfm_user(member.id)
    if not u2:
        await ctx.reply(f"❌ {member.display_name} no tiene cuenta vinculada.", mention_author=False)
        return
    await ctx.message.add_reaction("⏳")
    d1, d2 = await asyncio.gather(
        lastfm_get({"method": "user.gettopartists", "user": u1, "period": period, "limit": 200}),
        lastfm_get({"method": "user.gettopartists", "user": u2, "period": period, "limit": 200}),
    )
    await ctx.message.remove_reaction("⏳", ctx.guild.me)
    if not d1 or not d2 or "error" in d1 or "error" in d2:
        await ctx.reply("❌ No pude obtener los datos.", mention_author=False)
        return
    a1 = {a["name"].lower(): int(a["playcount"]) for a in d1.get("topartists", {}).get("artist", [])}
    a2 = {a["name"].lower(): int(a["playcount"]) for a in d2.get("topartists", {}).get("artist", [])}
    common = [(name, a1[name], a2[name]) for name in a1 if name in a2]
    common.sort(key=lambda x: x[1] + x[2], reverse=True)
    if not common:
        await ctx.reply(f"❌ **{ctx.author.display_name}** y **{member.display_name}** no tienen artistas en común.", mention_author=False)
        return
    lineas = [f"`{i}.` **{name.title()}** — {p1:,} / {p2:,}" for i, (name, p1, p2) in enumerate(common[:10], 1)]
    embed = discord.Embed(
        title=f"🎵 Taste — {ctx.author.display_name} & {member.display_name}",
        description="\n".join(lineas),
        color=0xd51007
    )
    embed.set_footer(text=f"{len(common)} artistas en común · {period_label(period)}")
    await ctx.reply(embed=embed, mention_author=False)


# ── .compatibility ─────────────────────────────────────────────────────────────

@bot.command(name="compatibility", aliases=["compat", "comp"])
async def compatibility(ctx, member: discord.Member = None, period: str = "overall"):
    """Compatibilidad musical con otro usuario. Uso: .compat @usuario"""
    u1 = get_lastfm_user(ctx.author.id)
    if not u1:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset tunombre`", mention_author=False)
        return
    if not member:
        await ctx.reply("❌ Menciona a un usuario. Ej: `.compat @usuario`", mention_author=False)
        return
    u2 = get_lastfm_user(member.id)
    if not u1:
        await ctx.reply("❌ No tienes cuenta vinculada.", mention_author=False)
        return
    if not u2:
        await ctx.reply(f"❌ {member.display_name} no tiene cuenta vinculada.", mention_author=False)
        return
    await ctx.message.add_reaction("⏳")
    d1, d2 = await asyncio.gather(
        lastfm_get({"method": "user.gettopartists", "user": u1, "period": period, "limit": 500}),
        lastfm_get({"method": "user.gettopartists", "user": u2, "period": period, "limit": 500}),
    )
    await ctx.message.remove_reaction("⏳", ctx.guild.me)
    if not d1 or not d2 or "error" in d1 or "error" in d2:
        await ctx.reply("❌ No pude obtener los datos.", mention_author=False)
        return
    a1 = {a["name"].lower(): int(a["playcount"]) for a in d1.get("topartists", {}).get("artist", [])}
    a2 = {a["name"].lower(): int(a["playcount"]) for a in d2.get("topartists", {}).get("artist", [])}
    if not a1 or not a2:
        await ctx.reply("❌ Sin suficientes datos.", mention_author=False)
        return
    common = [name for name in a1 if name in a2]
    total = len(set(list(a1.keys()) + list(a2.keys())))
    pct = round((len(common) / total) * 100) if total else 0
    # Peso por plays compartidos
    shared_plays = sum(min(a1[n], a2[n]) for n in common)
    total_plays  = sum(a1.values()) + sum(a2.values())
    weighted_pct = round((shared_plays / (total_plays / 2)) * 100) if total_plays else 0
    score = round((pct + weighted_pct) / 2)
    score = min(score, 100)
    if score >= 80:   label = "🔥 Almas gemelas musicales"
    elif score >= 60: label = "💚 Muy compatible"
    elif score >= 40: label = "🟡 Bastante compatible"
    elif score >= 20: label = "🟠 Poco en común"
    else:             label = "❄️ Gustos muy distintos"
    bar_filled = round(score / 10)
    bar = "█" * bar_filled + "░" * (10 - bar_filled)
    embed = discord.Embed(
        title=f"💿 Compatibilidad — {ctx.author.display_name} & {member.display_name}",
        color=0xd51007
    )
    embed.add_field(name="Score", value=f"`{bar}` **{score}%**", inline=False)
    embed.add_field(name="Veredicto", value=label, inline=False)
    embed.add_field(name="Artistas en común", value=f"{len(common):,} de {total:,}", inline=True)
    embed.set_footer(text=period_label(period))
    await ctx.reply(embed=embed, mention_author=False)


# ── .streak ───────────────────────────────────────────────────────────────────

@bot.command(name="streak", aliases=["str"])
async def streak(ctx, member: discord.Member = None):
    """Racha de scrobbles del mismo artista. Uso: .streak [@usuario]"""
    target = member or ctx.author
    username = get_lastfm_user(target.id)
    if not username:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset tunombre`", mention_author=False)
        return
    data = await lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 50})
    if not data or "error" in data:
        await ctx.reply("❌ No pude conectar con Last.fm.", mention_author=False)
        return
    tracks = data.get("recenttracks", {}).get("track", [])
    if not tracks:
        await ctx.reply("❌ Sin scrobbles recientes.", mention_author=False)
        return
    # Racha de artista
    first = tracks[0] if isinstance(tracks, list) else tracks
    first_artist = first.get("artist", {})
    streak_artist = first_artist.get("name", "") if isinstance(first_artist, dict) else str(first_artist)
    streak_count = 0
    for t in tracks:
        a = t.get("artist", {})
        name = (a.get("name") or a.get("#text") or "") if isinstance(a, dict) else str(a)
        if name.lower() == streak_artist.lower():
            streak_count += 1
        else:
            break
    # Racha de álbum
    first_album = first.get("album", {}).get("#text", "")
    album_streak = 0
    for t in tracks:
        if t.get("album", {}).get("#text", "") == first_album:
            album_streak += 1
        else:
            break
    embed = discord.Embed(
        title=f"🔥 Racha de {target.display_name}",
        color=0xd51007
    )
    embed.add_field(name="Artista", value=f"**{streak_artist}** — {streak_count} seguidas", inline=False)
    if first_album:
        embed.add_field(name="Álbum", value=f"**{first_album}** — {album_streak} seguidas", inline=False)
    embed.set_footer(text=lfm_footer(username))
    await ctx.reply(embed=embed, mention_author=False)


# ── .milestones ───────────────────────────────────────────────────────────────

@bot.command(name="milestones", aliases=["ms", "milestone"])
async def milestones(ctx, member: discord.Member = None):
    """Milestones de scrobbles. Uso: .milestones [@usuario]"""
    target = member or ctx.author
    username = get_lastfm_user(target.id)
    if not username:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset tunombre`", mention_author=False)
        return
    data = await lastfm_get({"method": "user.getinfo", "user": username})
    if not data or "error" in data:
        await ctx.reply("❌ No pude conectar con Last.fm.", mention_author=False)
        return
    playcount = int(data.get("user", {}).get("playcount", 0))
    milestones_list = [1000, 5000, 10000, 25000, 50000, 75000, 100000, 350000, 200000, 500000, 1000000]
    lineas = []
    for m in milestones_list:
        if playcount >= m:
            lineas.append(f"✅ **{m:,}** scrobbles")
        else:
            remaining = m - playcount
            lineas.append(f"⬜ **{m:,}** — faltan {remaining:,}")
            break
    # Siguiente milestone
    next_ms = next((m for m in milestones_list if m > playcount), None)
    embed = discord.Embed(
        title=f"🏆 Milestones de {target.display_name}",
        description="\n".join(lineas),
        color=0xd51007
    )
    embed.add_field(name="Total actual", value=f"🎵 **{playcount:,}** scrobbles", inline=True)
    if next_ms:
        pct = round((playcount / next_ms) * 100, 1)
        embed.add_field(name=f"Próximo: {next_ms:,}", value=f"{pct}% completado", inline=True)
    embed.set_footer(text=lfm_footer(username))
    await ctx.reply(embed=embed, mention_author=False)


# ── .compare ──────────────────────────────────────────────────────────────────

@bot.command(name="compare", aliases=["cmp"])
async def compare(ctx, member: discord.Member = None):
    """Compara tu perfil con otro usuario. Uso: .compare @usuario"""
    u1 = get_lastfm_user(ctx.author.id)
    if not u1:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset tunombre`", mention_author=False)
        return
    if not member:
        await ctx.reply("❌ Menciona a un usuario. Ej: `.compare @usuario`", mention_author=False)
        return
    u2 = get_lastfm_user(member.id)
    if not u1:
        await ctx.reply("❌ No tienes cuenta vinculada.", mention_author=False)
        return
    if not u2:
        await ctx.reply(f"❌ {member.display_name} no tiene cuenta vinculada.", mention_author=False)
        return
    await ctx.message.add_reaction("⏳")
    d1, d2 = await asyncio.gather(
        lastfm_get({"method": "user.getinfo", "user": u1}),
        lastfm_get({"method": "user.getinfo", "user": u2}),
    )
    await ctx.message.remove_reaction("⏳", ctx.guild.me)
    if not d1 or not d2:
        await ctx.reply("❌ No pude obtener los datos.", mention_author=False)
        return
    p1 = d1.get("user", {})
    p2 = d2.get("user", {})
    def stat(p): return {
        "plays":   int(p.get("playcount", 0)),
        "artists": int(p.get("artist_count", 0)),
        "albums":  int(p.get("album_count", 0)),
        "tracks":  int(p.get("track_count", 0)),
    }
    s1, s2 = stat(p1), stat(p2)
    def cmp(v1, v2):
        if v1 > v2: return "🟢", "🔴"
        if v1 < v2: return "🔴", "🟢"
        return "🟡", "🟡"
    rows = []
    for key, label in [("plays","Scrobbles"),("artists","Artistas"),("albums","Álbumes"),("tracks","Canciones")]:
        e1, e2 = cmp(s1[key], s2[key])
        rows.append(f"{e1} **{s1[key]:,}** {label} vs **{s2[key]:,}** {e2}")
    embed = discord.Embed(
        title=f"⚔️ {ctx.author.display_name} vs {member.display_name}",
        description="\n".join(rows),
        color=0xd51007
    )
    embed.set_footer(text=f"{u1} vs {u2}")
    await ctx.reply(embed=embed, mention_author=False)


