@bot.command(name="pace", aliases=["pc"])
async def pace(ctx, goal: int = None, member: discord.Member = None):
    """¿Vas a llegar a X scrobbles este año? Uso: .pace [meta] [@usuario]"""
    target = member or ctx.author
    username = get_lastfm_user(target.id)
    if not username:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset tunombre`", mention_author=False)
        return
    data = await lastfm_get({"method": "user.getinfo", "user": username})
    if not data or "error" in data:
        await ctx.reply("❌ No pude conectar con Last.fm.", mention_author=False)
        return
    import datetime
    now = datetime.datetime.utcnow()
    start_of_year = datetime.datetime(now.year, 1, 1)
    days_passed = (now - start_of_year).days + 1
    days_in_year = 366 if now.year % 4 == 0 else 365
    days_left = days_in_year - days_passed

    # Scrobbles este año
    year_data = await lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 1, "from": int(start_of_year.timestamp()), "to": int(now.timestamp())})
    scrobbles_this_year = int(year_data.get("recenttracks", {}).get("@attr", {}).get("total", 0)) if year_data and "error" not in year_data else 0

    rate_per_day = scrobbles_this_year / days_passed if days_passed > 0 else 0
    projected = int(rate_per_day * days_in_year)

    embed = discord.Embed(title=f"📈 Pace de {target.display_name}", color=0xd51007)
    embed.add_field(name="Scrobbles este año", value=f"{scrobbles_this_year:,}", inline=True)
    embed.add_field(name="Ritmo diario", value=f"{rate_per_day:.1f}/día", inline=True)
    embed.add_field(name="Proyección anual", value=f"{projected:,}", inline=True)

    if goal:
        needed = goal - scrobbles_this_year
        if needed <= 0:
            embed.add_field(name=f"🎯 Meta {goal:,}", value="✅ ¡Ya llegaste!", inline=False)
        else:
            needed_per_day = needed / days_left if days_left > 0 else needed
            on_track = rate_per_day >= needed_per_day
            status = "✅ Vas bien" if on_track else "❌ Necesitas acelerar"
            embed.add_field(name=f"🎯 Meta {goal:,}", value=f"{status}\nNecesitas **{needed_per_day:.1f}/día** ({needed:,} restantes)", inline=False)

    embed.set_footer(text=lfm_footer(username))
    await ctx.reply(embed=embed, mention_author=False)


# ── .year ─────────────────────────────────────────────────────────────────────

@bot.command(name="year", aliases=["yearly", "yr"])
async def year(ctx, year_num: int = None, member: discord.Member = None):
    """Resumen de tu año en Last.fm. Uso: .year [año] [@usuario]"""
    target = member or ctx.author
    username = get_lastfm_user(target.id)
    if not username:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset tunombre`", mention_author=False)
        return
    import datetime
    y = year_num or datetime.datetime.utcnow().year
    from_ts = int(datetime.datetime(y, 1, 1).timestamp())
    to_ts = int(datetime.datetime(y, 12, 31, 23, 59, 59).timestamp())

    await ctx.message.add_reaction("⏳")
    artists_data, tracks_data, albums_data, recent_data = await asyncio.gather(
        lastfm_get({"method": "user.gettopartists", "user": username, "period": "12month", "limit": 5}),
        lastfm_get({"method": "user.gettoptracks", "user": username, "period": "12month", "limit": 5}),
        lastfm_get({"method": "user.gettopalbums", "user": username, "period": "12month", "limit": 5}),
        lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 1, "from": from_ts, "to": to_ts}),
    )
    await ctx.message.remove_reaction("⏳", ctx.guild.me)

    total = int(recent_data.get("recenttracks", {}).get("@attr", {}).get("total", 0)) if recent_data and "error" not in recent_data else 0

    embed = discord.Embed(title=f"🗓️ {target.display_name} en {y}", color=0xd51007)
    embed.add_field(name="Total scrobbles", value=f"{total:,}", inline=False)

    if artists_data and "error" not in artists_data:
        arts = artists_data.get("topartists", {}).get("artist", [])[:5]
        embed.add_field(name="🎤 Top Artistas", value="\n".join(f"`{i}.` {a['name']} — {int(a['playcount']):,}" for i, a in enumerate(arts, 1)) or "Sin datos", inline=False)

    if tracks_data and "error" not in tracks_data:
        trks = tracks_data.get("toptracks", {}).get("track", [])[:5]
        embed.add_field(name="🎵 Top Canciones", value="\n".join(f"`{i}.` {t['name']} — {t['artist']['name']}" for i, t in enumerate(trks, 1)) or "Sin datos", inline=False)

    if albums_data and "error" not in albums_data:
        albs = albums_data.get("topalbums", {}).get("album", [])[:5]
        embed.add_field(name="💿 Top Álbumes", value="\n".join(f"`{i}.` {a['name']} — {a['artist']['name']}" for i, a in enumerate(albs, 1)) or "Sin datos", inline=False)

    embed.set_footer(text=lfm_footer(username))
    await ctx.reply(embed=embed, mention_author=False)


