@bot.command(name="serverartists", aliases=["sa", "sartists"])
async def serverartists(ctx):
    """Top artistas combinados del server. Uso: .sa"""
    if not get_lastfm_user(ctx.author.id):
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset tunombre`", mention_author=False)
        return
    await ctx.message.add_reaction("⏳")
    data = load_data()
    lfm_map = data.get("_lastfm", {})
    artist_counts = {}
    for discord_id_str, lfm_user in lfm_map.items():
        member = ctx.guild.get_member(int(discord_id_str))
        if not member:
            continue
        result = await lastfm_get({"method": "user.gettopartists", "user": lfm_user, "period": "overall", "limit": 50})
        if not result or "error" in result:
            continue
        for a in result.get("topartists", {}).get("artist", []):
            name = a["name"]
            plays = int(a["playcount"])
            artist_counts[name] = artist_counts.get(name, 0) + plays
    await ctx.message.remove_reaction("⏳", ctx.guild.me)
    if not artist_counts:
        await ctx.reply("❌ No hay datos del server.", mention_author=False)
        return
    top = sorted(artist_counts.items(), key=lambda x: x[1], reverse=True)[:10]
    lineas = [f"`{i}.` **{name}** — {plays:,} plays" for i, (name, plays) in enumerate(top, 1)]
    embed = discord.Embed(title=f"🎤 Top artistas de {ctx.guild.name}", description="\n".join(lineas), color=0xd51007)
    embed.set_footer(text=f"{len(lfm_map)} usuarios · overall")
    await ctx.reply(embed=embed, mention_author=False)


