# ── .topcrowns ────────────────────────────────────────────────────────────────

@bot.command(name="topcrowns", aliases=["tc2", "crownlb", "crownleaderboard"])
async def topcrowns(ctx):
    """Ranking de quién tiene más coronas en el server. Uso: .topcrowns"""
    crowns_data = get_crowns_data()
    guild_crowns = crowns_data.get(str(ctx.guild.id), {})
    if not guild_crowns:
        await ctx.reply("👑 Nadie tiene coronas aún. Usa `.wk` para empezar.", mention_author=False)
        return
    counter = {}
    for crown_info in guild_crowns.values():
        did = crown_info["discord_id"]
        counter[did] = counter.get(did, 0) + 1
    top = sorted(counter.items(), key=lambda x: x[1], reverse=True)[:10]
    lineas = []
    for i, (did, count) in enumerate(top, 1):
        member = ctx.guild.get_member(did)
        name = member.display_name if member else f"<@{did}>"
        icon = "👑 " if i == 1 else ""
        lineas.append(f"`{i}.` {icon}**{name}** — {count} corona(s)")
    embed = discord.Embed(
        title=f"👑 Crown Leaderboard — {ctx.guild.name}",
        description="\n".join(lineas),
        color=0xffd700
    )
    embed.set_footer(text=f"{len(guild_crowns)} coronas en total")
    await ctx.reply(embed=embed, mention_author=False)


# ── .overlap ──────────────────────────────────────────────────────────────────

@bot.command(name="overlap", aliases=["ov"])
async def overlap(ctx, member: discord.Member = None, period: str = "overall"):
    """Artistas en común con detalle de plays. Uso: .overlap @usuario [periodo]"""
    u1 = get_lastfm_user(ctx.author.id)
    if not u1:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset tunombre`", mention_author=False)
        return
    if not member:
        await ctx.reply("❌ Menciona a un usuario. Ej: `.overlap @usuario`", mention_author=False)
        return
    u2 = get_lastfm_user(member.id)
    if not u2:
        await ctx.reply(f"❌ {member.display_name} no tiene cuenta vinculada.", mention_author=False)
        return
    await ctx.message.add_reaction("⏳")
    d1, d2 = await asyncio.gather(
        lastfm_get({"method": "user.gettopartists", "user": u1, "period": period, "limit": 500}),
        lastfm_get({"method": "user.gettopartists", "user": u2, "period": period, "limit": 500}),
    )
    await ctx.message.remove_reaction("⏳", ctx.guild.me)
    if not d1 or not d2 or "error" in d1 or "error" in d2:
        await ctx.reply("❌ No pude obtener los datos.", mention_author=False)
        return
    a1 = {a["name"].lower(): (a["name"], int(a["playcount"])) for a in d1.get("topartists", {}).get("artist", [])}
    a2 = {a["name"].lower(): (a["name"], int(a["playcount"])) for a in d2.get("topartists", {}).get("artist", [])}
    common_keys = set(a1.keys()) & set(a2.keys())
    if not common_keys:
        await ctx.reply(f"❌ **{ctx.author.display_name}** y **{member.display_name}** no tienen artistas en común.", mention_author=False)
        return
    common = [(a1[k][0], a1[k][1], a2[k][1]) for k in common_keys]
    common.sort(key=lambda x: x[1] + x[2], reverse=True)
    lineas = [f"`{i}.` **{name}** — {p1:,} / {p2:,}" for i, (name, p1, p2) in enumerate(common[:10], 1)]
    embed = discord.Embed(
        title=f"🔀 Overlap — {ctx.author.display_name} & {member.display_name}",
        description=f"**{len(common_keys)}** artistas en común\n\n" + "\n".join(lineas),
        color=0xd51007
    )
    embed.set_footer(text=f"{ctx.author.display_name}: plays / {member.display_name}: plays · {period_label(period)}")
    await ctx.reply(embed=embed, mention_author=False)


# ── .featured ─────────────────────────────────────────────────────────────────

@bot.command(name="featured", aliases=["feat"])
async def featured(ctx):
    """Artista random del server destacado con stats. Uso: .featured"""
    if not get_lastfm_user(ctx.author.id):
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset tunombre`", mention_author=False)
        return
    import random
    data = load_data()
    lfm_map = data.get("_lastfm", {})
    members_in_server = [(did, u) for did, u in lfm_map.items() if ctx.guild.get_member(int(did))]
    if not members_in_server:
        await ctx.reply("❌ No hay usuarios vinculados en el server.", mention_author=False)
        return
    discord_id_str, lfm_user = random.choice(members_in_server)
    member = ctx.guild.get_member(int(discord_id_str))
    result = await lastfm_get({"method": "user.gettopartists", "user": lfm_user, "period": "overall", "limit": 20})
    if not result or "error" in result:
        await ctx.reply("❌ No pude obtener datos.", mention_author=False)
        return
    artists = result.get("topartists", {}).get("artist", [])
    if not artists:
        await ctx.reply("❌ Sin datos de artistas.", mention_author=False)
        return
    a = random.choice(artists[:10])
    artist_name = a["name"]
    plays = int(a["playcount"])
    info = await lastfm_get({"method": "artist.getinfo", "artist": artist_name, "autocorrect": 1})
    listeners = 0
    tags = []
    artist_url = ""
    if info and "error" not in info:
        art = info.get("artist", {})
        listeners = int(art.get("stats", {}).get("listeners", 0))
        tags = [t["name"] for t in art.get("tags", {}).get("tag", [])[:3]]
        artist_url = art.get("url", "")
    embed = discord.Embed(title=f"⭐ {artist_name}", url=artist_url, color=0xd51007)
    embed.set_author(name=f"Artista destacado de {member.display_name}", icon_url=member.display_avatar.url)
    embed.add_field(name="Plays de este usuario", value=f"{plays:,}", inline=True)
    embed.add_field(name="Listeners globales", value=f"{listeners:,}", inline=True)
    if tags:
        embed.add_field(name="Tags", value=" · ".join(tags), inline=False)
    embed.set_footer(text="Usa .featured de nuevo para otro artista random")
    await ctx.reply(embed=embed, mention_author=False)


