# ── .Tueni4 — CARTA SECRETA STAR ─────────────────────────────────────────────
@bot.command(name="tueni4")
async def tueni4(ctx):
    """⭐ Comando secreto — carta rareza STAR"""
    data = load_data()
    uid = str(ctx.author.id)
    if uid not in data:
        data[uid] = {"cards": [], "last_drop": None, "total_drops": 0, "coins": 100}
    player = data[uid]

    # Solo se puede obtener una vez
    if "star_001" in player["cards"]:
        try:
            await ctx.message.delete()
        except Exception:
            pass
        await ctx.author.send(
            "⭐ Ya tienes la carta **✦ TUENI ✦**... los secretos solo se descubren una vez."
        )
        return

    player["cards"].append("star_001")
    player["username"] = ctx.author.display_name
    save_data(data)

    star_card = next(c for c in CARDS if c["id"] == "star_001")
    embed = card_embed(star_card, ctx.author.display_name)
    embed.description = "✨ *Encontraste algo que casi nadie sabe que existe...*\n\n**🎵 ✦ TUENI ✦** (2026)"

    try:
        await ctx.message.delete()
    except Exception:
        pass

    await ctx.author.send(
        content="⭐ **S  T  A  R** ⭐\nUna carta que no debería existir... y sin embargo aquí está.",
        embed=embed
    )




# ═══════════════════════════════════════════════════════════════════════════════
# ─── IMPORTAR APPLE MUSIC ────────────────────────────────────────────────────
# ═══════════════════════════════════════════════════════════════════════════════

import csv as _csv_module
import zipfile as _zipfile_module
import time as _time_module
import io as _io_module


async def lastfm_scrobble_batch(session_key: str, tracks: list, progress_msg=None) -> tuple:
    """Scroblea una lista de tracks a Last.fm en lotes de 50, con updates de progreso."""
    import hashlib
    BATCH_SIZE = 50
    total_accepted = 0
    total_ignored = 0
    total_batches = (len(tracks) + BATCH_SIZE - 1) // BATCH_SIZE

    for batch_num, i in enumerate(range(0, len(tracks), BATCH_SIZE), 1):
        batch = tracks[i:i + BATCH_SIZE]
        params = {
            "method": "track.scrobble",
            "api_key": LASTFM_API_KEY,
            "sk": session_key,
            "format": "json",
        }
        for j, t in enumerate(batch):
            params[f"artist[{j}]"]    = t["artist"]
            params[f"track[{j}]"]     = t["track"]
            params[f"timestamp[{j}]"] = str(t["timestamp"])
            if t.get("album"):
                params[f"album[{j}]"] = t["album"]

        sig_str = "".join(f"{k}{v}" for k, v in sorted(params.items()) if k != "format")
        sig_str += LASTFM_API_SECRET
        params["api_sig"] = hashlib.md5(sig_str.encode("utf-8")).hexdigest()

        async with aiohttp.ClientSession() as sess:
            async with sess.post(LASTFM_BASE, data=params) as resp:
                try:
                    result = await resp.json(content_type=None)
                except Exception:
                    continue

        scrobbles = result.get("scrobbles", {})
        attr = scrobbles.get("@attr", {})
        total_accepted += int(attr.get("accepted", 0))
        total_ignored  += int(attr.get("ignored", 0))

        # Update progress every 10 batches (500 tracks)
        if progress_msg and batch_num % 10 == 0:
            pct = int((batch_num / total_batches) * 100)
            bar = "█" * (pct // 10) + "░" * (10 - pct // 10)
            try:
                await progress_msg.edit(content=(
                    f"⏳ Importando... `{bar}` {pct}%\n"
                    f"✅ Aceptadas: **{total_accepted:,}** | ⏭️ Ignoradas: **{total_ignored:,}**\n"
                    f"Lote {batch_num:,}/{total_batches:,} ({i + len(batch):,}/{len(tracks):,} canciones)"
                ))
            except Exception:
                pass

        await asyncio.sleep(0.25)

    return total_accepted, total_ignored


def parse_apple_music_csv(content: str) -> list:
    """Parsea el CSV de Apple Music Privacy Export."""
    from datetime import datetime, timezone

    tracks = []
    reader = _csv_module.DictReader(_io_module.StringIO(content))
    fieldnames = reader.fieldnames or []

    col_track = col_artist = col_date = col_album = None
    for f in fieldnames:
        fl = f.lower()
        if "track description" in fl or ("track" in fl and "title" in fl):
            col_track = f
        elif "artist" in fl:
            col_artist = f
        elif "play date" in fl or "date played" in fl:
            col_date = f
        elif "container" in fl or "album" in fl:
            col_album = f

    if not col_track or not col_date:
        return []

    now_ts = int(_time_module.time())
    for row in reader:
        artist   = row.get(col_artist, "").strip()
        track    = row.get(col_track, "").strip()
        album    = row.get(col_album, "").strip() if col_album else ""
        date_str = row.get(col_date, "").strip()

        if not track or not date_str:
            continue

        ts = None
        for fmt in ("%Y-%m-%d %H:%M:%S", "%Y-%m-%d %H:%M", "%Y-%m-%d",
                    "%d/%m/%Y %H:%M:%S", "%d/%m/%Y"):
            try:
                dt = datetime.strptime(date_str, fmt)
                ts = int(dt.replace(tzinfo=timezone.utc).timestamp())
                break
            except ValueError:
                continue
        if ts is None:
            continue
        if ts > now_ts or ts < 1009843200:
            continue

        tracks.append({
            "artist":    artist or "Unknown Artist",
            "track":     track,
            "album":     album,
            "timestamp": ts,
        })

    return tracks


