    try:
        file_bytes = await attachment.read()
    except Exception:
        await processing_msg.edit(content="❌ No pude descargar el archivo. Intenta de nuevo.")
        return

    csv_content = None
    if filename.endswith(".zip"):
        try:
            with _zipfile_module.ZipFile(_io_module.BytesIO(file_bytes)) as z:
                target_names = [
                    n for n in z.namelist()
                    if "play history daily tracks" in n.lower() and n.endswith(".csv")
                ]
                if not target_names:
                    csv_files = [n for n in z.namelist() if n.endswith(".csv")]
                    lista = "\n".join(f"• `{n}`" for n in csv_files[:10]) if csv_files else "*(ningún .csv encontrado)*"
                    await processing_msg.edit(
                        content=(
                            "❌ No encontré `Apple Music - Play History Daily Tracks.csv` en el zip.\n\n"
                            f"**Archivos CSV encontrados:**\n{lista}\n\n"
                            "Prueba subiendo el `.csv` directamente."
                        )
                    )
                    return
                with z.open(target_names[0]) as f:
                    csv_content = f.read().decode("utf-8", errors="replace")
        except _zipfile_module.BadZipFile:
            await processing_msg.edit(content="❌ El zip está corrupto o no es válido.")
            return
    else:
        csv_content = file_bytes.decode("utf-8", errors="replace")

    await processing_msg.edit(content="⏳ Parseando canciones...")
    tracks = parse_apple_music_csv(csv_content)

    if not tracks:
        await processing_msg.edit(
            content=(
                "❌ No pude leer ninguna canción del archivo.\n"
                "Asegúrate de subir `Apple Music - Play History Daily Tracks.csv`."
            )
        )
        return

    total = len(tracks)

    if total > 5000:
        confirm_embed = discord.Embed(
            title="⚠️ Importación grande",
            description=(
                f"Se encontraron **{total:,} scrobbles** para importar.\n\n"
                "Esto puede tardar varios minutos. Reacciona con ✅ para continuar o ❌ para cancelar."
            ),
            color=0xe67e22
        )
        await processing_msg.edit(content=None, embed=confirm_embed)
        await processing_msg.add_reaction("✅")
        await processing_msg.add_reaction("❌")

        def check(reaction, user):
            return (
                user == ctx.author
                and str(reaction.emoji) in ["✅", "❌"]
                and reaction.message.id == processing_msg.id
            )

        try:
            reaction, _ = await bot.wait_for("reaction_add", timeout=60.0, check=check)
        except asyncio.TimeoutError:
            await processing_msg.edit(
                content=None,
                embed=discord.Embed(title="⏰ Tiempo agotado", description="Importación cancelada.", color=0x95a5a6)
            )
            return

        if str(reaction.emoji) == "❌":
            await processing_msg.edit(
                content=None,
                embed=discord.Embed(title="❌ Cancelado", color=0x95a5a6)
            )
            return

    await processing_msg.edit(
        content=None,
        embed=discord.Embed(
            title="🍎 Importando Apple Music...",
            description=f"Enviando **{total:,} scrobbles** a Last.fm. Un momento...",
            color=0xd51007
        )
    )

    try:
        accepted, ignored = await lastfm_scrobble_batch(session_key, tracks, progress_msg=processing_msg)
    except Exception as e:
        await processing_msg.edit(
            content=None,
            embed=discord.Embed(
                title="❌ Error al scroblear",
                description=f"Hubo un problema: `{e}`\n\nIntenta de nuevo más tarde.",
                color=0xe74c3c
            )
        )
        return

    result_embed = discord.Embed(title="✅ Importación completada", color=0x2ecc71)
    result_embed.add_field(name="🍎 Canciones en el archivo", value=f"{total:,}",    inline=True)
    result_embed.add_field(name="✅ Aceptadas por Last.fm",   value=f"{accepted:,}", inline=True)
    result_embed.add_field(name="⏭️ Ignoradas",               value=f"{ignored:,}",  inline=True)
    result_embed.add_field(
        name="ℹ️ ¿Por qué se ignoran algunas?",
        value="Last.fm ignora duplicados, canciones sin artista válido, o scrobbles muy antiguos.",
        inline=False
    )
    result_embed.set_footer(text=f"🎵 last.fm/{username}")
    await processing_msg.edit(content=None, embed=result_embed)




