# ─── IMPORTAR SPOTIFY ────────────────────────────────────────────────────────
# ═══════════════════════════════════════════════════════════════════════════════

def parse_spotify_json(file_bytes: bytes) -> list:
    """
    Parsea los archivos de historial de Spotify del Privacy Export.
    Acepta un solo JSON (StreamingHistory_music_X.json) o un ZIP con varios.
    Devuelve lista de dicts {artist, track, timestamp}.
    """
    import json
    from datetime import datetime, timezone

    entries = []

    # Intentar como ZIP primero
    try:
        with _zipfile_module.ZipFile(_io_module.BytesIO(file_bytes)) as z:
            json_files = [
                n for n in z.namelist()
                if "streaminghistory" in n.lower() and n.endswith(".json")
            ]
            if not json_files:
                # Puede que sea el zip completo de Spotify con carpetas
                json_files = [
                    n for n in z.namelist()
                    if n.lower().endswith(".json") and "streaming" in n.lower()
                ]
            for name in json_files:
                with z.open(name) as f:
                    try:
                        data = json.load(f)
                        entries.extend(data if isinstance(data, list) else [])
                    except Exception:
                        continue
    except _zipfile_module.BadZipFile:
        # No es ZIP, intentar como JSON directo
        try:
            data = json.loads(file_bytes.decode("utf-8", errors="replace"))
            entries = data if isinstance(data, list) else []
        except Exception:
            return []

    if not entries:
        return []

    tracks = []
    now_ts = int(_time_module.time())
    seen_timestamps = {}  # para deduplicar timestamps iguales

    for entry in entries:
        # Spotify usa dos formatos según cuándo pediste los datos:
        # Formato corto (últimos 90 días): endTime, artistName, trackName, msPlayed
        # Formato extendido (historial completo): ts, master_metadata_track_name, master_metadata_album_artist_name, ms_played

        # Detectar formato
        if "master_metadata_track_name" in entry:
            # Formato extendido
            track  = (entry.get("master_metadata_track_name") or "").strip()
            artist = (entry.get("master_metadata_album_artist_name") or "").strip()
            album  = (entry.get("master_metadata_album_album_name") or "").strip()
            date_str = entry.get("ts", "")
        else:
            # Formato corto
            track  = (entry.get("trackName") or "").strip()
            artist = (entry.get("artistName") or "").strip()
            album  = ""
            date_str = entry.get("endTime", "")

        if not track or not artist or not date_str:
            continue

        # Filtro de tiempo mínimo bajado a 10 segundos (antes 30s)
        ms_played = entry.get("msPlayed") or entry.get("ms_played") or 0
        if ms_played < 10000:
            continue

        # Parsear fecha — intentar más formatos
        ts = None
        for fmt in ("%Y-%m-%dT%H:%M:%SZ", "%Y-%m-%d %H:%M", "%Y-%m-%dT%H:%M:%S", "%Y-%m-%dT%H:%M:%S.%fZ"):
            try:
                dt = datetime.strptime(date_str[:26], fmt)
                ts = int(dt.replace(tzinfo=timezone.utc).timestamp())
                break
            except ValueError:
                continue
        if ts is None:
            continue
        if ts > now_ts or ts < 946684800:  # desde año 2000 (antes 2002)
            continue

        # Deduplicar timestamps: si ya hay una canción en ese segundo, sumar 1s
        key = ts
        while key in seen_timestamps:
            key += 1
        seen_timestamps[key] = True
        ts = key

        tracks.append({
            "artist":    artist,
            "track":     track,
            "album":     album,
            "timestamp": ts,
        })

    # Ordenar por timestamp ascendente para que Last.fm los procese en orden
    tracks.sort(key=lambda x: x["timestamp"])
    return tracks


