# ─── GENIUS HELPER ───────────────────────────────────────────────────────────

GENIUS_TOKEN = ""  # ← Pon tu Genius API token aquí (gratis en genius.com/api-clients)

async def _genius_search(artist: str, title: str) -> str | None:
    """Busca la URL de la letra en Genius. Devuelve la URL o None."""
    if not GENIUS_TOKEN:
        return None
    import aiohttp
    headers = {"Authorization": f"Bearer {GENIUS_TOKEN}"}
    query = f"{artist} {title}"
    async with aiohttp.ClientSession() as session:
        async with session.get(
            "https://api.genius.com/search",
            params={"q": query},
            headers=headers,
            timeout=aiohttp.ClientTimeout(total=8)
        ) as resp:
            if resp.status != 200:
                return None
            data = await resp.json()
    hits = data.get("response", {}).get("hits", [])
    if not hits:
        return None
    return hits[0]["result"]["url"]

async def _fetch_lyrics(genius_url: str) -> str | None:
    """Scrapea la letra desde la página de Genius (primeras ~30 líneas)."""
    import aiohttp
    try:
        async with aiohttp.ClientSession() as session:
            async with session.get(genius_url, timeout=aiohttp.ClientTimeout(total=10)) as resp:
                if resp.status != 200:
                    return None
                html = await resp.text()
    except Exception:
        return None
    # Buscar los bloques de letra en el HTML
    lyrics_blocks = re.findall(r'<div data-lyrics-container="true"[^>]*>(.*?)</div>', html, re.DOTALL)
    if not lyrics_blocks:
        return None
    raw = " ".join(lyrics_blocks)
    # Limpiar HTML básico
    text = re.sub(r'<br\s*/?>', "\n", raw)
    text = re.sub(r'<[^>]+>', "", text)
    text = re.sub(r'\[.*?\]', "", text)  # quitar [Chorus], [Verse], etc.
    text = re.sub(r'\n{3,}', "\n\n", text).strip()
    lines = [l for l in text.splitlines() if l.strip()]
    # Devolver las primeras 25 líneas para no hacer el embed enorme
    return "\n".join(lines[:25]) + ("\n…" if len(lines) > 25 else "")


# ─── .lyrics ─────────────────────────────────────────────────────────────────

@bot.command(name="lyrics", aliases=["ly"])
async def lyrics_cmd(ctx, *, query: str = None):
    """Letra de lo que estás escuchando. Uso: .lyrics [artista | canción]"""
    username = get_lastfm_user(ctx.author.id)
    if not username:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset`", mention_author=False)
        return

    if query and "|" in query:
        parts = [p.strip() for p in query.split("|", 1)]
        artist_name, track_name = parts[0], parts[1]
    elif query:
        artist_name, track_name = None, query
        np_data = await lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 1})
        if np_data and "error" not in np_data:
            tracks = np_data.get("recenttracks", {}).get("track", [])
            if tracks:
                t = tracks[0] if isinstance(tracks, list) else tracks
                a = t.get("artist", {})
                artist_name = ((a.get("name") or a.get("#text") or "") if isinstance(a, dict) else str(a)).strip()
        if not artist_name:
            await ctx.reply("❌ No pude detectar el artista. Usa `.lyrics artista | canción`", mention_author=False)
            return
    else:
        np_data = await lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 1})
        if not np_data or "error" in np_data:
            await ctx.reply("❌ No pude conectar con Last.fm.", mention_author=False)
            return
        tracks = np_data.get("recenttracks", {}).get("track", [])
        if not tracks:
            await ctx.reply("❌ No hay scrobbles recientes.", mention_author=False)
            return
        t = tracks[0] if isinstance(tracks, list) else tracks
        a = t.get("artist", {})
        artist_name = ((a.get("name") or a.get("#text") or "") if isinstance(a, dict) else str(a)).strip()
        track_name  = t.get("name", "").strip()

    if not artist_name or not track_name:
        await ctx.reply("❌ No pude detectar la canción. Usa `.lyrics artista | canción`", mention_author=False)
        return

    if not GENIUS_TOKEN:
        # Sin token: solo enlazar a Genius en vez de mostrar letra
        query_enc = f"{artist_name} {track_name}".replace(" ", "%20")
        genius_search = f"https://genius.com/search?q={query_enc}"
        embed = discord.Embed(
            title=f"🎤 {track_name}",
            description=f"**{artist_name}**\n\n[Ver letra en Genius]({genius_search})",
            color=0xffff64
        )
        embed.set_footer(text="💡 Configura GENIUS_TOKEN en el bot para ver letras directamente")
        await ctx.reply(embed=embed, mention_author=False)
        return

    await ctx.message.add_reaction("⏳")
    genius_url = await _genius_search(artist_name, track_name)
    await ctx.message.remove_reaction("⏳", ctx.guild.me)

    if not genius_url:
        await ctx.reply(f"❌ No encontré letra para **{track_name}** de {artist_name} en Genius.", mention_author=False)
        return

    lyrics = await _fetch_lyrics(genius_url)
    if not lyrics:
        embed = discord.Embed(
            title=f"🎤 {track_name}",
            description=f"**{artist_name}**\n\n[Ver letra completa en Genius]({genius_url})",
            color=0xffff64
        )
        await ctx.reply(embed=embed, mention_author=False)
        return

    embed = discord.Embed(
        title=f"🎤 {track_name}",
        description=f"**{artist_name}**\n\n{lyrics}",
        color=0xffff64
    )
    embed.add_field(name="", value=f"[Ver completa en Genius]({genius_url})", inline=False)
    embed.set_footer(text=lfm_footer(username))
    await ctx.reply(embed=embed, mention_author=False)


# ─── HELPER: primer scrobble de un artista ────────────────────────────────────
# user.getartisttracks fue eliminado de la API pública de Last.fm.
# La alternativa es ir a la última página de user.getrecenttracks y filtrar
# por artista. Last.fm permite hasta 200 tracks por página y devuelve el
# total de páginas, así que vamos directo a la última y buscamos el hit.

async def _get_first_scrobble(username: str, artist_name: str) -> tuple[datetime | None, str | None]:
    """
    Devuelve (primera_fecha, primera_canción) del artista para ese usuario.
    Estrategia: ir a la última página de recenttracks y buscar el track más
    antiguo que coincida con el artista (comparación case-insensitive).
    Si en la última página no hay coincidencia, busca en las anteriores
    (hacia atrás) hasta encontrarla o agotar 5 páginas extra.
    """
    artist_lower = artist_name.lower()

    # 1. Saber cuántas páginas hay en total
    first_page = await lastfm_get({
        "method": "user.getrecenttracks",
        "user": username,
        "limit": 200,
        "page": 1,
    })
    if not first_page or "error" in first_page:
        return None, None

    total_pages = int(first_page.get("recenttracks", {}).get("@attr", {}).get("totalPages", 1))

    # 2. Iterar desde la última página hacia atrás buscando el artista
    found_date  = None
    found_track = None

    for offset in range(min(6, total_pages)):   # máx 6 páginas extra por velocidad
        page_num = total_pages - offset
        if page_num < 1:
            break

        data = await lastfm_get({
            "method": "user.getrecenttracks",
            "user": username,
            "limit": 200,
            "page": page_num,
        })
        if not data or "error" in data:
            continue

        tracks = data.get("recenttracks", {}).get("track", [])
        if not isinstance(tracks, list):
            tracks = [tracks]

        # En la última página los tracks están ordenados del más reciente al
        # más antiguo, así que el candidato más antiguo es el último de la lista
        # que coincida con el artista.
        for t in reversed(tracks):
            if t.get("@attr", {}).get("nowplaying"):
                continue
            a = t.get("artist", {})
            a_name = ((a.get("name") or a.get("#text") or "") if isinstance(a, dict) else str(a)).strip()
            if a_name.lower() == artist_lower:
                ts = t.get("date", {}).get("uts")
                if ts:
                    candidate = datetime.fromtimestamp(int(ts), tz=timezone.utc)
                    # Quedarnos con el más antiguo encontrado
                    if found_date is None or candidate < found_date:
                        found_date  = candidate
                        found_track = t.get("name", "?")

        # Si encontramos algo en esta página y ya estamos en la última, listo
        if found_date and offset == 0:
            break
        # Si encontramos algo y la página anterior ya no tendría más del artista,
        # podemos parar (heurística: si encontramos ≥1 hit, buscar 1 página más)
        if found_date and offset >= 1:
            break

    return found_date, found_track


# ─── .discoveries ─────────────────────────────────────────────────────────────

@bot.command(name="discoveries", aliases=["disc", "discovered"])
async def discoveries_cmd(ctx, member: discord.Member = None):
    """Cuándo escuchaste por primera vez tus artistas más escuchados. Uso: .discoveries [@usuario]"""
    target   = member or ctx.author
    username = get_lastfm_user(target.id)
    if not username:
        msg = "❌ No tienes cuenta vinculada. Usa `.fmset`" if target == ctx.author else f"❌ {target.display_name} no tiene cuenta vinculada."
        await ctx.reply(msg, mention_author=False)
        return

    await ctx.message.add_reaction("⏳")

    top_data = await lastfm_get({"method": "user.gettopartists", "user": username, "period": "overall", "limit": 10})
    if not top_data or "error" in top_data:
        await ctx.message.remove_reaction("⏳", ctx.guild.me)
        await ctx.reply("❌ No pude obtener los datos de Last.fm.", mention_author=False)
        return

    artists = top_data.get("topartists", {}).get("artist", [])
    if not artists:
        await ctx.message.remove_reaction("⏳", ctx.guild.me)
        await ctx.reply("❌ Sin artistas registrados.", mention_author=False)
        return

    lines = []
    for artist in artists[:8]:
        name  = artist["name"]
        plays = int(artist["playcount"])
        first_date, _ = await _get_first_scrobble(username, name)
        date_str = first_date.strftime("%d %b %Y") if first_date else "desconocido"
        lines.append(f"**{name}** — {plays:,} plays\n-# 🗓 Primera vez: {date_str}")

    await ctx.message.remove_reaction("⏳", ctx.guild.me)

    embed = discord.Embed(
        title=f"🔍 Descubrimientos de {target.display_name}",
        description="\n\n".join(lines) if lines else "Sin datos",
        color=0xd51007
    )
    embed.set_footer(text=lfm_footer(username) + " • Top 8 artistas")
    await ctx.reply(embed=embed, mention_author=False)


# ─── .discoverydate ───────────────────────────────────────────────────────────

@bot.command(name="discoverydate", aliases=["dd", "firstlisten"])
async def discoverydate_cmd(ctx, *, artist_query: str = None):
    """Cuándo escuchaste por primera vez a un artista. Uso: .dd artista"""
    username = get_lastfm_user(ctx.author.id)
    if not username:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset`", mention_author=False)
        return

    if not artist_query:
        np_data = await lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 1})
        if not np_data or "error" in np_data:
            await ctx.reply("❌ Pon el nombre del artista: `.dd artista`", mention_author=False)
            return
        tracks = np_data.get("recenttracks", {}).get("track", [])
        if not tracks:
            await ctx.reply("❌ Sin scrobbles recientes. Pon el artista: `.dd artista`", mention_author=False)
            return
        t = tracks[0] if isinstance(tracks, list) else tracks
        a = t.get("artist", {})
        artist_query = ((a.get("name") or a.get("#text") or "") if isinstance(a, dict) else str(a)).strip()

    await ctx.message.add_reaction("⏳")

    # Info del artista (nombre real + plays del usuario + imagen)
    info_data = await lastfm_get({
        "method": "artist.getinfo",
        "artist": artist_query,
        "username": username,
        "autocorrect": 1,
    })
    real_name = artist_query
    userplays  = 0
    if info_data and "error" not in info_data:
        real_name = info_data.get("artist", {}).get("name", artist_query)
        userplays = int(info_data.get("artist", {}).get("stats", {}).get("userplaycount", 0))

    if userplays == 0:
        await ctx.message.remove_reaction("⏳", ctx.guild.me)
        await ctx.reply(f"❌ No tienes scrobbles de **{real_name}**.", mention_author=False)
        return

    # Buscar primer scrobble
    first_date, first_track = await _get_first_scrobble(username, real_name)

    await ctx.message.remove_reaction("⏳", ctx.guild.me)

    # Imagen del artista
    img = None
    if info_data and "error" not in info_data:
        imgs = info_data.get("artist", {}).get("image", [])
        img  = next((i["#text"] for i in reversed(imgs) if i.get("#text")), None)
        img  = _clean_lfm_image(img)
    color = await get_dominant_color(img) if img else 0xd51007

    embed = discord.Embed(title=f"🔍 Primera vez que escuchaste a {real_name}", color=color)
    embed.set_author(name=ctx.author.display_name, icon_url=ctx.author.display_avatar.url)

    if first_date:
        days_ago = (datetime.now(timezone.utc) - first_date).days
        embed.add_field(name="📅 Fecha",            value=first_date.strftime("%d %B %Y"), inline=True)
        embed.add_field(name="⏳ Hace",             value=f"{days_ago:,} días",            inline=True)
        if first_track:
            embed.add_field(name="🎵 Primera canción", value=first_track, inline=True)
    else:
        embed.description = "No pude determinar la fecha exacta (historial muy largo o artista sin scrobbles recientes en las últimas páginas)."

    embed.add_field(name="📻 Total de plays", value=f"{userplays:,}", inline=True)
    if img:
        embed.set_thumbnail(url=img)
    embed.set_footer(text=lfm_footer(username))
    await ctx.reply(embed=embed, mention_author=False)


# ─── .gaps ────────────────────────────────────────────────────────────────────

@bot.command(name="gaps", aliases=["rediscovered", "gap"])
async def gaps_cmd(ctx, member: discord.Member = None):
    """Artistas que dejaste de escuchar y retomaste. Uso: .gaps [@usuario]"""
    target = member or ctx.author
    username = get_lastfm_user(target.id)
    if not username:
        msg = "❌ No tienes cuenta vinculada. Usa `.fmset`" if target == ctx.author else f"❌ {target.display_name} no tiene cuenta vinculada."
        await ctx.reply(msg, mention_author=False)
        return

    await ctx.message.add_reaction("⏳")

    # Comparar top artistas del último mes vs últimos 12 meses
    # Los que están en top del mes pero no en top de 3 meses son redescubrimientos
    month_data, year_data = await asyncio.gather(
        lastfm_get({"method": "user.gettopartists", "user": username, "period": "1month",  "limit": 50}),
        lastfm_get({"method": "user.gettopartists", "user": username, "period": "3month", "limit": 50}),
    )

    await ctx.message.remove_reaction("⏳", ctx.guild.me)

    if not month_data or not year_data:
        await ctx.reply("❌ No pude obtener los datos.", mention_author=False)
        return

    month_artists  = {a["name"].lower(): (a["name"], int(a["playcount"])) for a in month_data.get("topartists", {}).get("artist", [])}
    year_artists   = {a["name"].lower() for a in year_data.get("topartists", {}).get("artist", [])}

    # Redescubrimientos: están en top del mes pero NO en top de 3 meses
    gaps = [(name, plays) for key, (name, plays) in month_artists.items() if key not in year_artists]
    gaps.sort(key=lambda x: x[1], reverse=True)

    if not gaps:
        await ctx.reply(
            f"🔍 **{target.display_name}** no tiene redescubrimientos recientes — "
            "todos tus artistas del último mes también los escuchabas en los últimos 3 meses.",
            mention_author=False
        )
        return

    lines = [f"`{i}.` **{name}** — {plays:,} plays este mes 🔄" for i, (name, plays) in enumerate(gaps[:10], 1)]

    embed = discord.Embed(
        title=f"🔄 Redescubrimientos de {target.display_name}",
        description="Artistas que volviste a escuchar este mes después de un tiempo:\n\n" + "\n".join(lines),
        color=0xd51007
    )
    embed.set_footer(text=lfm_footer(username) + " • No aparecían en tus top de últimos 3 meses")
    await ctx.reply(embed=embed, mention_author=False)


# ─── .jumble (adivina la canción con letras mezcladas) ────────────────────────

def _jumble_word(word: str) -> str:
    """Mezcla las letras de una palabra (sin tocar chars especiales cortos)."""
    if len(word) <= 2:
        return word
    letters = list(word)
    random.shuffle(letters)
    return "".join(letters)

def _jumble_title(title: str) -> str:
    """Mezcla las letras de cada palabra del título."""
    words = title.split()
    return " ".join(_jumble_word(w) for w in words)

# Sesiones activas: {channel_id: {answer, artist, timeout_task}}
_jumble_active: dict[int, dict] = {}

@bot.command(name="jumble", aliases=["jmb", "jb"])
async def jumble_cmd(ctx):
    """Adivina la canción con sus letras mezcladas. Uso: .jumble"""
    username = get_lastfm_user(ctx.author.id)
    if not username:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset`", mention_author=False)
        return

    channel_id = ctx.channel.id
    if channel_id in _jumble_active:
        old = _jumble_active[channel_id]
        await ctx.reply(
            f"⚠️ Ya hay un jumble activo en este canal. La respuesta era: **{old['answer']}** de {old['artist']}",
            mention_author=False
        )
        if old.get("timeout_task"):
            old["timeout_task"].cancel()
        del _jumble_active[channel_id]

    await ctx.message.add_reaction("⏳")

    # Obtener top tracks del usuario
    data = await lastfm_get({"method": "user.gettoptracks", "user": username, "period": "overall", "limit": 100})
    await ctx.message.remove_reaction("⏳", ctx.guild.me)

    if not data or "error" in data:
        await ctx.reply("❌ No pude obtener tus canciones de Last.fm.", mention_author=False)
        return

    tracks = data.get("toptracks", {}).get("track", [])
    if not tracks:
        await ctx.reply("❌ Sin canciones en tu historial.", mention_author=False)
        return

    # Elegir una canción aleatoria (preferir las que tienen nombre interesante)
    eligible = [t for t in tracks if len(t["name"]) > 4 and " " in t["name"]]
    if not eligible:
        eligible = tracks
    pick = random.choice(eligible)
    answer  = pick["name"]
    artist  = pick["artist"]["name"]
    jumbled = _jumble_title(answer)

    # Guardar sesión
    async def _timeout_jumble():
        await asyncio.sleep(30)
        if channel_id in _jumble_active and _jumble_active[channel_id]["answer"] == answer:
            del _jumble_active[channel_id]
            await ctx.channel.send(
                f"⏰ **¡Tiempo!** Nadie adivinó. La respuesta era: **{answer}** de {artist}"
            )

    task = asyncio.create_task(_timeout_jumble())
    _jumble_active[channel_id] = {"answer": answer.lower(), "artist": artist, "timeout_task": task}

    embed = discord.Embed(
        title="🔀 ¡JUMBLE!",
        description=f"Adivina el nombre de la canción:\n\n## `{jumbled}`\n\n**Artista:** {artist}",
        color=0x6c5ce7
    )
    embed.set_footer(text="Escribe el nombre correcto en el chat • 30 segundos")
    await ctx.reply(embed=embed, mention_author=False)


@bot.listen("on_message")
async def jumble_listener(message: discord.Message):
    """Escucha respuestas al jumble activo."""
    if message.author.bot:
        return
    channel_id = message.channel.id
    session = _jumble_active.get(channel_id)
    if not session:
        return
    # Ignorar comandos del bot
    if message.content.startswith(bot.command_prefix if isinstance(bot.command_prefix, str) else tuple(bot.command_prefix)):
        return
    guess = message.content.strip().lower()
    if guess == session["answer"]:
        if session.get("timeout_task"):
            session["timeout_task"].cancel()
        del _jumble_active[channel_id]
        embed = discord.Embed(
            title="🎉 ¡Correcto!",
            description=f"{message.author.mention} adivinó: **{session['answer'].title()}** de {session['artist']}",
            color=0x2ecc71
        )
        await message.reply(embed=embed, mention_author=False)


# ─── .pixel (adivina el álbum por la portada pixelada) ───────────────────────

async def _pixelate_image_bytes(image_url: str, pixel_size: int = 32) -> bytes | None:
    """Descarga la imagen y la pixela. Devuelve bytes PNG o None."""
    import aiohttp
    try:
        from PIL import Image as _PILImage
        async with aiohttp.ClientSession() as session:
            async with session.get(image_url, timeout=aiohttp.ClientTimeout(total=8)) as resp:
                if resp.status != 200:
                    return None
                img_bytes = await resp.read()
        img = _PILImage.open(io.BytesIO(img_bytes)).convert("RGB")
        # Pixelar: reducir a minúsculo y escalar de vuelta
        small = img.resize((pixel_size, pixel_size), _PILImage.BILINEAR)
        pixelated = small.resize(img.size, _PILImage.NEAREST)
        out = io.BytesIO()
        pixelated.save(out, format="PNG")
        out.seek(0)
        return out.read()
    except Exception:
        return None

# Sesiones activas de pixel: {channel_id: {answer, artist, image_url, timeout_task}}
_pixel_active: dict[int, dict] = {}

@bot.command(name="pixel", aliases=["px", "pixelgame"])
async def pixel_cmd(ctx):
    """Adivina el álbum por su portada pixelada. Uso: .pixel"""
    username = get_lastfm_user(ctx.author.id)
    if not username:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset`", mention_author=False)
        return

    channel_id = ctx.channel.id
    if channel_id in _pixel_active:
        old = _pixel_active[channel_id]
        await ctx.reply(
            f"⚠️ Ya hay un pixel activo. La respuesta era: **{old['answer']}** de {old['artist']}",
            mention_author=False
        )
        if old.get("timeout_task"):
            old["timeout_task"].cancel()
        del _pixel_active[channel_id]

    await ctx.message.add_reaction("⏳")

    # Obtener top álbumes del usuario
    data = await lastfm_get({"method": "user.gettopalbums", "user": username, "period": "overall", "limit": 100})
    if not data or "error" in data:
        await ctx.message.remove_reaction("⏳", ctx.guild.me)
        await ctx.reply("❌ No pude obtener tus álbumes.", mention_author=False)
        return

    albums = data.get("topalbums", {}).get("album", [])
    if not albums:
        await ctx.message.remove_reaction("⏳", ctx.guild.me)
        await ctx.reply("❌ Sin álbumes en tu historial.", mention_author=False)
        return

    # Buscar un álbum con imagen
    eligible = []
    for alb in albums:
        img = next((i["#text"] for i in alb.get("image", []) if i.get("size") == "extralarge" and i.get("#text")), None)
        img = _clean_lfm_image(img)
        if img:
            eligible.append((alb["name"], alb["artist"]["name"], img))

    if not eligible:
        await ctx.message.remove_reaction("⏳", ctx.guild.me)
        await ctx.reply("❌ No encontré álbumes con portada.", mention_author=False)
        return

    answer_album, artist, image_url = random.choice(eligible)

    # Pixelar la imagen
    pixel_bytes = await _pixelate_image_bytes(image_url, pixel_size=16)
    await ctx.message.remove_reaction("⏳", ctx.guild.me)

    if not pixel_bytes:
        await ctx.reply("❌ No pude descargar la portada. Intenta de nuevo.", mention_author=False)
        return

    # Timeout de 30 segundos
    async def _timeout_pixel():
        await asyncio.sleep(30)
        if channel_id in _pixel_active and _pixel_active[channel_id]["answer"] == answer_album.lower():
            del _pixel_active[channel_id]
            await ctx.channel.send(
                f"⏰ **¡Tiempo!** La respuesta era: **{answer_album}** de {artist}"
            )

    task = asyncio.create_task(_timeout_pixel())
    _pixel_active[channel_id] = {
        "answer": answer_album.lower(),
        "artist": artist,
        "image_url": image_url,
        "timeout_task": task,
    }

    file = discord.File(io.BytesIO(pixel_bytes), filename="pixel.png")
    embed = discord.Embed(
        title="🖼️ ¡PIXEL! ¿Qué álbum es?",
        description=f"**Artista:** {artist}\n\nEscribe el nombre del álbum en el chat",
        color=0x6c5ce7
    )
    embed.set_image(url="attachment://pixel.png")
    embed.set_footer(text="30 segundos para adivinar")
    await ctx.reply(embed=embed, file=file, mention_author=False)


