# ─── HOOK EN .np PARA AÑADIR REACCIONES AUTOMÁTICAS ─────────────────────────
# Pega esta función DENTRO del comando .np existente, al final, antes del return
# O usa este listener que detecta los embeds del bot en el canal:

@bot.listen("on_message")
async def auto_reactions_listener(message: discord.Message):
    """Añade reacciones automáticas a los .np del usuario si las tiene configuradas."""
    if message.author.id != bot.user.id:
        return
    if not message.embeds:
        return
    emb = message.embeds[0]
    # Solo reaccionar a embeds de .np (tienen footer con last.fm/)
    if not emb.footer or not emb.footer.text or "last.fm/" not in emb.footer.text:
        return
    # Detectar a quién es el np mirando el reference del mensaje original
    # Como el bot hace reply, el reference apunta al autor real
    if not message.reference:
        return
    try:
        ref = message.reference.resolved
        if ref is None:
            return
        original_author_id = str(ref.author.id)
        reactions_data = _load_reactions()
        emojis = reactions_data.get(original_author_id, [])
        for emoji in emojis:
            try:
                await message.add_reaction(emoji)
            except Exception:
                pass
    except Exception:
        pass


