# .listeners — cuántos del server escuchan X artista
# ═══════════════════════════════════════════════════════════════════════════════

@bot.command(name="listeners", aliases=["ls", "serverlisteners"])
async def listeners_cmd(ctx, *, artist_query: str = None):
    """
    Cuántos del server escuchan un artista + stats globales.
    Uso: .listeners artista
    """
    username = get_lastfm_user(ctx.author.id)
    if not username:
        await ctx.reply("❌ No tienes cuenta vinculada. Usa `.fmset`", mention_author=False)
        return

    if not artist_query:
        # Usar el artista actual del np
        np_data = await lastfm_get({"method": "user.getrecenttracks", "user": username, "limit": 1})
        if not np_data or "error" in np_data:
            await ctx.reply("❌ Pon el artista: `.listeners artista`", mention_author=False)
            return
        tracks = np_data.get("recenttracks", {}).get("track", [])
        if not tracks:
            await ctx.reply("❌ Sin scrobbles recientes. Pon: `.listeners artista`", mention_author=False)
            return
        t = tracks[0] if isinstance(tracks, list) else tracks
        a = t.get("artist", {})
        artist_query = ((a.get("name") or a.get("#text") or "") if isinstance(a, dict) else str(a)).strip()

    await ctx.message.add_reaction("⏳")

    # Info global del artista
    global_info = await lastfm_get({"method": "artist.getinfo", "artist": artist_query, "autocorrect": 1})
    real_name      = artist_query
    global_listeners = 0
    global_plays     = 0
    img_url          = None

    if global_info and "error" not in global_info:
        art = global_info.get("artist", {})
        real_name        = art.get("name", artist_query)
        stats            = art.get("stats", {})
        global_listeners = int(stats.get("listeners", 0))
        global_plays     = int(stats.get("playcount", 0))
        imgs = art.get("image", [])
        img_url = next((i["#text"] for i in reversed(imgs) if i.get("#text")), None)
        img_url = _clean_lfm_image(img_url)

    # Buscar en el server (igual que .whoknows pero más simple)
    data = load_data()
    lfm_map = data.get("_lastfm", {})
    server_results = []

    tasks = []
    members_lfm = []
    for uid_str, lfm_user in lfm_map.items():
        m = ctx.guild.get_member(int(uid_str))
        if m:
            members_lfm.append((m, lfm_user))
            tasks.append(lastfm_get({
                "method": "artist.getinfo",
                "artist": real_name,
                "username": lfm_user,
                "autocorrect": 1,
            }))

    results = await asyncio.gather(*tasks)
    await ctx.message.remove_reaction("⏳", ctx.guild.me)

    for (member, lfm_user), result in zip(members_lfm, results):
        if result and "error" not in result:
            plays = int(result.get("artist", {}).get("stats", {}).get("userplaycount", 0))
            if plays > 0:
                server_results.append((member, lfm_user, plays))

    server_results.sort(key=lambda x: x[2], reverse=True)

    color = await get_dominant_color(img_url) if img_url else 0xd51007

    embed = discord.Embed(
        title=f"🎤 {real_name}",
        color=color
    )
    if img_url:
        embed.set_thumbnail(url=img_url)

    # Stats globales
    embed.add_field(
        name="🌍 Global",
        value=f"👥 {global_listeners:,} oyentes\n🎵 {global_plays:,} plays",
        inline=True
    )

    # Stats del server
    embed.add_field(
        name=f"🏠 {ctx.guild.name}",
        value=f"👥 **{len(server_results)}** oyentes\n🎵 {sum(x[2] for x in server_results):,} plays en total",
        inline=True
    )

    if server_results:
        lines = []
        for i, (member, lfm_user, plays) in enumerate(server_results[:8], 1):
            crown = "👑 " if i == 1 else ""
            lines.append(f"`{i}.` {crown}**{member.display_name}** — {plays:,}")
        embed.add_field(name="🏆 Ranking del server", value="\n".join(lines), inline=False)
    else:
        embed.add_field(name="🏠 Server", value="Nadie en el server ha escuchado a este artista.", inline=False)

    embed.set_footer(text=f"Fuente: Last.fm • {ctx.guild.name}")
    await ctx.reply(embed=embed, mention_author=False)


