_cover_cache: dict = {}

async def _fetch_era_cover(era: str) -> str | None:
    """Busca el cover del era/album en Last.fm. Retorna URL o None."""
    key = _normalize(era)
    if key in _cover_cache:
        return _cover_cache[key]

    # Buscar match en el mapa (parcial)
    pair = None
    for era_key, val in _ERA_TO_ALBUM.items():
        if era_key in key or key in era_key:
            pair = val
            break

    if not pair:
        _cover_cache[key] = None
        return None

    artist, album = pair
    try:
        data = await lastfm_get({"method": "album.getinfo", "artist": artist, "album": album, "autocorrect": 1})
        if data and "error" not in data:
            imgs = data.get("album", {}).get("image", [])
            url  = next((i["#text"] for i in reversed(imgs) if i.get("#text")), None)
            url  = _clean_lfm_image(url) if url else None
            _cover_cache[key] = url
            return url
    except Exception:
        pass

    _cover_cache[key] = None
    return None


import urllib.request as _urlreq

def _load_csv(local_path: str, github_url: str) -> str:
    """Carga un CSV: primero local, luego GitHub."""
    import os as _o
    # Intentar rutas locales
    for path in [local_path, _o.path.join(_o.getcwd(), _o.path.basename(local_path)), _o.path.basename(local_path)]:
        if _o.path.exists(path):
            print(f"[TRACKER] Cargando local: {path}")
            with open(path, encoding="utf-8") as f:
                return f.read()
    # Descargar desde GitHub
    print(f"[TRACKER] Descargando: {github_url}")
    try:
        with _urlreq.urlopen(github_url, timeout=30) as r:
            data = r.read().decode("utf-8")
            print(f"[TRACKER] Descargado OK: {len(data)} bytes")
            return data
    except Exception as e:
        print(f"[TRACKER] ERROR descargando {github_url}: {e}")
        return ""

# CARTI TRACKER — Pega este bloque ANTES de bot.run(TOKEN)
#
# Comandos:
#   .carti <nombre>        — resultado rápido (disponibilidad + tipo + era)
#   .carti <nombre> link   — solo el link + fecha + calidad
#   .carti <nombre> info   — ficha completa con todo
#   .carti era <era>       — canciones de una era (con botones)
#   .carti grails          — grails 🏆 (con botones)
#   .carti best            — Best Of ⭐ (con botones)
#   .carti stats           — estadísticas generales
# ═══════════════════════════════════════════════════════════════════════════════

import csv        as _csv
import io         as _io
import os         as _os
import re         as _re
import unicodedata as _ud

CARTI_CSV_PATH = next((p for p in [_os.path.join(_os.path.dirname(__file__), "tracker.csv"), _os.path.join(_os.getcwd(), "tracker.csv"), "tracker.csv"] if _os.path.exists(p)), "tracker.csv")

# ─── PARSER ────────────────────────────────────────────────────────────────────
def _load_carti_songs():
    raw = _load_csv(CARTI_CSV_PATH, "https://raw.githubusercontent.com/tapepink21-gif/UG-CARTAS-2/main/tracker.csv")
    if not raw:
        return []

    valid_types = {
        "OG", "Demo", "Throwaway", "Alt Mix", "Remix", "Feature",
        "OG File", "Freestyle", "Unknown", "Album Track",
        "Snippet", "High Bitrate Rip", "Scrapped Release",
        "Album/Zip", "Beat", "Lost", "Other", "Production",
        "Ref Track", "Session", "Stem Edit", "Tour Intro",
        "OG/High Bitrate Rip", "N/A",
    }

    songs = []
    for row in _csv.reader(_io.StringIO(raw)):
        if len(row) < 7:
            continue
        era       = row[0].strip().replace("\n", " ")
        name      = row[1].strip().replace("\n", " ")
        notes     = row[2].strip().replace("\n", " ")[:600] if len(row) > 2 else ""
        length    = row[3].strip() if len(row) > 3 else ""
        leak_date = row[4].strip() if len(row) > 4 else ""
        file_date = row[5].strip() if len(row) > 5 else ""
        typ       = row[6].strip() if len(row) > 6 else ""
        available = row[7].strip() if len(row) > 7 else ""
        quality   = row[8].strip() if len(row) > 8 else ""
        link      = row[9].strip() if len(row) > 9 else ""

        if not era or not name or len(name) > 150:
            continue
        if "Total Full" in era:
            continue
        if typ not in valid_types and not any(t in typ for t in valid_types):
            continue

        is_best    = "⭐" in name
        is_grail   = "🏆" in name
        is_special = "✨" in name
        is_wanted  = "🥉" in name
        is_worst   = "🗑️" in name

        clean_name = _re.sub(r'^[⭐✨🏆🥉🗑️🤖️\s]+', '', name).strip()
        if not clean_name:
            continue

        # Extraer alias reales (entre paréntesis, sin prod./feat./with)
        _alias_raw = _re.findall(r'\(([^)]+)\)', clean_name)
        aliases = []
        for _a in _alias_raw:
            if not _re.match(r'(?i)^(prod|feat|ft|with|perf|og |aka)\.?', _a.strip()):
                # Puede haber varios separados por coma dentro del paréntesis
                aliases += [x.strip() for x in _a.split(',') if x.strip()]

        songs.append({
            "era":        era,
            "name":       clean_name,
            "aliases":    aliases,
            "notes":      notes,
            "length":     length    or "N/A",
            "leak_date":  leak_date or "N/A",
            "file_date":  file_date or "N/A",
            "type":       typ       or "Unknown",
            "available":  available or "N/A",
            "quality":    quality   or "N/A",
            "link":       link if link and link.startswith("http") else None,
            "is_grail":   is_grail,
            "is_best":    is_best,
            "is_special": is_special,
            "is_wanted":  is_wanted,
            "is_worst":   is_worst,
        })
    return songs

_CARTI_SONGS = _load_carti_songs()
print(f"[TRACKER] Carti: {len(_CARTI_SONGS)} canciones cargadas")

# ─── HELPERS ───────────────────────────────────────────────────────────────────
def _av_emoji(available: str) -> str:
    a = available.lower()
    if a in ("full", "og file"):     return "✅"
    if "partial" in a or "cut" in a: return "✂️"
    if "snippet" in a:               return "🎵"
    if "not available" in a:         return "❌"
    if "rumored" in a:               return "👀"
    if "confirmed" in a:             return "📋"
    if "tagged" in a:                return "🏷️"
    return "❓"

def _quality_emoji(quality: str) -> str:
    q = quality.lower()
    if "lossless" in q:      return "💎"
    if "cd" in q:            return "💿"
    if "high" in q:          return "🔊"
    if "recording" in q:     return "🎙️"
    if "low" in q:           return "📻"
    if "inaudible" in q:     return "🔇"
    if "not available" in q: return "—"
    return "🔈"

_ERA_COLORS = {
    "aviation":    0x808080,
    "thc":         0x4a7c59,
    "young mi":    0x8B4513,
    "awful":       0xff4444,
    "self":        0xff6b35,
    "die lit":     0xcc0000,
    "whole lotta": 0x9b59b6,
    "music":       0x1a1a2e,
    "antagonist":  0xe74c3c,
    "baby boi":    0xf39c12,
    "004pf":       0x00bcd4,
    "opium":       0x8B0000,
}

def _era_color(era: str) -> int:
    e = era.lower()
    for key, color in _ERA_COLORS.items():
        if key in e:
            return color
    return 0x2b2d31

def _normalize(s: str) -> str:
    # Quitar caracteres invisibles (zero-width spaces, etc.)
    s = _re.sub(r'[\u200b\u200c\u200d\ufeff]', '', s)
    # Quitar emojis/badges del inicio
    s = _re.sub(r'^[⭐✨🏆🥉🗑️🤖️\s]+', '', s)
    # Quitar acentos: é→e, ú→u, ñ→n, etc.
    s = _ud.normalize('NFD', s)
    s = ''.join(c for c in s if _ud.category(c) != 'Mn')
    # Eliminar [], (), {} para que "MUSIC [V2]" == "MUSIC V2"
    s = _re.sub(r'[\[\](){}]', '', s)
    # Quitar feat/prod y variantes ANTES de quitar puntuación
    s = _re.sub(r'\b(feat\.?|ft\.?|prod\.?|with|perf|featuring|produced by)\s*', ' ', s, flags=_re.IGNORECASE)
    # Guiones y comas → espacio
    s = _re.sub(r'[-_,]', ' ', s)
    # Quitar puntuación extra
    s = _re.sub(r'[.!?&"'+"'"+']', '', s)
    # Colapsar espacios múltiples
    s = _re.sub(r'  +', ' ', s)
    return s.lower().replace("$", "s").replace("*", "").strip()

def _badges(s: dict) -> str:
    b = ""
    if s["is_grail"]:   b += "🏆 Grail  "
    if s["is_best"]:    b += "⭐ Best Of  "
    if s["is_special"]: b += "✨ Special  "
    if s["is_wanted"]:  b += "🥉 Wanted  "
    if s["is_worst"]:   b += "🗑️ Worst Of  "
    return b.strip()

def _search(query: str):
    q = _normalize(query)
    exact, by_name, by_era = [], [], []
    for s in _CARTI_SONGS:
        n       = _normalize(s["name"])
        e       = _normalize(s["era"])
        aliases = [_normalize(a) for a in s.get("aliases", [])]
        if n == q or q in aliases:
            exact.append(s)
        elif q in n or any(q in a for a in aliases):
            by_name.append(s)
        elif q in e:
            by_era.append(s)

    # Si hay matches por nombre o alias, ignorar los de era
    if exact or by_name:
        return exact + by_name
    return by_era

# ─── EMBED BUILDERS ────────────────────────────────────────────────────────────

def _embed_quick(s: dict) -> discord.Embed:
    """Una línea por campo — resultado rápido."""
    av  = _av_emoji(s["available"])
    qe  = _quality_emoji(s["quality"])
    bdg = _badges(s)

    embed = discord.Embed(
        title=f"{av}  {s['name']}",
        color=_era_color(s["era"]),
    )
    if bdg:
        embed.description = bdg

    embed.add_field(name="🗂️ Era",       value=s["era"],       inline=True)
    embed.add_field(name="🎭 Tipo",      value=s["type"],      inline=True)
    embed.add_field(name=f"{av} Estado", value=s["available"], inline=True)

    embed.set_footer(text="💡  .carti <nombre> info  •  .carti <nombre> link")
    return embed


def _embed_link(s: dict) -> discord.Embed:
    """Solo link + datos de descarga."""
    av = _av_emoji(s["available"])
    qe = _quality_emoji(s["quality"])

    embed = discord.Embed(
        title=f"🔗  {s['name']}",
        color=_era_color(s["era"]),
    )

    if s["link"]:
        embed.description = f"## [⬇️  Descargar / Escuchar]({s['link']})"
    else:
        embed.description = "❌  No hay link disponible para esta canción."

    embed.add_field(name=f"{qe} Calidad",    value=s["quality"],   inline=True)
    embed.add_field(name="⏱️ Duración",      value=s["length"],    inline=True)
    embed.add_field(name="📅 Fecha de leak", value=s["leak_date"], inline=True)

    if s["file_date"] != "N/A":
        embed.add_field(name="📁 Fecha archivo", value=s["file_date"], inline=True)

    embed.add_field(name="🗂️ Era", value=s["era"], inline=True)

    embed.set_footer(text="Playboi Carti Tracker • grails.cx/tracker")
    return embed


def _embed_info(s: dict) -> discord.Embed:
    """Ficha completa con todo."""
    av  = _av_emoji(s["available"])
    qe  = _quality_emoji(s["quality"])
    bdg = _badges(s)

    embed = discord.Embed(
        title=f"{av}  {s['name']}",
        color=_era_color(s["era"]),
    )
    if bdg:
        embed.description = bdg

    # Bloque 1 — identidad
    embed.add_field(name="🗂️ Era",            value=s["era"],       inline=True)
    embed.add_field(name="🎭 Tipo",           value=s["type"],      inline=True)
    embed.add_field(name="\u200b",            value="\u200b",       inline=True)  # spacer

    # Bloque 2 — disponibilidad y calidad
    embed.add_field(name=f"{av} Disponible", value=s["available"],  inline=True)
    embed.add_field(name=f"{qe} Calidad",    value=s["quality"],    inline=True)
    embed.add_field(name="⏱️ Duración",      value=s["length"],     inline=True)

    # Bloque 3 — fechas
    embed.add_field(name="📅 Leak",          value=s["leak_date"],  inline=True)
    if s["file_date"] != "N/A":
        embed.add_field(name="📁 Archivo",   value=s["file_date"],  inline=True)

    # Notas
    if s["notes"] and len(s["notes"]) > 3:
        note = s["notes"][:500] + ("…" if len(s["notes"]) > 500 else "")
        embed.add_field(name="📝 Notas", value=note, inline=False)

    # Link al final
    if s["link"]:
        embed.add_field(name="🔗 Link", value=f"[Descargar / Ver]({s['link']})", inline=False)
    else:
        embed.add_field(name="🔗 Link", value="❌ No disponible", inline=False)

    embed.set_footer(text="Playboi Carti Tracker • grails.cx/tracker")
    return embed


def _embed_list(results: list, title: str, page: int = 0) -> discord.Embed:
    PAGE = 8
    start       = page * PAGE
    chunk       = results[start:start + PAGE]
    total_pages = max(1, -(-len(results) // PAGE))

    lines = []
    for i, s in enumerate(chunk, start + 1):
        av   = _av_emoji(s["available"])
        name = f"[{s['name']}]({s['link']})" if s.get("link") else s['name']
        bdg  = ""
        if s["is_grail"]:   bdg += "🏆"
        if s["is_best"]:    bdg += "⭐"
        if s["is_special"]: bdg += "✨"
        lines.append(f"{av} `{i}.` **{name}**{' ' + bdg if bdg else ''}")
        lines.append(f"┗ {s['era']}  •  *{s['type']}*")
        lines.append("")   # línea vacía entre canciones

    embed = discord.Embed(
        title=title,
        description="\n".join(lines).rstrip() or "Sin resultados.",
        color=0x2b2d31,
    )
    embed.set_footer(
        text=f"Página {page+1}/{total_pages} • {len(results)} canciones  •  .carti <nombre> info / link"
    )
    return embed


# ─── DOWNLOAD VIEW (botón de descarga para quick/link) ────────────────────────
class DownloadView(discord.ui.View):
    """View minimalista con solo el botón de descarga para embeds quick/link."""

    def __init__(self, song: dict, artista: str):
        super().__init__(timeout=120)
        self.song    = song
        self.artista = artista
        if not song.get("link") or "pillows.su" not in (song.get("link") or ""):
            self.download_btn.disabled = True

    @discord.ui.button(label="⬇️ Descargar", style=discord.ButtonStyle.success)
    async def download_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        await interaction.response.defer(thinking=True)
        button.disabled = True
        await interaction.edit_original_response(view=self)

        data, nombre, cover_url, error = await _pillowcase_download(
            self.song["link"], self.artista, self.song["name"]
        )
        if error:
            await interaction.followup.send(embed=discord.Embed(title="❌ Error", description=error, color=0xe74c3c))
            return

        tamaño = len(data)
        if tamaño > 25 * 1024 * 1024:
            mb = tamaño / (1024 * 1024)
            await interaction.followup.send(embed=discord.Embed(
                title="❌ Archivo demasiado grande",
                description=f"El archivo pesa **{mb:.1f} MB** y supera el límite de Discord (25 MB).",
                color=0xe74c3c,
            ))
            return

        mb = len(data) / (1024 * 1024)
        embed_ok = discord.Embed(
            title="✅ ¡Listo!",
            description=f"🎵 **{self.song['name']}**\n👤 {self.artista}\n\n`{nombre}` — **{mb:.1f} MB**",
            color=0x2ecc71,
        )
        embed_ok.set_thumbnail(url=cover_url)
        embed_ok.set_footer(text="Pillowcase")
        archivo = discord.File(io.BytesIO(data), filename=nombre)
        await interaction.followup.send(embed=embed_ok, file=archivo)

    async def on_timeout(self):
        for item in self.children:
            item.disabled = True


# ─── PAGINATION VIEW ───────────────────────────────────────────────────────────
class CartiPageView(discord.ui.View):
    def __init__(self, results: list, title: str, author_id: int):
        super().__init__(timeout=120)
        self.results     = results
        self.title       = title
        self.author_id   = author_id
        self.page        = 0
        self.total_pages = max(1, -(-len(results) // 8))
        self._sync()

    def _sync(self):
        self.prev_btn.disabled = self.page == 0
        self.next_btn.disabled = self.page >= self.total_pages - 1
        self.page_btn.label    = f"{self.page + 1} / {self.total_pages}"

    async def _guard(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.author_id:
            await interaction.response.send_message(
                "Solo quien usó el comando puede cambiar la página.", ephemeral=True
            )
            return False
        return True

    @discord.ui.button(emoji="⬅️", style=discord.ButtonStyle.secondary)
    async def prev_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not await self._guard(interaction): return
        self.page -= 1
        self._sync()
        await interaction.response.edit_message(
            embed=_embed_list(self.results, self.title, self.page), view=self
        )

    @discord.ui.button(label="1 / 1", style=discord.ButtonStyle.primary, disabled=True)
    async def page_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        await interaction.response.defer()

    @discord.ui.button(emoji="➡️", style=discord.ButtonStyle.secondary)
    async def next_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not await self._guard(interaction): return
        self.page += 1
        self._sync()
        await interaction.response.edit_message(
            embed=_embed_list(self.results, self.title, self.page), view=self
        )

    async def on_timeout(self):
        for item in self.children:
            item.disabled = True



# ─── INFO VIEW (con botón de traducción) ──────────────────────────────────────
class InfoView(discord.ui.View):
    """View para el embed de info — botón de traducir notas y botón de descarga."""

    def __init__(self, song: dict, author_id: int, artista: str = ""):
        super().__init__(timeout=120)
        self.song      = song
        self.author_id = author_id
        self.artista   = artista
        self._translated = False
        # Ocultar botón traducir si no hay notas
        if not song.get("notes") or len(song["notes"]) <= 3:
            self.translate_btn.disabled = True
        # Ocultar botón descargar si no hay link de pillowcase
        if not song.get("link") or "pillows.su" not in (song.get("link") or ""):
            self.download_btn.disabled = True

    @discord.ui.button(label="⬇️ Descargar", style=discord.ButtonStyle.success, row=0)
    async def download_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        await interaction.response.defer(thinking=True, ephemeral=False)
        button.disabled = True
        await interaction.edit_original_response(view=self)

        data, nombre, cover_url, error = await _pillowcase_download(
            self.song["link"], self.artista, self.song["name"]
        )
        if error:
            await interaction.followup.send(embed=discord.Embed(title="❌ Error", description=error, color=0xe74c3c))
            return

        tamaño = len(data)
        if tamaño > 25 * 1024 * 1024:
            mb = tamaño / (1024 * 1024)
            await interaction.followup.send(embed=discord.Embed(
                title="❌ Archivo demasiado grande",
                description=f"El archivo pesa **{mb:.1f} MB** y supera el límite de Discord (25 MB).",
                color=0xe74c3c,
            ))
            return

        mb = len(data) / (1024 * 1024)
        embed_ok = discord.Embed(
            title="✅ ¡Listo!",
            description=f"🎵 **{self.song['name']}**\n👤 {self.artista}\n\n`{nombre}` — **{mb:.1f} MB**",
            color=0x2ecc71,
        )
        embed_ok.set_thumbnail(url=cover_url)
        embed_ok.set_footer(text="Pillowcase")
        archivo = discord.File(io.BytesIO(data), filename=nombre)
        await interaction.followup.send(embed=embed_ok, file=archivo)

    @discord.ui.button(label="🌐 Traducir notas", style=discord.ButtonStyle.secondary, row=0)
    async def translate_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.author_id:
            await interaction.response.send_message("Solo el autor puede usar esto.", ephemeral=True)
            return

        if self._translated:
            await interaction.response.send_message("Las notas ya están traducidas.", ephemeral=True)
            return

        await interaction.response.defer()

        notes = self.song["notes"]
        try:
            from deep_translator import GoogleTranslator
            import asyncio as _asyncio
            loop = _asyncio.get_event_loop()
            translated = await loop.run_in_executor(
                None,
                lambda: GoogleTranslator(source="en", target="es").translate(notes)
            )
        except Exception as e:
            await interaction.followup.send(f"❌ Error al traducir: {e}", ephemeral=True)
            return

        song_copy = dict(self.song)
        song_copy["notes"] = translated
        new_embed = _embed_info(song_copy)
        new_embed.set_footer(text="📝 Notas traducidas al español")

        self._translated = True
        button.disabled  = True
        button.label     = "✅ Traducido"
        await interaction.edit_original_response(embed=new_embed, view=self)

    async def on_timeout(self):
        for item in self.children:
            item.disabled = True

# ─── MULTI-RESULT VIEW (cuando hay varias canciones con el mismo nombre) ───────
class CartiPickView(discord.ui.View):
    """Botones para elegir entre versiones de la misma canción."""
    def __init__(self, results: list, mode: str, author_id: int):
        super().__init__(timeout=60)
        self.results   = results
        self.mode      = mode      # "quick" | "link" | "info"
        self.author_id = author_id
        for i, s in enumerate(results[:5]):  # max 5 botones
            label = f"[{s['type']}] {s['era'][:28]}"
            btn   = discord.ui.Button(label=label, style=discord.ButtonStyle.secondary, custom_id=str(i))
            btn.callback = self._make_cb(i)
            self.add_item(btn)

    def _make_cb(self, idx: int):
        async def callback(interaction: discord.Interaction):
            if interaction.user.id != self.author_id:
                await interaction.response.send_message("Solo el autor puede elegir.", ephemeral=True)
                return
            s = self.results[idx]
            embed = {"quick": _embed_quick, "link": _embed_link, "info": _embed_info}[self.mode](s)
            await interaction.response.edit_message(embed=embed, view=None)
        return callback


# ─── HELPERS para resolver canción única o mostrar selector ───────────────────
async def _resolve_and_reply(ctx, query: str, mode: str):
    """
    Busca la canción y responde según el modo.
    Si hay un solo resultado → embed directo.
    Si hay varios con nombre idéntico → botones de selección.
    Si hay varios con nombre distinto → lista paginada.
    """
    results = _search(query)

    if not results:
        return await ctx.reply(
            embed=discord.Embed(
                title="❌ Sin resultados",
                description=f"No encontré **\"{query}\"**.\nRevisa el spelling o intenta con parte del nombre.",
                color=0xe74c3c,
            ),
            mention_author=False,
        )

    embed_fn = {"quick": _embed_quick, "link": _embed_link, "info": _embed_info}[mode]

    # Resultado único
    if len(results) == 1:
        s     = results[0]
        if mode == "info":
            view = InfoView(s, ctx.author.id, artista="Playboi Carti")
        else:
            view = DownloadView(s, "Playboi Carti")
        emb   = embed_fn(s)
        cover = await _fetch_era_cover(s["era"])
        if cover: emb.set_thumbnail(url=cover)
        return await ctx.reply(embed=emb, view=view, mention_author=False)

    # Varios resultados — ¿son todos variaciones del mismo nombre?
    norm_names = set(_normalize(s["name"]) for s in results)
    if len(norm_names) == 1:
        # Mismo nombre, versiones distintas → botones de selección
        intro = discord.Embed(
            title=f"🎵  {results[0]['name']}",
            description=f"Hay **{len(results)}** versiones. ¿Cuál quieres ver?",
            color=_era_color(results[0]["era"]),
        )
        view = CartiPickView(results[:5], mode, ctx.author.id)
        return await ctx.reply(embed=intro, view=view, mention_author=False)

    # Match exacto de nombre → embed directo
    exact = [s for s in results if _normalize(s["name"]) == _normalize(query)]
    if len(exact) == 1:
        s     = exact[0]
        if mode == "info":
            view = InfoView(s, ctx.author.id, artista="Playboi Carti")
        else:
            view = DownloadView(s, "Playboi Carti")
        emb   = embed_fn(s)
        cover = await _fetch_era_cover(s["era"])
        if cover: emb.set_thumbnail(url=cover)
        return await ctx.reply(embed=emb, view=view, mention_author=False)

    # Múltiples nombres distintos → lista paginada
    title = f"🔍  \"{query}\""
    view  = CartiPageView(results, title, ctx.author.id)
    await ctx.reply(embed=_embed_list(results, title), view=view, mention_author=False)


# ─── COMMAND ───────────────────────────────────────────────────────────────────
@bot.command(name="carti")
async def carti_cmd(ctx, *, query: str = None):
    """
    .carti <nombre>         resultado rápido
    .carti <nombre> link    solo el link
    .carti <nombre> info    ficha completa
    .carti era <era>        canciones de una era
    .carti grails           grails 🏆
    .carti best             Best Of ⭐
    .carti stats            estadísticas
    """
    if not query:
        embed = discord.Embed(
            title="🩸  Carti Tracker",
            color=0xcc0000,
            description=(
                "**Buscar una canción**\n"
                "`.carti goku` — resultado rápido\n"
                "`.carti goku link` — link + calidad + fecha\n"
                "`.carti goku info` — ficha completa\n"
                "\n"
                "**Explorar**\n"
                "`.carti era whole lotta red` — canciones de una era\n"
                "`.carti grails` — los grails 🏆\n"
                "`.carti best` — Best Of ⭐\n"
                "`.carti stats` — estadísticas del tracker\n"
                "\n"
                "**Disponibilidad**\n"
                "✅ Full / OG  •  ✂️ Partial  •  🎵 Snippet  •  ❌ No disponible  •  👀 Rumored"
            ),
        )
        embed.set_footer(text=f"{len(_CARTI_SONGS)} canciones en el tracker")
        return await ctx.reply(embed=embed, mention_author=False)

    q = query.strip()
    q_lower = q.lower()

    # ── stats ─────────────────────────────────────────────────────────────────
    if q_lower == "stats":
        total    = len(_CARTI_SONGS)
        full     = sum(1 for s in _CARTI_SONGS if _normalize(s["available"]) in ("full", "og file"))
        snippets = sum(1 for s in _CARTI_SONGS if "snippet"  in s["available"].lower())
        partial  = sum(1 for s in _CARTI_SONGS if "partial"  in s["available"].lower() or "cut" in s["available"].lower())
        unavail  = sum(1 for s in _CARTI_SONGS if "not available" in s["available"].lower())
        grails   = sum(1 for s in _CARTI_SONGS if s["is_grail"])
        best     = sum(1 for s in _CARTI_SONGS if s["is_best"])

        embed = discord.Embed(title="📊  Carti Tracker — Stats", color=0xcc0000)
        embed.add_field(name="🎵 Total",          value=str(total),    inline=True)
        embed.add_field(name="✅ Full / OG",       value=str(full),     inline=True)
        embed.add_field(name="🎵 Snippets",        value=str(snippets), inline=True)
        embed.add_field(name="✂️ Partial",          value=str(partial),  inline=True)
        embed.add_field(name="❌ No disponible",   value=str(unavail),  inline=True)
        embed.add_field(name="🏆 Grails",          value=str(grails),   inline=True)
        embed.add_field(name="⭐ Best Of",         value=str(best),     inline=True)
        embed.set_footer(text="grails.cx/tracker")
        return await ctx.reply(embed=embed, mention_author=False)

    # ── grails ────────────────────────────────────────────────────────────────
    if q_lower == "grails":
        g = [s for s in _CARTI_SONGS if s["is_grail"]]
        if not g:
            return await ctx.reply("No hay grails en el tracker.", mention_author=False)
        view = CartiPageView(g, "🏆  Grails", ctx.author.id)
        return await ctx.reply(embed=_embed_list(g, "🏆  Grails"), view=view, mention_author=False)

    # ── best ──────────────────────────────────────────────────────────────────
    if q_lower in ("best", "bestof", "best of"):
        b = [s for s in _CARTI_SONGS if s["is_best"]]
        if not b:
            return await ctx.reply("No hay Best Of marcados.", mention_author=False)
        view = CartiPageView(b, "⭐  Best Of", ctx.author.id)
        return await ctx.reply(embed=_embed_list(b, "⭐  Best Of"), view=view, mention_author=False)

    # ── era <name> ────────────────────────────────────────────────────────────
    if q_lower.startswith("era "):
        era_q   = q[4:].strip()
        matches = [s for s in _CARTI_SONGS if _normalize(era_q) in _normalize(s["era"])]
        if not matches:
            return await ctx.reply(f"❌ No encontré la era **{era_q}**.", mention_author=False)
        title = f"🗂️  Era: {era_q}"
        view  = CartiPageView(matches, title, ctx.author.id)
        return await ctx.reply(embed=_embed_list(matches, title), view=view, mention_author=False)

    # ── <nombre> link ─────────────────────────────────────────────────────────
    if q_lower.endswith(" link"):
        song_q = q[:-5].strip()
        return await _resolve_and_reply(ctx, song_q, "link")

    # ── <nombre> info ─────────────────────────────────────────────────────────
    if q_lower.endswith(" info"):
        song_q = q[:-5].strip()
        return await _resolve_and_reply(ctx, song_q, "info")

    # ── <nombre> dl ───────────────────────────────────────────────────────────
    if q_lower.endswith(" dl"):
        song_q = q[:-3].strip()
        results = _search(song_q)
        if not results:
            return await ctx.reply(embed=discord.Embed(title="❌ Sin resultados", description=f"No encontré **\"{song_q}\"**.", color=0xe74c3c), mention_author=False)
        exact = [s for s in results if _normalize(s["name"]) == _normalize(song_q)]
        song = exact[0] if exact else results[0]
        return await _tracker_dl(ctx, song, "Playboi Carti")

    # ── <nombre> (resultado rápido) ───────────────────────────────────────────
    return await _resolve_and_reply(ctx, q, "quick")

