# ═══════════════════════════════════════════════════════════════════════════════
# DESTROY LONELY TRACKER
#
# Comandos:
#   .lone <nombre>        — resultado rápido
#   .lone <nombre> link   — solo el link
#   .lone <nombre> info   — ficha completa
#   .lone era <era>       — canciones de una era
#   .lone grails          — grails 🏆
#   .lone best            — Best Of ⭐
#   .lone stats           — estadísticas generales
# ═══════════════════════════════════════════════════════════════════════════════

import os as _los

LONE_CSV_PATH = "lone_tracker.csv"

def _load_lone_songs():
    try:
        raw = _load_csv(LONE_CSV_PATH, "https://raw.githubusercontent.com/tapepink21-gif/UG-CARTAS-2/main/lone_tracker.csv")
        if not raw:
            return []
    except Exception as e:
        print(f"[TRACKER] Lone crash: {e}")
        return []

    try:
        valid_avail = {"Full","OG File","Partial","Snippet","Confirmed","Rumored","Beat Only","Self-Bounce","Cut"}

        songs = []
        for row in _csv.reader(_io.StringIO(raw)):
            if len(row) < 8:
                continue
            era       = row[0].strip().replace("\n", " ")
            name      = row[1].strip().replace("\n", " ")
            notes     = row[2].strip().replace("\n", " ")[:600] if len(row) > 2 else ""
            length    = row[3].strip() if len(row) > 3 else ""
            file_date = row[4].strip() if len(row) > 4 else ""
            leak_date = row[5].strip() if len(row) > 5 else ""
            typ       = row[6].strip() if len(row) > 6 else ""
            available = row[7].strip() if len(row) > 7 else ""
            quality   = row[8].strip() if len(row) > 8 else ""
            link      = row[9].strip() if len(row) > 9 else ""

            if not era or not name or len(name) > 150:
                continue
            if "Total Full" in era or "OG File(s)" in era:
                continue
            if available not in valid_avail and available not in ("Full","OG File","Partial","Snippet"):
                continue

            is_best    = "⭐" in name or "🥇" in name
            is_grail   = "🏆" in name
            is_special = "✨" in name
            is_wanted  = False
            is_worst   = "🗑" in name

            clean_name = _re.sub(r'^[⭐✨🏆🥉🗑️🤖️🥇\s\u200b\u200e]+', '', name).strip()
            if not clean_name:
                continue

            _alias_raw = _re.findall(r'\(([^)]+)\)', clean_name)
            aliases = []
            for _a in _alias_raw:
                if not _re.match(r'(?i)^(prod|feat|ft|with|perf|og |aka)\.?', _a.strip()):
                    aliases += [x.strip() for x in _a.split(',') if x.strip()]

            songs.append({
                "era":        era,
                "name":       clean_name,
                "aliases":    aliases,
                "notes":      notes,
                "length":     length    or "N/A",
                "leak_date":  leak_date or "N/A",
                "file_date":  file_date or "N/A",
                "type":       typ       or "Unknown",
                "available":  available or "N/A",
                "quality":    quality   or "N/A",
                "link":       link if link and link.startswith("http") else None,
                "is_grail":   is_grail,
                "is_best":    is_best,
                "is_special": is_special,
                "is_wanted":  is_wanted,
                "is_worst":   is_worst,
            })
        return songs
    except Exception as e:
        print(f"[TRACKER] Lone parse error: {e}")
        return []

print("[TRACKER] Iniciando carga Lone...")
_LONE_SONGS = _load_lone_songs()
print(f"[TRACKER] Lone: {len(_LONE_SONGS)} canciones cargadas")

# ─── HELPERS ───────────────────────────────────────────────────────────────────
def _lone_search(query: str):
    q = _normalize(query)
    exact, by_name, by_era = [], [], []
    for s in _LONE_SONGS:
        n       = _normalize(s["name"])
        e       = _normalize(s["era"])
        aliases = [_normalize(a) for a in s.get("aliases", [])]
        if n == q or q in aliases:
            exact.append(s)
        elif q in n or any(q in a for a in aliases):
            by_name.append(s)
        elif q in e:
            by_era.append(s)
    if exact or by_name:
        return exact + by_name
    return by_era

def _lone_badges(s: dict) -> str:
    b = ""
    if s["is_grail"]:   b += "🏆 Grail  "
    if s["is_best"]:    b += "⭐ Best Of  "
    if s["is_special"]: b += "✨  "
    if s["is_worst"]:   b += "🗑️ Worst Of  "
    return b.strip()

# ─── EMBED BUILDERS ────────────────────────────────────────────────────────────
def _lone_embed_quick(s: dict) -> discord.Embed:
    av    = _av_emoji(s["available"])
