# ─── INFO VIEW (botón de traducción) ──────────────────────────────────────────
class LoneInfoView(discord.ui.View):
    def __init__(self, song: dict, author_id: int, artista: str = "Lil Uzi Vert"):
        super().__init__(timeout=120)
        self.song        = song
        self.author_id   = author_id
        self.artista     = artista
        if not song.get("link") or "pillows.su" not in (song.get("link") or ""):
            self.download_btn.disabled = True
        self.artista     = artista
        if not song.get("link") or "pillows.su" not in (song.get("link") or ""):
            self.download_btn.disabled = True
        self._translated = False
        if not song.get("notes") or len(song["notes"]) <= 3:
            self.translate_btn.disabled = True


    @discord.ui.button(label="⬇️ Descargar", style=discord.ButtonStyle.success, row=0)
    async def download_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        await interaction.response.defer(thinking=True)
        button.disabled = True
        await interaction.edit_original_response(view=self)
        data, nombre, cover_url, error = await _pillowcase_download(
            self.song["link"], self.artista, self.song["name"]
        )
        if error:
            await interaction.followup.send(embed=discord.Embed(title="❌ Error", description=error, color=0xe74c3c))
            return
        tamaño = len(data)
        if tamaño > 25 * 1024 * 1024:
            mb = tamaño / (1024 * 1024)
            await interaction.followup.send(embed=discord.Embed(
                title="❌ Archivo demasiado grande",
                description=f"El archivo pesa **{mb:.1f} MB** y supera el límite de Discord (25 MB).",
                color=0xe74c3c,
            ))
            return
        mb = len(data) / (1024 * 1024)
        embed_ok = discord.Embed(
            title="✅ ¡Listo!",
            description=f"🎵 **{self.song['name']}**\n👤 {self.artista}\n\n`{nombre}` — **{mb:.1f} MB**",
            color=0x2ecc71,
        )
        embed_ok.set_thumbnail(url=cover_url)
        embed_ok.set_footer(text="Pillowcase")
        archivo = discord.File(io.BytesIO(data), filename=nombre)
        await interaction.followup.send(embed=embed_ok, file=archivo)

    @discord.ui.button(label="🌐 Traducir notas", style=discord.ButtonStyle.secondary)
    async def translate_btn(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id != self.author_id:
            await interaction.response.send_message("Solo el autor puede usar esto.", ephemeral=True)
            return
        if self._translated:
            await interaction.response.send_message("Las notas ya están traducidas.", ephemeral=True)
            return
        await interaction.response.defer()
        try:
            from deep_translator import GoogleTranslator
            import asyncio as _asyncio
            loop = _asyncio.get_event_loop()
            translated = await loop.run_in_executor(
                None,
                lambda: GoogleTranslator(source="en", target="es").translate(self.song["notes"])
            )
        except Exception as e:
            await interaction.followup.send(f"❌ Error al traducir: {e}", ephemeral=True)
            return
        song_copy = dict(self.song)
        song_copy["notes"] = translated
        new_embed = _lone_embed_info(song_copy)
        new_embed.set_footer(text="📝 Notas traducidas al español")
        self._translated = True
        button.disabled  = True
        button.label     = "✅ Traducido"
        await interaction.edit_original_response(embed=new_embed, view=self)

    async def on_timeout(self):
        for item in self.children:
            item.disabled = True

# ─── RESOLVER ──────────────────────────────────────────────────────────────────
async def _lone_resolve(ctx, query: str, mode: str):
    results  = _lone_search(query)
    embed_fn = {"quick": _lone_embed_quick, "link": _lone_embed_link, "info": _lone_embed_info}[mode]

    if not results:
        return await ctx.reply(
            embed=discord.Embed(
                title="❌  Sin resultados",
                description=f'No encontré **"{query}"**.\nRevisa el spelling o intenta con parte del nombre.',
                color=0xe74c3c,
            ),
            mention_author=False,
        )

    if len(results) == 1:
        s    = results[0]
        view = LoneInfoView(s, ctx.author.id) if mode == "info" else DownloadView(s, "Lil Uzi Vert")
        return await ctx.reply(embed=embed_fn(s), view=view, mention_author=False)

    exact = [s for s in results if _normalize(s["name"]) == _normalize(query)]
    if len(exact) == 1:
        s    = exact[0]
        view = LoneInfoView(s, ctx.author.id) if mode == "info" else DownloadView(s, "Lil Uzi Vert")
        return await ctx.reply(embed=embed_fn(s), view=view, mention_author=False)

    title = f'🔍  "{query}"'
    view  = CartiPageView(results, title, ctx.author.id)
    await ctx.reply(embed=_embed_list(results, title), view=view, mention_author=False)

# ─── COMANDO .lone ──────────────────────────────────────────────────────────────
@bot.command(name="lone")
async def lone_cmd(ctx, *, args: str = ""):
    args = args.strip()
    if not args:
        total = len(_LONE_SONGS)
        full  = sum(1 for s in _LONE_SONGS if _normalize(s["available"]) in ("full", "og file"))
        return await ctx.reply(
            embed=discord.Embed(
                title="🎵  Destroy Lonely Tracker",
                description=(
                    f"**{total}** canciones registradas\n"
                    f"**{full}** disponibles (full / OG file)\n\n"
                    "`.lone <nombre>` — búsqueda rápida\n"
                    "`.lone <nombre> link` — link directo\n"
                    "`.lone <nombre> info` — ficha completa\n"
                    "`.lone era <era>` — canciones de una era\n"
                    "`.lone grails` — grails 🏆\n"
                    "`.lone best` — Best Of ⭐\n"
                    "`.lone stats` — estadísticas"
                ),
                color=0x2b2d31,
            ),
            mention_author=False,
        )

    # ── grails ───────────────────────────────────────────────────────────────
    if args.lower() == "grails":
        g    = [s for s in _LONE_SONGS if s["is_grail"]]
        view = CartiPageView(g, "🏆  Grails", ctx.author.id)
        return await ctx.reply(embed=_embed_list(g, "🏆  Grails"), view=view, mention_author=False)

    # ── best ─────────────────────────────────────────────────────────────────
    if args.lower() == "best":
        b    = [s for s in _LONE_SONGS if s["is_best"]]
        view = CartiPageView(b, "⭐  Best Of", ctx.author.id)
        return await ctx.reply(embed=_embed_list(b, "⭐  Best Of"), view=view, mention_author=False)

    # ── stats ────────────────────────────────────────────────────────────────
    if args.lower() == "stats":
        total   = len(_LONE_SONGS)
        full    = sum(1 for s in _LONE_SONGS if _normalize(s["available"]) in ("full", "og file"))
        partial = sum(1 for s in _LONE_SONGS if "partial" in _normalize(s["available"]))
        snippet = sum(1 for s in _LONE_SONGS if "snippet" in _normalize(s["available"]))
        grails  = sum(1 for s in _LONE_SONGS if s["is_grail"])
        best    = sum(1 for s in _LONE_SONGS if s["is_best"])
        embed   = discord.Embed(title="📊  Destroy Lonely — Stats", color=0x2b2d31)
        embed.add_field(name="Total",    value=str(total),   inline=True)
        embed.add_field(name="Full/OG",  value=str(full),    inline=True)
        embed.add_field(name="Partial",  value=str(partial), inline=True)
        embed.add_field(name="Snippets", value=str(snippet), inline=True)
        embed.add_field(name="Grails 🏆",value=str(grails),  inline=True)
        embed.add_field(name="Best ⭐",  value=str(best),    inline=True)
        return await ctx.reply(embed=embed, mention_author=False)

    # ── era ──────────────────────────────────────────────────────────────────
    if args.lower().startswith("era "):
        era_q   = args[4:].strip()
        matches = [s for s in _LONE_SONGS if _normalize(era_q) in _normalize(s["era"])]
        title   = f"📁  Era: {era_q}"
        view    = CartiPageView(matches, title, ctx.author.id)
        return await ctx.reply(embed=_embed_list(matches, title), view=view, mention_author=False)

    # ── <nombre> link / info ──────────────────────────────────────────────────
    parts = args.rsplit(None, 1)
    if len(parts) == 2 and parts[1].lower() in ("link", "info"):
        q, mode = parts[0], parts[1].lower()
        return await _lone_resolve(ctx, q, mode)

    if len(parts) == 2 and parts[1].lower() == "dl":
        q = parts[0]
        results = _lone_search(q)
        if not results:
            return await ctx.reply(embed=discord.Embed(title="❌ Sin resultados", description=f"No encontré **\"{q}\"**.", color=0xe74c3c), mention_author=False)
        exact = [s for s in results if _normalize(s["name"]) == _normalize(q)]
        song = exact[0] if exact else results[0]
        return await _tracker_dl(ctx, song, "Lil Uzi Vert")

    return await _lone_resolve(ctx, args, "quick")

