    embed = discord.Embed(title=f"{av}  {s['name']}", color=color)
    embed.add_field(name="Era",        value=s["era"],       inline=True)
    embed.add_field(name="Disponible", value=s["available"], inline=True)
    embed.add_field(name="Calidad",    value=s["quality"],   inline=True)
