import glob
import unicodedata as _unicodedata

FORMATOS_VALIDOS_DL = ["mp3", "flac", "wav", "ogg"]

PLATAFORMAS_NOMBRES = {
    "youtube":     "YouTube",
    "youtu.be":    "YouTube",
    "soundcloud":  "SoundCloud",
    "spotify":     "Spotify",
    "music.apple": "Apple Music",
}

def _detectar_plataforma(url: str) -> str:
    url_lower = url.lower()
    for key, nombre in PLATAFORMAS_NOMBRES.items():
        if key in url_lower:
            return nombre
    return "URL"

def _nombre_limpio_dl(artista: str, titulo: str) -> str:
    def limpiar(s: str) -> str:
        s = _unicodedata.normalize("NFKC", s)
        s = re.sub(r'[\\/*?:"<>|]', "", s)
        s = re.sub(r"\s+", " ", s).strip()
        return s
    artista = limpiar(artista or "Desconocido")
    titulo  = limpiar(titulo  or "Sin título")
    return f"{artista} - {titulo}"

def _pillowcase_hash(url: str):
    m = _re_pillow_mod.search(r"pillows\.su/f/([a-f0-9]{32})", url)
    return m.group(1) if m else None

async def _pillowcase_download(url: str, artista: str = "", titulo: str = ""):
    """Descarga de pillows.su. Devuelve (bytes, nombre, cover_url, error)."""
    hash_id = _pillowcase_hash(url)
    if not hash_id:
        return None, None, None, "❌ URL de Pillowcase inválida."

    dl_url    = f"https://api.pillows.su/api/download/{hash_id}"
    cover_url = f"https://api.pillows.su/api/cover/{hash_id}.webp"

    try:
        async with aiohttp.ClientSession() as session:
            async with session.get(dl_url, timeout=aiohttp.ClientTimeout(total=120)) as resp:
                if resp.status != 200:
                    return None, None, None, f"❌ Error al descargar (HTTP {resp.status})."
                data = await resp.read()
                ct = resp.headers.get("Content-Type", "audio/mpeg")
                ext = "mp3" if "mpeg" in ct else ct.split("/")[-1].split(";")[0].strip()
                if artista and titulo:
                    titulo_clean = re.sub(r'^\d+\s+', '', titulo).strip()
                    titulo_clean = re.sub(r'\s*\(.*?\)', '', titulo_clean).strip()
                    titulo_clean = re.sub(r'\s*\[.*?\]', '', titulo_clean).strip()
                    titulo_clean = titulo_clean.strip(' )')  # quitar ) sobrante
                    titulo_clean = titulo_clean[:60] if len(titulo_clean) > 60 else titulo_clean
                    artista_clean = artista[:30] if len(artista) > 30 else artista
                    nombre = re.sub(r'[\\/*?:"<>|]', "", f"{artista_clean} - {titulo_clean}.{ext}")
                else:
                    nombre = f"descarga_{hash_id[:8]}.mp3"
                return data, nombre, cover_url, None
    except asyncio.TimeoutError:
        return None, None, None, "⏱️ Tiempo de espera agotado."
    except Exception as e:
        return None, None, None, f"❌ Error: {e}"


async def _tracker_dl(ctx, song: dict, artista_tracker: str):
    """Descarga compartida para todos los trackers via Pillowcase."""
    link = song.get("link")
    if not link or "pillows.su" not in link:
        await ctx.reply(
            embed=discord.Embed(
                title="❌ Sin link de Pillowcase",
                description=f"**{song['name']}** no tiene link de descarga disponible en el tracker.",
                color=0xe74c3c,
            ),
            mention_author=False,
        )
        return

    msg = await ctx.reply(
        embed=discord.Embed(
            title="⬇️ Descargando...",
            description=f"🎵 **{song['name']}**\n👤 {artista_tracker}\n\n`Pillowcase` — un momento...",
            color=0x3498db,
        ),
        mention_author=False,
    )

    data, nombre, cover_url, error = await _pillowcase_download(
        link, artista_tracker, song["name"]
    )

    if error:
        await msg.edit(embed=discord.Embed(title="❌ Error", description=error, color=0xe74c3c))
        return

    tamaño = len(data)
    if tamaño > 25 * 1024 * 1024:
        mb = tamaño / (1024 * 1024)
        await msg.edit(embed=discord.Embed(
            title="❌ Archivo demasiado grande",
            description=f"El archivo pesa **{mb:.1f} MB** y supera el límite de Discord (25 MB).",
            color=0xe74c3c,
        ))
        return

    mb = tamaño / (1024 * 1024)
    embed_ok = discord.Embed(
        title="✅ ¡Listo!",
        description=(
            f"🎵 **{song['name']}**\n"
            f"👤 {artista_tracker}\n\n"
            f"`{nombre}` — **{mb:.1f} MB**"
        ),
        color=0x2ecc71,
    )
    embed_ok.set_thumbnail(url=cover_url)
    embed_ok.set_footer(text="Pillowcase")

    archivo = discord.File(io.BytesIO(data), filename=nombre)
    await msg.edit(embed=embed_ok, attachments=[archivo])

