# ─── GENIUS HELPER ───────────────────────────────────────────────────────────

GENIUS_TOKEN = ""  # ← Pon tu Genius API token aquí (gratis en genius.com/api-clients)

async def _genius_search(artist: str, title: str) -> str | None:
    """Busca la URL de la letra en Genius. Devuelve la URL o None."""
    if not GENIUS_TOKEN:
        return None
    import aiohttp
    headers = {"Authorization": f"Bearer {GENIUS_TOKEN}"}
    query = f"{artist} {title}"
    async with aiohttp.ClientSession() as session:
        async with session.get(
            "https://api.genius.com/search",
            params={"q": query},
            headers=headers,
            timeout=aiohttp.ClientTimeout(total=8)
        ) as resp:
            if resp.status != 200:
                return None
            data = await resp.json()
    hits = data.get("response", {}).get("hits", [])
    if not hits:
        return None
    return hits[0]["result"]["url"]

async def _fetch_lyrics(genius_url: str) -> str | None:
    """Scrapea la letra desde la página de Genius (primeras ~30 líneas)."""
    import aiohttp
    try:
        async with aiohttp.ClientSession() as session:
            async with session.get(genius_url, timeout=aiohttp.ClientTimeout(total=10)) as resp:
                if resp.status != 200:
                    return None
                html = await resp.text()
    except Exception:
        return None
    # Buscar los bloques de letra en el HTML
    lyrics_blocks = re.findall(r'<div data-lyrics-container="true"[^>]*>(.*?)</div>', html, re.DOTALL)
    if not lyrics_blocks:
        return None
    raw = " ".join(lyrics_blocks)
    # Limpiar HTML básico
    text = re.sub(r'<br\s*/?>', "\n", raw)
    text = re.sub(r'<[^>]+>', "", text)
    text = re.sub(r'\[.*?\]', "", text)  # quitar [Chorus], [Verse], etc.
    text = re.sub(r'\n{3,}', "\n\n", text).strip()
    lines = [l for l in text.splitlines() if l.strip()]
    # Devolver las primeras 25 líneas para no hacer el embed enorme
    return "\n".join(lines[:25]) + ("\n…" if len(lines) > 25 else "")

# ─── HELPER: descargar imagen como bytes ─────────────────────────────────────

async def _download_image_bytes(url: str) -> bytes | None:
    import aiohttp
    try:
        async with aiohttp.ClientSession() as session:
            async with session.get(url, timeout=aiohttp.ClientTimeout(total=8)) as resp:
                if resp.status != 200:
                    return None
                return await resp.read()
    except Exception:
        return None


# ═══════════════════════════════════════════════════════════════════════════════
# .fmcard — tarjeta de perfil visual
# ═══════════════════════════════════════════════════════════════════════════════

async def _build_fmcard(username: str, display_name: str, avatar_url: str) -> bytes | None:
    """
    Tarjeta de perfil musical — layout calculado al píxel para que nada se corte.
    Canvas: 1000 x 500 px (exportado directo, sin escalar)
    Secciones:
      HEADER  (avatar + nombre + stats)   — 0..150
      ─── separador ──────────────────────  150
      BODY izq (5 artistas + barras)      — 158..460
      BODY der (grid 2x2 álbumes)         — 158..460
      FOOTER                              — 465..500
    """
    try:
        from PIL import Image, ImageDraw, ImageFont, ImageFilter, ImageEnhance

        # ── Dimensiones fijas ──
        W, H  = 1000, 500
        PAD   = 36

        # ── Colores ──
        ACCENT  = (213, 16,  7)
        WHITE   = (255, 255, 255)
        GRAY    = (170, 170, 170)
        DIMGRAY = (110, 110, 110)
        OVERLAY = (8,   8,   8,  210)

        # ── Fuentes ──
        def _lf(paths, size):
            for p in paths:
                try: return ImageFont.truetype(p, size)
                except: pass
            return ImageFont.load_default()

        B = ["/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf",
             "/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf"]
        R = ["/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf",
             "/usr/share/fonts/truetype/liberation/LiberationSans-Regular.ttf"]

        f28 = _lf(B, 28)   # nombre usuario
        f15 = _lf(B, 15)   # artista nombre / stat valor
        f13 = _lf(R, 13)   # stat label / álbum nombre
        f12 = _lf(R, 12)   # plays, url
        f11 = _lf(R, 11)   # footer / sección label

        # ── Datos Last.fm ──
        user_info, top_artists, top_albums = await asyncio.gather(
            lastfm_get({"method": "user.getinfo",       "user": username}),
            lastfm_get({"method": "user.gettopartists", "user": username, "period": "1month", "limit": 5}),
            lastfm_get({"method": "user.gettopalbums",  "user": username, "period": "1month", "limit": 4}),
        )
        u            = (user_info   or {}).get("user",       {})
        playcount    = int(u.get("playcount",    0))
        artist_count = int(u.get("artist_count", 0))
        track_count  = int(u.get("track_count",  0))
        artists      = (top_artists or {}).get("topartists", {}).get("artist", [])[:5]
        albums       = (top_albums  or {}).get("topalbums",  {}).get("album",  [])[:4]

        # ── URLs de imágenes ──
        def _best_img(item):
            url = next((i["#text"] for i in item.get("image", [])
                        if i.get("size") == "extralarge" and i.get("#text")), None)
            return _clean_lfm_image(url)

        bg_url   = _best_img(albums[0]) if albums else None
        cov_urls = [_best_img(a) for a in albums[:4]]

        # ── Descargar todo en paralelo ──
        dl = lambda u: _download_image_bytes(u) if u else asyncio.sleep(0)
        raw = await asyncio.gather(dl(avatar_url), dl(bg_url), *[dl(u) for u in cov_urls])
        av_raw   = raw[0] if isinstance(raw[0], bytes) else None
        bg_raw   = raw[1] if isinstance(raw[1], bytes) else None
        cov_raws = [r if isinstance(r, bytes) else None for r in raw[2:]]

        # ══════════════ CANVAS ══════════════
        card = Image.new("RGBA", (W, H), (12, 12, 12, 255))

        # Fondo blureado
        if bg_raw:
            try:
                bg = Image.open(io.BytesIO(bg_raw)).convert("RGB")
                r  = max(W / bg.width, H / bg.height)
                bg = bg.resize((int(bg.width * r), int(bg.height * r)), Image.LANCZOS)
                ox = (bg.width  - W) // 2
                oy = (bg.height - H) // 2
                bg = bg.crop((ox, oy, ox + W, oy + H))
                bg = bg.filter(ImageFilter.GaussianBlur(radius=8))
                bg = ImageEnhance.Brightness(bg).enhance(0.45)
                card.paste(bg.convert("RGBA"), (0, 0))
            except Exception:
                pass

        card = Image.alpha_composite(card, Image.new("RGBA", (W, H), OVERLAY))
        draw = ImageDraw.Draw(card, "RGBA")

        # ══════════════ HEADER ══════════════
        # Avatar circular 96x96
        AV   = 96
        av_x = PAD
        av_y = PAD
        draw.ellipse((av_x - 4, av_y - 4, av_x + AV + 4, av_y + AV + 4), fill=ACCENT)
        if av_raw:
            try:
                av  = Image.open(io.BytesIO(av_raw)).convert("RGBA").resize((AV, AV), Image.LANCZOS)
                msk = Image.new("L", (AV, AV), 0)
                ImageDraw.Draw(msk).ellipse((0, 0, AV, AV), fill=255)
                base = Image.new("RGBA", (AV, AV), (0, 0, 0, 0))
                base.paste(av, mask=msk)
                card.paste(base, (av_x, av_y), base)
            except Exception:
                draw.ellipse((av_x, av_y, av_x + AV, av_y + AV), fill=(50, 50, 50))
        else:
            draw.ellipse((av_x, av_y, av_x + AV, av_y + AV), fill=(50, 50, 50))

        # Nombre + url
        tx = av_x + AV + 22
        ty = av_y + 6
        dn = display_name if len(display_name) <= 24 else display_name[:23] + "…"
        draw.text((tx, ty),      dn,                  font=f28, fill=WHITE)
        draw.text((tx, ty + 36), f"last.fm/{username}", font=f12, fill=(140, 140, 140, 200))

        # Stats en fila  valor GRANDE + label pequeño
        sy = ty + 62
        for val, lbl in [(f"{playcount:,}", "scrobbles"),
                         (f"{artist_count:,}", "artistas"),
                         (f"{track_count:,}", "canciones")]:
            draw.text((tx, sy), val, font=f15, fill=WHITE)
            vw = int(draw.textlength(val, font=f15))
            draw.text((tx + vw + 5, sy + 3), lbl, font=f11, fill=(150, 150, 150, 210))
            tx += vw + int(draw.textlength(lbl, font=f11)) + 30

        # ══════════════ SEPARADOR HORIZONTAL ══════════════
        SEP_Y = av_y + AV + 22   # = 36+96+22 = 154
        draw.line((PAD, SEP_Y, W - PAD, SEP_Y), fill=(255, 255, 255, 30), width=1)

        # ══════════════ COLUMNA IZQUIERDA — artistas ══════════════
        # Zona: x=PAD..PAD+460,  y=SEP_Y+14..H-PAD
        # Espacio vertical disponible para 5 artistas:
        #   top_y = SEP_Y + 14 + 16(label) = SEP_Y+30
        #   bottom_y = H - PAD - 20(footer) = 444
        #   disponible = 444 - (SEP_Y+30) = 444 - 184 = 260 → 52px por artista

        LEFT_W  = 440
        VDIV_X  = PAD + LEFT_W + 18
        top_y   = SEP_Y + 14

        draw.text((PAD, top_y), "TOP ARTISTAS  •  este mes", font=f11, fill=(140, 140, 140, 180))

        bar_start = top_y + 18
        ROW_H     = 50          # altura exacta por fila (5 × 50 = 250, cabe de sobra)
        BAR_H     = 7
        BAR_X     = PAD
        BAR_W     = LEFT_W - 4
        max_p     = int(artists[0]["playcount"]) if artists else 1

        for i, art in enumerate(artists[:5]):
            name  = art["name"]
            plays = int(art["playcount"])
            ry    = bar_start + i * ROW_H

            # "1." número
            n_str = f"{i + 1}."
            draw.text((BAR_X, ry), n_str, font=f12, fill=(120, 120, 120, 200))
            nx = BAR_X + int(draw.textlength("5.", font=f12)) + 6

            # nombre artista
            name_disp = name if len(name) <= 26 else name[:25] + "…"
            draw.text((nx, ry), name_disp, font=f15, fill=WHITE)

            # plays alineados a la derecha
            p_str = f"{plays:,}"
            pw    = int(draw.textlength(p_str, font=f12))
            draw.text((BAR_X + BAR_W - pw, ry), p_str, font=f12, fill=(150, 150, 150, 200))

            # barra de progreso
            by      = ry + 22
            fill_px = max(8, int((plays / max_p) * BAR_W))
            draw.rounded_rectangle((BAR_X, by, BAR_X + BAR_W, by + BAR_H),
                                   radius=3, fill=(255, 255, 255, 25))
            draw.rounded_rectangle((BAR_X, by, BAR_X + fill_px, by + BAR_H),
                                   radius=3, fill=ACCENT)

        # ══════════════ DIVISOR VERTICAL ══════════════
        draw.line((VDIV_X, SEP_Y + 8, VDIV_X, H - PAD - 16),
                  fill=(255, 255, 255, 28), width=1)

        # ══════════════ COLUMNA DERECHA — álbumes 2×2 ══════════════
        # Zona disponible: x=VDIV_X+20..W-PAD,  y=top_y..H-PAD-20
        # Ancho derecho: W - PAD - (VDIV_X+20) = 1000-36-458-20 = 486
        # 2 portadas por fila → COV = (486 - GAP) // 2
        RIGHT_X = VDIV_X + 24
        RIGHT_W = W - PAD - RIGHT_X    # ~482
        GAP     = 12
        COV     = (RIGHT_W - GAP) // 2  # ~235  — portadas grandes

        draw.text((RIGHT_X, top_y), "TOP ÁLBUMES  •  este mes", font=f11, fill=(140, 140, 140, 180))

        grid_y = top_y + 18
        # Altura disponible para 2 filas + labels
        # label alto = 14, gap entre fila = 8
        # 2 filas: grid_y .. grid_y + COV + 14 + 8 + COV + 14
        # COV máximo para que quepa: (H - PAD - 20 - grid_y - 14*2 - 8) // 2
        available_h = H - PAD - 20 - grid_y
        COV_H = (available_h - 14 * 2 - GAP) // 2   # altura máxima por portada
        COV   = min(COV, COV_H)                       # respetar el límite vertical también

        for j in range(min(4, len(albums))):
            col = j % 2
            row = j // 2
            cx  = RIGHT_X + col * (COV + GAP)
            cy  = grid_y  + row * (COV + 16 + GAP)  # 16 = altura del label debajo

            alb = albums[j]
            cb  = cov_raws[j] if j < len(cov_raws) else None

            # Portada
            if cb:
                try:
                    cim = Image.open(io.BytesIO(cb)).convert("RGBA").resize((COV, COV), Image.LANCZOS)
                    msk = Image.new("L", (COV, COV), 0)
                    ImageDraw.Draw(msk).rounded_rectangle((0, 0, COV, COV), radius=8, fill=255)
                    base = Image.new("RGBA", (COV, COV), (0, 0, 0, 0))
                    base.paste(cim, mask=msk)
                    card.paste(base, (cx, cy), base)
                except Exception:
                    draw.rounded_rectangle((cx, cy, cx + COV, cy + COV), radius=8, fill=(40, 40, 40))
            else:
                draw.rounded_rectangle((cx, cy, cx + COV, cy + COV), radius=8, fill=(35, 35, 35))

            # Nombre álbum debajo
            aname = alb["name"]
            adisp = aname if len(aname) <= 18 else aname[:17] + "…"
            draw.text((cx, cy + COV + 3), adisp, font=f11, fill=(190, 190, 190, 200))

        # ══════════════ FOOTER ══════════════
        fy = H - 20
        draw.text((PAD, fy), "last.fm  •  fmcard", font=f11, fill=(80, 80, 80, 180))
        ru = f"/{username}"
        draw.text((W - PAD - int(draw.textlength(ru, font=f11)), fy),
                  ru, font=f11, fill=(80, 80, 80, 180))

        # ── Exportar PNG ──
        out = io.BytesIO()
        card.convert("RGB").save(out, format="PNG", optimize=False)
        out.seek(0)
        return out.read()

    except Exception as e:
        print(f"[fmcard error] {e}")
        return None



