# ─── Editor de metadatos post-descarga ────────────────────────────────────────

class MetaEditModal(discord.ui.Modal):
    def __init__(self, field: str, current: str, edit_view):
        labels = {
            "title":     "Título",
            "artist":    "Artista",
            "album":     "Álbum",
            "cover_url": "URL del cover (imagen)",
        }
        super().__init__(title=f"Editar {labels.get(field, field)}")
        self.field     = field
        self.edit_view = edit_view
        self.input = discord.ui.TextInput(
            label=labels.get(field, field),
            default=current,
            required=True,
            max_length=200,
        )
        self.add_item(self.input)

    async def on_submit(self, interaction: discord.Interaction):
        self.edit_view.meta[self.field] = self.input.value.strip()
        await interaction.response.edit_message(
            embed=self.edit_view.build_embed(),
            view=self.edit_view,
        )


class MetaEditView(discord.ui.View):
    def __init__(self, file_bytes: bytes, filename: str, meta: dict, fmt: str, author_id: int):
        super().__init__(timeout=300)
        self.file_bytes = file_bytes
        self.filename   = filename
        self.meta       = dict(meta)
        self.fmt        = fmt
        self.author_id  = author_id

    def build_embed(self):
        embed = discord.Embed(
            title=self.meta.get("title", "Desconocido"),
            description=(
                f"👤 **{self.meta.get('artist', 'Desconocido')}**\n"
                f"💿 {self.meta.get('album', 'Desconocido')}"
            ),
            color=0xf39c12,
        )
        thumb = self.meta.get("cover_url") or self.meta.get("thumbnail")
        if thumb:
            embed.set_thumbnail(url=thumb)
        embed.set_footer(text=f"{DL_FORMATS[self.fmt]['label']} • {self.meta.get('duration_str', '')} • Edita o envía")
        return embed

    async def _check(self, interaction):
        if interaction.user.id != self.author_id:
            await interaction.response.send_message("Solo quien descargó puede editar.", ephemeral=True)
            return False
        return True

    @discord.ui.button(label="✏️ Título", style=discord.ButtonStyle.secondary, row=0)
    async def edit_title(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not await self._check(interaction): return
        await interaction.response.send_modal(MetaEditModal("title", self.meta.get("title", ""), self))

    @discord.ui.button(label="👤 Artista", style=discord.ButtonStyle.secondary, row=0)
    async def edit_artist(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not await self._check(interaction): return
        await interaction.response.send_modal(MetaEditModal("artist", self.meta.get("artist", ""), self))

    @discord.ui.button(label="💿 Álbum", style=discord.ButtonStyle.secondary, row=0)
    async def edit_album(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not await self._check(interaction): return
        await interaction.response.send_modal(MetaEditModal("album", self.meta.get("album", ""), self))

    @discord.ui.button(label="🖼️ Cover URL", style=discord.ButtonStyle.secondary, row=1)
    async def edit_cover(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not await self._check(interaction): return
        current = self.meta.get("cover_url") or self.meta.get("thumbnail") or ""
        await interaction.response.send_modal(MetaEditModal("cover_url", current, self))

    @discord.ui.button(label="✅ Enviar", style=discord.ButtonStyle.success, row=1)
    async def send_file(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not await self._check(interaction): return

        for child in self.children:
            child.disabled = True

        await interaction.response.edit_message(
            embed=discord.Embed(
                title="📦 Empaquetando...",
                description="Aplicando metadatos y enviando...",
                color=0x3498db,
            ),
            view=self,
        )

        # Aplicar metadatos con mutagen
        file_bytes = self.file_bytes
        fmt = self.fmt
        try:
            file_bytes = _apply_metadata(
                file_bytes, fmt,
                title=self.meta.get("title"),
                artist=self.meta.get("artist"),
                album=self.meta.get("album"),
                cover_url=self.meta.get("cover_url") or self.meta.get("thumbnail"),
            )
        except Exception as e:
            print(f"[meta] Error aplicando metadatos: {e}")

        # Nombre limpio
        t = re.sub(r'\s*\(.*?\)', '', self.meta.get("title", "track")).strip()[:60]
        a = self.meta.get("artist", "Artista")[:30]
        clean_name = re.sub(r'[\\/*?:"<>|]', "", f"{a} - {t}.{fmt}")

        embed = discord.Embed(
            title=self.meta.get("title", clean_name),
            description=f"👤 {self.meta.get('artist', 'Desconocido')}  •  💿 {self.meta.get('album', 'Desconocido')}",
            color=0x1db954,
        )
        embed.set_footer(text=f"{DL_FORMATS[fmt]['label']} • {self.meta.get('duration_str', '')}")
        thumb = self.meta.get("cover_url") or self.meta.get("thumbnail")
        if thumb:
            embed.set_thumbnail(url=thumb)

        discord_file = discord.File(io.BytesIO(file_bytes), filename=clean_name)
        await interaction.edit_original_response(embed=embed, view=None, attachments=[discord_file])

    @discord.ui.button(label="❌ Cancelar", style=discord.ButtonStyle.danger, row=1)
    async def cancel(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not await self._check(interaction): return
        await interaction.response.edit_message(
            embed=discord.Embed(title="❌ Cancelado", color=0xe74c3c),
            view=None,
        )


def _apply_metadata(file_bytes: bytes, fmt: str, title=None, artist=None, album=None, cover_url=None) -> bytes:
    """Aplica metadatos al archivo de audio usando mutagen."""
    import tempfile, os, urllib.request
    from mutagen.id3 import ID3, TIT2, TPE1, TALB, APIC, ID3NoHeaderError
    from mutagen.mp3 import MP3
    from mutagen.mp4 import MP4, MP4Cover
    from mutagen.flac import FLAC, Picture

    # Descargar cover
    cover_data = None
    if cover_url:
        try:
            req = urllib.request.Request(cover_url, headers={"User-Agent": "Mozilla/5.0"})
            with urllib.request.urlopen(req, timeout=10) as r:
                cover_data = r.read()
        except Exception as e:
            print(f"[mutagen] cover error: {e}")

    # Escribir a archivo temporal
    suffix = f".{fmt}"
    with tempfile.NamedTemporaryFile(suffix=suffix, delete=False) as tmp:
        tmp.write(file_bytes)
        tmp_path = tmp.name

    try:
        if fmt == "mp3":
            audio = MP3(tmp_path)
            try:
                audio.tags = ID3(tmp_path)
            except ID3NoHeaderError:
                audio.add_tags()
            if title:  audio.tags["TIT2"] = TIT2(encoding=3, text=title)
            if artist: audio.tags["TPE1"] = TPE1(encoding=3, text=artist)
            if album:  audio.tags["TALB"] = TALB(encoding=3, text=album)
            if cover_data:
                audio.tags.delall("APIC")
                audio.tags["APIC"] = APIC(encoding=3, mime="image/jpeg", type=3, desc="Cover", data=cover_data)
            audio.save(tmp_path)

        elif fmt == "m4a":
            audio = MP4(tmp_path)
            if title:  audio["©nam"] = [title]
            if artist: audio["©ART"] = [artist]
            if album:  audio["©alb"] = [album]
            if cover_data:
                audio["covr"] = [MP4Cover(cover_data, imageformat=MP4Cover.FORMAT_JPEG)]
            audio.save()

        elif fmt == "flac":
            audio = FLAC(tmp_path)
            if title:  audio["title"]  = [title]
            if artist: audio["artist"] = [artist]
            if album:  audio["album"]  = [album]
            if cover_data:
                pic = Picture()
                pic.type = 3
                pic.mime = "image/jpeg"
                pic.data = cover_data
                audio.clear_pictures()
                audio.add_picture(pic)
            audio.save()

        elif fmt == "wav":
            # WAV no soporta tags estándar, devolver original
            return file_bytes

        with open(tmp_path, "rb") as f:
            result = f.read()
        print(f"[mutagen] metadatos aplicados OK ({fmt})")
        return result

    except Exception as e:
        print(f"[mutagen] error: {e}")
        return file_bytes
    finally:
        try: os.unlink(tmp_path)
        except: pass


# ─── .dl (YouTube / SoundCloud / Spotify / Apple Music) ──────────────────────

DL_FORMATS = {
    "mp3":  {"ext": "mp3",  "label": "MP3 320kbps",  "ytdlp_format": "bestaudio[ext=webm]/bestaudio[ext=m4a]/bestaudio/best", "postprocessor": "mp3",  "quality": "320"},
    "flac": {"ext": "flac", "label": "FLAC",          "ytdlp_format": "bestaudio[ext=webm]/bestaudio[ext=m4a]/bestaudio/best", "postprocessor": "flac", "quality": "0"},
    "wav":  {"ext": "wav",  "label": "WAV",           "ytdlp_format": "bestaudio[ext=webm]/bestaudio[ext=m4a]/bestaudio/best", "postprocessor": "wav",  "quality": "0"},
    "m4a":  {"ext": "m4a",  "label": "M4A (AAC)",     "ytdlp_format": "bestaudio[ext=m4a]/bestaudio[ext=webm]/bestaudio/best", "postprocessor": "m4a", "quality": "0"},
}

class DlFormatView(discord.ui.View):
    def __init__(self, url: str, author_id: int, is_search: bool = False):
        super().__init__(timeout=60)
        self.url       = url
        self.author_id = author_id
        self.is_search = is_search

    async def _do_download(self, interaction: discord.Interaction, fmt: str):
        if interaction.user.id != self.author_id:
            await interaction.response.send_message("Solo quien usó el comando puede elegir el formato.", ephemeral=True)
            return

        for child in self.children:
            child.disabled = True
        await interaction.response.edit_message(
            embed=discord.Embed(
                title="⬇️ Descargando...",
                description=f"Formato: **{DL_FORMATS[fmt]['label']}**\nUn momento...",
                color=0x3498db,
            ),
            view=self,
        )

        # Tarea de progreso animado mientras descarga
        progress_task = None
        async def _update_progress():
            msgs = [
                "🔍 Buscando la canción...",
                "📡 Conectando con la fuente...",
                "⬇️ Descargando audio...",
                "🎵 Procesando archivo...",
                "🏷️ Aplicando metadatos...",
                "⏳ Casi listo...",
            ]
            for i, msg in enumerate(msgs * 5):
                await asyncio.sleep(6)
                try:
                    await interaction.edit_original_response(
                        embed=discord.Embed(
                            title="⬇️ Descargando...",
                            description=f"Formato: **{DL_FORMATS[fmt]['label']}**\n{msg}",
                            color=0x3498db,
                        )
                    )
                except:
                    break

        progress_task = asyncio.create_task(_update_progress())

        try:
            file_bytes, filename, meta, error = await _ytdlp_download(self.url, fmt, is_search=self.is_search)
        except Exception as e:
            if progress_task: progress_task.cancel()
            await interaction.edit_original_response(
                embed=discord.Embed(title="❌ Error", description=str(e), color=0xe74c3c),
                view=None,
            )
            return
        finally:
            if progress_task: progress_task.cancel()

        if error:
            await interaction.edit_original_response(
                embed=discord.Embed(title="❌ Error", description=error, color=0xe74c3c),
                view=None,
            )
            return

        # Mostrar editor de metadatos antes de mandar
        edit_view = MetaEditView(file_bytes, filename, meta, fmt, interaction.user.id)
        await interaction.edit_original_response(
            embed=edit_view.build_embed(),
            view=edit_view,
        )

    @discord.ui.button(label="MP3 320kbps", style=discord.ButtonStyle.primary, emoji="🎵")
    async def btn_mp3(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._do_download(interaction, "mp3")

    @discord.ui.button(label="FLAC", style=discord.ButtonStyle.secondary, emoji="💎")
    async def btn_flac(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._do_download(interaction, "flac")

    @discord.ui.button(label="WAV", style=discord.ButtonStyle.secondary, emoji="🎚️")
    async def btn_wav(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._do_download(interaction, "wav")

    @discord.ui.button(label="M4A (AAC)", style=discord.ButtonStyle.secondary, emoji="🍎")
    async def btn_m4a(self, interaction: discord.Interaction, button: discord.ui.Button):
        await self._do_download(interaction, "m4a")


def _is_spotify(url: str) -> bool:
    return "spotify.com" in url or "spotify:" in url

def _is_apple_music(url: str) -> bool:
    return "music.apple.com" in url

async def _ytdlp_download(url: str, fmt: str, is_search: bool = False):
    """Descarga con yt-dlp o spotDL y devuelve (bytes, filename, meta, error)."""
    import tempfile, os

    finfo   = DL_FORMATS[fmt]
    tmp_dir = tempfile.mkdtemp()

    try:
        loop = asyncio.get_event_loop()

        # ── Búsqueda de texto → SoundCloud directo con yt-dlp ───────────────────
        if is_search or (not url.startswith("http") and not url.startswith("ytdl:")):
            import yt_dlp
            spotdl_fmt = fmt if fmt in ("mp3", "flac", "wav", "m4a") else "mp3"
            ffmpeg_loc = os.environ.get("FFMPEG_PATH", "/root/.config/spotdl/ffmpeg")
            proxy_url = os.environ.get("HTTPS_PROXY", "http://cgjmxtbq:qwt45zlcd33m@38.154.203.95:5863")
            ydl_opts = {
                "format": "bestaudio/best",
                "outtmpl": os.path.join(tmp_dir, "%(title)s.%(ext)s"),
                "quiet": True,
                "no_warnings": True,
                "ffmpeg_location": ffmpeg_loc,
                "writethumbnail": True,
                "proxy": proxy_url,
                "cookiefile": "/app/cookies.txt",
                "extractor_args": {"youtube": {"player_client": ["ios"]}},
                "postprocessors": [
                    {"key": "FFmpegExtractAudio", "preferredcodec": spotdl_fmt, "preferredquality": "320"},
                    {"key": "FFmpegMetadata"},
                    {"key": "EmbedThumbnail"},
                ],
            }
            def _run_sc_search():
                # Intentar SoundCloud primero, luego YouTube con proxy
                for search_prefix in [f"scsearch3:{url}", f"ytsearch3:{url}"]:
                    try:
                        with yt_dlp.YoutubeDL({**ydl_opts, "skip_download": True, "quiet": True}) as ydl:
                            results = ydl.extract_info(search_prefix, download=False)
                        entries = results.get("entries", []) if results else []
                        for entry in entries:
                            try:
                                with yt_dlp.YoutubeDL(ydl_opts) as ydl:
                                    info = ydl.extract_info(entry["webpage_url"], download=True)
                                    return info
                            except Exception as e:
                                print(f"[search] skipping {entry.get('title')}: {e}")
                                continue
                    except Exception as e:
                        print(f"[search] {search_prefix} falló: {e}")
                        continue
                raise Exception("No results en ninguna plataforma")

            try:
                info = await loop.run_in_executor(None, _run_sc_search)
            except Exception as _se:
                return None, None, {}, f"❌ No encontré la canción: **{url}**"

            audio_exts = (".mp3", ".flac", ".wav", ".m4a", ".ogg", ".opus", ".webm")
            files = [f for f in os.listdir(tmp_dir) if f.lower().endswith(audio_exts)]
            print(f"[scsearch] archivos: {files}")

            if not files:
                return None, None, {}, f"❌ No encontré la canción: **{url}**"

            filepath = os.path.join(tmp_dir, files[0])
            with open(filepath, "rb") as f:
                file_bytes = f.read()

            # Metadata desde yt-dlp info
            entries = info.get("entries", [info]) if info else [{}]
            iinfo = entries[0] if entries else {}
            duration_s = iinfo.get("duration", 0)
            mins, secs = divmod(int(duration_s), 60)
            raw_title  = iinfo.get("title", os.path.splitext(files[0])[0])
            raw_artist = iinfo.get("uploader") or iinfo.get("artist") or "Desconocido"
            thumbs = iinfo.get("thumbnails", [])
            thumbnail = iinfo.get("thumbnail")
            if thumbs:
                best = max(thumbs, key=lambda t: t.get("width", 0) * t.get("height", 0) if t.get("width") else 0)
                thumbnail = best.get("url") or thumbnail

            meta = {
                "title":        raw_title,
                "artist":       raw_artist,
                "album":        raw_title,
                "thumbnail":    thumbnail,
                "duration_str": f"{mins}:{secs:02d}",
            }
            t = re.sub(r'\s*\(.*?\)', '', raw_title).strip()[:60]
            filename = re.sub(r'[\\/*?:"<>|]', "", f"{raw_artist[:30]} - {t}.{spotdl_fmt}")
            for f in os.listdir(tmp_dir):
                try: os.remove(os.path.join(tmp_dir, f))
                except: pass
            try: os.rmdir(tmp_dir)
            except: pass
            return file_bytes, filename, meta, None

        # ── Spotify / Apple Music → spotDL ───────────────────────────────────
        if _is_spotify(url) or _is_apple_music(url):
            import subprocess

            # spotDL siempre descarga en MP3 de alta calidad; convertimos después si hace falta
            spotdl_fmt = fmt if fmt in ("mp3", "flac", "wav", "m4a") else "mp3"
            import pathlib, shutil
            spotdl_bin_dir = str(pathlib.Path.home() / ".spotdl")

            # Agregar ~/.spotdl al PATH para que spotDL encuentre ffmpeg y deno
            env = os.environ.copy()
            env["PATH"] = spotdl_bin_dir + os.pathsep + env.get("PATH", "")

            cmd = [
                "spotdl", "download", url,
                "--output", tmp_dir,
                "--format", spotdl_fmt,
                "--bitrate", "320k",
                "--overwrite", "skip",
                "--audio", "soundcloud", "youtube",
                "--cookie-file", "/app/cookies.txt",
            ]

            def _run_spotdl():
                result = subprocess.run(cmd, capture_output=True, text=True, timeout=300, env=env)
                return result

            result = await loop.run_in_executor(None, _run_spotdl)

            print(f"[spotDL] returncode: {result.returncode}")
            print(f"[spotDL] stdout: {result.stdout[:500] if result.stdout else 'vacío'}")
            print(f"[spotDL] stderr: {result.stderr[:500] if result.stderr else 'vacío'}")
            print(f"[spotDL] archivos en tmp: {os.listdir(tmp_dir)}")

            if result.returncode != 0 and not os.listdir(tmp_dir):
                err = (result.stderr or result.stdout or "Sin output")[:400]
                return None, None, {}, f"❌ spotDL error: {err}"

            ext   = spotdl_fmt
            audio_exts = (".mp3", ".flac", ".wav", ".m4a", ".ogg", ".opus", ".webm")
            files = [f for f in os.listdir(tmp_dir) if f.endswith(f".{ext}")]
            if not files:
                files = [f for f in os.listdir(tmp_dir) if f.lower().endswith(audio_exts)]
            if not files:
                files = [f for f in os.listdir(tmp_dir) if not f.endswith((".jpg", ".png", ".webp", ".part", ".tmp"))]
            print(f"[spotDL] archivos encontrados: {files}")
            if not files:
                return None, None, {}, "❌ No se encontró el archivo descargado."

            filepath = os.path.join(tmp_dir, files[0])
            current_ext = os.path.splitext(files[0])[1].lower().lstrip(".")

            # Si el archivo no es el formato pedido, convertir con ffmpeg
            if current_ext != spotdl_fmt:
                converted = filepath.replace(f".{current_ext}", f".{spotdl_fmt}")
                def _convert():
                    import subprocess as sp
                    sp.run(
                        ["ffmpeg", "-i", filepath, "-b:a", "320k", "-y", converted],
                        capture_output=True, timeout=120
                    )
                await loop.run_in_executor(None, _convert)
                if os.path.exists(converted):
                    filepath = converted
                    files[0] = os.path.basename(converted)

            with open(filepath, "rb") as f:
                file_bytes = f.read()

            # Extraer metadata del nombre del archivo (spotDL usa "Artista - Título.ext")
            base = os.path.splitext(files[0])[0]
            # Quitar número de track al inicio (ej: "01 Yo Voy" -> "Yo Voy")
            base = re.sub(r'^\d+\s+', '', base).strip()
            parts = base.split(" - ", 1)
            artist = parts[0].strip() if len(parts) > 1 else "Desconocido"
            title  = parts[1].strip() if len(parts) > 1 else base
            # Quitar número de track del título también por si acaso
            title = re.sub(r'^\d+\s+', '', title).strip()

            # Intentar sacar album real con mutagen
            album = "Desconocido"
            thumbnail = None
            try:
                from mutagen.mp3 import MP3
                from mutagen.id3 import ID3
                from mutagen.mp4 import MP4
                from mutagen.flac import FLAC
                _mpath = os.path.join(tmp_dir, files[0])
                if ext == "mp3":
                    _tags = ID3(_mpath)
                    album = str(_tags.get("TALB", "Desconocido"))
                    artist = str(_tags.get("TPE1", artist))
                    title  = str(_tags.get("TIT2", title))
                    apic = _tags.get("APIC:")
                    if apic: thumbnail = None  # no podemos usar bytes como URL
                elif ext == "m4a":
                    _tags = MP4(_mpath)
                    album  = str(_tags.get("©alb", ["Desconocido"])[0])
                    artist = str(_tags.get("©ART", [artist])[0])
                    title  = str(_tags.get("©nam", [title])[0])
                elif ext == "flac":
                    _tags = FLAC(_mpath)
                    album  = _tags.get("album",  ["Desconocido"])[0]
                    artist = _tags.get("artist", [artist])[0]
                    title  = _tags.get("title",  [title])[0]
            except Exception as _me:
                print(f"[mutagen] read error: {_me}")

            meta = {
                "title":        title,
                "artist":       artist,
                "album":        album if album and album != "Desconocido" else title,
                "thumbnail":    thumbnail,
                "duration_str": "",
            }
            # Limpiar y truncar nombre para que no se corte en Discord
            title_clean  = re.sub(r'\s*\(.*?\)', '', title).strip()
            title_clean  = re.sub(r'\s*\[.*?\]', '', title_clean).strip()
            title_clean  = title_clean[:60] if len(title_clean) > 60 else title_clean
            artist_clean = artist[:30] if len(artist) > 30 else artist
            filename = re.sub(r'[\\/*?:"<>|]', "", f"{artist_clean} - {title_clean}.{ext}")

        # ── YouTube → extraer título y buscar via spotDL (evita bloqueo de IP) ──
        elif "youtube.com" in url or "youtu.be" in url:
            import subprocess
            import pathlib, shutil
            spotdl_bin_dir = str(pathlib.Path.home() / ".spotdl")
            env = os.environ.copy()
            env["PATH"] = spotdl_bin_dir + os.pathsep + env.get("PATH", "")

            # Extraer título del video via oEmbed (no requiere auth ni descarga)
            search_query = None
            try:
                import urllib.request, json as _json
                vid_id = None
                if "youtu.be/" in url:
                    vid_id = url.split("youtu.be/")[1].split("?")[0]
                elif "v=" in url:
                    vid_id = url.split("v=")[1].split("&")[0]
                if vid_id:
                    oembed_url = f"https://www.youtube.com/oembed?url=https://www.youtube.com/watch?v={vid_id}&format=json"
                    req = urllib.request.Request(oembed_url, headers={"User-Agent": "Mozilla/5.0"})
                    with urllib.request.urlopen(req, timeout=10) as r:
                        data = _json.loads(r.read())
                        search_query = data.get("title", "")
                        print(f"[YT] título via oEmbed: {search_query}")
            except Exception as _e:
                print(f"[YT] oEmbed falló: {_e}")

            if not search_query:
                return None, None, {}, "❌ No pude obtener el título del video. Intenta con Spotify o SoundCloud."

            print(f"[YT] buscando como: {search_query}")

            spotdl_fmt = fmt if fmt in ("mp3", "flac", "wav", "m4a") else "mp3"
            cmd = [
                "spotdl", "download", search_query,
                "--output", tmp_dir,
                "--format", spotdl_fmt,
                "--bitrate", "320k",
                "--overwrite", "skip",
                "--audio", "soundcloud", "youtube",
                "--cookie-file", "/app/cookies.txt",
            ]

            def _run_yt_spotdl():
                return subprocess.run(cmd, capture_output=True, text=True, timeout=300, env=env)

            result = await loop.run_in_executor(None, _run_yt_spotdl)
            print(f"[spotDL-YT] returncode: {result.returncode}")
            print(f"[spotDL-YT] stdout: {result.stdout[:300]}")

            audio_exts = (".mp3", ".flac", ".wav", ".m4a", ".ogg", ".opus", ".webm")
            files = [f for f in os.listdir(tmp_dir) if f.lower().endswith(audio_exts)]

            if not files:
                return None, None, {}, "❌ YouTube no está soportado. Usa un link de Spotify o SoundCloud."

            filepath = os.path.join(tmp_dir, files[0])
            current_ext = os.path.splitext(files[0])[1].lower().lstrip(".")
            if current_ext != spotdl_fmt:
                converted = filepath.replace(f".{current_ext}", f".{spotdl_fmt}")
                def _conv():
                    import subprocess as sp
                    sp.run(["ffmpeg", "-i", filepath, "-b:a", "320k", "-y", converted], capture_output=True, timeout=120)
                await loop.run_in_executor(None, _conv)
                if os.path.exists(converted):
                    filepath = converted
                    files[0] = os.path.basename(converted)

            with open(filepath, "rb") as f:
                file_bytes = f.read()

            base = os.path.splitext(files[0])[0]
            base = re.sub(r'^\d+\s+', '', base).strip()
            parts = base.split(" - ", 1)
            artist = parts[0].strip() if len(parts) > 1 else "Desconocido"
            title  = parts[1].strip() if len(parts) > 1 else base

            meta = {"title": title, "artist": artist, "album": title, "thumbnail": None, "duration_str": ""}
            t = re.sub(r'\s*\(.*?\)', '', title).strip()[:60]
            filename = re.sub(r'[\\/*?:"<>|]', "", f"{artist[:30]} - {t}.{spotdl_fmt}")

            for f in os.listdir(tmp_dir):
                try: os.remove(os.path.join(tmp_dir, f))
                except: pass
            try: os.rmdir(tmp_dir)
            except: pass

            return file_bytes, filename, meta, None

        # ── SoundCloud / Apple Music → yt-dlp ────────────────────────────────
        else:
            import yt_dlp

            import pathlib, shutil, glob, subprocess as _sp
            # Buscar ffmpeg en todas las rutas posibles incluyendo nix store
            def _find_ffmpeg():
                # 1. which
                w = shutil.which("ffmpeg")
                if w: return w
                # 2. glob en nix store
                nix_matches = glob.glob("/nix/store/*/bin/ffmpeg")
                if nix_matches: return nix_matches[0]
                # 3. find command
                try:
                    r = _sp.run(["find", "/", "-name", "ffmpeg", "-type", "f"], 
                                capture_output=True, text=True, timeout=5)
                    lines = [l for l in r.stdout.splitlines() if "ffmpeg" in l and "ffprobe" not in l]
                    if lines: return lines[0]
                except: pass
                # 4. spotdl
                p = pathlib.Path.home() / ".spotdl" / "ffmpeg"
                if p.exists(): return str(p)
                return None
            ffmpeg_loc = _find_ffmpeg()
            print(f"[yt-dlp] usando ffmpeg: {ffmpeg_loc}")

            proxy_url = os.environ.get("HTTPS_PROXY", "http://cgjmxtbq:qwt45zlcd33m@38.154.203.95:5863")
            ydl_opts = {
                "format": finfo["ytdlp_format"],
                "outtmpl": os.path.join(tmp_dir, "%(title)s.%(ext)s"),
                "quiet": True,
                "no_warnings": True,
                "cookiefile": "/app/cookies.txt",
                "ffmpeg_location": ffmpeg_loc,
                "proxy": proxy_url,
                "extractor_args": {"youtube": {"player_client": ["ios", "web"]}},
                "writethumbnail": True,
                "postprocessors": [
                    {
                        "key": "FFmpegExtractAudio",
                        "preferredcodec": finfo["postprocessor"],
                        "preferredquality": finfo["quality"],
                    },
                    {"key": "FFmpegMetadata"},
                    {"key": "EmbedThumbnail"},
                ],
                "embedthumbnail": True,
                "addmetadata": True,
            }

            def _run_ytdlp():
                with yt_dlp.YoutubeDL(ydl_opts) as ydl:
                    return ydl.extract_info(url, download=True)

            info = await loop.run_in_executor(None, _run_ytdlp)

            ext   = finfo["ext"]
            files = [f for f in os.listdir(tmp_dir) if f.endswith(f".{ext}")]
            if not files:
                files = [f for f in os.listdir(tmp_dir) if not f.endswith((".jpg", ".png", ".webp", ".part"))]
            if not files:
                return None, None, {}, "❌ No se encontró el archivo descargado."

            filepath = os.path.join(tmp_dir, files[0])
            with open(filepath, "rb") as f:
                file_bytes = f.read()

            duration_s = info.get("duration", 0)
            mins, secs = divmod(int(duration_s), 60)

            # Limpiar título de basura como {{121}}
            raw_title  = info.get("title", "Desconocido")
            raw_artist = info.get("artist") or info.get("uploader") or "Desconocido"
            raw_album  = info.get("album") or info.get("playlist_title") or "Desconocido"
            clean_title  = re.sub(r'\{\{.*?\}\}', '', raw_title).strip()
            clean_title  = re.sub(r'\[.*?\]', '', clean_title).strip()
            clean_artist = re.sub(r'\{\{.*?\}\}', '', raw_artist).strip()

            # Mejor thumbnail: preferir la más grande
            thumbs = info.get("thumbnails", [])
            thumbnail = info.get("thumbnail")
            if thumbs:
                best = max(thumbs, key=lambda t: t.get("width", 0) * t.get("height", 0) if t.get("width") else 0)
                thumbnail = best.get("url") or thumbnail

            meta = {
                "title":        clean_title or raw_title,
                "artist":       clean_artist or raw_artist,
                "album":        raw_album if raw_album != "Desconocido" else clean_title,
                "thumbnail":    thumbnail,
                "duration_str": f"{mins}:{secs:02d}",
            }
            # Limpiar nombre de archivo
            title_clean  = re.sub(r'\s*\(.*?\)', '', meta['title']).strip()
            artist_clean = meta['artist'][:40]
            title_clean  = title_clean[:60] if len(title_clean) > 60 else title_clean
            filename = re.sub(r'[\\/*?:"<>|]', "", f"{artist_clean} - {title_clean}.{ext}")

        # Limpiar tmp
        for f in os.listdir(tmp_dir):
            try: os.remove(os.path.join(tmp_dir, f))
            except: pass
        try: os.rmdir(tmp_dir)
        except: pass

        return file_bytes, filename, meta, None

    except Exception as e:
        return None, None, {}, f"❌ Error al descargar: {e}"


@bot.command(name="dl", aliases=["download", "descargar"])
async def dl_cmd(ctx, *, url: str = None):
    """Descarga una canción de YouTube, SoundCloud, Spotify o Apple Music. Uso: .dl <url>"""
    try:
        await ctx.message.delete()
    except (discord.Forbidden, discord.NotFound):
        pass

    # Si es reply, extraer canción
    if not url and ctx.message.reference:
        try:
            ref_msg = ctx.message.reference.resolved or await ctx.channel.fetch_message(ctx.message.reference.message_id)
            # 1. Si tiene embed de texto, leer título de ahí
            if ref_msg.embeds:
                emb = ref_msg.embeds[0]
                song_name = emb.title or ""
                if not song_name and emb.description:
                    song_name = emb.description.split("\n")[0].strip()
                import re as _re2
                song_name = _re2.sub(r"[*_`]", "", song_name).strip()
                if song_name:
                    url = song_name
                    print(f"[dl] extraído del embed: {url}")
            # 2. Si es un .np del bot (imagen/fmcard), consultar Last.fm del AUTOR del .np
            # Solo si el mensaje referenciado es del bot Y fue invocado por alguien
            if not url and ref_msg.author.id == bot.user.id:
                # Buscar quién invocó ese .np — revisar si el mensaje tiene referencia a un usuario
                # Buscar la Last.fm del autor del .dl (quien responde)
                lfm_user = get_lastfm_user(ctx.author.id)
                # Pero solo usar Last.fm si el mensaje es reciente (menos de 5 min)
                import datetime
                msg_age = (discord.utils.utcnow() - ref_msg.created_at).total_seconds()
                if lfm_user and msg_age < 300:
                    data = await lastfm_get({"method": "user.getrecenttracks", "user": lfm_user, "limit": 1})
                    tracks = data.get("recenttracks", {}).get("track", []) if data else []
                    if tracks:
                        t = tracks[0] if isinstance(tracks, list) else tracks
                        artist_name = t.get("artist", {}).get("#text", "")
                        track_name  = t.get("name", "")
                        if artist_name and track_name:
                            url = f"{artist_name} - {track_name}"
                        elif track_name:
                            url = track_name
                        print(f"[dl] extraído de Last.fm: {url}")
        except Exception as e:
            print(f"[dl] error extrayendo del reply: {e}")

    if not url:
        embed = discord.Embed(
            title="⬇️ .dl — Descargador de música",
            description=(
                "Manda el link de una canción o responde al .np del bot.\n\n"
                "**Plataformas soportadas:**\n"
                "🎬 YouTube\n"
                "☁️ SoundCloud\n"
                "💚 Spotify\n"
                "🍎 Apple Music\n\n"
                "**Uso:** `.dl <url>` o responde al .np con `.dl`"
            ),
            color=0x1db954,
        )
        return await ctx.send(embed=embed)

    # Si no es URL, tratar como búsqueda de texto via spotDL
    is_search = not url.startswith("http")

    embed = discord.Embed(
        title="🎵 Elige el formato",
        description=f"**{url[:60] + ('...' if len(url) > 60 else '')}**\n\nToca el formato que quieres:",
        color=0x3498db,
    )
    view = DlFormatView(url, ctx.author.id, is_search=is_search)
    await ctx.send(embed=embed, view=view)


bot.run(TOKEN)
